def _resolve_config(
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
) -> ExperimentConfig:
    if config is not None:
        return config
    return get_preset(preset_name)


def _write_json(path: Path, payload: object) -> None:
    path.write_text(json.dumps(payload, indent=2, sort_keys=True), encoding="utf-8")


def _write_stage0_provenance(
    *,
    store: RunStore,
    run_dir: Path,
    manifest: RunManifest,
    resolved_config: ExperimentConfig,
) -> None:
    store.write_provenance(
        run_dir,
        manifest,
        resolved_config=resolved_config.to_dict(),
    )


def _serialize_simulation(simulation) -> dict[str, object]:
    return {
        "states": simulation.states,
        "observations": simulation.observations,
        "context_predictions": simulation.context_predictions,
        "precision": simulation.precision,
        "metadata": simulation.metadata,
    }


def _serialize_batch(batch: TrialBatch) -> dict[str, object]:
    return {
        "orientations": batch.orientations,
        "blank_mask": batch.blank_mask,
        "expected_mask": batch.expected_mask,
        "context_ids": batch.context_ids,
        "task_mode": batch.task_mode,
        "prestim_mode": batch.prestim_mode,
        "orthogonal_events": batch.orthogonal_events,
        "metadata": batch.metadata,
    }


def _serialize_context_prediction(prediction: ContextPrediction) -> dict[str, object]:
    return {
        "orientation_logits": prediction.orientation_logits,
        "precision_logit": prediction.precision_logit,
    }


def _zero_context_prediction(prediction: ContextPrediction) -> ContextPrediction:
    return ContextPrediction(
        orientation_logits=torch.zeros_like(prediction.orientation_logits),
        precision_logit=torch.full_like(prediction.orientation_logits[..., :1], -30.0),
    )


def _oracle_context_prediction(
    batch: TrialBatch,
    *,
    use_precision: bool,
) -> ContextPrediction:
    expected_distribution = batch.metadata["expected_distribution"].to(torch.float32)
    oracle_logits = torch.log(expected_distribution.clamp_min(1e-8))
    precision_logit = None
    if use_precision:
        # The generator does not expose a privileged oracle precision state.
        # A zero logit keeps oracle precision neutral at sigmoid(0) = 0.5.
        precision_logit = torch.zeros((*oracle_logits.shape[:2], 1), dtype=oracle_logits.dtype, device=oracle_logits.device)
    return ContextPrediction(
        orientation_logits=oracle_logits,
        precision_logit=precision_logit,
    )


def _slice_metadata(
    metadata: dict[str, object],
    trial_mask: torch.Tensor,
    *,
    batch_size: int,
) -> dict[str, object]:
    sliced: dict[str, object] = {}
    for key, value in metadata.items():
        if isinstance(value, torch.Tensor) and value.ndim > 0 and value.shape[0] == batch_size:
            sliced[key] = value[trial_mask]
        else:
            sliced[key] = value
    return sliced


def _slice_batch(batch: TrialBatch, trial_mask: torch.Tensor) -> TrialBatch:
    batch_size = batch.orientations.shape[0]
    return TrialBatch(
        orientations=batch.orientations[trial_mask],
        blank_mask=batch.blank_mask[trial_mask] if batch.blank_mask is not None else None,
        expected_mask=batch.expected_mask[trial_mask],
        context_ids=batch.context_ids[trial_mask],
        task_mode=batch.task_mode[trial_mask],
        prestim_mode=batch.prestim_mode[trial_mask],
        orthogonal_events=batch.orthogonal_events[trial_mask],
        metadata=_slice_metadata(batch.metadata, trial_mask, batch_size=batch_size),
    )


def _slice_simulation(simulation: SimulationOutput, trial_mask: torch.Tensor) -> SimulationOutput:
    batch_size = next(iter(simulation.states.values())).shape[0]
    context_prediction = None
    if simulation.context_prediction is not None:
        context_prediction = ContextPrediction(
            orientation_logits=simulation.context_prediction.orientation_logits[trial_mask],
            precision_logit=(
                simulation.context_prediction.precision_logit[trial_mask]
                if simulation.context_prediction.precision_logit is not None
                else None
            ),
        )
    return SimulationOutput(
        states={name: state[trial_mask] for name, state in simulation.states.items()},
        observations={name: value[trial_mask] for name, value in simulation.observations.items()},
        context_prediction=context_prediction,
        metadata=_slice_metadata(simulation.metadata, trial_mask, batch_size=batch_size),
    )


def _compute_task_mode_metrics(
    batch: TrialBatch,
    simulations: dict[str, SimulationOutput],
    assay_runner: AssayRunner,
) -> dict[str, dict[str, object]]:
    task_mode_names = batch.metadata.get(
        "task_mode_names",
        {0: "orientation_relevant", 1: "orthogonal_relevant"},
    )
    task_mode_metrics: dict[str, dict[str, object]] = {}
    for task_mode_id, task_mode_name in sorted(task_mode_names.items()):
        trial_mask = batch.task_mode.eq(int(task_mode_id))
        entry: dict[str, object] = {
            "n_trials": int(trial_mask.sum().item()),
            "metrics": {},
        }
        if trial_mask.any():
            sliced_batch = _slice_batch(batch, trial_mask)
            entry["metrics"] = {
                subcase: assay_runner.compute_primary_metrics(_slice_simulation(simulation, trial_mask), sliced_batch)
                for subcase, simulation in simulations.items()
            }
        task_mode_metrics[task_mode_name] = entry
    return task_mode_metrics


def _evaluate_context_source(
    *,
    batch: TrialBatch,
    prediction: ContextPrediction,
    subcases: tuple[str, ...],
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    config: ExperimentConfig,
) -> tuple[
    dict[str, dict[str, float]],
    dict[str, dict[str, dict[str, torch.Tensor]]],
    dict[str, dict[str, object]],
    dict[str, dict[str, object]],
]:
    primary_metrics: dict[str, dict[str, float]] = {}
    window_summaries: dict[str, dict[str, dict[str, torch.Tensor]]] = {}
    trajectory_payload: dict[str, dict[str, object]] = {}
    simulations: dict[str, SimulationOutput] = {}

    for subcase in subcases:
        simulation = model.rollout(batch, prediction, subcase=subcase)
        evaluated, summary = evaluate_with_observations(simulation, config)
        simulations[subcase] = evaluated
        primary_metrics[subcase] = assay_runner.compute_primary_metrics(evaluated, batch)
        window_summaries[subcase] = summary.summaries
        if config.artifacts.save_full_trajectories:
            trajectory_payload[subcase] = _serialize_simulation(evaluated)

    task_mode_metrics = _compute_task_mode_metrics(batch, simulations, assay_runner)
    return primary_metrics, window_summaries, trajectory_payload, task_mode_metrics


def _prestim_condition_masks(batch: TrialBatch) -> dict[str, torch.Tensor]:
    prestim_valid = batch.blank_mask & batch.metadata["omission_targets"].lt(0)
    return {
        "cue_only": prestim_valid & batch.prestim_mode.eq(PRESTIM_CUE_ONLY).unsqueeze(1),
        "context_only": prestim_valid & batch.prestim_mode.eq(PRESTIM_CONTEXT_ONLY).unsqueeze(1),
        "neutral": prestim_valid & batch.context_ids.eq(2).unsqueeze(1),
    }


def _prestim_gate_condition_report(simulation, batch: TrialBatch) -> dict[str, dict[str, float | int]]:
    expected_targets = batch.metadata["expected_distribution"].argmax(dim=-1)
    deep_template = simulation.states["deep_template"]
    reports: dict[str, dict[str, float | int]] = {}
    for condition, mask in _prestim_condition_masks(batch).items():
        n_steps = int(mask.sum().item())
        n_trials = int(mask.any(dim=1).sum().item())
        if n_steps == 0:
            reports[condition] = {
                "n_steps": 0,
                "n_trials": n_trials,
                "prestimulus_template_specificity": 0.0,
                "template_peak": 0.0,
            }
            continue
        activity = deep_template[mask]
        targets = expected_targets[mask]
        reports[condition] = {
            "n_steps": n_steps,
            "n_trials": n_trials,
            "prestimulus_template_specificity": float(template_specificity(activity, targets).mean().item()),
            "template_peak": float(activity.max(dim=-1).values.mean().item()),
        }
    return reports


def _evaluate_single_subcase(
    *,
    batch: TrialBatch,
    prediction: ContextPrediction,
    subcase: str,
    model: V1ExpectationModel,
    config: ExperimentConfig,
) -> tuple[SimulationOutput, dict[str, dict[str, torch.Tensor]]]:
    simulation = model.rollout(batch, prediction, subcase=subcase)
    evaluated, summary = evaluate_with_observations(simulation, config)
    return evaluated, summary.summaries


def _fixed_state_name(values: torch.Tensor, names: dict[int, str]) -> str:
    unique = torch.unique(values)
    if unique.numel() != 1:
        raise ValueError("local-global probe gate expects a fixed state across the held-out batch.")
    return names[int(unique.item())]


def _rowwise_comparator_nonuniformity(rows: torch.Tensor) -> torch.Tensor:
    return (rows - rows.mean(dim=-1, keepdim=True)).abs().mean(dim=-1)


def _build_probe_table(
    batch: TrialBatch,
    oracle_simulation: SimulationOutput,
    learned_simulation: SimulationOutput,
) -> list[dict[str, object]]:
    probe_mask = batch.metadata["probe_step_mask"] & batch.metadata["probe_valid_mask"]
    probe_indices = torch.nonzero(probe_mask, as_tuple=False)
    target_bins = batch.metadata["probe_target_orientation"]
    source_bins = batch.metadata["probe_source_orientation"]
    pair_ids = batch.metadata["probe_pair_id"]
    offsets = batch.metadata["probe_local_offset_bins"]
    global_expected = batch.metadata["probe_global_expected_mask"]
    global_unexpected = batch.metadata["probe_global_unexpected_mask"]
    condition_codes = batch.metadata["condition_codes"]
    repetition_lag = batch.metadata["repetition_lag"]
    run_length = batch.metadata["run_length"]
    controlled_source_steps = batch.metadata["controlled_source_steps"]
    pair_descriptors = batch.metadata["probe_report"]["pair_descriptors"]
    symmetry_mate_lookup = {
        int(pair_id): int(descriptor["symmetry_mate_pair_id"])
        for pair_id, descriptor in pair_descriptors.items()
    }

    oracle_pooled = oracle_simulation.observations.get("gaussian_orientation_bank")
    if oracle_pooled is None:
        oracle_pooled = oracle_simulation.observations.get("identity", oracle_simulation.states["l23_readout"])
    learned_pooled = learned_simulation.observations.get("gaussian_orientation_bank")
    if learned_pooled is None:
        learned_pooled = learned_simulation.observations.get("identity", learned_simulation.states["l23_readout"])

    task_mode_names = batch.metadata["task_mode_names"]
    prestim_mode_names = batch.metadata["prestim_mode_names"]

    rows: list[dict[str, object]] = []
    for probe_row_index, (trial_idx_tensor, step_idx_tensor) in enumerate(probe_indices.tolist()):
        trial_idx = int(trial_idx_tensor)
        step_idx = int(step_idx_tensor)
        target = int(target_bins[trial_idx].item())
        pair_id = int(pair_ids[trial_idx].item())
        symmetry_mate_pair_id = symmetry_mate_lookup[pair_id]
        target_tensor = torch.tensor([target], dtype=torch.long)
        oracle_l23 = oracle_simulation.states["l23_readout"][trial_idx, step_idx].unsqueeze(0)
        learned_l23 = learned_simulation.states["l23_readout"][trial_idx, step_idx].unsqueeze(0)
        oracle_comparator = oracle_simulation.states["context_comparator"][trial_idx, step_idx].unsqueeze(0)
        learned_comparator = learned_simulation.states["context_comparator"][trial_idx, step_idx].unsqueeze(0)
        rows.append(
            {
                "probe_row_index": probe_row_index,
                "trial_index": trial_idx,
                "step_index": step_idx,
                "probe_visible_step_index": int(batch.metadata["probe_visible_step_index"]),
                "pair_id": pair_id,
                "source_orientation": int(source_bins[trial_idx].item()),
                "target_orientation": target,
                "local_offset_bins": int(offsets[trial_idx].item()),
                "context_id": int(batch.context_ids[trial_idx].item()),
                "task_mode": task_mode_names[int(batch.task_mode[trial_idx].item())],
                "prestim_mode": prestim_mode_names[int(batch.prestim_mode[trial_idx].item())],
                "condition_code": int(condition_codes[trial_idx, step_idx].item()),
                "orthogonal_event": int(batch.orthogonal_events[trial_idx, step_idx].item()),
                "repetition_lag": int(repetition_lag[trial_idx, step_idx].item()),
                "run_length": int(run_length[trial_idx, step_idx].item()),
                "controlled_source_step": bool(controlled_source_steps[trial_idx, step_idx].item()),
                # Exactly one member of each symmetry-linked pair is flagged as the mate:
                # the larger pair_id in the linked pair receives is_symmetry_mate=True.
                "is_symmetry_mate": pair_id > symmetry_mate_pair_id,
                "global_expected": bool(global_expected[trial_idx, step_idx].item()),
                "global_unexpected": bool(global_unexpected[trial_idx, step_idx].item()),
                "oracle_l23_target_aligned_specificity": float(template_specificity(oracle_l23, target_tensor).item()),
                "learned_l23_target_aligned_specificity": float(template_specificity(learned_l23, target_tensor).item()),
                "oracle_pooled_target_aligned_specificity": float(
                    template_specificity(oracle_pooled[trial_idx, step_idx].unsqueeze(0), target_tensor).item()
                ),
                "learned_pooled_target_aligned_specificity": float(
                    template_specificity(learned_pooled[trial_idx, step_idx].unsqueeze(0), target_tensor).item()
                ),
                "oracle_context_comparator_nonuniformity": float(_rowwise_comparator_nonuniformity(oracle_comparator).item()),
                "learned_context_comparator_nonuniformity": float(_rowwise_comparator_nonuniformity(learned_comparator).item()),
            }
        )
    return rows


def _probe_scoring_mask(batch: TrialBatch) -> torch.Tensor:
    return batch.metadata["probe_step_mask"] & batch.metadata["probe_valid_mask"]


def _same_batch_provenance_ok(
    batch: TrialBatch,
    oracle_simulation: SimulationOutput,
    learned_simulation: SimulationOutput,
) -> bool:
    required_tensor_keys = ("controlled_sources",)
    required_scalar_keys = ("generator_seed", "probe_visible_step_index")
    for simulation in (oracle_simulation, learned_simulation):
        metadata = simulation.metadata
        for key in required_scalar_keys:
            if key not in metadata or key not in batch.metadata:
                return False
            if int(metadata[key]) != int(batch.metadata[key]):
                return False
        for key in required_tensor_keys:
            if key not in metadata or key not in batch.metadata:
                return False
            if not torch.equal(torch.as_tensor(metadata[key]), torch.as_tensor(batch.metadata[key])):
                return False
    return True


def _build_probe_design_report(
    batch: TrialBatch,
    *,
    task_mode_fixed_state: str,
    prestim_fixed_state: str,
    oracle_simulation: SimulationOutput,
    learned_simulation: SimulationOutput,
) -> dict[str, object]:
    probe_mask = _probe_scoring_mask(batch)
    condition_codes = batch.metadata["condition_codes"]
    visible_step_index = batch.metadata["visible_step_index"]
    probe_trial_indices = torch.nonzero(probe_mask, as_tuple=False)[:, 0]
    pair_ids = batch.metadata["probe_pair_id"][probe_trial_indices]
    contexts = batch.context_ids[probe_trial_indices]
    sources = batch.metadata["probe_source_orientation"][probe_trial_indices]
    targets = batch.metadata["probe_target_orientation"][probe_trial_indices]
    expected_rows = batch.metadata["probe_global_expected_mask"][probe_mask]
    unexpected_rows = batch.metadata["probe_global_unexpected_mask"][probe_mask]
    pair_descriptors = batch.metadata["probe_report"]["pair_descriptors"]
    contexts_used = sorted(int(value) for value in batch.metadata["probe_report"]["contexts_used"])

    pair_balance_rows: dict[str, dict[str, object]] = {}
    scored_pair_count = 0
    all_pairs_have_two_rows = True
    all_pairs_span_contexts_0_1 = True
    all_pairs_same_source = True
    all_pairs_same_target = True
    all_pairs_flip_global_expectedness = True
    all_pairs_have_symmetry_mate = True

    for pair_id in sorted(int(value) for value in torch.unique(pair_ids).tolist()):
        current_pair = pair_ids.eq(pair_id)
        contexts_present = sorted({int(value) for value in contexts[current_pair].tolist()})
        source_values = sorted({int(value) for value in sources[current_pair].tolist()})
        target_values = sorted({int(value) for value in targets[current_pair].tolist()})
        descriptor = pair_descriptors[str(pair_id)]
        n_expected = int(expected_rows[current_pair].sum().item())
        n_unexpected = int(unexpected_rows[current_pair].sum().item())
        if n_expected > 0 and n_unexpected > 0:
            scored_pair_count += 1
        symmetry_mate_pair_id = int(descriptor["symmetry_mate_pair_id"])
        pair_balance_rows[str(pair_id)] = {
            "source": int(descriptor["source"]),
            "target": int(descriptor["target"]),
            "contexts_present": contexts_present,
            "n_expected": n_expected,
            "n_unexpected": n_unexpected,
            "symmetry_mate_pair_id": symmetry_mate_pair_id,
        }
        all_pairs_have_two_rows &= int(current_pair.sum().item()) == 2
        all_pairs_span_contexts_0_1 &= contexts_present == contexts_used
        all_pairs_same_source &= len(source_values) == 1 and source_values[0] == int(descriptor["source"])
        all_pairs_same_target &= len(target_values) == 1 and target_values[0] == int(descriptor["target"])
        all_pairs_flip_global_expectedness &= n_expected == 1 and n_unexpected == 1
        all_pairs_have_symmetry_mate &= str(symmetry_mate_pair_id) in pair_descriptors

    return {
        "probe_visible_step_index": int(batch.metadata["probe_visible_step_index"]),
        "task_mode_fixed_state": task_mode_fixed_state,
        "prestim_fixed_state": prestim_fixed_state,
        "contexts_used": contexts_used,
        "controlled_sources": batch.metadata["controlled_sources"].tolist(),
        "n_probe_rows": int(probe_mask.sum().item()),
        "n_probe_global_expected_rows": int(expected_rows.sum().item()),
        "n_probe_global_unexpected_rows": int(unexpected_rows.sum().item()),
        "n_probe_pairs_total": len(pair_balance_rows),
        "n_probe_pairs_scored": scored_pair_count,
        "all_probe_rows_nonblank": bool(batch.blank_mask[probe_mask].eq(False).all().item()),
        "all_probe_rows_nonomission": bool(condition_codes[probe_mask].ne(4).all().item()),
        "all_probe_rows_controlled_source": bool(batch.metadata["controlled_source_steps"][probe_mask].all().item()),
        "all_probe_rows_at_fixed_visible_step": bool(
            visible_step_index[probe_mask].eq(int(batch.metadata["probe_visible_step_index"])).all().item()
        ),
        "all_pairs_have_two_rows": all_pairs_have_two_rows,
        "all_pairs_span_contexts_0_1": all_pairs_span_contexts_0_1,
        "all_pairs_same_source": all_pairs_same_source,
        "all_pairs_same_target": all_pairs_same_target,
        "all_pairs_flip_global_expectedness": all_pairs_flip_global_expectedness,
        "all_pairs_have_symmetry_mate": all_pairs_have_symmetry_mate,
        "same_batch_provenance_ok": _same_batch_provenance_ok(
            batch,
            oracle_simulation=oracle_simulation,
            learned_simulation=learned_simulation,
        ),
        "pair_balance_rows": pair_balance_rows,
    }


def _probe_alignment_stats(
    prediction_logits: torch.Tensor,
    expected_distribution: torch.Tensor,
) -> tuple[float, float]:
    expected = expected_distribution.to(torch.float32).clamp_min(1e-8)
    log_expected = expected.log()
    log_predicted = torch.log_softmax(prediction_logits, dim=-1)
    alignment_kl = float((expected * (log_expected - log_predicted)).sum(dim=-1).mean().item())
    expected_logprob = float((expected * log_predicted).sum(dim=-1).mean().item())
    return alignment_kl, expected_logprob


def _probe_alignment_behavior_metrics(
    batch: TrialBatch,
    prediction_logits: torch.Tensor,
) -> dict[str, float]:
    probe_mask = _probe_scoring_mask(batch)
    probe_trial_indices = torch.nonzero(probe_mask, as_tuple=False)[:, 0]
    expected_targets = batch.metadata["expected_distribution"].argmax(dim=-1)[probe_mask]
    predicted_targets = prediction_logits.argmax(dim=-1)[probe_mask]
    pair_ids = batch.metadata["probe_pair_id"][probe_trial_indices]
    contexts = batch.context_ids[probe_trial_indices]
    pair_descriptors = batch.metadata["probe_report"]["pair_descriptors"]

    probe_expected_target_top1_rate = float(predicted_targets.eq(expected_targets).to(torch.float32).mean().item())

    pair_context_top1: dict[int, dict[int, int]] = {}
    for row_index, pair_id in enumerate(pair_ids.tolist()):
        current_pair = int(pair_id)
        context_id = int(contexts[row_index].item())
        predicted_bin = int(predicted_targets[row_index].item())
        pair_context_top1.setdefault(current_pair, {})[context_id] = predicted_bin

    pair_flip_values: list[float] = []
    for pair_id, context_predictions in pair_context_top1.items():
        if 0 in context_predictions and 1 in context_predictions:
            pair_flip_values.append(float(context_predictions[0] != context_predictions[1]))
    probe_pair_flip_rate = float(sum(pair_flip_values) / len(pair_flip_values)) if pair_flip_values else 0.0

    symmetry_consistency_values: list[float] = []
    for pair_id_str, descriptor in pair_descriptors.items():
        pair_id = int(pair_id_str)
        symmetry_mate_pair_id = int(descriptor["symmetry_mate_pair_id"])
        if pair_id >= symmetry_mate_pair_id:
            continue
        pair_predictions = pair_context_top1.get(pair_id)
        mate_predictions = pair_context_top1.get(symmetry_mate_pair_id)
        if pair_predictions is None or mate_predictions is None:
            continue
        if not ({0, 1} <= set(pair_predictions) and {0, 1} <= set(mate_predictions)):
            continue
        symmetry_consistency_values.append(
            float(
                pair_predictions[0] == mate_predictions[0]
                and pair_predictions[1] == mate_predictions[1]
            )
        )
    probe_pair_flip_symmetry_consistency = (
        float(sum(symmetry_consistency_values) / len(symmetry_consistency_values))
        if symmetry_consistency_values
        else 0.0
    )
    return {
        "probe_expected_target_top1_rate": probe_expected_target_top1_rate,
        "probe_pair_flip_rate": probe_pair_flip_rate,
        "probe_pair_flip_symmetry_consistency": probe_pair_flip_symmetry_consistency,
    }


def _build_probe_context_alignment_report(
    batch: TrialBatch,
    oracle_simulation: SimulationOutput,
    learned_simulation: SimulationOutput,
) -> dict[str, float]:
    probe_mask = _probe_scoring_mask(batch)
    expected_distribution = batch.metadata["expected_distribution"][probe_mask]
    oracle_predictions = oracle_simulation.context_predictions
    learned_predictions = learned_simulation.context_predictions
    if oracle_predictions is None or learned_predictions is None:
        raise ValueError("local-global probe gate requires saved context predictions for oracle and learned paths.")
    oracle_kl, oracle_expected_logprob = _probe_alignment_stats(oracle_predictions[probe_mask], expected_distribution)
    learned_kl, learned_expected_logprob = _probe_alignment_stats(learned_predictions[probe_mask], expected_distribution)
    oracle_behavior = _probe_alignment_behavior_metrics(batch, oracle_predictions)
    learned_behavior = _probe_alignment_behavior_metrics(batch, learned_predictions)
    return {
        "learned_probe_alignment_kl": learned_kl,
        "oracle_probe_alignment_kl": oracle_kl,
        "learned_probe_expected_logprob": learned_expected_logprob,
        "oracle_probe_expected_logprob": oracle_expected_logprob,
        "learned_probe_expected_target_top1_rate": learned_behavior["probe_expected_target_top1_rate"],
        "oracle_probe_expected_target_top1_rate": oracle_behavior["probe_expected_target_top1_rate"],
        "learned_probe_pair_flip_rate": learned_behavior["probe_pair_flip_rate"],
        "oracle_probe_pair_flip_rate": oracle_behavior["probe_pair_flip_rate"],
        "learned_probe_pair_flip_symmetry_consistency": learned_behavior["probe_pair_flip_symmetry_consistency"],
        "oracle_probe_pair_flip_symmetry_consistency": oracle_behavior["probe_pair_flip_symmetry_consistency"],
    }


def _stage4_metadata(
    *,
    metric_versions: dict[str, str],
    source_metric_versions: list[str],
) -> dict[str, object]:
    return {
        "metric_schema_version": STAGE4_METRIC_SCHEMA_VERSION,
        "metric_versions": metric_versions,
        "classification_rule_version": STAGE4_CLASSIFICATION_RULE_VERSION,
        "source_metric_versions": source_metric_versions,
        "benchmark_registry_version": BENCHMARK_REGISTRY_VERSION,
        "stage3_task_version": STAGE3_TASK_VERSION,
        "stage4_package_version": STAGE4_PACKAGE_VERSION,
    }


def _stage4_training_config(resolved_config: ExperimentConfig):
    return replace(
        resolved_config.training,
        learning_rate=1e-3,
        weight_decay=1e-4,
        batch_size=32,
        n_epochs=10,
    )


def _stage4_repo_root() -> Path:
    return Path(__file__).resolve().parents[2]


def _stage4_benchmark_paths(benchmark_artifacts_root: str | Path) -> tuple[Path, Path]:
    resolved_artifacts_root = Path(benchmark_artifacts_root)
    benchmarks_root = resolved_artifacts_root / "benchmarks"
    if not benchmarks_root.exists():
        benchmarks_root = resolved_artifacts_root
    return resolved_artifacts_root, benchmarks_root


def _stage4_read_json(path: Path) -> dict[str, object]:
    return json.loads(path.read_text(encoding="utf-8"))


def _stage4_run_validation_command(command: list[str], *, cwd: Path) -> dict[str, object]:
    if os.environ.get("LVC_EXPECTATION_STAGE4_PARENT_VALIDATION") == "1":
        return {
            "command": command,
            "cwd": str(cwd),
            "ok": True,
            "returncode": 0,
            "inherited_from_parent": True,
            "stdout_tail": [],
            "stderr_tail": [],
        }
    env = os.environ.copy()
    env["LVC_EXPECTATION_STAGE4_PARENT_VALIDATION"] = "1"
    repo_src = str(cwd / "src")
    existing_pythonpath = env.get("PYTHONPATH")
    env["PYTHONPATH"] = (
        f"{repo_src}{os.pathsep}{existing_pythonpath}"
        if existing_pythonpath
        else repo_src
    )
    completed = subprocess.run(
        command,
        cwd=cwd,
        env=env,
        check=False,
        capture_output=True,
        text=True,
    )
    return {
        "command": command,
        "cwd": str(cwd),
        "ok": completed.returncode == 0,
        "returncode": completed.returncode,
        "inherited_from_parent": False,
        "stdout_tail": completed.stdout.splitlines()[-20:],
        "stderr_tail": completed.stderr.splitlines()[-20:],
    }


def _stage4_sign_counts(values: list[float]) -> dict[str, int]:
    return {
        "positive": sum(1 for value in values if value > 0.0),
        "negative": sum(1 for value in values if value < 0.0),
        "zero": sum(1 for value in values if value == 0.0),
    }


def _stage4_mean(values: list[float | None]) -> float | None:
    resolved_values = [float(value) for value in values if value is not None]
    if not resolved_values:
        return None
    return float(sum(resolved_values) / len(resolved_values))


def _stage4_probe_ratio(numerator: float, denominator: float) -> float | None:
    if denominator == 0.0:
        return None
    return float(numerator / denominator)


def _stage4_bool_true_count(values: list[bool]) -> dict[str, int]:
    true_count = sum(1 for value in values if value)
    return {
        "true": true_count,
        "false": len(values) - true_count,
    }


def _stage4_anchor_panel_required_successes(seed_panel: str) -> int:
    if seed_panel == "primary":
        return STAGE4_PRIMARY_PANEL_REQUIRED_SUCCESSES
    if seed_panel == "confirmation":
        return STAGE4_CONFIRMATION_PANEL_REQUIRED_SUCCESSES
    raise ValueError(f"unknown Stage-4 seed panel: {seed_panel}")


def _stage4_learned_panel_required_successes(seed_panel: str) -> int:
    if seed_panel == "primary":
        return STAGE4_LEARNED_PRIMARY_PANEL_REQUIRED_SUCCESSES
    if seed_panel == "confirmation":
        return STAGE4_CONFIRMATION_PANEL_REQUIRED_SUCCESSES
    raise ValueError(f"unknown Stage-4 seed panel: {seed_panel}")


def _stage4_no_sign_reversal(latent_value: float, pooled_value: float) -> bool:
    return latent_value == 0.0 or pooled_value == 0.0 or (latent_value > 0.0) == (pooled_value > 0.0)


def _stage4_count_true(values: list[bool]) -> int:
    return sum(1 for value in values if value)


def _stage4_bootstrap_mean_ci(
    values: list[float],
    *,
    seed: int,
) -> dict[str, float] | None:
    if not values:
        return None
    value_tensor = torch.tensor(values, dtype=torch.float64)
    bootstrap_generator = torch.Generator(device="cpu")
    bootstrap_generator.manual_seed(seed)
    sample_indices = torch.randint(
        low=0,
        high=value_tensor.numel(),
        size=(STAGE4_BOOTSTRAP_RESAMPLES, value_tensor.numel()),
        generator=bootstrap_generator,
    )
    sampled_means = value_tensor[sample_indices].mean(dim=1)
    alpha = 1.0 - STAGE4_BOOTSTRAP_CONFIDENCE_LEVEL
    lower = float(torch.quantile(sampled_means, alpha / 2.0).item())
    upper = float(torch.quantile(sampled_means, 1.0 - alpha / 2.0).item())
    return {
        "lower": lower,
        "upper": upper,
        "n_resamples": STAGE4_BOOTSTRAP_RESAMPLES,
        "confidence_level": STAGE4_BOOTSTRAP_CONFIDENCE_LEVEL,
    }


