def _standard_end_build_anchor_panel_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = _standard_end_panel_required_successes(seed_panel)
    seedwise: list[dict[str, object]] = []
    latent_values: list[float] = []
    pooled_values: list[float] = []
    learned_symmetry_values: list[bool] = []
    latent_ratio_values: list[float | None] = []
    no_sign_reversal_values: list[bool] = []
    for entry in run_entries:
        latent = float(entry["probe_metrics"]["probe_target_aligned_specificity_contrast"])
        pooled = float(entry["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"])
        oracle_latent = float(entry["oracle_probe_metrics"]["probe_target_aligned_specificity_contrast"])
        learned_symmetry = (
            float(entry["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]) >= 1.0
        )
        latent_ratio = _stage4_probe_ratio(latent, oracle_latent)
        no_sign_reversal = _stage4_no_sign_reversal(latent, pooled)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "probe_target_aligned_specificity_contrast": latent,
                "probe_pooled_target_aligned_specificity_contrast": pooled,
                "learned_probe_pair_flip_symmetry_consistency": float(
                    entry["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]
                ),
                "learned_oracle_latent_ratio": latent_ratio,
                "checks": {
                    "latent_positive": latent > 0.0,
                    "pooled_positive": pooled > 0.0,
                    "learned_symmetry_consistency": learned_symmetry,
                    "learned_oracle_latent_ratio_ge_0_25": latent_ratio is not None
                    and latent_ratio >= STANDARD_END_ANCHOR_LATENT_RATIO_FLOOR,
                    "no_latent_pooled_sign_reversal": no_sign_reversal,
                },
            }
        )
        latent_values.append(latent)
        pooled_values.append(pooled)
        learned_symmetry_values.append(learned_symmetry)
        latent_ratio_values.append(latent_ratio)
        no_sign_reversal_values.append(no_sign_reversal)
    mean_latent = _stage4_mean(latent_values)
    mean_pooled = _stage4_mean(pooled_values)
    checks = {
        "all_runs_have_artifacts": all(bool(entry["artifacts_complete"]) for entry in run_entries),
        "required_successes": required_successes,
        "latent_positive_count": _stage4_count_true([value > 0.0 for value in latent_values]),
        "pooled_positive_count": _stage4_count_true([value > 0.0 for value in pooled_values]),
        "learned_symmetry_consistency_count": _stage4_count_true(learned_symmetry_values),
        "learned_oracle_latent_ratio_ge_0_25_count": _stage4_count_true(
            [value is not None and value >= STANDARD_END_ANCHOR_LATENT_RATIO_FLOOR for value in latent_ratio_values]
        ),
        "mean_latent_ge_floor": mean_latent is not None and float(mean_latent) >= STANDARD_END_ANCHOR_MEAN_LATENT_FLOOR,
        "mean_pooled_ge_floor": mean_pooled is not None and float(mean_pooled) >= STANDARD_END_ANCHOR_MEAN_POOLED_FLOOR,
        "no_latent_pooled_sign_reversal": all(no_sign_reversal_values),
    }
    checks["count_thresholds_met"] = (
        checks["latent_positive_count"] >= required_successes
        and checks["pooled_positive_count"] >= required_successes
        and checks["learned_symmetry_consistency_count"] >= required_successes
        and checks["learned_oracle_latent_ratio_ge_0_25_count"] >= required_successes
    )
    return {
        "seed_panel": seed_panel,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "probe_target_aligned_specificity_contrast_sign_counts": _stage4_sign_counts(latent_values),
            "probe_pooled_target_aligned_specificity_contrast_sign_counts": _stage4_sign_counts(pooled_values),
            "learned_symmetry_consistency_counts": _stage4_bool_true_count(learned_symmetry_values),
            "mean_probe_target_aligned_specificity_contrast": mean_latent,
            "mean_probe_pooled_target_aligned_specificity_contrast": mean_pooled,
            "mean_learned_oracle_latent_ratio": _stage4_mean(latent_ratio_values),
        },
        "checks": checks,
        "passes": (
            checks["all_runs_have_artifacts"]
            and checks["count_thresholds_met"]
            and checks["mean_latent_ge_floor"]
            and checks["mean_pooled_ge_floor"]
            and checks["no_latent_pooled_sign_reversal"]
        ),
    }


def _standard_end_build_anchor_report(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
) -> dict[str, object]:
    primary_panel_summary = _standard_end_build_anchor_panel_summary(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    confirmation_panel_summary = (
        _standard_end_build_anchor_panel_summary(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
        if confirmation_run_entries is not None
        else None
    )
    return {
        **_standard_end_localization_metadata(
            metric_versions={
                "probe_target_aligned_specificity_contrast": "v1",
                "probe_pooled_target_aligned_specificity_contrast": "v1",
                "learned_probe_pair_flip_symmetry_consistency": "v1",
                "learned_oracle_latent_ratio": "reporting_v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "primary_panel_summary": primary_panel_summary,
        "confirmation_panel_summary": confirmation_panel_summary,
        "primary_passes": bool(primary_panel_summary["passes"]),
        "confirmation_executed": confirmation_run_entries is not None,
        "confirmation_passes": (
            bool(confirmation_panel_summary["passes"])
            if confirmation_panel_summary is not None
            else None
        ),
        "passes": bool(primary_panel_summary["passes"])
        and (
            confirmation_panel_summary is None
            or bool(confirmation_panel_summary["passes"])
        ),
        "skipped": False,
    }


def _standard_end_build_linear_probe_panel_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = _standard_end_linear_probe_required_successes(seed_panel)
    seedwise: list[dict[str, object]] = []
    alignment_values: list[float] = []
    top1_values: list[float] = []
    correct_pair_flip_values: list[float | None] = []
    within_pair_mass_values: list[float | None] = []
    source_bin_kl_values: list[float | None] = []
    for entry in run_entries:
        linear_report = entry["linear_probe_report"]
        alignment = float(linear_report["linear_probe_alignment_kl"])
        top1 = float(linear_report["linear_probe_expected_target_top1_rate"])
        correct_pair_flip = linear_report["linear_probe_correct_pair_flip_rate__v2"]
        within_pair_mass = linear_report["linear_probe_within_pair_mass__v2"]
        source_bin_kl = linear_report["linear_probe_source_bin_kl__v2"]
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "auxiliary_seed": int(entry["auxiliary_seed"]),
                "linear_probe_alignment_kl": alignment,
                "linear_probe_expected_target_top1_rate": top1,
                "linear_probe_correct_pair_flip_rate__v2": correct_pair_flip,
                "linear_probe_within_pair_mass__v2": within_pair_mass,
                "linear_probe_source_bin_kl__v2": source_bin_kl,
                "train_eval_disjoint": bool(entry["train_eval_disjoint"]),
                "checks": {
                    "linear_probe_alignment_kl_le_0_75": alignment <= STANDARD_END_LINEAR_PROBE_ALIGNMENT_KL_MAX,
                    "linear_probe_expected_target_top1_rate_ge_0_75": top1
                    >= STANDARD_END_LINEAR_PROBE_EXPECTED_TARGET_TOP1_MIN,
                    "linear_probe_correct_pair_flip_rate__v2_ge_0_75": correct_pair_flip is not None
                    and float(correct_pair_flip) >= STANDARD_END_LINEAR_PROBE_CORRECT_PAIR_FLIP_RATE_MIN,
                    "linear_probe_within_pair_mass__v2_ge_0_40": within_pair_mass is not None
                    and float(within_pair_mass) >= STANDARD_END_LINEAR_PROBE_WITHIN_PAIR_MASS_MIN,
                    "linear_probe_source_bin_kl__v2_ge_2_00": source_bin_kl is not None
                    and float(source_bin_kl) >= STANDARD_END_LINEAR_PROBE_SOURCE_BIN_KL_MIN,
                    "train_eval_disjoint": bool(entry["train_eval_disjoint"]),
                },
            }
        )
        alignment_values.append(alignment)
        top1_values.append(top1)
        correct_pair_flip_values.append(correct_pair_flip)
        within_pair_mass_values.append(within_pair_mass)
        source_bin_kl_values.append(source_bin_kl)
    checks = {
        "all_runs_have_artifacts": all(bool(entry["artifacts_complete"]) for entry in run_entries),
        "required_successes": required_successes,
        "train_eval_disjoint_for_all_runs": all(bool(entry["train_eval_disjoint"]) for entry in run_entries),
        "linear_probe_alignment_kl_le_0_75_count": _stage4_count_true(
            [value <= STANDARD_END_LINEAR_PROBE_ALIGNMENT_KL_MAX for value in alignment_values]
        ),
        "linear_probe_expected_target_top1_rate_ge_0_75_count": _stage4_count_true(
            [value >= STANDARD_END_LINEAR_PROBE_EXPECTED_TARGET_TOP1_MIN for value in top1_values]
        ),
        "linear_probe_correct_pair_flip_rate__v2_ge_0_75_count": _stage4_count_true(
            [value is not None and float(value) >= STANDARD_END_LINEAR_PROBE_CORRECT_PAIR_FLIP_RATE_MIN for value in correct_pair_flip_values]
        ),
        "linear_probe_within_pair_mass__v2_ge_0_40_count": _stage4_count_true(
            [value is not None and float(value) >= STANDARD_END_LINEAR_PROBE_WITHIN_PAIR_MASS_MIN for value in within_pair_mass_values]
        ),
        "linear_probe_source_bin_kl__v2_ge_2_00_count": _stage4_count_true(
            [value is not None and float(value) >= STANDARD_END_LINEAR_PROBE_SOURCE_BIN_KL_MIN for value in source_bin_kl_values]
        ),
    }
    checks["strong_gate_passes"] = (
        checks["linear_probe_alignment_kl_le_0_75_count"] >= required_successes
        and checks["linear_probe_expected_target_top1_rate_ge_0_75_count"] >= required_successes
        and checks["linear_probe_correct_pair_flip_rate__v2_ge_0_75_count"] >= required_successes
        and checks["linear_probe_within_pair_mass__v2_ge_0_40_count"] >= required_successes
        and checks["linear_probe_source_bin_kl__v2_ge_2_00_count"] >= required_successes
    )
    return {
        **_standard_end_localization_metadata(
            metric_versions={
                "linear_probe_alignment_kl": "v1",
                "linear_probe_expected_target_top1_rate": "v1",
                "linear_probe_correct_pair_flip_rate__v2": "v2",
                "linear_probe_within_pair_mass__v2": "v2",
                "linear_probe_source_bin_kl__v2": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "mean_linear_probe_alignment_kl": _stage4_mean(alignment_values),
            "max_linear_probe_alignment_kl": max(alignment_values) if alignment_values else None,
            "mean_linear_probe_expected_target_top1_rate": _stage4_mean(top1_values),
            "mean_linear_probe_correct_pair_flip_rate__v2": _stage4_mean(correct_pair_flip_values),
            "mean_linear_probe_within_pair_mass__v2": _stage4_mean(within_pair_mass_values),
            "mean_linear_probe_source_bin_kl__v2": _stage4_mean(source_bin_kl_values),
        },
        "checks": checks,
        "passes": (
            checks["all_runs_have_artifacts"]
            and checks["train_eval_disjoint_for_all_runs"]
            and checks["strong_gate_passes"]
        ),
        "skipped": False,
    }


def _standard_end_localization_delta_panel_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    seedwise: list[dict[str, object]] = []
    alignment_deltas: list[float] = []
    top1_deltas: list[float] = []
    correct_pair_flip_deltas: list[float] = []
    within_pair_mass_deltas: list[float] = []
    source_bin_kl_deltas: list[float] = []
    kl_reductions: list[float] = []
    for entry in run_entries:
        native_alignment = float(entry["probe_context_alignment_report"]["learned_probe_alignment_kl"])
        linear_alignment = float(entry["linear_probe_report"]["linear_probe_alignment_kl"])
        native_top1 = float(entry["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"])
        linear_top1 = float(entry["linear_probe_report"]["linear_probe_expected_target_top1_rate"])
        native_correct_pair_flip = entry["hidden_state_diagnostics"]["probe_correct_pair_flip_rate__v2"]
        linear_correct_pair_flip = entry["linear_probe_report"]["linear_probe_correct_pair_flip_rate__v2"]
        native_within_pair_mass = entry["hidden_state_diagnostics"]["probe_within_pair_mass__v2"]
        linear_within_pair_mass = entry["linear_probe_report"]["linear_probe_within_pair_mass__v2"]
        native_source_bin_kl = entry["hidden_state_diagnostics"]["probe_source_bin_kl__v2"]
        linear_source_bin_kl = entry["linear_probe_report"]["linear_probe_source_bin_kl__v2"]

        alignment_delta = float(linear_alignment - native_alignment)
        kl_reduction = float(native_alignment - linear_alignment)
        top1_delta = float(linear_top1 - native_top1)
        correct_pair_flip_delta = float(linear_correct_pair_flip - native_correct_pair_flip)
        within_pair_mass_delta = float(linear_within_pair_mass - native_within_pair_mass)
        source_bin_kl_delta = float(linear_source_bin_kl - native_source_bin_kl)

        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "auxiliary_seed": int(entry["auxiliary_seed"]),
                "delta_alignment_kl__linear_minus_native": alignment_delta,
                "delta_expected_target_top1_rate__linear_minus_native": top1_delta,
                "delta_correct_pair_flip_rate__v2__linear_minus_native": correct_pair_flip_delta,
                "delta_within_pair_mass__v2__linear_minus_native": within_pair_mass_delta,
                "delta_source_bin_kl__v2__linear_minus_native": source_bin_kl_delta,
                "alignment_kl_reduction__native_minus_linear": kl_reduction,
            }
        )
        alignment_deltas.append(alignment_delta)
        kl_reductions.append(kl_reduction)
        top1_deltas.append(top1_delta)
        correct_pair_flip_deltas.append(correct_pair_flip_delta)
        within_pair_mass_deltas.append(within_pair_mass_delta)
        source_bin_kl_deltas.append(source_bin_kl_delta)

    def _ci(values: list[float], offset: int) -> dict[str, float] | None:
        return _standard_end_bootstrap_mean_ci(
            values,
            seed=STANDARD_END_LINEAR_PROBE_BOOTSTRAP_SEED + offset,
        )

    return {
        "seed_panel": seed_panel,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "mean_delta_alignment_kl__linear_minus_native": _stage4_mean(alignment_deltas),
            "mean_alignment_kl_reduction__native_minus_linear": _stage4_mean(kl_reductions),
            "mean_delta_expected_target_top1_rate__linear_minus_native": _stage4_mean(top1_deltas),
            "mean_delta_correct_pair_flip_rate__v2__linear_minus_native": _stage4_mean(correct_pair_flip_deltas),
            "mean_delta_within_pair_mass__v2__linear_minus_native": _stage4_mean(within_pair_mass_deltas),
            "mean_delta_source_bin_kl__v2__linear_minus_native": _stage4_mean(source_bin_kl_deltas),
            "bootstrap_ci_95": {
                "delta_alignment_kl__linear_minus_native": _ci(alignment_deltas, 11),
                "alignment_kl_reduction__native_minus_linear": _ci(kl_reductions, 12),
                "delta_expected_target_top1_rate__linear_minus_native": _ci(top1_deltas, 13),
                "delta_correct_pair_flip_rate__v2__linear_minus_native": _ci(correct_pair_flip_deltas, 14),
                "delta_within_pair_mass__v2__linear_minus_native": _ci(within_pair_mass_deltas, 15),
                "delta_source_bin_kl__v2__linear_minus_native": _ci(source_bin_kl_deltas, 16),
            },
        },
    }


def _standard_end_build_localization_delta_report(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
) -> dict[str, object]:
    panels = {
        "primary": _standard_end_localization_delta_panel_report(
            seed_panel="primary",
            run_entries=primary_run_entries,
        ),
    }
    if confirmation_run_entries is not None:
        panels["confirmation"] = _standard_end_localization_delta_panel_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
    return {
        **_standard_end_localization_metadata(
            metric_versions={
                "delta_alignment_kl__linear_minus_native": "v1",
                "alignment_kl_reduction__native_minus_linear": "v1",
                "delta_expected_target_top1_rate__linear_minus_native": "v1",
                "delta_correct_pair_flip_rate__v2__linear_minus_native": "v2",
                "delta_within_pair_mass__v2__linear_minus_native": "v2",
                "delta_source_bin_kl__v2__linear_minus_native": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "panels": panels,
        "skipped": False,
    }


def _standard_end_primary_candidate(
    *,
    anchor_report: dict[str, object],
    linear_probe_primary_report: dict[str, object],
    localization_delta_report: dict[str, object],
) -> dict[str, object]:
    primary_anchor_summary = anchor_report["primary_panel_summary"]
    primary_linear_summary = linear_probe_primary_report["summary"]
    primary_delta_summary = localization_delta_report["panels"]["primary"]["summary"]
    top1_improvement = primary_delta_summary["mean_delta_expected_target_top1_rate__linear_minus_native"]
    kl_reduction = primary_delta_summary["mean_alignment_kl_reduction__native_minus_linear"]
    top1_ci = primary_delta_summary["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_reduction_ci = primary_delta_summary["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]

    restoration_candidate = bool(anchor_report["primary_passes"])
    readout_candidate = (
        not restoration_candidate
        and bool(linear_probe_primary_report["passes"])
        and top1_improvement is not None
        and float(top1_improvement) >= STANDARD_END_LOCALIZATION_TOP1_IMPROVEMENT_MIN
        and top1_ci is not None
        and float(top1_ci["lower"]) > 0.0
        and kl_reduction is not None
        and float(kl_reduction) >= STANDARD_END_LOCALIZATION_KL_REDUCTION_MIN
        and kl_reduction_ci is not None
        and float(kl_reduction_ci["lower"]) > 0.0
    )
    upstream_or_nonlinear_candidate = (
        not restoration_candidate
        and not bool(linear_probe_primary_report["passes"])
        and top1_ci is not None
        and float(top1_ci["upper"]) < STANDARD_END_LOCALIZATION_TOP1_IMPROVEMENT_NO_ADVANTAGE_MAX
        and kl_reduction_ci is not None
        and float(kl_reduction_ci["upper"]) < STANDARD_END_LOCALIZATION_KL_REDUCTION_NO_ADVANTAGE_MAX
    )
    classification = "NO-GO clean negative"
    if restoration_candidate:
        classification = "GO-restoration-candidate"
    elif readout_candidate:
        classification = "GO-localization-readout-candidate"
    elif upstream_or_nonlinear_candidate:
        classification = "GO-localization-upstream-or-nonlinear-candidate"
    return {
        "primary_anchor_passes": bool(anchor_report["primary_passes"]),
        "primary_linear_probe_strong_gate_passes": bool(linear_probe_primary_report["passes"]),
        "primary_top1_improvement_mean": top1_improvement,
        "primary_kl_reduction_mean": kl_reduction,
        "primary_top1_improvement_ci_95": top1_ci,
        "primary_kl_reduction_ci_95": kl_reduction_ci,
        "classification": classification,
        "restoration_candidate": restoration_candidate,
        "readout_candidate": readout_candidate,
        "upstream_or_nonlinear_candidate": upstream_or_nonlinear_candidate,
        "primary_anchor_summary": primary_anchor_summary,
        "primary_linear_summary": primary_linear_summary,
    }


def _standard_end_confirmation_replication(
    *,
    candidate: dict[str, object],
    anchor_report: dict[str, object],
    linear_probe_confirmation_report: dict[str, object] | None,
    localization_delta_report: dict[str, object],
) -> dict[str, object]:
    if not anchor_report.get("confirmation_executed", False):
        return {"replicates": False, "reason": "confirmation_not_executed"}
    confirmation_anchor_summary = anchor_report["confirmation_panel_summary"]
    confirmation_delta_summary = localization_delta_report["panels"].get("confirmation", {}).get("summary", {})
    if candidate["restoration_candidate"]:
        replicates = bool(anchor_report["confirmation_passes"])
        return {
            "replicates": replicates,
            "reason": "native_anchor_confirmation",
            "confirmation_anchor_summary": confirmation_anchor_summary,
        }
    if linear_probe_confirmation_report is None:
        return {"replicates": False, "reason": "missing_confirmation_linear_probe_report"}
    top1_ci = confirmation_delta_summary.get("bootstrap_ci_95", {}).get(
        "delta_expected_target_top1_rate__linear_minus_native"
    )
    kl_reduction_ci = confirmation_delta_summary.get("bootstrap_ci_95", {}).get(
        "alignment_kl_reduction__native_minus_linear"
    )
    top1_improvement = confirmation_delta_summary.get("mean_delta_expected_target_top1_rate__linear_minus_native")
    kl_reduction = confirmation_delta_summary.get("mean_alignment_kl_reduction__native_minus_linear")
    if candidate["readout_candidate"]:
        replicates = (
            bool(linear_probe_confirmation_report["passes"])
            and top1_improvement is not None
            and float(top1_improvement) >= STANDARD_END_LOCALIZATION_TOP1_IMPROVEMENT_MIN
            and top1_ci is not None
            and float(top1_ci["lower"]) > 0.0
            and kl_reduction is not None
            and float(kl_reduction) >= STANDARD_END_LOCALIZATION_KL_REDUCTION_MIN
            and kl_reduction_ci is not None
            and float(kl_reduction_ci["lower"]) > 0.0
        )
        return {
            "replicates": replicates,
            "reason": "linear_probe_readout_confirmation",
            "confirmation_linear_probe_report": linear_probe_confirmation_report,
            "confirmation_delta_summary": confirmation_delta_summary,
        }
    replicates = (
        not bool(linear_probe_confirmation_report["passes"])
        and top1_ci is not None
        and float(top1_ci["upper"]) < STANDARD_END_LOCALIZATION_TOP1_IMPROVEMENT_NO_ADVANTAGE_MAX
        and kl_reduction_ci is not None
        and float(kl_reduction_ci["upper"]) < STANDARD_END_LOCALIZATION_KL_REDUCTION_NO_ADVANTAGE_MAX
    )
    return {
        "replicates": replicates,
        "reason": "linear_probe_upstream_or_nonlinear_confirmation",
        "confirmation_linear_probe_report": linear_probe_confirmation_report,
        "confirmation_delta_summary": confirmation_delta_summary,
    }


def _standard_end_build_verdict(
    *,
    nonregression_report: dict[str, object],
    anchor_report: dict[str, object],
    linear_probe_primary_report: dict[str, object],
    linear_probe_confirmation_report: dict[str, object] | None,
    localization_delta_report: dict[str, object],
    confirmation_executed: bool,
) -> dict[str, object]:
    if not bool(nonregression_report["passes"]):
        classification = "NO-GO invalid execution"
        return {
            **_standard_end_localization_metadata(
                metric_versions={"standard_end_localization_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": classification,
            "execution_valid": False,
            "stop_stage": "nonregression",
            "stop_gate": "S1 non-regression",
            "confirmation_executed": False,
            "package_complete": True,
        }

    candidate = _standard_end_primary_candidate(
        anchor_report=anchor_report,
        linear_probe_primary_report=linear_probe_primary_report,
        localization_delta_report=localization_delta_report,
    )
    if candidate["classification"] == "NO-GO clean negative":
        stop_stage = "primary_localization"
        stop_gate = "ambiguous_primary_outcome"
        confirmation = {"replicates": False, "reason": "not_run"}
        classification = "NO-GO clean negative"
    else:
        confirmation = _standard_end_confirmation_replication(
            candidate=candidate,
            anchor_report=anchor_report,
            linear_probe_confirmation_report=linear_probe_confirmation_report,
            localization_delta_report=localization_delta_report,
        )
        if not confirmation["replicates"]:
            classification = "NO-GO clean negative"
            stop_stage = "confirmation" if confirmation_executed else "primary"
            stop_gate = confirmation["reason"]
        elif candidate["restoration_candidate"]:
            classification = "GO-restoration"
            stop_stage = None
            stop_gate = None
        elif candidate["readout_candidate"]:
            classification = "GO-localization-readout"
            stop_stage = None
            stop_gate = None
        else:
            classification = "GO-localization-upstream-or-nonlinear"
            stop_stage = None
            stop_gate = None

    return {
        **_standard_end_localization_metadata(
            metric_versions={"standard_end_localization_verdict": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "classification": classification,
        "execution_valid": True,
        "primary_candidate": candidate,
        "confirmation": confirmation,
        "confirmation_executed": confirmation_executed,
        "stop_stage": stop_stage,
        "stop_gate": stop_gate,
        "package_complete": True,
    }


def run_standard_end_localization_package(
    *,
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
    primary_seed_panel: tuple[tuple[int, int], ...] = STAGE3_PRIMARY_SEED_PANEL,
    confirmation_seed_panel: tuple[tuple[int, int], ...] = STAGE3_CONFIRMATION_SEED_PANEL,
    benchmark_artifacts_root: str | Path = "artifacts",
) -> StandardEndLocalizationRunResult:
    resolved_config = _resolve_config(config=config, preset_name=preset_name)
    if resolved_config.name != "phase1_core":
        raise ValueError("standard_end_localization is frozen to the phase1_core configuration family.")

    output_root = (
        resolved_config.artifacts.root_dir
        / "standard_end_localization"
        / STANDARD_END_LOCALIZATION_PACKAGE_VERSION
    )
    output_root.mkdir(parents=True, exist_ok=True)
    training_config = _stage4_training_config(resolved_config)
    package_manifest = {
        **_standard_end_localization_metadata(
            metric_versions={"standard_end_localization_manifest": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "changed_files": ["src/lvc_expectation/runner.py"],
        "checkpoint_policy": {"mandatory": ["standard_end"], "optional": []},
        "pretraining": {
            "config_family": "phase1_core",
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "n_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "training_source": "ordinary generate_batch() only",
            "stage3_exposure_during_pretraining": False,
        },
        "linear_probe": {
            "form": STANDARD_END_LINEAR_PROBE_FORM,
            "target": STANDARD_END_LINEAR_PROBE_TARGET,
            "ridge_lambda": STANDARD_END_LINEAR_PROBE_RIDGE_LAMBDA,
            "fit_mask": "probe_step_mask & probe_valid_mask",
            "hidden_state_tensor_name": STANDARD_END_HIDDEN_STATE_TENSOR_NAME,
            "bootstrap_resamples": STANDARD_END_LINEAR_PROBE_BOOTSTRAP_RESAMPLES,
            "bootstrap_seed": STANDARD_END_LINEAR_PROBE_BOOTSTRAP_SEED,
            "train_eval_leakage_policy": "disjoint_auxiliary_fixed_probe_batch",
        },
        "seed_panels": {
            "primary": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in primary_seed_panel],
            "confirmation": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in confirmation_seed_panel],
        },
        "stop_rules": {
            "halt_on_nonregression_failure": True,
            "run_confirmation_on_restoration_candidate": True,
            "run_confirmation_on_localization_candidate": True,
            "stop_on_ambiguous_primary": True,
            "stop_on_failed_confirmation_replication": True,
            "no_harder_evaluation": True,
            "no_second_package": True,
            "no_sweep": True,
        },
        "package_run_order": [
            "write_standard_end_localization_manifest",
            "rerun_stage0_to_stage3_nonregression_checks",
            "run_primary_standard_end_native_and_linear_probe_panel",
            "run_confirmation_panel_if_candidate",
            "write_standard_end_reports_and_verdict",
        ],
        "explicit_statement": "No sweep, no second package, no continuation, no Stage-3 learned evaluation.",
    }
    _write_json(output_root / STANDARD_END_LOCALIZATION_MANIFEST_V1_ARTIFACT, package_manifest)

    nonregression_report = _standard_end_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
    )
    _write_json(output_root / STANDARD_END_NONREGRESSION_REPORT_V1_ARTIFACT, nonregression_report)

    if not bool(nonregression_report["passes"]):
        anchor_report = _standard_end_build_skipped_anchor_report(stop_reason="nonregression_failed")
        linear_probe_primary_report = _standard_end_build_skipped_linear_probe_report(
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        localization_delta_report = _standard_end_build_empty_delta_report(stop_reason="nonregression_failed")
        verdict = _standard_end_build_verdict(
            nonregression_report=nonregression_report,
            anchor_report=anchor_report,
            linear_probe_primary_report=linear_probe_primary_report,
            linear_probe_confirmation_report=None,
            localization_delta_report=localization_delta_report,
            confirmation_executed=False,
        )
        _write_json(output_root / STANDARD_END_ANCHOR_REPORT_V1_ARTIFACT, anchor_report)
        _write_json(output_root / STANDARD_END_LINEAR_PROBE_PRIMARY_REPORT_V1_ARTIFACT, linear_probe_primary_report)
        _write_json(output_root / STANDARD_END_LOCALIZATION_DELTA_REPORT_V1_ARTIFACT, localization_delta_report)
        _write_json(output_root / STANDARD_END_LOCALIZATION_VERDICT_V1_ARTIFACT, verdict)
        return StandardEndLocalizationRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            anchor_report=anchor_report,
            linear_probe_primary_report=linear_probe_primary_report,
            linear_probe_confirmation_report=None,
            localization_delta_report=localization_delta_report,
            verdict=verdict,
            run_ids=[],
        )

    store = RunStore(resolved_config.artifacts.root_dir)
    generator = Phase1ParadigmGenerator(resolved_config, controlled_sources=STAGE3_FULL_CONTROLLED_SOURCES)
    model = V1ExpectationModel(resolved_config)
    model.eval()
    assay_runner = AssayRunner(resolved_config)

    primary_run_entries: list[dict[str, object]] = []
    all_run_ids: list[str] = []
    for train_seed, heldout_seed in primary_seed_panel:
        entry = _standard_end_execute_localization_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="primary",
        )
        primary_run_entries.append(entry)
        all_run_ids.append(entry["run_id"])

    anchor_report = _standard_end_build_anchor_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=None,
    )
    linear_probe_primary_report = _standard_end_build_linear_probe_panel_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    localization_delta_report = _standard_end_build_localization_delta_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=None,
    )

    candidate = _standard_end_primary_candidate(
        anchor_report=anchor_report,
        linear_probe_primary_report=linear_probe_primary_report,
        localization_delta_report=localization_delta_report,
    )

    confirmation_run_entries: list[dict[str, object]] | None = None
    linear_probe_confirmation_report: dict[str, object] | None = None
    if candidate["classification"] != "NO-GO clean negative":
        confirmation_run_entries = []
        for train_seed, heldout_seed in confirmation_seed_panel:
            entry = _standard_end_execute_localization_run(
                resolved_config=resolved_config,
                store=store,
                generator=generator,
                model=model,
                assay_runner=assay_runner,
                train_seed=int(train_seed),
                heldout_seed=int(heldout_seed),
                seed_panel="confirmation",
            )
            confirmation_run_entries.append(entry)
            all_run_ids.append(entry["run_id"])
        anchor_report = _standard_end_build_anchor_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_run_entries,
        )
        linear_probe_confirmation_report = _standard_end_build_linear_probe_panel_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
        localization_delta_report = _standard_end_build_localization_delta_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_run_entries,
        )

    verdict = _standard_end_build_verdict(
        nonregression_report=nonregression_report,
        anchor_report=anchor_report,
        linear_probe_primary_report=linear_probe_primary_report,
        linear_probe_confirmation_report=linear_probe_confirmation_report,
        localization_delta_report=localization_delta_report,
        confirmation_executed=confirmation_run_entries is not None,
    )

    _write_json(output_root / STANDARD_END_ANCHOR_REPORT_V1_ARTIFACT, anchor_report)
    _write_json(output_root / STANDARD_END_LINEAR_PROBE_PRIMARY_REPORT_V1_ARTIFACT, linear_probe_primary_report)
    if linear_probe_confirmation_report is not None:
        _write_json(output_root / STANDARD_END_LINEAR_PROBE_CONFIRMATION_REPORT_V1_ARTIFACT, linear_probe_confirmation_report)
    _write_json(output_root / STANDARD_END_LOCALIZATION_DELTA_REPORT_V1_ARTIFACT, localization_delta_report)
    _write_json(output_root / STANDARD_END_LOCALIZATION_VERDICT_V1_ARTIFACT, verdict)

    return StandardEndLocalizationRunResult(
        output_root=output_root,
        package_manifest=package_manifest,
        nonregression_report=nonregression_report,
        anchor_report=anchor_report,
        linear_probe_primary_report=linear_probe_primary_report,
        linear_probe_confirmation_report=linear_probe_confirmation_report,
        localization_delta_report=localization_delta_report,
        verdict=verdict,
        run_ids=all_run_ids,
    )


def _readout_alignment_metadata(
    *,
    metric_versions: dict[str, str],
    source_metric_versions: list[str],
) -> dict[str, object]:
    return {
        "metric_schema_version": READOUT_ALIGNMENT_METRIC_SCHEMA_VERSION,
        "metric_versions": metric_versions,
        "classification_rule_version": READOUT_ALIGNMENT_CLASSIFICATION_RULE_VERSION,
        "source_metric_versions": source_metric_versions,
        "benchmark_registry_version": BENCHMARK_REGISTRY_VERSION,
        "readout_alignment_package_version": READOUT_ALIGNMENT_PACKAGE_VERSION,
    }


def _readout_alignment_build_nonregression_report(
    *,
    resolved_config: ExperimentConfig,
    output_root: Path,
    benchmark_artifacts_root: str | Path,
) -> dict[str, object]:
    raw_report = _stage4_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
        primary_seed_panel=STAGE3_PRIMARY_SEED_PANEL,
        confirmation_seed_panel=STAGE3_CONFIRMATION_SEED_PANEL,
    )
    stripped = dict(raw_report)
    for key in (
        "metric_schema_version",
        "metric_versions",
        "classification_rule_version",
        "source_metric_versions",
        "benchmark_registry_version",
        "stage3_task_version",
        "stage4_package_version",
    ):
        stripped.pop(key, None)
    return {
        **_readout_alignment_metadata(
            metric_versions={
                "stage0_registry_verification": "v1",
                "stage1_tranche_runner_replay": "v1",
                "stage2_diagnostic_calibration_report": "v2",
                "stage3_oracle_task_definition_verdict": "v2",
                "phase15_continuation_retention": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        **stripped,
    }


def _tensor_fingerprint(tensor: torch.Tensor | None) -> str | None:
    if tensor is None:
        return None
    resolved = tensor.detach().cpu().contiguous()
    payload = json.dumps(
        {
            "shape": list(resolved.shape),
            "dtype": str(resolved.dtype),
        },
        sort_keys=True,
    ).encode("utf-8") + resolved.numpy().tobytes()
    return hashlib.sha256(payload).hexdigest()


def _named_parameter_fingerprint(named_parameters: list[tuple[str, torch.Tensor]]) -> str:
    digest = hashlib.sha256()
    for name, parameter in named_parameters:
        digest.update(name.encode("utf-8"))
        digest.update(b"\0")
        fingerprint = _tensor_fingerprint(parameter)
        if fingerprint is not None:
            digest.update(fingerprint.encode("utf-8"))
        digest.update(b"\0")
    return digest.hexdigest()


def _readout_alignment_parameter_scope_snapshot(
    predictor: CausalContextPredictor,
) -> dict[str, object]:
    recurrent_core_parameters = [(name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("gru.")]
    precision_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("precision_head.")
    ]
    orientation_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("orientation_head.")
    ]
    trainable_parameter_names = [name for name, parameter in predictor.named_parameters() if parameter.requires_grad]
    return {
        "trainable_parameter_names": trainable_parameter_names,
        "recurrent_core_parameter_names": [name for name, _ in recurrent_core_parameters],
        "precision_head_parameter_names": [name for name, _ in precision_parameters],
        "orientation_head_parameter_names": [name for name, _ in orientation_parameters],
        "recurrent_core_fingerprint": _named_parameter_fingerprint(recurrent_core_parameters),
        "precision_head_fingerprint": (
            _named_parameter_fingerprint(precision_parameters) if precision_parameters else "disabled"
        ),
        "orientation_head_fingerprint": _named_parameter_fingerprint(orientation_parameters),
    }


def _readout_alignment_freeze_orientation_head_only(
    predictor: CausalContextPredictor,
) -> list[str]:
    for name, parameter in predictor.named_parameters():
        parameter.requires_grad = name in READOUT_ALIGNMENT_PARAM_UPDATE_SCOPE
    trainable_parameter_names = [name for name, parameter in predictor.named_parameters() if parameter.requires_grad]
    if trainable_parameter_names != list(READOUT_ALIGNMENT_PARAM_UPDATE_SCOPE):
        raise AssertionError("readout_alignment may only train predictor.orientation_head.{weight,bias}.")
    return trainable_parameter_names


def _readout_alignment_write_hidden_state_artifacts(
    *,
    run_id: str,
    batch: TrialBatch,
    learned_simulation: SimulationOutput,
    oracle_simulation: SimulationOutput,
    symmetry_mate_lookup: dict[int, int],
    output_dir: Path,
) -> dict[str, object]:
    payload = _stage4_probe_run_payload(
        run_id=run_id,
        batch=batch,
        learned_simulation=learned_simulation,
        oracle_simulation=oracle_simulation,
        symmetry_mate_lookup=symmetry_mate_lookup,
    )
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    for row in rows:
        pair_id = int(row["pair_id"])
        row["_symmetry_group_id"] = min(pair_id, int(symmetry_mate_lookup[pair_id]))
    diagnostics = build_hidden_state_diagnostics_v2(rows)
    diagnostics_payload = {
        **_readout_alignment_metadata(
            metric_versions=metric_versions_v2_payload(),
            source_metric_versions=[DIAGNOSTIC_SCHEMA_VERSION, FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "diagnostic_schema_version": DIAGNOSTIC_SCHEMA_VERSION,
        **diagnostics,
    }
    write_hidden_state_probe_table_v2(rows, output_dir / HIDDEN_STATE_PROBE_TABLE_V2_ARTIFACT)
    write_hidden_state_diagnostics_v2_json(
        diagnostics_payload,
        output_dir / HIDDEN_STATE_DIAGNOSTICS_V2_ARTIFACT,
    )
    return {
        "rows": rows,
        "diagnostics": diagnostics_payload,
    }


def _readout_alignment_write_linear_probe_artifacts(
    *,
    run_id: str,
    batch: TrialBatch,
    linear_probe_logits: torch.Tensor,
    oracle_prediction: ContextPrediction,
    output_dir: Path,
    auxiliary_seed: int,
) -> dict[str, object]:
    payload = {
        "run_id": run_id,
        "batch": _serialize_batch(batch),
        "learned_logits": linear_probe_logits,
        "oracle_logits": oracle_prediction.orientation_logits,
        "learned_precision": None,
        "oracle_precision": oracle_prediction.precision_logit,
        "l23_readout": None,
        "gaussian_orientation_bank": None,
        "context_comparator": None,
    }
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    diagnostics = build_hidden_state_diagnostics_v2(rows)
    diagnostics_payload = {
        **_readout_alignment_metadata(
            metric_versions=metric_versions_v2_payload(),
            source_metric_versions=[DIAGNOSTIC_SCHEMA_VERSION, FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "diagnostic_schema_version": DIAGNOSTIC_SCHEMA_VERSION,
        **diagnostics,
    }
    write_hidden_state_probe_table_v2(rows, output_dir / READOUT_ALIGNMENT_LINEAR_PROBE_HIDDEN_STATE_TABLE_V2_ARTIFACT)
    write_hidden_state_diagnostics_v2_json(
        diagnostics_payload,
        output_dir / READOUT_ALIGNMENT_LINEAR_PROBE_HIDDEN_STATE_DIAGNOSTICS_V2_ARTIFACT,
    )
    probe_mask = _probe_scoring_mask(batch)
    expected_distribution = batch.metadata["expected_distribution"][probe_mask]
    alignment_kl, expected_logprob = _probe_alignment_stats(linear_probe_logits[probe_mask], expected_distribution)
    behavior_metrics = _probe_alignment_behavior_metrics(batch, linear_probe_logits)
    report = {
        **_readout_alignment_metadata(
            metric_versions={
                "linear_probe_alignment_kl": "v1",
                "linear_probe_expected_logprob": "v1",
                "linear_probe_expected_target_top1_rate": "v1",
                "linear_probe_correct_pair_flip_rate__v2": "v2",
                "linear_probe_within_pair_mass__v2": "v2",
                "linear_probe_source_bin_kl__v2": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "run_id": run_id,
        "heldout_generator_seed": int(batch.metadata["generator_seed"]),
        "auxiliary_generator_seed": int(auxiliary_seed),
        "train_eval_disjoint": int(batch.metadata["generator_seed"]) != int(auxiliary_seed),
        "linear_probe_alignment_kl": alignment_kl,
        "linear_probe_expected_logprob": expected_logprob,
        "linear_probe_expected_target_top1_rate": behavior_metrics["probe_expected_target_top1_rate"],
        "linear_probe_pair_flip_rate": behavior_metrics["probe_pair_flip_rate"],
        "linear_probe_pair_flip_symmetry_consistency": behavior_metrics["probe_pair_flip_symmetry_consistency"],
        "linear_probe_correct_pair_flip_rate__v2": diagnostics["probe_correct_pair_flip_rate__v2"],
        "linear_probe_within_pair_mass__v2": diagnostics["probe_within_pair_mass__v2"],
        "linear_probe_source_bin_kl__v2": diagnostics["probe_source_bin_kl__v2"],
    }
    _write_json(output_dir / READOUT_ALIGNMENT_LINEAR_PROBE_REPORT_V1_ARTIFACT, report)
    return {
        "rows": rows,
        "diagnostics": diagnostics_payload,
        "report": report,
    }


def _readout_alignment_alignment_seeds(heldout_seed: int) -> list[int]:
    return [
        int(heldout_seed) + READOUT_ALIGNMENT_ALIGNMENT_SEED_BASE_OFFSET + step_index
        for step_index in range(READOUT_ALIGNMENT_ALIGNMENT_BATCH_COUNT)
    ]


def _readout_alignment_evaluate_checkpoint(
    *,
    predictor: CausalContextPredictor,
    heldout_batch: TrialBatch,
    auxiliary_probe_fit_batch: TrialBatch,
    standard_heldout_batch: TrialBatch,
    run_id: str,
    run_dir: Path,
    checkpoint_dirname: str,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    generator: Phase1ParadigmGenerator,
    resolved_config: ExperimentConfig,
    save_native_refit_outputs: bool = False,
) -> dict[str, object]:
    checkpoint_dir = run_dir / checkpoint_dirname
    checkpoint_dir.mkdir(parents=True, exist_ok=True)
    (checkpoint_dir / "eval").mkdir(parents=True, exist_ok=True)
    with torch.no_grad():
        learned_prediction, heldout_hidden_states = _predict_with_hidden_states(predictor, heldout_batch)
        _, auxiliary_hidden_states = _predict_with_hidden_states(predictor, auxiliary_probe_fit_batch)
        oracle_prediction = _oracle_context_prediction(
            heldout_batch,
            use_precision=resolved_config.context.use_precision,
        )
        learned_simulation, learned_window_summaries = _evaluate_single_subcase(
            batch=heldout_batch,
            prediction=learned_prediction,
            subcase="dampening",
            model=model,
            config=resolved_config,
        )
        oracle_simulation, oracle_window_summaries = _evaluate_single_subcase(
            batch=heldout_batch,
            prediction=oracle_prediction,
            subcase="dampening",
            model=model,
            config=resolved_config,
        )
    standard_sanity = {
        "nuisance_only": asdict(generator.run_nuisance_only_failure_test(standard_heldout_batch)),
        "predictive_structure": asdict(generator.run_predictive_structure_success_test(standard_heldout_batch)),
    }
    standard_predictive_metrics = evaluate_context_predictor(
        predictor,
        standard_heldout_batch,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )

    torch.save(
        _standard_end_hidden_state_payload(
            batch=heldout_batch,
            hidden_states=heldout_hidden_states,
            batch_role="heldout_eval",
        ),
        checkpoint_dir / READOUT_ALIGNMENT_RAW_HIDDEN_STATE_EVAL_ARTIFACT,
    )
    torch.save(
        _standard_end_hidden_state_payload(
            batch=auxiliary_probe_fit_batch,
            hidden_states=auxiliary_hidden_states,
            batch_role="auxiliary_probe_fit",
        ),
        checkpoint_dir / READOUT_ALIGNMENT_RAW_HIDDEN_STATE_AUX_ARTIFACT,
    )
    torch.save(_serialize_batch(auxiliary_probe_fit_batch), checkpoint_dir / READOUT_ALIGNMENT_AUX_BATCH_ARTIFACT)

    probe_metrics = assay_runner.compute_local_global_probe_metrics(learned_simulation, heldout_batch)
    oracle_probe_metrics = assay_runner.compute_local_global_probe_metrics(oracle_simulation, heldout_batch)
    probe_context_alignment_report = _build_probe_context_alignment_report(
        heldout_batch,
        oracle_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=oracle_prediction,
            metadata=heldout_batch.metadata,
        ),
        learned_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=learned_prediction,
            metadata=heldout_batch.metadata,
        ),
    )
    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    probe_design_report = {
        **_readout_alignment_metadata(
            metric_versions={
                "n_probe_rows": "v1",
                "n_probe_global_expected_rows": "v1",
                "n_probe_global_unexpected_rows": "v1",
                "n_probe_pairs_total": "v1",
                "n_probe_pairs_scored": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **_build_probe_design_report(
            heldout_batch,
            task_mode_fixed_state=task_mode_fixed_state,
            prestim_fixed_state=prestim_fixed_state,
            oracle_simulation=oracle_simulation,
            learned_simulation=learned_simulation,
        ),
    }
    probe_metrics_payload = {
        **_readout_alignment_metadata(
            metric_versions={metric_name: "v1" for metric_name in sorted(probe_metrics)},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **probe_metrics,
    }
    oracle_probe_metrics_payload = {
        **_readout_alignment_metadata(
            metric_versions={metric_name: "v1" for metric_name in sorted(oracle_probe_metrics)},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **oracle_probe_metrics,
    }
    probe_context_alignment_payload = {
        **_readout_alignment_metadata(
            metric_versions={
                "learned_probe_alignment_kl": "v1",
                "oracle_probe_alignment_kl": "v1",
                "learned_probe_expected_logprob": "v1",
                "oracle_probe_expected_logprob": "v1",
                "learned_probe_expected_target_top1_rate": "v1",
                "oracle_probe_expected_target_top1_rate": "v1",
                "learned_probe_pair_flip_rate": "v1",
                "oracle_probe_pair_flip_rate": "v1",
                "learned_probe_pair_flip_symmetry_consistency": "v1",
                "oracle_probe_pair_flip_symmetry_consistency": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **probe_context_alignment_report,
    }
    probe_table_payload = {
        **_readout_alignment_metadata(
            metric_versions={"probe_table_rows": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "rows": _build_probe_table(heldout_batch, oracle_simulation, learned_simulation),
    }
    probe_symmetry_mates = {
        int(pair_id): int(descriptor["symmetry_mate_pair_id"])
        for pair_id, descriptor in heldout_batch.metadata["probe_report"]["pair_descriptors"].items()
    }
    native_hidden_state_outputs = _readout_alignment_write_hidden_state_artifacts(
        run_id=run_id,
        batch=heldout_batch,
        learned_simulation=learned_simulation,
        oracle_simulation=oracle_simulation,
        symmetry_mate_lookup=probe_symmetry_mates,
        output_dir=checkpoint_dir,
    )
    linear_probe = _standard_end_fit_linear_probe(
        hidden_states=auxiliary_hidden_states,
        batch=auxiliary_probe_fit_batch,
    )
    linear_probe_logits = _standard_end_apply_linear_probe(
        hidden_states=heldout_hidden_states,
        linear_probe=linear_probe,
    )
    linear_probe_outputs = _readout_alignment_write_linear_probe_artifacts(
        run_id=run_id,
        batch=heldout_batch,
        linear_probe_logits=linear_probe_logits,
        oracle_prediction=oracle_prediction,
        output_dir=checkpoint_dir,
        auxiliary_seed=int(auxiliary_probe_fit_batch.metadata["generator_seed"]),
    )
    torch.save(linear_probe, checkpoint_dir / READOUT_ALIGNMENT_LINEAR_PROBE_PARAMETERS_ARTIFACT)

    _write_json(checkpoint_dir / "probe_design_report.json", probe_design_report)
    _write_json(checkpoint_dir / "probe_metrics.json", probe_metrics_payload)
    _write_json(checkpoint_dir / "oracle_probe_metrics.json", oracle_probe_metrics_payload)
    _write_json(checkpoint_dir / "probe_context_alignment_report.json", probe_context_alignment_payload)
    _write_json(checkpoint_dir / "probe_table.json", probe_table_payload)
    torch.save(_serialize_batch(heldout_batch), checkpoint_dir / "eval" / "heldout_batch.pt")
    torch.save({"dampening": learned_window_summaries}, checkpoint_dir / "eval" / "window_summaries.pt")
    torch.save({"dampening": oracle_window_summaries}, checkpoint_dir / "eval" / "oracle_window_summaries.pt")
    torch.save({"dampening": _serialize_simulation(learned_simulation)}, checkpoint_dir / "eval" / "full_trajectories.pt")
    torch.save({"dampening": _serialize_simulation(oracle_simulation)}, checkpoint_dir / "eval" / "oracle_full_trajectories.pt")

    if save_native_refit_outputs:
        (run_dir / "eval").mkdir(parents=True, exist_ok=True)
        torch.save(_serialize_context_prediction(learned_prediction), run_dir / READOUT_ALIGNMENT_NATIVE_HEAD_REFIT_PREDICTIONS_ARTIFACT)
        torch.save(
            {key: value.detach().cpu() for key, value in predictor.orientation_head.state_dict().items()},
            run_dir / READOUT_ALIGNMENT_NATIVE_HEAD_REFIT_ORIENTATION_HEAD_STATE_ARTIFACT,
        )

    return {
        "checkpoint": checkpoint_dirname,
        "probe_metrics": probe_metrics,
        "oracle_probe_metrics": oracle_probe_metrics,
        "probe_context_alignment_report": probe_context_alignment_report,
        "hidden_state_diagnostics": native_hidden_state_outputs["diagnostics"],
        "linear_probe_report": linear_probe_outputs["report"],
        "linear_probe_diagnostics": linear_probe_outputs["diagnostics"],
        "standard_predictive_metrics": standard_predictive_metrics,
        "standard_sanity": standard_sanity,
        "heldout_generator_seed": int(heldout_batch.metadata["generator_seed"]),
        "auxiliary_generator_seed": int(auxiliary_probe_fit_batch.metadata["generator_seed"]),
        "heldout_hidden_state_fingerprint": _tensor_fingerprint(heldout_hidden_states),
        "auxiliary_hidden_state_fingerprint": _tensor_fingerprint(auxiliary_hidden_states),
        "heldout_hidden_states": heldout_hidden_states.detach().cpu(),
        "auxiliary_hidden_states": auxiliary_hidden_states.detach().cpu(),
        "artifacts_complete": True,
    }


def _readout_alignment_align_orientation_head_only(
    *,
    predictor: CausalContextPredictor,
    generator: Phase1ParadigmGenerator,
    heldout_seed: int,
    auxiliary_probe_fit_seed: int,
) -> tuple[list[EpochMetrics], list[int]]:
    trainable_parameter_names = _readout_alignment_freeze_orientation_head_only(predictor)
    if trainable_parameter_names != list(READOUT_ALIGNMENT_PARAM_UPDATE_SCOPE):
        raise AssertionError("unexpected readout alignment parameter scope.")
    optimizer = torch.optim.Adam(
        predictor.orientation_head.parameters(),
        lr=READOUT_ALIGNMENT_ALIGNMENT_LEARNING_RATE,
        weight_decay=READOUT_ALIGNMENT_ALIGNMENT_WEIGHT_DECAY,
    )
    alignment_seeds = _readout_alignment_alignment_seeds(heldout_seed)
    if heldout_seed in alignment_seeds or auxiliary_probe_fit_seed in alignment_seeds:
        raise AssertionError("alignment auxiliary seeds must remain disjoint from held-out and probe-fit seeds.")
    history: list[EpochMetrics] = []
    predictor.train()
    for step_index, batch_seed in enumerate(alignment_seeds, start=1):
        batch = generator.generate_local_global_probe_batch(seed=batch_seed)
        optimizer.zero_grad(set_to_none=True)
        prediction = predictor(batch)
        losses = predictive_loss(
            prediction,
            batch,
            objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
            loss_mask=_probe_scoring_mask(batch),
        )
        losses.total.backward()
        optimizer.step()
        history.append(
            EpochMetrics(
                epoch=step_index,
                total=float(losses.total.item()),
                predictive_loss=float(losses.predictive_loss.item()),
                energy_penalty=float(losses.energy_penalty.item()),
                homeostasis_penalty=float(losses.homeostasis_penalty.item()),
            )
        )
    predictor.eval()
    return history, alignment_seeds


def _readout_alignment_prepare_run(
    *,
    resolved_config: ExperimentConfig,
    store: RunStore,
    generator: Phase1ParadigmGenerator,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    train_seed: int,
    heldout_seed: int,
    seed_panel: str,
) -> dict[str, object]:
    training_config = _stage4_training_config(resolved_config)
    auxiliary_probe_fit_seed = heldout_seed + READOUT_ALIGNMENT_AUXILIARY_PROBE_FIT_SEED_OFFSET
    if auxiliary_probe_fit_seed == heldout_seed:
        raise AssertionError("auxiliary probe-fit seed must differ from held-out seed.")
    train_batches = [
        generator.generate_batch(
            batch_size=training_config.batch_size,
            seed=train_seed + epoch,
        )
        for epoch in range(training_config.n_epochs)
    ]
    heldout_batch = generator.generate_local_global_probe_batch(seed=heldout_seed)
    auxiliary_probe_fit_batch = generator.generate_local_global_probe_batch(seed=auxiliary_probe_fit_seed)
    standard_heldout_batch = generator.generate_batch(
        batch_size=training_config.batch_size,
        seed=heldout_seed,
    )
    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    manifest, run_dir = store.create_run(
        resolved_config.name,
        train_objectives=[f"{resolved_config.training.predictive_objective}:{EXPECTED_DISTRIBUTION_OBJECTIVE}"],
        heldout_assays=[
            "probe_target_aligned_specificity_contrast",
            "probe_pooled_target_aligned_specificity_contrast",
            "probe_context_comparator_nonuniformity_contrast",
            "linear_probe_alignment_kl",
            "linear_probe_expected_target_top1_rate",
            "linear_probe_correct_pair_flip_rate__v2",
            "linear_probe_within_pair_mass__v2",
            "linear_probe_source_bin_kl__v2",
        ],
        notes={
            "gate": "readout_alignment",
            "readout_alignment_package_version": READOUT_ALIGNMENT_PACKAGE_VERSION,
            "checkpoints": [READOUT_ALIGNMENT_PRE_CHECKPOINT_DIRNAME, READOUT_ALIGNMENT_POST_CHECKPOINT_DIRNAME],
            "seed_panel": seed_panel,
            "train_seed": int(train_seed),
            "heldout_seed": int(heldout_seed),
            "auxiliary_probe_fit_seed": int(auxiliary_probe_fit_seed),
            "alignment_auxiliary_seeds": _readout_alignment_alignment_seeds(heldout_seed),
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "initial_standard_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "alignment_optimizer": "Adam",
            "alignment_steps": READOUT_ALIGNMENT_ALIGNMENT_STEPS,
            "alignment_batch_count": READOUT_ALIGNMENT_ALIGNMENT_BATCH_COUNT,
            "alignment_learning_rate": READOUT_ALIGNMENT_ALIGNMENT_LEARNING_RATE,
            "alignment_weight_decay": READOUT_ALIGNMENT_ALIGNMENT_WEIGHT_DECAY,
            "parameter_update_scope": list(READOUT_ALIGNMENT_PARAM_UPDATE_SCOPE),
            "controlled_sources": heldout_batch.metadata["controlled_sources"].tolist(),
            "probe_visible_step_index": int(heldout_batch.metadata["probe_visible_step_index"]),
            "task_mode_fixed_state": task_mode_fixed_state,
            "prestim_fixed_state": prestim_fixed_state,
            "heldout_batch_identity_rule": "fixed_probe_batch(seed=heldout_seed)",
            "auxiliary_probe_fit_identity_rule": "fixed_probe_batch(seed=heldout_seed + 1)",
            "alignment_auxiliary_identity_rule": "fixed_probe_batch(seed=heldout_seed + 100 + step_index)",
            "hidden_state_tensors_exported": [READOUT_ALIGNMENT_HIDDEN_STATE_TENSOR_NAME],
            "linear_probe_form": READOUT_ALIGNMENT_LINEAR_PROBE_FORM,
            "linear_probe_target": READOUT_ALIGNMENT_LINEAR_PROBE_TARGET,
            "linear_probe_ridge_lambda": READOUT_ALIGNMENT_LINEAR_PROBE_RIDGE_LAMBDA,
            "linear_probe_train_eval_disjoint": True,
            "linear_probe_fit_mask": "probe_step_mask & probe_valid_mask",
            "bootstrap_seed": READOUT_ALIGNMENT_BOOTSTRAP_SEED,
            "bootstrap_resamples": READOUT_ALIGNMENT_BOOTSTRAP_RESAMPLES,
            "no_sweep": True,
            "no_second_package": True,
            "no_harder_evaluation": True,
            "oracle_precision_mode": "neutral_zero_logit" if resolved_config.context.use_precision else "disabled",
        },
    )

    predictor = CausalContextPredictor(resolved_config.geometry, resolved_config.context)
    train_history = train_context_predictor(
        predictor,
        train_batches,
        training_config,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )
    _write_json(run_dir / READOUT_ALIGNMENT_PRETRAIN_HISTORY_ARTIFACT, [asdict(item) for item in train_history])

    pre_parameter_snapshot = _readout_alignment_parameter_scope_snapshot(predictor)
    _write_json(
        run_dir / READOUT_ALIGNMENT_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT,
        {
            **_readout_alignment_metadata(
                metric_versions={"parameter_scope_fingerprints": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "run_id": manifest.run_id,
            "parameter_update_scope": list(READOUT_ALIGNMENT_PARAM_UPDATE_SCOPE),
            "pre_alignment": pre_parameter_snapshot,
            "post_alignment": None,
            "checks": {},
        },
    )
    pre_checkpoint = _readout_alignment_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        auxiliary_probe_fit_batch=auxiliary_probe_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=manifest.run_id,
        run_dir=run_dir,
        checkpoint_dirname=READOUT_ALIGNMENT_PRE_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        save_native_refit_outputs=False,
    )
    _write_stage0_provenance(store=store, run_dir=run_dir, manifest=manifest, resolved_config=resolved_config)
    return {
        "run_id": manifest.run_id,
        "run_dir": run_dir,
        "seed_panel": seed_panel,
        "train_seed": int(train_seed),
        "heldout_seed": int(heldout_seed),
        "auxiliary_probe_fit_seed": int(auxiliary_probe_fit_seed),
        "predictor": predictor,
        "generator": generator,
        "model": model,
        "assay_runner": assay_runner,
        "resolved_config": resolved_config,
        "heldout_batch": heldout_batch,
        "auxiliary_probe_fit_batch": auxiliary_probe_fit_batch,
        "standard_heldout_batch": standard_heldout_batch,
        "pre_alignment": pre_checkpoint,
        "pre_parameter_snapshot": pre_parameter_snapshot,
    }


def _readout_alignment_complete_run(
    prepared_run: dict[str, object],
) -> dict[str, object]:
    predictor = prepared_run["predictor"]
    heldout_batch = prepared_run["heldout_batch"]
    auxiliary_probe_fit_batch = prepared_run["auxiliary_probe_fit_batch"]
    standard_heldout_batch = prepared_run["standard_heldout_batch"]
    generator = prepared_run["generator"]
    model = prepared_run["model"]
    assay_runner = prepared_run["assay_runner"]
    resolved_config = prepared_run["resolved_config"]
    run_dir = prepared_run["run_dir"]
    run_id = prepared_run["run_id"]
    auxiliary_probe_fit_seed = int(prepared_run["auxiliary_probe_fit_seed"])

    alignment_history, alignment_auxiliary_seeds = _readout_alignment_align_orientation_head_only(
        predictor=predictor,
        generator=generator,
        heldout_seed=int(prepared_run["heldout_seed"]),
        auxiliary_probe_fit_seed=auxiliary_probe_fit_seed,
    )
    _write_json(run_dir / READOUT_ALIGNMENT_ALIGNMENT_HISTORY_ARTIFACT, [asdict(item) for item in alignment_history])
    post_parameter_snapshot = _readout_alignment_parameter_scope_snapshot(predictor)
    post_checkpoint = _readout_alignment_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        auxiliary_probe_fit_batch=auxiliary_probe_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=run_id,
        run_dir=run_dir,
        checkpoint_dirname=READOUT_ALIGNMENT_POST_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        save_native_refit_outputs=True,
    )

    pre_checkpoint = prepared_run["pre_alignment"]
    heldout_batch_same_pre_post = (
        int(pre_checkpoint["heldout_generator_seed"]) == int(post_checkpoint["heldout_generator_seed"])
    )
    auxiliary_batch_same_pre_post = (
        int(pre_checkpoint["auxiliary_generator_seed"]) == int(post_checkpoint["auxiliary_generator_seed"])
    )
    heldout_hidden_state_max_abs_diff = float(
        (pre_checkpoint["heldout_hidden_states"] - post_checkpoint["heldout_hidden_states"]).abs().max().item()
    )
    auxiliary_hidden_state_max_abs_diff = float(
        (pre_checkpoint["auxiliary_hidden_states"] - post_checkpoint["auxiliary_hidden_states"]).abs().max().item()
    )
    heldout_hidden_states_unchanged = bool(
        torch.allclose(
            pre_checkpoint["heldout_hidden_states"],
            post_checkpoint["heldout_hidden_states"],
            atol=READOUT_ALIGNMENT_HIDDEN_STATE_ATOL,
            rtol=0.0,
        )
    )
    auxiliary_hidden_states_unchanged = bool(
        torch.allclose(
            pre_checkpoint["auxiliary_hidden_states"],
            post_checkpoint["auxiliary_hidden_states"],
            atol=READOUT_ALIGNMENT_HIDDEN_STATE_ATOL,
            rtol=0.0,
        )
    )
    recurrent_core_parameter_fingerprint_unchanged = (
        prepared_run["pre_parameter_snapshot"]["recurrent_core_fingerprint"]
        == post_parameter_snapshot["recurrent_core_fingerprint"]
    )
    precision_head_parameter_fingerprint_unchanged = (
        prepared_run["pre_parameter_snapshot"]["precision_head_fingerprint"]
        == post_parameter_snapshot["precision_head_fingerprint"]
    )
    orientation_head_parameter_fingerprint_changed = (
        prepared_run["pre_parameter_snapshot"]["orientation_head_fingerprint"]
        != post_parameter_snapshot["orientation_head_fingerprint"]
    )
    predictive_loss_pre = float(pre_checkpoint["standard_predictive_metrics"]["predictive_loss"])
    predictive_loss_post = float(post_checkpoint["standard_predictive_metrics"]["predictive_loss"])
    predictive_structure_accuracy_pre = float(pre_checkpoint["standard_sanity"]["predictive_structure"]["accuracy"])
    predictive_structure_accuracy_post = float(post_checkpoint["standard_sanity"]["predictive_structure"]["accuracy"])
    nuisance_only_accuracy_pre = float(pre_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"])
    nuisance_only_accuracy_post = float(post_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"])
    integrity = {
        "heldout_batch_identity_same_pre_post": heldout_batch_same_pre_post,
        "auxiliary_batch_identity_same_pre_post": auxiliary_batch_same_pre_post,
        "auxiliary_eval_disjoint_from_heldout": int(prepared_run["heldout_seed"]) != auxiliary_probe_fit_seed,
        "recurrent_core_parameter_fingerprint_unchanged": recurrent_core_parameter_fingerprint_unchanged,
        "precision_head_parameter_fingerprint_unchanged": precision_head_parameter_fingerprint_unchanged,
        "orientation_head_parameter_fingerprint_changed": orientation_head_parameter_fingerprint_changed,
        "heldout_hidden_states_unchanged": heldout_hidden_states_unchanged,
        "auxiliary_hidden_states_unchanged": auxiliary_hidden_states_unchanged,
        "heldout_hidden_state_max_abs_diff": heldout_hidden_state_max_abs_diff,
        "auxiliary_hidden_state_max_abs_diff": auxiliary_hidden_state_max_abs_diff,
        "predictive_loss_pre": predictive_loss_pre,
        "predictive_loss_post": predictive_loss_post,
        "predictive_structure_accuracy_pre": predictive_structure_accuracy_pre,
        "predictive_structure_accuracy_post": predictive_structure_accuracy_post,
        "nuisance_only_accuracy_pre": nuisance_only_accuracy_pre,
        "nuisance_only_accuracy_post": nuisance_only_accuracy_post,
        "delta_predictive_loss": predictive_loss_post - predictive_loss_pre,
        "delta_predictive_structure_accuracy": (
            predictive_structure_accuracy_post - predictive_structure_accuracy_pre
        ),
        "delta_nuisance_only_accuracy": nuisance_only_accuracy_post - nuisance_only_accuracy_pre,
        "predictive_nonregression_passes": (
            (predictive_loss_post - predictive_loss_pre) <= READOUT_ALIGNMENT_PREDICTIVE_LOSS_DELTA_MAX
            and (predictive_structure_accuracy_post - predictive_structure_accuracy_pre)
            >= READOUT_ALIGNMENT_PREDICTIVE_STRUCTURE_DELTA_MIN
            and (nuisance_only_accuracy_post - nuisance_only_accuracy_pre) <= READOUT_ALIGNMENT_NUISANCE_ONLY_DELTA_MAX
            and nuisance_only_accuracy_post < READOUT_ALIGNMENT_NUISANCE_ONLY_POST_MAX
        ),
    }
    parameter_scope_payload = {
        **_readout_alignment_metadata(
            metric_versions={"parameter_scope_fingerprints": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "parameter_update_scope": list(READOUT_ALIGNMENT_PARAM_UPDATE_SCOPE),
        "alignment_auxiliary_seeds": alignment_auxiliary_seeds,
        "pre_alignment": prepared_run["pre_parameter_snapshot"],
        "post_alignment": post_parameter_snapshot,
        "checks": {
            "recurrent_core_parameter_fingerprint_unchanged": recurrent_core_parameter_fingerprint_unchanged,
            "precision_head_parameter_fingerprint_unchanged": precision_head_parameter_fingerprint_unchanged,
            "orientation_head_parameter_fingerprint_changed": orientation_head_parameter_fingerprint_changed,
            "exact_trainable_parameter_scope_during_alignment": (
                post_parameter_snapshot["trainable_parameter_names"] == list(READOUT_ALIGNMENT_PARAM_UPDATE_SCOPE)
            ),
        },
    }
    _write_json(run_dir / READOUT_ALIGNMENT_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT, parameter_scope_payload)

    return {
        "run_id": run_id,
        "run_dir": run_dir,
        "seed_panel": prepared_run["seed_panel"],
        "train_seed": int(prepared_run["train_seed"]),
        "heldout_seed": int(prepared_run["heldout_seed"]),
        "auxiliary_probe_fit_seed": auxiliary_probe_fit_seed,
        "alignment_auxiliary_seeds": alignment_auxiliary_seeds,
        "pre_alignment": {
            key: value
            for key, value in pre_checkpoint.items()
            if key not in ("heldout_hidden_states", "auxiliary_hidden_states")
        },
        "post_alignment": {
            key: value
            for key, value in post_checkpoint.items()
            if key not in ("heldout_hidden_states", "auxiliary_hidden_states")
        },
        "alignment_integrity": integrity,
        "artifacts_complete": True,
    }


def _readout_alignment_anchor_required_successes(seed_panel: str) -> int:
    if seed_panel == "primary":
        return READOUT_ALIGNMENT_NATIVE_PRIMARY_REQUIRED_SUCCESSES
    if seed_panel == "confirmation":
        return READOUT_ALIGNMENT_NATIVE_CONFIRMATION_REQUIRED_SUCCESSES
    raise ValueError(f"unknown readout-alignment seed panel: {seed_panel}")


def _readout_alignment_strong_gate_required_successes(seed_panel: str) -> int:
    if seed_panel in ("primary", "confirmation"):
        return READOUT_ALIGNMENT_STRONG_GATE_REQUIRED_SUCCESSES
    raise ValueError(f"unknown readout-alignment seed panel: {seed_panel}")


def _readout_alignment_native_anchor_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    required_successes = _readout_alignment_anchor_required_successes(seed_panel)
    seedwise: list[dict[str, object]] = []
    latent_values: list[float] = []
    pooled_values: list[float] = []
    learned_symmetry_values: list[bool] = []
    latent_ratio_values: list[float | None] = []
    no_sign_reversal_values: list[bool] = []
    for entry in run_entries:
        checkpoint = entry[checkpoint_key]
        latent = float(checkpoint["probe_metrics"]["probe_target_aligned_specificity_contrast"])
        pooled = float(checkpoint["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"])
        oracle_latent = float(checkpoint["oracle_probe_metrics"]["probe_target_aligned_specificity_contrast"])
        learned_symmetry = (
            float(checkpoint["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]) >= 1.0
        )
        latent_ratio = _stage4_probe_ratio(latent, oracle_latent)
        no_sign_reversal = _stage4_no_sign_reversal(latent, pooled)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "probe_target_aligned_specificity_contrast": latent,
                "probe_pooled_target_aligned_specificity_contrast": pooled,
                "learned_probe_pair_flip_symmetry_consistency": float(
                    checkpoint["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]
                ),
                "learned_oracle_latent_ratio": latent_ratio,
                "checks": {
                    "latent_positive": latent > 0.0,
                    "pooled_positive": pooled > 0.0,
                    "learned_symmetry_consistency": learned_symmetry,
                    "learned_oracle_latent_ratio_ge_0_25": latent_ratio is not None
                    and latent_ratio >= READOUT_ALIGNMENT_ANCHOR_LATENT_RATIO_FLOOR,
                    "no_latent_pooled_sign_reversal": no_sign_reversal,
                },
            }
        )
        latent_values.append(latent)
        pooled_values.append(pooled)
        learned_symmetry_values.append(learned_symmetry)
        latent_ratio_values.append(latent_ratio)
        no_sign_reversal_values.append(no_sign_reversal)
    mean_latent = _stage4_mean(latent_values)
    mean_pooled = _stage4_mean(pooled_values)
    checks = {
        "all_runs_have_artifacts": all(bool(entry["artifacts_complete"]) for entry in run_entries),
        "required_successes": required_successes,
        "latent_positive_count": _stage4_count_true([value > 0.0 for value in latent_values]),
        "pooled_positive_count": _stage4_count_true([value > 0.0 for value in pooled_values]),
        "learned_symmetry_consistency_count": _stage4_count_true(learned_symmetry_values),
        "learned_oracle_latent_ratio_ge_0_25_count": _stage4_count_true(
            [value is not None and value >= READOUT_ALIGNMENT_ANCHOR_LATENT_RATIO_FLOOR for value in latent_ratio_values]
        ),
        "mean_latent_ge_floor": mean_latent is not None and float(mean_latent) >= READOUT_ALIGNMENT_ANCHOR_MEAN_LATENT_FLOOR,
        "mean_pooled_ge_floor": mean_pooled is not None and float(mean_pooled) >= READOUT_ALIGNMENT_ANCHOR_MEAN_POOLED_FLOOR,
        "no_latent_pooled_sign_reversal": all(no_sign_reversal_values),
    }
    checks["count_thresholds_met"] = (
        checks["latent_positive_count"] >= required_successes
        and checks["pooled_positive_count"] >= required_successes
        and checks["learned_symmetry_consistency_count"] >= required_successes
        and checks["learned_oracle_latent_ratio_ge_0_25_count"] >= required_successes
    )
    return {
        "seed_panel": seed_panel,
        "checkpoint": checkpoint_key,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "probe_target_aligned_specificity_contrast_sign_counts": _stage4_sign_counts(latent_values),
            "probe_pooled_target_aligned_specificity_contrast_sign_counts": _stage4_sign_counts(pooled_values),
            "learned_symmetry_consistency_counts": _stage4_bool_true_count(learned_symmetry_values),
            "mean_probe_target_aligned_specificity_contrast": mean_latent,
            "mean_probe_pooled_target_aligned_specificity_contrast": mean_pooled,
            "mean_learned_oracle_latent_ratio": _stage4_mean(latent_ratio_values),
        },
        "checks": checks,
        "passes": (
            checks["all_runs_have_artifacts"]
            and checks["count_thresholds_met"]
            and checks["mean_latent_ge_floor"]
            and checks["mean_pooled_ge_floor"]
            and checks["no_latent_pooled_sign_reversal"]
        ),
    }


def _readout_alignment_native_strong_gate_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    required_successes = _readout_alignment_strong_gate_required_successes(seed_panel)
    seedwise: list[dict[str, object]] = []
    alignment_values: list[float] = []
    top1_values: list[float] = []
    correct_pair_flip_values: list[float | None] = []
    within_pair_mass_values: list[float | None] = []
    source_bin_kl_values: list[float | None] = []
    for entry in run_entries:
        checkpoint = entry[checkpoint_key]
        alignment = float(checkpoint["probe_context_alignment_report"]["learned_probe_alignment_kl"])
        top1 = float(checkpoint["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"])
        correct_pair_flip = checkpoint["hidden_state_diagnostics"]["probe_correct_pair_flip_rate__v2"]
        within_pair_mass = checkpoint["hidden_state_diagnostics"]["probe_within_pair_mass__v2"]
        source_bin_kl = checkpoint["hidden_state_diagnostics"]["probe_source_bin_kl__v2"]
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "native_alignment_kl": alignment,
                "native_expected_target_top1_rate": top1,
                "native_correct_pair_flip_rate__v2": correct_pair_flip,
                "native_within_pair_mass__v2": within_pair_mass,
                "native_source_bin_kl__v2": source_bin_kl,
                "checks": {
                    "native_alignment_kl_le_0_75": alignment <= READOUT_ALIGNMENT_STRONG_ALIGNMENT_KL_MAX,
                    "native_expected_target_top1_rate_ge_0_75": top1 >= READOUT_ALIGNMENT_STRONG_EXPECTED_TARGET_TOP1_MIN,
                    "native_correct_pair_flip_rate__v2_ge_0_75": correct_pair_flip is not None
                    and float(correct_pair_flip) >= READOUT_ALIGNMENT_STRONG_CORRECT_PAIR_FLIP_RATE_MIN,
                    "native_within_pair_mass__v2_ge_0_40": within_pair_mass is not None
                    and float(within_pair_mass) >= READOUT_ALIGNMENT_STRONG_WITHIN_PAIR_MASS_MIN,
                    "native_source_bin_kl__v2_ge_2_00": source_bin_kl is not None
                    and float(source_bin_kl) >= READOUT_ALIGNMENT_STRONG_SOURCE_BIN_KL_MIN,
                },
            }
        )
        alignment_values.append(alignment)
        top1_values.append(top1)
        correct_pair_flip_values.append(correct_pair_flip)
        within_pair_mass_values.append(within_pair_mass)
        source_bin_kl_values.append(source_bin_kl)
    checks = {
        "all_runs_have_artifacts": all(bool(entry["artifacts_complete"]) for entry in run_entries),
        "required_successes": required_successes,
        "native_alignment_kl_le_0_75_count": _stage4_count_true(
            [value <= READOUT_ALIGNMENT_STRONG_ALIGNMENT_KL_MAX for value in alignment_values]
        ),
        "native_expected_target_top1_rate_ge_0_75_count": _stage4_count_true(
            [value >= READOUT_ALIGNMENT_STRONG_EXPECTED_TARGET_TOP1_MIN for value in top1_values]
        ),
        "native_correct_pair_flip_rate__v2_ge_0_75_count": _stage4_count_true(
            [value is not None and float(value) >= READOUT_ALIGNMENT_STRONG_CORRECT_PAIR_FLIP_RATE_MIN for value in correct_pair_flip_values]
        ),
        "native_within_pair_mass__v2_ge_0_40_count": _stage4_count_true(
            [value is not None and float(value) >= READOUT_ALIGNMENT_STRONG_WITHIN_PAIR_MASS_MIN for value in within_pair_mass_values]
        ),
        "native_source_bin_kl__v2_ge_2_00_count": _stage4_count_true(
            [value is not None and float(value) >= READOUT_ALIGNMENT_STRONG_SOURCE_BIN_KL_MIN for value in source_bin_kl_values]
        ),
    }
    checks["strong_gate_passes"] = (
        checks["native_alignment_kl_le_0_75_count"] >= required_successes
        and checks["native_expected_target_top1_rate_ge_0_75_count"] >= required_successes
        and checks["native_correct_pair_flip_rate__v2_ge_0_75_count"] >= required_successes
        and checks["native_within_pair_mass__v2_ge_0_40_count"] >= required_successes
        and checks["native_source_bin_kl__v2_ge_2_00_count"] >= required_successes
    )
    return {
        "seed_panel": seed_panel,
        "checkpoint": checkpoint_key,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "mean_native_alignment_kl": _stage4_mean(alignment_values),
            "max_native_alignment_kl": max(alignment_values) if alignment_values else None,
            "mean_native_expected_target_top1_rate": _stage4_mean(top1_values),
            "mean_native_correct_pair_flip_rate__v2": _stage4_mean(correct_pair_flip_values),
            "mean_native_within_pair_mass__v2": _stage4_mean(within_pair_mass_values),
            "mean_native_source_bin_kl__v2": _stage4_mean(source_bin_kl_values),
        },
        "checks": checks,
        "passes": checks["all_runs_have_artifacts"] and checks["strong_gate_passes"],
    }


def _readout_alignment_linear_probe_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    required_successes = _readout_alignment_strong_gate_required_successes(seed_panel)
    seedwise: list[dict[str, object]] = []
    alignment_values: list[float] = []
    top1_values: list[float] = []
    correct_pair_flip_values: list[float | None] = []
    within_pair_mass_values: list[float | None] = []
    source_bin_kl_values: list[float | None] = []
    train_eval_disjoint_values: list[bool] = []
    for entry in run_entries:
        checkpoint = entry[checkpoint_key]
        linear_report = checkpoint["linear_probe_report"]
        alignment = float(linear_report["linear_probe_alignment_kl"])
        top1 = float(linear_report["linear_probe_expected_target_top1_rate"])
        correct_pair_flip = linear_report["linear_probe_correct_pair_flip_rate__v2"]
        within_pair_mass = linear_report["linear_probe_within_pair_mass__v2"]
        source_bin_kl = linear_report["linear_probe_source_bin_kl__v2"]
        train_eval_disjoint = bool(linear_report["train_eval_disjoint"])
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "auxiliary_probe_fit_seed": int(entry["auxiliary_probe_fit_seed"]),
                "linear_probe_alignment_kl": alignment,
                "linear_probe_expected_target_top1_rate": top1,
                "linear_probe_correct_pair_flip_rate__v2": correct_pair_flip,
                "linear_probe_within_pair_mass__v2": within_pair_mass,
                "linear_probe_source_bin_kl__v2": source_bin_kl,
                "train_eval_disjoint": train_eval_disjoint,
            }
        )
        alignment_values.append(alignment)
        top1_values.append(top1)
        correct_pair_flip_values.append(correct_pair_flip)
        within_pair_mass_values.append(within_pair_mass)
        source_bin_kl_values.append(source_bin_kl)
        train_eval_disjoint_values.append(train_eval_disjoint)
    checks = {
        "all_runs_have_artifacts": all(bool(entry["artifacts_complete"]) for entry in run_entries),
        "required_successes": required_successes,
        "train_eval_disjoint_for_all_runs": all(train_eval_disjoint_values),
        "linear_probe_alignment_kl_le_0_75_count": _stage4_count_true(
            [value <= READOUT_ALIGNMENT_STRONG_ALIGNMENT_KL_MAX for value in alignment_values]
        ),
        "linear_probe_expected_target_top1_rate_ge_0_75_count": _stage4_count_true(
            [value >= READOUT_ALIGNMENT_STRONG_EXPECTED_TARGET_TOP1_MIN for value in top1_values]
        ),
        "linear_probe_correct_pair_flip_rate__v2_ge_0_75_count": _stage4_count_true(
            [value is not None and float(value) >= READOUT_ALIGNMENT_STRONG_CORRECT_PAIR_FLIP_RATE_MIN for value in correct_pair_flip_values]
        ),
        "linear_probe_within_pair_mass__v2_ge_0_40_count": _stage4_count_true(
            [value is not None and float(value) >= READOUT_ALIGNMENT_STRONG_WITHIN_PAIR_MASS_MIN for value in within_pair_mass_values]
        ),
        "linear_probe_source_bin_kl__v2_ge_2_00_count": _stage4_count_true(
            [value is not None and float(value) >= READOUT_ALIGNMENT_STRONG_SOURCE_BIN_KL_MIN for value in source_bin_kl_values]
        ),
    }
    checks["strong_gate_passes"] = (
        checks["linear_probe_alignment_kl_le_0_75_count"] >= required_successes
        and checks["linear_probe_expected_target_top1_rate_ge_0_75_count"] >= required_successes
        and checks["linear_probe_correct_pair_flip_rate__v2_ge_0_75_count"] >= required_successes
        and checks["linear_probe_within_pair_mass__v2_ge_0_40_count"] >= required_successes
        and checks["linear_probe_source_bin_kl__v2_ge_2_00_count"] >= required_successes
    )
    return {
        "seed_panel": seed_panel,
        "checkpoint": checkpoint_key,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "mean_linear_probe_alignment_kl": _stage4_mean(alignment_values),
            "max_linear_probe_alignment_kl": max(alignment_values) if alignment_values else None,
            "mean_linear_probe_expected_target_top1_rate": _stage4_mean(top1_values),
            "mean_linear_probe_correct_pair_flip_rate__v2": _stage4_mean(correct_pair_flip_values),
            "mean_linear_probe_within_pair_mass__v2": _stage4_mean(within_pair_mass_values),
            "mean_linear_probe_source_bin_kl__v2": _stage4_mean(source_bin_kl_values),
        },
        "checks": checks,
        "passes": checks["all_runs_have_artifacts"] and checks["train_eval_disjoint_for_all_runs"] and checks["strong_gate_passes"],
    }


def _readout_alignment_delta_panel_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    seedwise: list[dict[str, object]] = []
    alignment_deltas: list[float] = []
    top1_deltas: list[float] = []
    correct_pair_flip_deltas: list[float] = []
    within_pair_mass_deltas: list[float] = []
    source_bin_kl_deltas: list[float] = []
    kl_reductions: list[float] = []
    for entry in run_entries:
        checkpoint = entry[checkpoint_key]
        native_alignment = float(checkpoint["probe_context_alignment_report"]["learned_probe_alignment_kl"])
        linear_alignment = float(checkpoint["linear_probe_report"]["linear_probe_alignment_kl"])
        native_top1 = float(checkpoint["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"])
        linear_top1 = float(checkpoint["linear_probe_report"]["linear_probe_expected_target_top1_rate"])
        native_correct_pair_flip = checkpoint["hidden_state_diagnostics"]["probe_correct_pair_flip_rate__v2"]
        linear_correct_pair_flip = checkpoint["linear_probe_report"]["linear_probe_correct_pair_flip_rate__v2"]
        native_within_pair_mass = checkpoint["hidden_state_diagnostics"]["probe_within_pair_mass__v2"]
        linear_within_pair_mass = checkpoint["linear_probe_report"]["linear_probe_within_pair_mass__v2"]
        native_source_bin_kl = checkpoint["hidden_state_diagnostics"]["probe_source_bin_kl__v2"]
        linear_source_bin_kl = checkpoint["linear_probe_report"]["linear_probe_source_bin_kl__v2"]
        alignment_delta = float(linear_alignment - native_alignment)
        kl_reduction = float(native_alignment - linear_alignment)
        top1_delta = float(linear_top1 - native_top1)
        correct_pair_flip_delta = float(linear_correct_pair_flip - native_correct_pair_flip)
        within_pair_mass_delta = float(linear_within_pair_mass - native_within_pair_mass)
        source_bin_kl_delta = float(linear_source_bin_kl - native_source_bin_kl)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "auxiliary_probe_fit_seed": int(entry["auxiliary_probe_fit_seed"]),
                "delta_alignment_kl__linear_minus_native": alignment_delta,
                "delta_expected_target_top1_rate__linear_minus_native": top1_delta,
                "delta_correct_pair_flip_rate__v2__linear_minus_native": correct_pair_flip_delta,
                "delta_within_pair_mass__v2__linear_minus_native": within_pair_mass_delta,
                "delta_source_bin_kl__v2__linear_minus_native": source_bin_kl_delta,
                "alignment_kl_reduction__native_minus_linear": kl_reduction,
            }
        )
        alignment_deltas.append(alignment_delta)
        top1_deltas.append(top1_delta)
        correct_pair_flip_deltas.append(correct_pair_flip_delta)
        within_pair_mass_deltas.append(within_pair_mass_delta)
        source_bin_kl_deltas.append(source_bin_kl_delta)
        kl_reductions.append(kl_reduction)

    def _ci(values: list[float], offset: int) -> dict[str, float] | None:
        return _standard_end_bootstrap_mean_ci(values, seed=READOUT_ALIGNMENT_BOOTSTRAP_SEED + offset)

    return {
        "seed_panel": seed_panel,
        "checkpoint": checkpoint_key,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "mean_delta_alignment_kl__linear_minus_native": _stage4_mean(alignment_deltas),
            "mean_alignment_kl_reduction__native_minus_linear": _stage4_mean(kl_reductions),
            "mean_delta_expected_target_top1_rate__linear_minus_native": _stage4_mean(top1_deltas),
            "mean_delta_correct_pair_flip_rate__v2__linear_minus_native": _stage4_mean(correct_pair_flip_deltas),
            "mean_delta_within_pair_mass__v2__linear_minus_native": _stage4_mean(within_pair_mass_deltas),
            "mean_delta_source_bin_kl__v2__linear_minus_native": _stage4_mean(source_bin_kl_deltas),
            "bootstrap_ci_95": {
                "delta_alignment_kl__linear_minus_native": _ci(alignment_deltas, 11),
                "alignment_kl_reduction__native_minus_linear": _ci(kl_reductions, 12),
                "delta_expected_target_top1_rate__linear_minus_native": _ci(top1_deltas, 13),
                "delta_correct_pair_flip_rate__v2__linear_minus_native": _ci(correct_pair_flip_deltas, 14),
                "delta_within_pair_mass__v2__linear_minus_native": _ci(within_pair_mass_deltas, 15),
                "delta_source_bin_kl__v2__linear_minus_native": _ci(source_bin_kl_deltas, 16),
            },
        },
    }


def _readout_alignment_build_skipped_panel_report(
    *,
    artifact_key: str,
    seed_panel: str,
    stop_reason: str,
) -> dict[str, object]:
    return {
        **_readout_alignment_metadata(
            metric_versions={artifact_key: "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "skipped": True,
        "stop_reason": stop_reason,
        "passes": False,
    }


def _readout_alignment_build_pre_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    native_anchor_summary = _readout_alignment_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_alignment",
    )
    linear_probe_summary = _readout_alignment_linear_probe_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_alignment",
    )
    delta_summary = _readout_alignment_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_alignment",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "native_anchor_fails": not native_anchor_summary["passes"],
        "linear_probe_strong_gate_passes": bool(linear_probe_summary["passes"]),
        "mean_top1_improvement_ge_0_25": (
            delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"] is not None
            and float(delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"])
            >= READOUT_ALIGNMENT_TOP1_IMPROVEMENT_MIN
        ),
        "top1_improvement_ci_lower_gt_0": top1_ci is not None and float(top1_ci["lower"]) > 0.0,
        "mean_kl_reduction_ge_0_50": (
            delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"] is not None
            and float(delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"])
            >= READOUT_ALIGNMENT_KL_REDUCTION_MIN
        ),
        "kl_reduction_ci_lower_gt_0": kl_ci is not None and float(kl_ci["lower"]) > 0.0,
    }
    return {
        **_readout_alignment_metadata(
            metric_versions={"pre_alignment_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "linear_probe_summary": linear_probe_summary,
        "localization_delta_summary": delta_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _readout_alignment_build_integrity_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = len(run_entries)
    seedwise: list[dict[str, object]] = []
    boolean_fields = {
        "heldout_batch_identity_same_pre_post": [],
        "auxiliary_batch_identity_same_pre_post": [],
        "auxiliary_eval_disjoint_from_heldout": [],
        "recurrent_core_parameter_fingerprint_unchanged": [],
        "precision_head_parameter_fingerprint_unchanged": [],
        "orientation_head_parameter_fingerprint_changed": [],
        "heldout_hidden_states_unchanged": [],
        "auxiliary_hidden_states_unchanged": [],
        "predictive_nonregression_passes": [],
    }
    for entry in run_entries:
        integrity = entry["alignment_integrity"]
        seedwise_entry = {
            "run_id": entry["run_id"],
            "train_seed": int(entry["train_seed"]),
            "heldout_seed": int(entry["heldout_seed"]),
            "auxiliary_probe_fit_seed": int(entry["auxiliary_probe_fit_seed"]),
            **integrity,
        }
        seedwise.append(seedwise_entry)
        for key in boolean_fields:
            boolean_fields[key].append(bool(integrity[key]))
    checks = {
        "required_successes": required_successes,
        "heldout_batch_identity_same_pre_post_count": _stage4_count_true(boolean_fields["heldout_batch_identity_same_pre_post"]),
        "auxiliary_batch_identity_same_pre_post_count": _stage4_count_true(boolean_fields["auxiliary_batch_identity_same_pre_post"]),
        "auxiliary_eval_disjoint_from_heldout_count": _stage4_count_true(boolean_fields["auxiliary_eval_disjoint_from_heldout"]),
        "recurrent_core_parameter_fingerprint_unchanged_count": _stage4_count_true(boolean_fields["recurrent_core_parameter_fingerprint_unchanged"]),
        "precision_head_parameter_fingerprint_unchanged_count": _stage4_count_true(boolean_fields["precision_head_parameter_fingerprint_unchanged"]),
        "orientation_head_parameter_fingerprint_changed_count": _stage4_count_true(boolean_fields["orientation_head_parameter_fingerprint_changed"]),
        "heldout_hidden_states_unchanged_count": _stage4_count_true(boolean_fields["heldout_hidden_states_unchanged"]),
        "auxiliary_hidden_states_unchanged_count": _stage4_count_true(boolean_fields["auxiliary_hidden_states_unchanged"]),
        "predictive_nonregression_count": _stage4_count_true(boolean_fields["predictive_nonregression_passes"]),
    }
    checks["passes"] = all(value >= required_successes for key, value in checks.items() if key.endswith("_count"))
    return {
        **_readout_alignment_metadata(
            metric_versions={"alignment_integrity_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "checks": checks,
        "passes": bool(checks["passes"]),
        "skipped": False,
    }


def _readout_alignment_build_post_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    overall_entries: list[dict[str, object]] | None = None,
) -> dict[str, object]:
    native_anchor_summary = _readout_alignment_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_alignment",
    )
    native_strong_gate_summary = _readout_alignment_native_strong_gate_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_alignment",
    )
    linear_probe_summary = _readout_alignment_linear_probe_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_alignment",
    )
    delta_summary = _readout_alignment_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_alignment",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "native_anchor_passes": bool(native_anchor_summary["passes"]),
        "native_strong_gate_passes": bool(native_strong_gate_summary["passes"]),
        "no_material_linear_probe_top1_advantage": top1_ci is not None
        and float(top1_ci["upper"]) < READOUT_ALIGNMENT_TOP1_IMPROVEMENT_NO_ADVANTAGE_MAX,
        "no_material_linear_probe_kl_advantage": kl_ci is not None
        and float(kl_ci["upper"]) < READOUT_ALIGNMENT_KL_REDUCTION_NO_ADVANTAGE_MAX,
    }
    overall_post_alignment_summary = None
    if overall_entries is not None:
        post_latent_values = [float(entry["post_alignment"]["probe_metrics"]["probe_target_aligned_specificity_contrast"]) for entry in overall_entries]
        post_pooled_values = [float(entry["post_alignment"]["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"]) for entry in overall_entries]
        post_symmetry_values = [
            float(entry["post_alignment"]["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]) >= 1.0
            for entry in overall_entries
        ]
        post_ratio_values = [
            _stage4_probe_ratio(
                float(entry["post_alignment"]["probe_metrics"]["probe_target_aligned_specificity_contrast"]),
                float(entry["post_alignment"]["oracle_probe_metrics"]["probe_target_aligned_specificity_contrast"]),
            )
            for entry in overall_entries
        ]
        overall_post_alignment_summary = {
            "latent_positive_count": _stage4_count_true([value > 0.0 for value in post_latent_values]),
            "pooled_positive_count": _stage4_count_true([value > 0.0 for value in post_pooled_values]),
            "learned_symmetry_consistency_count": _stage4_count_true(post_symmetry_values),
            "learned_oracle_latent_ratio_ge_0_25_count": _stage4_count_true(
                [value is not None and value >= READOUT_ALIGNMENT_ANCHOR_LATENT_RATIO_FLOOR for value in post_ratio_values]
            ),
            "passes": (
                _stage4_count_true([value > 0.0 for value in post_latent_values]) >= 9
                and _stage4_count_true([value > 0.0 for value in post_pooled_values]) >= 9
                and _stage4_count_true(post_symmetry_values) >= 9
                and _stage4_count_true(
                    [value is not None and value >= READOUT_ALIGNMENT_ANCHOR_LATENT_RATIO_FLOOR for value in post_ratio_values]
                ) >= 9
            ),
        }
        checks["overall_10_seed_post_anchor_closure"] = bool(overall_post_alignment_summary["passes"])
    return {
        **_readout_alignment_metadata(
            metric_versions={"post_alignment_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "native_strong_gate_summary": native_strong_gate_summary,
        "linear_probe_summary": linear_probe_summary,
        "readout_gap_summary": delta_summary,
        "overall_post_alignment_summary": overall_post_alignment_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _readout_alignment_build_gap_report(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
) -> dict[str, object]:
    panels: dict[str, object] = {
        "pre_alignment_primary": _readout_alignment_delta_panel_summary(
            seed_panel="primary",
            run_entries=primary_run_entries,
            checkpoint_key="pre_alignment",
        ),
    }
    post_primary_entries = [entry for entry in primary_run_entries if "post_alignment" in entry]
    if post_primary_entries:
        panels["post_alignment_primary"] = _readout_alignment_delta_panel_summary(
            seed_panel="primary",
            run_entries=post_primary_entries,
            checkpoint_key="post_alignment",
        )
    if confirmation_run_entries is not None:
        panels["pre_alignment_confirmation"] = _readout_alignment_delta_panel_summary(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            checkpoint_key="pre_alignment",
        )
        post_confirmation_entries = [entry for entry in confirmation_run_entries if "post_alignment" in entry]
        if post_confirmation_entries:
            panels["post_alignment_confirmation"] = _readout_alignment_delta_panel_summary(
                seed_panel="confirmation",
                run_entries=post_confirmation_entries,
                checkpoint_key="post_alignment",
            )
    return {
        **_readout_alignment_metadata(
            metric_versions={
                "delta_alignment_kl__linear_minus_native": "v1",
                "alignment_kl_reduction__native_minus_linear": "v1",
                "delta_expected_target_top1_rate__linear_minus_native": "v1",
                "delta_correct_pair_flip_rate__v2__linear_minus_native": "v2",
                "delta_within_pair_mass__v2__linear_minus_native": "v2",
                "delta_source_bin_kl__v2__linear_minus_native": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "panels": panels,
        "skipped": False,
    }


def _readout_alignment_build_verdict(
    *,
    nonregression_report: dict[str, object],
    pre_alignment_primary_report: dict[str, object],
    post_alignment_primary_report: dict[str, object],
    alignment_integrity_primary_report: dict[str, object],
    pre_alignment_confirmation_report: dict[str, object] | None,
    post_alignment_confirmation_report: dict[str, object] | None,
    alignment_integrity_confirmation_report: dict[str, object] | None,
    confirmation_executed: bool,
) -> dict[str, object]:
    if not bool(nonregression_report["passes"]):
        return {
            **_readout_alignment_metadata(
                metric_versions={"readout_alignment_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "nonregression",
            "stop_gate": "R1 frozen non-regression",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not bool(pre_alignment_primary_report["passes"]):
        return {
            **_readout_alignment_metadata(
                metric_versions={"readout_alignment_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "pre_alignment_primary",
            "stop_gate": "R2 pre-alignment localization reproduction",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not bool(alignment_integrity_primary_report["passes"]):
        return {
            **_readout_alignment_metadata(
                metric_versions={"readout_alignment_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "alignment_integrity_primary",
            "stop_gate": "R3 alignment integrity",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not bool(post_alignment_primary_report["passes"]):
        return {
            **_readout_alignment_metadata(
                metric_versions={"readout_alignment_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "post_alignment_primary",
            "stop_gate": "R4 primary post-alignment success",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not confirmation_executed:
        return {
            **_readout_alignment_metadata(
                metric_versions={"readout_alignment_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation_not_executed",
            "stop_gate": "R5 confirmation replication",
            "confirmation_executed": False,
            "package_complete": True,
        }
    confirmation_passes = (
        pre_alignment_confirmation_report is not None
        and bool(pre_alignment_confirmation_report["passes"])
        and alignment_integrity_confirmation_report is not None
        and bool(alignment_integrity_confirmation_report["passes"])
        and post_alignment_confirmation_report is not None
        and bool(post_alignment_confirmation_report["passes"])
    )
    if not confirmation_passes:
        return {
            **_readout_alignment_metadata(
                metric_versions={"readout_alignment_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation",
            "stop_gate": "R5 confirmation replication",
            "confirmation_executed": True,
            "package_complete": True,
        }
    return {
        **_readout_alignment_metadata(
            metric_versions={"readout_alignment_verdict": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "classification": "GO-readout-aligned",
        "execution_valid": True,
        "stop_stage": None,
        "stop_gate": None,
        "confirmation_executed": True,
        "package_complete": True,
    }


def run_readout_alignment_package(
    *,
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
    primary_seed_panel: tuple[tuple[int, int], ...] = STAGE3_PRIMARY_SEED_PANEL,
    confirmation_seed_panel: tuple[tuple[int, int], ...] = STAGE3_CONFIRMATION_SEED_PANEL,
    benchmark_artifacts_root: str | Path = "artifacts",
) -> ReadoutAlignmentRunResult:
    resolved_config = _resolve_config(config=config, preset_name=preset_name)
    if resolved_config.name != "phase1_core":
        raise ValueError("readout_alignment is frozen to the phase1_core configuration family.")

    output_root = (
        resolved_config.artifacts.root_dir
        / "readout_alignment"
        / READOUT_ALIGNMENT_PACKAGE_VERSION
    )
    output_root.mkdir(parents=True, exist_ok=True)
    training_config = _stage4_training_config(resolved_config)
    package_manifest = {
        **_readout_alignment_metadata(
            metric_versions={"readout_alignment_manifest": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "changed_files": ["src/lvc_expectation/runner.py"],
        "package_checkpoints": [
            READOUT_ALIGNMENT_PRE_CHECKPOINT_DIRNAME,
            READOUT_ALIGNMENT_POST_CHECKPOINT_DIRNAME,
        ],
        "pretraining": {
            "config_family": "phase1_core",
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "n_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "training_source": "ordinary generate_batch() only",
            "stage3_exposure_during_pretraining": False,
        },
        "alignment_phase": {
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "optimizer": "Adam",
            "step_count": READOUT_ALIGNMENT_ALIGNMENT_STEPS,
            "batch_count": READOUT_ALIGNMENT_ALIGNMENT_BATCH_COUNT,
            "learning_rate": READOUT_ALIGNMENT_ALIGNMENT_LEARNING_RATE,
            "weight_decay": READOUT_ALIGNMENT_ALIGNMENT_WEIGHT_DECAY,
            "parameter_update_scope": list(READOUT_ALIGNMENT_PARAM_UPDATE_SCOPE),
            "loss_mask": "probe_step_mask & probe_valid_mask",
            "training_source": "disjoint auxiliary fixed-probe batches only",
        },
        "linear_probe": {
            "form": READOUT_ALIGNMENT_LINEAR_PROBE_FORM,
            "target": READOUT_ALIGNMENT_LINEAR_PROBE_TARGET,
            "ridge_lambda": READOUT_ALIGNMENT_LINEAR_PROBE_RIDGE_LAMBDA,
            "fit_mask": "probe_step_mask & probe_valid_mask",
            "hidden_state_tensor_name": READOUT_ALIGNMENT_HIDDEN_STATE_TENSOR_NAME,
            "train_eval_split": "auxiliary_probe_fit_batch vs heldout_fixed_probe_batch",
        },
        "batch_identity_rules": {
            "heldout_eval_batch": "fixed_probe_batch(seed=heldout_seed)",
            "auxiliary_probe_fit_batch": "fixed_probe_batch(seed=heldout_seed + 1)",
            "alignment_auxiliary_batches": "fixed_probe_batch(seed=heldout_seed + 100 + step_index)",
        },
        "bootstrap": {
            "seed": READOUT_ALIGNMENT_BOOTSTRAP_SEED,
            "resamples": READOUT_ALIGNMENT_BOOTSTRAP_RESAMPLES,
            "confidence_level": READOUT_ALIGNMENT_BOOTSTRAP_CONFIDENCE_LEVEL,
        },
        "seed_panels": {
            "primary": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in primary_seed_panel],
            "confirmation": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in confirmation_seed_panel],
        },
        "run_order": [
            "write_readout_alignment_manifest",
            "rerun_stage0_to_stage3_nonregression_checks",
            "run_primary_pre_alignment_panel",
            "run_primary_post_alignment_panel_if_R2_passes",
            "run_confirmation_panels_if_R4_passes",
            "write_readout_alignment_reports_and_verdict",
        ],
        "stop_rules": {
            "halt_on_nonregression_failure": True,
            "halt_on_pre_alignment_localization_failure": True,
            "halt_on_alignment_integrity_failure": True,
            "halt_on_primary_post_alignment_failure": True,
            "confirmation_only_if_primary_passes": True,
            "halt_on_confirmation_failure": True,
            "no_harder_evaluation": True,
            "no_second_package": True,
            "no_sweep": True,
        },
        "explicit_statements": {
            "no_sweep": True,
            "no_second_package": True,
            "no_harder_evaluation": True,
            "no_stage3_learned_evaluation": True,
            "linear_probe_instrumentation_only": True,
        },
    }
    _write_json(output_root / READOUT_ALIGNMENT_MANIFEST_V1_ARTIFACT, package_manifest)

    nonregression_report = _readout_alignment_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
    )
    _write_json(output_root / READOUT_ALIGNMENT_NONREGRESSION_REPORT_V1_ARTIFACT, nonregression_report)
    if not bool(nonregression_report["passes"]):
        pre_primary_report = _readout_alignment_build_skipped_panel_report(
            artifact_key="pre_alignment_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        post_primary_report = _readout_alignment_build_skipped_panel_report(
            artifact_key="post_alignment_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        integrity_primary_report = _readout_alignment_build_skipped_panel_report(
            artifact_key="alignment_integrity_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        gap_report = {
            **_readout_alignment_metadata(
                metric_versions={"readout_gap_report": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "panels": {},
            "skipped": True,
            "stop_reason": "nonregression_failed",
        }
        verdict = _readout_alignment_build_verdict(
            nonregression_report=nonregression_report,
            pre_alignment_primary_report=pre_primary_report,
            post_alignment_primary_report=post_primary_report,
            alignment_integrity_primary_report=integrity_primary_report,
            pre_alignment_confirmation_report=None,
            post_alignment_confirmation_report=None,
            alignment_integrity_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / READOUT_ALIGNMENT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / READOUT_ALIGNMENT_VERDICT_V1_ARTIFACT, verdict)
        return ReadoutAlignmentRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_alignment_primary_report=pre_primary_report,
            post_alignment_primary_report=post_primary_report,
            alignment_integrity_primary_report=integrity_primary_report,
            readout_gap_report=gap_report,
            verdict=verdict,
            pre_alignment_confirmation_report=None,
            post_alignment_confirmation_report=None,
            alignment_integrity_confirmation_report=None,
            run_ids=[],
        )

    store = RunStore(resolved_config.artifacts.root_dir)
    generator = Phase1ParadigmGenerator(resolved_config, controlled_sources=STAGE3_FULL_CONTROLLED_SOURCES)
    model = V1ExpectationModel(resolved_config)
    model.eval()
    assay_runner = AssayRunner(resolved_config)

    primary_prepared_runs: list[dict[str, object]] = []
    run_ids: list[str] = []
    for train_seed, heldout_seed in primary_seed_panel:
        prepared_run = _readout_alignment_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="primary",
        )
        primary_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    primary_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["auxiliary_probe_fit_seed"],
            "pre_alignment": {
                key: value
                for key, value in prepared_run["pre_alignment"].items()
                if key not in ("heldout_hidden_states", "auxiliary_hidden_states")
            },
            "artifacts_complete": True,
        }
        for prepared_run in primary_prepared_runs
    ]
    pre_primary_report = _readout_alignment_build_pre_report(
        seed_panel="primary",
        run_entries=primary_pre_entries,
    )
    gap_report = _readout_alignment_build_gap_report(
        primary_run_entries=primary_pre_entries,
        confirmation_run_entries=None,
    )
    if not bool(pre_primary_report["passes"]):
        post_primary_report = _readout_alignment_build_skipped_panel_report(
            artifact_key="post_alignment_report",
            seed_panel="primary",
            stop_reason="pre_alignment_failed",
        )
        integrity_primary_report = _readout_alignment_build_skipped_panel_report(
            artifact_key="alignment_integrity_report",
            seed_panel="primary",
            stop_reason="pre_alignment_failed",
        )
        verdict = _readout_alignment_build_verdict(
            nonregression_report=nonregression_report,
            pre_alignment_primary_report=pre_primary_report,
            post_alignment_primary_report=post_primary_report,
            alignment_integrity_primary_report=integrity_primary_report,
            pre_alignment_confirmation_report=None,
            post_alignment_confirmation_report=None,
            alignment_integrity_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / READOUT_ALIGNMENT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / READOUT_ALIGNMENT_VERDICT_V1_ARTIFACT, verdict)
        return ReadoutAlignmentRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_alignment_primary_report=pre_primary_report,
            post_alignment_primary_report=post_primary_report,
            alignment_integrity_primary_report=integrity_primary_report,
            readout_gap_report=gap_report,
            verdict=verdict,
            pre_alignment_confirmation_report=None,
            post_alignment_confirmation_report=None,
            alignment_integrity_confirmation_report=None,
            run_ids=run_ids,
        )

    primary_run_entries = [_readout_alignment_complete_run(prepared_run) for prepared_run in primary_prepared_runs]
    integrity_primary_report = _readout_alignment_build_integrity_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    post_primary_report = _readout_alignment_build_post_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
        overall_entries=None,
    )
    gap_report = _readout_alignment_build_gap_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=None,
    )
    if not bool(integrity_primary_report["passes"]) or not bool(post_primary_report["passes"]):
        verdict = _readout_alignment_build_verdict(
            nonregression_report=nonregression_report,
            pre_alignment_primary_report=pre_primary_report,
            post_alignment_primary_report=post_primary_report,
            alignment_integrity_primary_report=integrity_primary_report,
            pre_alignment_confirmation_report=None,
            post_alignment_confirmation_report=None,
            alignment_integrity_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / READOUT_ALIGNMENT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / READOUT_ALIGNMENT_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / READOUT_ALIGNMENT_VERDICT_V1_ARTIFACT, verdict)
        return ReadoutAlignmentRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_alignment_primary_report=pre_primary_report,
            post_alignment_primary_report=post_primary_report,
            alignment_integrity_primary_report=integrity_primary_report,
            readout_gap_report=gap_report,
            verdict=verdict,
            pre_alignment_confirmation_report=None,
            post_alignment_confirmation_report=None,
            alignment_integrity_confirmation_report=None,
            run_ids=run_ids,
        )

    confirmation_prepared_runs: list[dict[str, object]] = []
    for train_seed, heldout_seed in confirmation_seed_panel:
        prepared_run = _readout_alignment_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="confirmation",
        )
        confirmation_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    confirmation_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["auxiliary_probe_fit_seed"],
            "pre_alignment": {
                key: value
                for key, value in prepared_run["pre_alignment"].items()
                if key not in ("heldout_hidden_states", "auxiliary_hidden_states")
            },
            "artifacts_complete": True,
        }
        for prepared_run in confirmation_prepared_runs
    ]
    pre_confirmation_report = _readout_alignment_build_pre_report(
        seed_panel="confirmation",
        run_entries=confirmation_pre_entries,
    )
    confirmation_run_entries: list[dict[str, object]] | None = None
    integrity_confirmation_report: dict[str, object] | None = None
    post_confirmation_report: dict[str, object] | None = None
    if bool(pre_confirmation_report["passes"]):
        confirmation_run_entries = [_readout_alignment_complete_run(prepared_run) for prepared_run in confirmation_prepared_runs]
        integrity_confirmation_report = _readout_alignment_build_integrity_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
        post_confirmation_report = _readout_alignment_build_post_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            overall_entries=primary_run_entries + confirmation_run_entries,
        )
        gap_report = _readout_alignment_build_gap_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_run_entries,
        )
    else:
        gap_report = _readout_alignment_build_gap_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_pre_entries,
        )

    verdict = _readout_alignment_build_verdict(
        nonregression_report=nonregression_report,
        pre_alignment_primary_report=pre_primary_report,
        post_alignment_primary_report=post_primary_report,
        alignment_integrity_primary_report=integrity_primary_report,
        pre_alignment_confirmation_report=pre_confirmation_report,
        post_alignment_confirmation_report=post_confirmation_report,
        alignment_integrity_confirmation_report=integrity_confirmation_report,
        confirmation_executed=True,
    )

    _write_json(output_root / READOUT_ALIGNMENT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
    _write_json(output_root / READOUT_ALIGNMENT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
    _write_json(output_root / READOUT_ALIGNMENT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
    _write_json(output_root / READOUT_ALIGNMENT_GAP_REPORT_V1_ARTIFACT, gap_report)
    _write_json(output_root / READOUT_ALIGNMENT_VERDICT_V1_ARTIFACT, verdict)
    _write_json(output_root / READOUT_ALIGNMENT_PRE_CONFIRMATION_REPORT_V1_ARTIFACT, pre_confirmation_report)
    if post_confirmation_report is not None:
        _write_json(output_root / READOUT_ALIGNMENT_POST_CONFIRMATION_REPORT_V1_ARTIFACT, post_confirmation_report)
    if integrity_confirmation_report is not None:
        _write_json(output_root / READOUT_ALIGNMENT_INTEGRITY_CONFIRMATION_REPORT_V1_ARTIFACT, integrity_confirmation_report)

    return ReadoutAlignmentRunResult(
        output_root=output_root,
        package_manifest=package_manifest,
        nonregression_report=nonregression_report,
        pre_alignment_primary_report=pre_primary_report,
        post_alignment_primary_report=post_primary_report,
        alignment_integrity_primary_report=integrity_primary_report,
        readout_gap_report=gap_report,
        verdict=verdict,
        pre_alignment_confirmation_report=pre_confirmation_report,
        post_alignment_confirmation_report=post_confirmation_report,
        alignment_integrity_confirmation_report=integrity_confirmation_report,
        run_ids=run_ids,
    )


def _linear_probe_transplant_metadata(
    *,
    metric_versions: dict[str, str],
    source_metric_versions: list[str],
) -> dict[str, object]:
    return {
        "metric_schema_version": LINEAR_PROBE_TRANSPLANT_METRIC_SCHEMA_VERSION,
        "metric_versions": metric_versions,
        "classification_rule_version": LINEAR_PROBE_TRANSPLANT_CLASSIFICATION_RULE_VERSION,
        "source_metric_versions": source_metric_versions,
        "benchmark_registry_version": BENCHMARK_REGISTRY_VERSION,
        "linear_probe_transplant_package_version": LINEAR_PROBE_TRANSPLANT_PACKAGE_VERSION,
    }


def _linear_probe_transplant_build_nonregression_report(
    *,
    resolved_config: ExperimentConfig,
    output_root: Path,
    benchmark_artifacts_root: str | Path,
) -> dict[str, object]:
    raw_report = _stage4_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
        primary_seed_panel=STAGE3_PRIMARY_SEED_PANEL,
        confirmation_seed_panel=STAGE3_CONFIRMATION_SEED_PANEL,
    )
    stripped = dict(raw_report)
    for key in (
        "metric_schema_version",
        "metric_versions",
        "classification_rule_version",
        "source_metric_versions",
        "benchmark_registry_version",
        "stage3_task_version",
        "stage4_package_version",
    ):
        stripped.pop(key, None)
    return {
        **_linear_probe_transplant_metadata(
            metric_versions={
                "stage0_registry_verification": "v1",
                "stage1_tranche_runner_replay": "v1",
                "stage2_diagnostic_calibration_report": "v2",
                "stage3_oracle_task_definition_verdict": "v2",
                "phase15_continuation_retention": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        **stripped,
    }


def _linear_probe_transplant_parameter_scope_snapshot(
    predictor: CausalContextPredictor,
) -> dict[str, object]:
    recurrent_core_parameters = [(name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("gru.")]
    precision_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("precision_head.")
    ]
    orientation_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("orientation_head.")
    ]
    return {
        "trainable_parameter_names": [name for name, parameter in predictor.named_parameters() if parameter.requires_grad],
        "recurrent_core_parameter_names": [name for name, _ in recurrent_core_parameters],
        "precision_head_parameter_names": [name for name, _ in precision_parameters],
        "orientation_head_parameter_names": [name for name, _ in orientation_parameters],
        "recurrent_core_fingerprint": _named_parameter_fingerprint(recurrent_core_parameters),
        "precision_head_fingerprint": (
            _named_parameter_fingerprint(precision_parameters) if precision_parameters else "disabled"
        ),
        "orientation_head_fingerprint": _named_parameter_fingerprint(orientation_parameters),
    }


def _linear_probe_transplant_write_hidden_state_artifacts(
    *,
    run_id: str,
    batch: TrialBatch,
    learned_simulation: SimulationOutput,
    oracle_simulation: SimulationOutput,
    symmetry_mate_lookup: dict[int, int],
    output_dir: Path,
) -> dict[str, object]:
    payload = _stage4_probe_run_payload(
        run_id=run_id,
        batch=batch,
        learned_simulation=learned_simulation,
        oracle_simulation=oracle_simulation,
        symmetry_mate_lookup=symmetry_mate_lookup,
    )
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    for row in rows:
        pair_id = int(row["pair_id"])
        row["_symmetry_group_id"] = min(pair_id, int(symmetry_mate_lookup[pair_id]))
    diagnostics = build_hidden_state_diagnostics_v2(rows)
    diagnostics_payload = {
        **_linear_probe_transplant_metadata(
            metric_versions=metric_versions_v2_payload(),
            source_metric_versions=[DIAGNOSTIC_SCHEMA_VERSION, FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "diagnostic_schema_version": DIAGNOSTIC_SCHEMA_VERSION,
        **diagnostics,
    }
    write_hidden_state_probe_table_v2(rows, output_dir / HIDDEN_STATE_PROBE_TABLE_V2_ARTIFACT)
    write_hidden_state_diagnostics_v2_json(
        diagnostics_payload,
        output_dir / HIDDEN_STATE_DIAGNOSTICS_V2_ARTIFACT,
    )
    return {
        "rows": rows,
        "diagnostics": diagnostics_payload,
    }


def _linear_probe_transplant_write_linear_probe_artifacts(
    *,
    run_id: str,
    batch: TrialBatch,
    linear_probe_logits: torch.Tensor,
    oracle_prediction: ContextPrediction,
    output_dir: Path,
    auxiliary_seed: int,
) -> dict[str, object]:
    payload = {
        "run_id": run_id,
        "batch": _serialize_batch(batch),
        "learned_logits": linear_probe_logits,
        "oracle_logits": oracle_prediction.orientation_logits,
        "learned_precision": None,
        "oracle_precision": oracle_prediction.precision_logit,
        "l23_readout": None,
        "gaussian_orientation_bank": None,
        "context_comparator": None,
    }
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    diagnostics = build_hidden_state_diagnostics_v2(rows)
    diagnostics_payload = {
        **_linear_probe_transplant_metadata(
            metric_versions=metric_versions_v2_payload(),
            source_metric_versions=[DIAGNOSTIC_SCHEMA_VERSION, FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "diagnostic_schema_version": DIAGNOSTIC_SCHEMA_VERSION,
        **diagnostics,
    }
    write_hidden_state_probe_table_v2(rows, output_dir / LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_HIDDEN_STATE_TABLE_V2_ARTIFACT)
    write_hidden_state_diagnostics_v2_json(
        diagnostics_payload,
        output_dir / LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_HIDDEN_STATE_DIAGNOSTICS_V2_ARTIFACT,
    )
    probe_mask = _probe_scoring_mask(batch)
    expected_distribution = batch.metadata["expected_distribution"][probe_mask]
    alignment_kl, expected_logprob = _probe_alignment_stats(linear_probe_logits[probe_mask], expected_distribution)
    behavior_metrics = _probe_alignment_behavior_metrics(batch, linear_probe_logits)
    report = {
        **_linear_probe_transplant_metadata(
            metric_versions={
                "linear_probe_alignment_kl": "v1",
                "linear_probe_expected_logprob": "v1",
                "linear_probe_expected_target_top1_rate": "v1",
                "linear_probe_correct_pair_flip_rate__v2": "v2",
                "linear_probe_within_pair_mass__v2": "v2",
                "linear_probe_source_bin_kl__v2": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "run_id": run_id,
        "heldout_generator_seed": int(batch.metadata["generator_seed"]),
        "auxiliary_generator_seed": int(auxiliary_seed),
        "train_eval_disjoint": int(batch.metadata["generator_seed"]) != int(auxiliary_seed),
        "linear_probe_alignment_kl": alignment_kl,
        "linear_probe_expected_logprob": expected_logprob,
        "linear_probe_expected_target_top1_rate": behavior_metrics["probe_expected_target_top1_rate"],
        "linear_probe_pair_flip_rate": behavior_metrics["probe_pair_flip_rate"],
        "linear_probe_pair_flip_symmetry_consistency": behavior_metrics["probe_pair_flip_symmetry_consistency"],
        "linear_probe_correct_pair_flip_rate__v2": diagnostics["probe_correct_pair_flip_rate__v2"],
        "linear_probe_within_pair_mass__v2": diagnostics["probe_within_pair_mass__v2"],
        "linear_probe_source_bin_kl__v2": diagnostics["probe_source_bin_kl__v2"],
    }
    _write_json(output_dir / LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_REPORT_V1_ARTIFACT, report)
    return {
        "rows": rows,
        "diagnostics": diagnostics_payload,
        "report": report,
    }


def _linear_probe_transplant_anchor_required_successes(seed_panel: str) -> int:
    if seed_panel == "primary":
        return LINEAR_PROBE_TRANSPLANT_NATIVE_PRIMARY_REQUIRED_SUCCESSES
    if seed_panel == "confirmation":
        return LINEAR_PROBE_TRANSPLANT_NATIVE_CONFIRMATION_REQUIRED_SUCCESSES
    raise ValueError(f"unknown linear-probe-transplant seed panel: {seed_panel}")


def _linear_probe_transplant_strong_gate_required_successes(seed_panel: str) -> int:
    if seed_panel in ("primary", "confirmation"):
        return LINEAR_PROBE_TRANSPLANT_STRONG_GATE_REQUIRED_SUCCESSES
    raise ValueError(f"unknown linear-probe-transplant seed panel: {seed_panel}")


def _linear_probe_transplant_evaluate_checkpoint(
    *,
    predictor: CausalContextPredictor,
    heldout_batch: TrialBatch,
    auxiliary_probe_fit_batch: TrialBatch,
    standard_heldout_batch: TrialBatch,
    run_id: str,
    run_dir: Path,
    checkpoint_dirname: str,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    generator: Phase1ParadigmGenerator,
    resolved_config: ExperimentConfig,
    linear_probe: dict[str, object],
    save_transplant_outputs: bool = False,
) -> dict[str, object]:
    checkpoint_dir = run_dir / checkpoint_dirname
    checkpoint_dir.mkdir(parents=True, exist_ok=True)
    (checkpoint_dir / "eval").mkdir(parents=True, exist_ok=True)
    with torch.no_grad():
        learned_prediction, heldout_hidden_states = _predict_with_hidden_states(predictor, heldout_batch)
        _, auxiliary_hidden_states = _predict_with_hidden_states(predictor, auxiliary_probe_fit_batch)
        oracle_prediction = _oracle_context_prediction(
            heldout_batch,
            use_precision=resolved_config.context.use_precision,
        )
        learned_simulation, learned_window_summaries = _evaluate_single_subcase(
            batch=heldout_batch,
            prediction=learned_prediction,
            subcase="dampening",
            model=model,
            config=resolved_config,
        )
        oracle_simulation, oracle_window_summaries = _evaluate_single_subcase(
            batch=heldout_batch,
            prediction=oracle_prediction,
            subcase="dampening",
            model=model,
            config=resolved_config,
        )
    standard_sanity = {
        "nuisance_only": asdict(generator.run_nuisance_only_failure_test(standard_heldout_batch)),
        "predictive_structure": asdict(generator.run_predictive_structure_success_test(standard_heldout_batch)),
    }
    standard_predictive_metrics = evaluate_context_predictor(
        predictor,
        standard_heldout_batch,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )

    torch.save(
        _standard_end_hidden_state_payload(
            batch=heldout_batch,
            hidden_states=heldout_hidden_states,
            batch_role="heldout_eval",
        ),
        checkpoint_dir / LINEAR_PROBE_TRANSPLANT_RAW_HIDDEN_STATE_EVAL_ARTIFACT,
    )
    torch.save(
        _standard_end_hidden_state_payload(
            batch=auxiliary_probe_fit_batch,
            hidden_states=auxiliary_hidden_states,
            batch_role="auxiliary_probe_fit",
        ),
        checkpoint_dir / LINEAR_PROBE_TRANSPLANT_RAW_HIDDEN_STATE_AUX_ARTIFACT,
    )
    torch.save(_serialize_batch(auxiliary_probe_fit_batch), checkpoint_dir / LINEAR_PROBE_TRANSPLANT_AUX_BATCH_ARTIFACT)

    probe_metrics = assay_runner.compute_local_global_probe_metrics(learned_simulation, heldout_batch)
    oracle_probe_metrics = assay_runner.compute_local_global_probe_metrics(oracle_simulation, heldout_batch)
    probe_context_alignment_report = _build_probe_context_alignment_report(
        heldout_batch,
        oracle_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=oracle_prediction,
            metadata=heldout_batch.metadata,
        ),
        learned_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=learned_prediction,
            metadata=heldout_batch.metadata,
        ),
    )
    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    probe_design_report = {
        **_linear_probe_transplant_metadata(
            metric_versions={
                "n_probe_rows": "v1",
                "n_probe_global_expected_rows": "v1",
                "n_probe_global_unexpected_rows": "v1",
                "n_probe_pairs_total": "v1",
                "n_probe_pairs_scored": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **_build_probe_design_report(
            heldout_batch,
            task_mode_fixed_state=task_mode_fixed_state,
            prestim_fixed_state=prestim_fixed_state,
            oracle_simulation=oracle_simulation,
            learned_simulation=learned_simulation,
        ),
    }
    probe_metrics_payload = {
        **_linear_probe_transplant_metadata(
            metric_versions={metric_name: "v1" for metric_name in sorted(probe_metrics)},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **probe_metrics,
    }
    oracle_probe_metrics_payload = {
        **_linear_probe_transplant_metadata(
            metric_versions={metric_name: "v1" for metric_name in sorted(oracle_probe_metrics)},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **oracle_probe_metrics,
    }
    probe_context_alignment_payload = {
        **_linear_probe_transplant_metadata(
            metric_versions={
                "learned_probe_alignment_kl": "v1",
                "oracle_probe_alignment_kl": "v1",
                "learned_probe_expected_logprob": "v1",
                "oracle_probe_expected_logprob": "v1",
                "learned_probe_expected_target_top1_rate": "v1",
                "oracle_probe_expected_target_top1_rate": "v1",
                "learned_probe_pair_flip_rate": "v1",
                "oracle_probe_pair_flip_rate": "v1",
                "learned_probe_pair_flip_symmetry_consistency": "v1",
                "oracle_probe_pair_flip_symmetry_consistency": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **probe_context_alignment_report,
    }
    probe_table_payload = {
        **_linear_probe_transplant_metadata(
            metric_versions={"probe_table_rows": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "rows": _build_probe_table(heldout_batch, oracle_simulation, learned_simulation),
    }
    probe_symmetry_mates = {
        int(pair_id): int(descriptor["symmetry_mate_pair_id"])
        for pair_id, descriptor in heldout_batch.metadata["probe_report"]["pair_descriptors"].items()
    }
    native_hidden_state_outputs = _linear_probe_transplant_write_hidden_state_artifacts(
        run_id=run_id,
        batch=heldout_batch,
        learned_simulation=learned_simulation,
        oracle_simulation=oracle_simulation,
        symmetry_mate_lookup=probe_symmetry_mates,
        output_dir=checkpoint_dir,
    )

    linear_probe_logits = _standard_end_apply_linear_probe(
        hidden_states=heldout_hidden_states,
        linear_probe=linear_probe,
    )
    linear_probe_outputs = _linear_probe_transplant_write_linear_probe_artifacts(
        run_id=run_id,
        batch=heldout_batch,
        linear_probe_logits=linear_probe_logits,
        oracle_prediction=oracle_prediction,
        output_dir=checkpoint_dir,
        auxiliary_seed=int(auxiliary_probe_fit_batch.metadata["generator_seed"]),
    )
    torch.save(linear_probe, checkpoint_dir / LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_PARAMETERS_ARTIFACT)

    _write_json(checkpoint_dir / "probe_design_report.json", probe_design_report)
    _write_json(checkpoint_dir / "probe_metrics.json", probe_metrics_payload)
    _write_json(checkpoint_dir / "oracle_probe_metrics.json", oracle_probe_metrics_payload)
    _write_json(checkpoint_dir / "probe_context_alignment_report.json", probe_context_alignment_payload)
    _write_json(checkpoint_dir / "probe_table.json", probe_table_payload)
    torch.save(_serialize_batch(heldout_batch), checkpoint_dir / "eval" / "heldout_batch.pt")
    torch.save({"dampening": learned_window_summaries}, checkpoint_dir / "eval" / "window_summaries.pt")
    torch.save({"dampening": oracle_window_summaries}, checkpoint_dir / "eval" / "oracle_window_summaries.pt")
    torch.save({"dampening": _serialize_simulation(learned_simulation)}, checkpoint_dir / "eval" / "full_trajectories.pt")
    torch.save({"dampening": _serialize_simulation(oracle_simulation)}, checkpoint_dir / "eval" / "oracle_full_trajectories.pt")

    return {
        "checkpoint": checkpoint_dirname,
        "probe_metrics": probe_metrics,
        "oracle_probe_metrics": oracle_probe_metrics,
        "probe_context_alignment_report": probe_context_alignment_report,
        "hidden_state_diagnostics": native_hidden_state_outputs["diagnostics"],
        "linear_probe_report": linear_probe_outputs["report"],
        "linear_probe_diagnostics": linear_probe_outputs["diagnostics"],
        "standard_predictive_metrics": standard_predictive_metrics,
        "standard_sanity": standard_sanity,
        "heldout_generator_seed": int(heldout_batch.metadata["generator_seed"]),
        "auxiliary_generator_seed": int(auxiliary_probe_fit_batch.metadata["generator_seed"]),
        "heldout_hidden_state_fingerprint": _tensor_fingerprint(heldout_hidden_states),
        "auxiliary_hidden_state_fingerprint": _tensor_fingerprint(auxiliary_hidden_states),
        "heldout_hidden_states": heldout_hidden_states.detach().cpu(),
        "auxiliary_hidden_states": auxiliary_hidden_states.detach().cpu(),
        "heldout_native_orientation_logits": learned_prediction.orientation_logits.detach().cpu(),
        "heldout_linear_probe_logits": linear_probe_logits.detach().cpu(),
        "artifacts_complete": True,
    }


def _linear_probe_transplant_prepare_run(
    *,
    resolved_config: ExperimentConfig,
    store: RunStore,
    generator: Phase1ParadigmGenerator,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    train_seed: int,
    heldout_seed: int,
    seed_panel: str,
) -> dict[str, object]:
    training_config = _stage4_training_config(resolved_config)
    auxiliary_probe_fit_seed = heldout_seed + LINEAR_PROBE_TRANSPLANT_AUXILIARY_PROBE_FIT_SEED_OFFSET
    if auxiliary_probe_fit_seed == heldout_seed:
        raise AssertionError("auxiliary probe-fit seed must differ from held-out seed.")
    train_batches = [
        generator.generate_batch(
            batch_size=training_config.batch_size,
            seed=train_seed + epoch,
        )
        for epoch in range(training_config.n_epochs)
    ]
    heldout_batch = generator.generate_local_global_probe_batch(seed=heldout_seed)
    auxiliary_probe_fit_batch = generator.generate_local_global_probe_batch(seed=auxiliary_probe_fit_seed)
    standard_heldout_batch = generator.generate_batch(
        batch_size=training_config.batch_size,
        seed=heldout_seed,
    )
    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    manifest, run_dir = store.create_run(
        resolved_config.name,
        train_objectives=[f"{resolved_config.training.predictive_objective}:{EXPECTED_DISTRIBUTION_OBJECTIVE}"],
        heldout_assays=[
            "probe_target_aligned_specificity_contrast",
            "probe_pooled_target_aligned_specificity_contrast",
            "probe_context_comparator_nonuniformity_contrast",
            "linear_probe_alignment_kl",
            "linear_probe_expected_target_top1_rate",
            "linear_probe_correct_pair_flip_rate__v2",
            "linear_probe_within_pair_mass__v2",
            "linear_probe_source_bin_kl__v2",
        ],
        notes={
            "gate": "linear_probe_transplant",
            "linear_probe_transplant_package_version": LINEAR_PROBE_TRANSPLANT_PACKAGE_VERSION,
            "checkpoints": [LINEAR_PROBE_TRANSPLANT_PRE_CHECKPOINT_DIRNAME, LINEAR_PROBE_TRANSPLANT_POST_CHECKPOINT_DIRNAME],
            "seed_panel": seed_panel,
            "train_seed": int(train_seed),
            "heldout_seed": int(heldout_seed),
            "auxiliary_probe_fit_seed": int(auxiliary_probe_fit_seed),
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "initial_standard_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "parameter_update_scope": list(LINEAR_PROBE_TRANSPLANT_PARAM_UPDATE_SCOPE),
            "controlled_sources": heldout_batch.metadata["controlled_sources"].tolist(),
            "probe_visible_step_index": int(heldout_batch.metadata["probe_visible_step_index"]),
            "task_mode_fixed_state": task_mode_fixed_state,
            "prestim_fixed_state": prestim_fixed_state,
            "heldout_batch_identity_rule": "fixed_probe_batch(seed=heldout_seed)",
            "auxiliary_probe_fit_identity_rule": "fixed_probe_batch(seed=heldout_seed + 1)",
            "hidden_state_tensors_exported": [LINEAR_PROBE_TRANSPLANT_HIDDEN_STATE_TENSOR_NAME],
            "linear_probe_form": LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_FORM,
            "linear_probe_target": LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_TARGET,
            "linear_probe_ridge_lambda": LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_RIDGE_LAMBDA,
            "linear_probe_train_eval_disjoint": True,
            "linear_probe_fit_mask": "probe_step_mask & probe_valid_mask",
            "transplant_type": "exact_affine_copy",
            "no_optimization_after_transplant": True,
            "logit_match_tolerance": LINEAR_PROBE_TRANSPLANT_LOGIT_MATCH_ATOL,
            "bootstrap_seed": LINEAR_PROBE_TRANSPLANT_BOOTSTRAP_SEED,
            "bootstrap_resamples": LINEAR_PROBE_TRANSPLANT_BOOTSTRAP_RESAMPLES,
            "no_sweep": True,
            "no_second_package": True,
            "no_harder_evaluation": True,
            "oracle_precision_mode": "neutral_zero_logit" if resolved_config.context.use_precision else "disabled",
        },
    )

    predictor = CausalContextPredictor(resolved_config.geometry, resolved_config.context)
    train_history = train_context_predictor(
        predictor,
        train_batches,
        training_config,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )
    _write_json(run_dir / LINEAR_PROBE_TRANSPLANT_PRETRAIN_HISTORY_ARTIFACT, [asdict(item) for item in train_history])
    pre_parameter_snapshot = _linear_probe_transplant_parameter_scope_snapshot(predictor)
    pre_linear_probe = None
    with torch.no_grad():
        _, auxiliary_hidden_states = _predict_with_hidden_states(predictor, auxiliary_probe_fit_batch)
        pre_linear_probe = _standard_end_fit_linear_probe(
            hidden_states=auxiliary_hidden_states,
            batch=auxiliary_probe_fit_batch,
        )
    _write_json(
        run_dir / LINEAR_PROBE_TRANSPLANT_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT,
        {
            **_linear_probe_transplant_metadata(
                metric_versions={"parameter_scope_fingerprints": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "run_id": manifest.run_id,
            "parameter_update_scope": list(LINEAR_PROBE_TRANSPLANT_PARAM_UPDATE_SCOPE),
            "pre_transplant": pre_parameter_snapshot,
            "post_transplant": None,
            "checks": {},
        },
    )
    pre_checkpoint = _linear_probe_transplant_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        auxiliary_probe_fit_batch=auxiliary_probe_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=manifest.run_id,
        run_dir=run_dir,
        checkpoint_dirname=LINEAR_PROBE_TRANSPLANT_PRE_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        linear_probe=pre_linear_probe,
        save_transplant_outputs=False,
    )
    _write_stage0_provenance(store=store, run_dir=run_dir, manifest=manifest, resolved_config=resolved_config)
    return {
        "run_id": manifest.run_id,
        "run_dir": run_dir,
        "seed_panel": seed_panel,
        "train_seed": int(train_seed),
        "heldout_seed": int(heldout_seed),
        "auxiliary_probe_fit_seed": int(auxiliary_probe_fit_seed),
        "predictor": predictor,
        "generator": generator,
        "model": model,
        "assay_runner": assay_runner,
        "resolved_config": resolved_config,
        "heldout_batch": heldout_batch,
        "auxiliary_probe_fit_batch": auxiliary_probe_fit_batch,
        "standard_heldout_batch": standard_heldout_batch,
        "pre_transplant": pre_checkpoint,
        "pre_parameter_snapshot": pre_parameter_snapshot,
        "donor_linear_probe": pre_linear_probe,
    }


def _linear_probe_transplant_apply_exact_copy(
    *,
    predictor: CausalContextPredictor,
    linear_probe: dict[str, object],
    run_dir: Path,
    run_id: str,
    heldout_hidden_states: torch.Tensor,
) -> dict[str, object]:
    donor_weight = linear_probe["weight"]
    donor_bias = linear_probe["bias"]
    target_weight = predictor.orientation_head.weight
    target_bias = predictor.orientation_head.bias
    weight_shape_match = tuple(target_weight.shape) == (int(donor_weight.shape[1]), int(donor_weight.shape[0]))
    bias_shape_match = tuple(target_bias.shape) == tuple(donor_bias.shape)
    if not weight_shape_match or not bias_shape_match:
        raise ValueError(
            "linear-probe transplant shape mismatch: "
            f"orientation_head.weight={tuple(target_weight.shape)} donor_weight={tuple(donor_weight.shape)} "
            f"orientation_head.bias={tuple(target_bias.shape)} donor_bias={tuple(donor_bias.shape)}"
        )
    with torch.no_grad():
        predictor.orientation_head.weight.copy_(donor_weight.transpose(0, 1).to(dtype=target_weight.dtype))
        predictor.orientation_head.bias.copy_(donor_bias.to(dtype=target_bias.dtype))
    copied_weight = predictor.orientation_head.weight.detach().cpu()
    copied_bias = predictor.orientation_head.bias.detach().cpu()
    max_abs_weight_diff_after_copy = float(
        (copied_weight - donor_weight.transpose(0, 1).detach().cpu()).abs().max().item()
    )
    max_abs_bias_diff_after_copy = float(
        (copied_bias - donor_bias.detach().cpu()).abs().max().item()
    )
    if max_abs_weight_diff_after_copy != 0.0 or max_abs_bias_diff_after_copy != 0.0:
        raise AssertionError("linear-probe transplant must copy donor weight and bias exactly.")
    with torch.no_grad():
        transplanted_native_logits = predictor.orientation_head(heldout_hidden_states.to(dtype=target_weight.dtype))
        standalone_logits = _standard_end_apply_linear_probe(
            hidden_states=heldout_hidden_states,
            linear_probe=linear_probe,
        )
    max_abs_logit_diff = float((transplanted_native_logits - standalone_logits).abs().max().item())
    mean_abs_logit_diff = float((transplanted_native_logits - standalone_logits).abs().mean().item())
    logit_match_within_tolerance = max_abs_logit_diff <= LINEAR_PROBE_TRANSPLANT_LOGIT_MATCH_ATOL
    torch.save(
        {key: value.detach().cpu() for key, value in predictor.orientation_head.state_dict().items()},
        run_dir / LINEAR_PROBE_TRANSPLANT_HEAD_STATE_ARTIFACT,
    )
    torch.save(
        {
            "native_orientation_logits": transplanted_native_logits.detach().cpu(),
            "standalone_linear_probe_logits": standalone_logits.detach().cpu(),
            "heldout_generator_seed": int(run_id is not None) if False else None,
        },
        run_dir / LINEAR_PROBE_TRANSPLANT_PREDICTIONS_ARTIFACT,
    )
    report = {
        **_linear_probe_transplant_metadata(
            metric_versions={
                "weight_shape_match": "v1",
                "bias_shape_match": "v1",
                "max_abs_weight_diff_after_copy": "v1",
                "max_abs_bias_diff_after_copy": "v1",
                "max_abs_logit_diff": "v1",
                "mean_abs_logit_diff": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "weight_shape_match": weight_shape_match,
        "bias_shape_match": bias_shape_match,
        "max_abs_weight_diff_after_copy": max_abs_weight_diff_after_copy,
        "max_abs_bias_diff_after_copy": max_abs_bias_diff_after_copy,
        "max_abs_logit_diff": max_abs_logit_diff,
        "mean_abs_logit_diff": mean_abs_logit_diff,
        "logit_match_tolerance": LINEAR_PROBE_TRANSPLANT_LOGIT_MATCH_ATOL,
        "native_logits_match_standalone_linear_probe": logit_match_within_tolerance,
        "no_optimization_after_transplant": True,
    }
    _write_json(run_dir / LINEAR_PROBE_TRANSPLANT_LOGIT_MATCH_REPORT_V1_ARTIFACT, report)
    return report


def _linear_probe_transplant_complete_run(
    prepared_run: dict[str, object],
) -> dict[str, object]:
    predictor = prepared_run["predictor"]
    heldout_batch = prepared_run["heldout_batch"]
    auxiliary_probe_fit_batch = prepared_run["auxiliary_probe_fit_batch"]
    standard_heldout_batch = prepared_run["standard_heldout_batch"]
    generator = prepared_run["generator"]
    model = prepared_run["model"]
    assay_runner = prepared_run["assay_runner"]
    resolved_config = prepared_run["resolved_config"]
    run_dir = prepared_run["run_dir"]
    run_id = prepared_run["run_id"]
    auxiliary_probe_fit_seed = int(prepared_run["auxiliary_probe_fit_seed"])
    donor_linear_probe = prepared_run["donor_linear_probe"]

    transplant_report = _linear_probe_transplant_apply_exact_copy(
        predictor=predictor,
        linear_probe=donor_linear_probe,
        run_dir=run_dir,
        run_id=run_id,
        heldout_hidden_states=prepared_run["pre_transplant"]["heldout_hidden_states"],
    )
    post_parameter_snapshot = _linear_probe_transplant_parameter_scope_snapshot(predictor)
    post_checkpoint = _linear_probe_transplant_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        auxiliary_probe_fit_batch=auxiliary_probe_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=run_id,
        run_dir=run_dir,
        checkpoint_dirname=LINEAR_PROBE_TRANSPLANT_POST_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        linear_probe=donor_linear_probe,
        save_transplant_outputs=True,
    )
    pre_checkpoint = prepared_run["pre_transplant"]
    heldout_hidden_state_max_abs_diff = float(
        (pre_checkpoint["heldout_hidden_states"] - post_checkpoint["heldout_hidden_states"]).abs().max().item()
    )
    auxiliary_hidden_state_max_abs_diff = float(
        (pre_checkpoint["auxiliary_hidden_states"] - post_checkpoint["auxiliary_hidden_states"]).abs().max().item()
    )
    integrity = {
        "heldout_batch_identity_same_pre_post": int(pre_checkpoint["heldout_generator_seed"]) == int(post_checkpoint["heldout_generator_seed"]),
        "auxiliary_batch_identity_same_pre_post": int(pre_checkpoint["auxiliary_generator_seed"]) == int(post_checkpoint["auxiliary_generator_seed"]),
        "auxiliary_eval_disjoint_from_heldout": int(prepared_run["heldout_seed"]) != auxiliary_probe_fit_seed,
        "recurrent_core_parameter_fingerprint_unchanged": (
            prepared_run["pre_parameter_snapshot"]["recurrent_core_fingerprint"]
            == post_parameter_snapshot["recurrent_core_fingerprint"]
        ),
        "precision_head_parameter_fingerprint_unchanged": (
            prepared_run["pre_parameter_snapshot"]["precision_head_fingerprint"]
            == post_parameter_snapshot["precision_head_fingerprint"]
        ),
        "orientation_head_parameter_fingerprint_changed": (
            prepared_run["pre_parameter_snapshot"]["orientation_head_fingerprint"]
            != post_parameter_snapshot["orientation_head_fingerprint"]
        ),
        "heldout_hidden_states_unchanged": bool(
            torch.allclose(
                pre_checkpoint["heldout_hidden_states"],
                post_checkpoint["heldout_hidden_states"],
                atol=LINEAR_PROBE_TRANSPLANT_HIDDEN_STATE_ATOL,
                rtol=0.0,
            )
        ),
        "auxiliary_hidden_states_unchanged": bool(
            torch.allclose(
                pre_checkpoint["auxiliary_hidden_states"],
                post_checkpoint["auxiliary_hidden_states"],
                atol=LINEAR_PROBE_TRANSPLANT_HIDDEN_STATE_ATOL,
                rtol=0.0,
            )
        ),
        "heldout_hidden_state_max_abs_diff": heldout_hidden_state_max_abs_diff,
        "auxiliary_hidden_state_max_abs_diff": auxiliary_hidden_state_max_abs_diff,
        "transplanted_native_orientation_head_equals_donor": bool(
            transplant_report["weight_shape_match"]
            and transplant_report["bias_shape_match"]
            and float(transplant_report["max_abs_weight_diff_after_copy"]) == 0.0
            and float(transplant_report["max_abs_bias_diff_after_copy"]) == 0.0
        ),
        "native_orientation_logits_match_standalone_linear_probe": bool(
            transplant_report["native_logits_match_standalone_linear_probe"]
        ),
        "no_optimization_after_transplant": True,
        "optimization_steps_after_transplant": 0,
        "predictive_loss_pre": float(pre_checkpoint["standard_predictive_metrics"]["predictive_loss"]),
        "predictive_loss_post": float(post_checkpoint["standard_predictive_metrics"]["predictive_loss"]),
        "predictive_structure_accuracy_pre": float(pre_checkpoint["standard_sanity"]["predictive_structure"]["accuracy"]),
        "predictive_structure_accuracy_post": float(post_checkpoint["standard_sanity"]["predictive_structure"]["accuracy"]),
        "nuisance_only_accuracy_pre": float(pre_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"]),
        "nuisance_only_accuracy_post": float(post_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"]),
    }
    integrity["delta_predictive_loss"] = integrity["predictive_loss_post"] - integrity["predictive_loss_pre"]
    integrity["delta_predictive_structure_accuracy"] = (
        integrity["predictive_structure_accuracy_post"] - integrity["predictive_structure_accuracy_pre"]
    )
    integrity["delta_nuisance_only_accuracy"] = integrity["nuisance_only_accuracy_post"] - integrity["nuisance_only_accuracy_pre"]
    integrity["predictive_nonregression_passes"] = (
        integrity["delta_predictive_loss"] <= LINEAR_PROBE_TRANSPLANT_PREDICTIVE_LOSS_DELTA_MAX
        and integrity["delta_predictive_structure_accuracy"] >= LINEAR_PROBE_TRANSPLANT_PREDICTIVE_STRUCTURE_DELTA_MIN
        and integrity["delta_nuisance_only_accuracy"] <= LINEAR_PROBE_TRANSPLANT_NUISANCE_ONLY_DELTA_MAX
        and integrity["nuisance_only_accuracy_post"] < LINEAR_PROBE_TRANSPLANT_NUISANCE_ONLY_POST_MAX
    )
    parameter_scope_payload = {
        **_linear_probe_transplant_metadata(
            metric_versions={"parameter_scope_fingerprints": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "parameter_update_scope": list(LINEAR_PROBE_TRANSPLANT_PARAM_UPDATE_SCOPE),
        "pre_transplant": prepared_run["pre_parameter_snapshot"],
        "post_transplant": post_parameter_snapshot,
        "checks": {
            "recurrent_core_parameter_fingerprint_unchanged": integrity["recurrent_core_parameter_fingerprint_unchanged"],
            "precision_head_parameter_fingerprint_unchanged": integrity["precision_head_parameter_fingerprint_unchanged"],
            "orientation_head_parameter_fingerprint_changed": integrity["orientation_head_parameter_fingerprint_changed"],
            "no_optimization_after_transplant": True,
        },
    }
    _write_json(run_dir / LINEAR_PROBE_TRANSPLANT_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT, parameter_scope_payload)
    transplant_predictions_path = run_dir / LINEAR_PROBE_TRANSPLANT_PREDICTIONS_ARTIFACT
    transplant_predictions = torch.load(transplant_predictions_path)
    transplant_predictions["heldout_generator_seed"] = int(prepared_run["heldout_seed"])
    torch.save(transplant_predictions, transplant_predictions_path)
    return {
        "run_id": run_id,
        "run_dir": run_dir,
        "seed_panel": prepared_run["seed_panel"],
        "train_seed": int(prepared_run["train_seed"]),
        "heldout_seed": int(prepared_run["heldout_seed"]),
        "auxiliary_probe_fit_seed": auxiliary_probe_fit_seed,
        "pre_transplant": {
            key: value for key, value in pre_checkpoint.items() if key not in ("heldout_hidden_states", "auxiliary_hidden_states", "heldout_native_orientation_logits", "heldout_linear_probe_logits")
        },
        "post_transplant": {
            key: value for key, value in post_checkpoint.items() if key not in ("heldout_hidden_states", "auxiliary_hidden_states", "heldout_native_orientation_logits", "heldout_linear_probe_logits")
        },
        "transplant_integrity": integrity,
        "transplant_logit_match_report": transplant_report,
        "artifacts_complete": True,
    }


def _linear_probe_transplant_build_skipped_panel_report(
    *,
    artifact_key: str,
    seed_panel: str,
    stop_reason: str,
) -> dict[str, object]:
    return {
        **_linear_probe_transplant_metadata(
            metric_versions={artifact_key: "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "skipped": True,
        "stop_reason": stop_reason,
        "passes": False,
    }


def _linear_probe_transplant_native_anchor_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    required_successes = _linear_probe_transplant_anchor_required_successes(seed_panel)
    seedwise: list[dict[str, object]] = []
    latent_values: list[float] = []
    pooled_values: list[float] = []
    learned_symmetry_values: list[bool] = []
    latent_ratio_values: list[float | None] = []
    no_sign_reversal_values: list[bool] = []
    for entry in run_entries:
        checkpoint = entry[checkpoint_key]
        latent = float(checkpoint["probe_metrics"]["probe_target_aligned_specificity_contrast"])
        pooled = float(checkpoint["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"])
        oracle_latent = float(checkpoint["oracle_probe_metrics"]["probe_target_aligned_specificity_contrast"])
        learned_symmetry = (
            float(checkpoint["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]) >= 1.0
        )
        latent_ratio = _stage4_probe_ratio(latent, oracle_latent)
        no_sign_reversal = _stage4_no_sign_reversal(latent, pooled)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "probe_target_aligned_specificity_contrast": latent,
                "probe_pooled_target_aligned_specificity_contrast": pooled,
                "learned_probe_pair_flip_symmetry_consistency": float(
                    checkpoint["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]
                ),
                "learned_oracle_latent_ratio": latent_ratio,
            }
        )
        latent_values.append(latent)
        pooled_values.append(pooled)
        learned_symmetry_values.append(learned_symmetry)
        latent_ratio_values.append(latent_ratio)
        no_sign_reversal_values.append(no_sign_reversal)
    mean_latent = _stage4_mean(latent_values)
    mean_pooled = _stage4_mean(pooled_values)
    checks = {
        "all_runs_have_artifacts": all(bool(entry["artifacts_complete"]) for entry in run_entries),
        "required_successes": required_successes,
        "latent_positive_count": _stage4_count_true([value > 0.0 for value in latent_values]),
        "pooled_positive_count": _stage4_count_true([value > 0.0 for value in pooled_values]),
        "learned_symmetry_consistency_count": _stage4_count_true(learned_symmetry_values),
        "learned_oracle_latent_ratio_ge_0_25_count": _stage4_count_true(
            [value is not None and value >= LINEAR_PROBE_TRANSPLANT_ANCHOR_LATENT_RATIO_FLOOR for value in latent_ratio_values]
        ),
        "mean_latent_ge_floor": mean_latent is not None and float(mean_latent) >= LINEAR_PROBE_TRANSPLANT_ANCHOR_MEAN_LATENT_FLOOR,
        "mean_pooled_ge_floor": mean_pooled is not None and float(mean_pooled) >= LINEAR_PROBE_TRANSPLANT_ANCHOR_MEAN_POOLED_FLOOR,
        "no_latent_pooled_sign_reversal": all(no_sign_reversal_values),
    }
    checks["count_thresholds_met"] = (
        checks["latent_positive_count"] >= required_successes
        and checks["pooled_positive_count"] >= required_successes
        and checks["learned_symmetry_consistency_count"] >= required_successes
        and checks["learned_oracle_latent_ratio_ge_0_25_count"] >= required_successes
    )
    return {
        "seed_panel": seed_panel,
        "checkpoint": checkpoint_key,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "probe_target_aligned_specificity_contrast_sign_counts": _stage4_sign_counts(latent_values),
            "probe_pooled_target_aligned_specificity_contrast_sign_counts": _stage4_sign_counts(pooled_values),
            "learned_symmetry_consistency_counts": _stage4_bool_true_count(learned_symmetry_values),
            "mean_probe_target_aligned_specificity_contrast": mean_latent,
            "mean_probe_pooled_target_aligned_specificity_contrast": mean_pooled,
            "mean_learned_oracle_latent_ratio": _stage4_mean(latent_ratio_values),
        },
        "checks": checks,
        "passes": (
            checks["all_runs_have_artifacts"]
            and checks["count_thresholds_met"]
            and checks["mean_latent_ge_floor"]
            and checks["mean_pooled_ge_floor"]
            and checks["no_latent_pooled_sign_reversal"]
        ),
    }


def _linear_probe_transplant_native_strong_gate_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    required_successes = _linear_probe_transplant_strong_gate_required_successes(seed_panel)
    seedwise: list[dict[str, object]] = []
    alignment_values: list[float] = []
    top1_values: list[float] = []
    correct_pair_flip_values: list[float | None] = []
    within_pair_mass_values: list[float | None] = []
    source_bin_kl_values: list[float | None] = []
    for entry in run_entries:
        checkpoint = entry[checkpoint_key]
        alignment = float(checkpoint["probe_context_alignment_report"]["learned_probe_alignment_kl"])
        top1 = float(checkpoint["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"])
        correct_pair_flip = checkpoint["hidden_state_diagnostics"]["probe_correct_pair_flip_rate__v2"]
        within_pair_mass = checkpoint["hidden_state_diagnostics"]["probe_within_pair_mass__v2"]
        source_bin_kl = checkpoint["hidden_state_diagnostics"]["probe_source_bin_kl__v2"]
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "native_alignment_kl": alignment,
                "native_expected_target_top1_rate": top1,
                "native_correct_pair_flip_rate__v2": correct_pair_flip,
                "native_within_pair_mass__v2": within_pair_mass,
                "native_source_bin_kl__v2": source_bin_kl,
            }
        )
        alignment_values.append(alignment)
        top1_values.append(top1)
        correct_pair_flip_values.append(correct_pair_flip)
        within_pair_mass_values.append(within_pair_mass)
        source_bin_kl_values.append(source_bin_kl)
    checks = {
        "all_runs_have_artifacts": all(bool(entry["artifacts_complete"]) for entry in run_entries),
        "required_successes": required_successes,
        "native_alignment_kl_le_0_75_count": _stage4_count_true(
            [value <= LINEAR_PROBE_TRANSPLANT_STRONG_ALIGNMENT_KL_MAX for value in alignment_values]
        ),
        "native_expected_target_top1_rate_ge_0_75_count": _stage4_count_true(
            [value >= LINEAR_PROBE_TRANSPLANT_STRONG_EXPECTED_TARGET_TOP1_MIN for value in top1_values]
        ),
        "native_correct_pair_flip_rate__v2_ge_0_75_count": _stage4_count_true(
            [value is not None and float(value) >= LINEAR_PROBE_TRANSPLANT_STRONG_CORRECT_PAIR_FLIP_RATE_MIN for value in correct_pair_flip_values]
        ),
        "native_within_pair_mass__v2_ge_0_40_count": _stage4_count_true(
            [value is not None and float(value) >= LINEAR_PROBE_TRANSPLANT_STRONG_WITHIN_PAIR_MASS_MIN for value in within_pair_mass_values]
        ),
        "native_source_bin_kl__v2_ge_2_00_count": _stage4_count_true(
            [value is not None and float(value) >= LINEAR_PROBE_TRANSPLANT_STRONG_SOURCE_BIN_KL_MIN for value in source_bin_kl_values]
        ),
    }
    checks["strong_gate_passes"] = (
        checks["native_alignment_kl_le_0_75_count"] >= required_successes
        and checks["native_expected_target_top1_rate_ge_0_75_count"] >= required_successes
        and checks["native_correct_pair_flip_rate__v2_ge_0_75_count"] >= required_successes
        and checks["native_within_pair_mass__v2_ge_0_40_count"] >= required_successes
        and checks["native_source_bin_kl__v2_ge_2_00_count"] >= required_successes
    )
    return {
        "seed_panel": seed_panel,
        "checkpoint": checkpoint_key,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "mean_native_alignment_kl": _stage4_mean(alignment_values),
            "max_native_alignment_kl": max(alignment_values) if alignment_values else None,
            "mean_native_expected_target_top1_rate": _stage4_mean(top1_values),
            "mean_native_correct_pair_flip_rate__v2": _stage4_mean(correct_pair_flip_values),
            "mean_native_within_pair_mass__v2": _stage4_mean(within_pair_mass_values),
            "mean_native_source_bin_kl__v2": _stage4_mean(source_bin_kl_values),
        },
        "checks": checks,
        "passes": checks["all_runs_have_artifacts"] and checks["strong_gate_passes"],
    }


def _linear_probe_transplant_linear_probe_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    required_successes = _linear_probe_transplant_strong_gate_required_successes(seed_panel)
    seedwise: list[dict[str, object]] = []
    alignment_values: list[float] = []
    top1_values: list[float] = []
    correct_pair_flip_values: list[float | None] = []
    within_pair_mass_values: list[float | None] = []
    source_bin_kl_values: list[float | None] = []
    disjoint_values: list[bool] = []
    for entry in run_entries:
        checkpoint = entry[checkpoint_key]
        report = checkpoint["linear_probe_report"]
        alignment = float(report["linear_probe_alignment_kl"])
        top1 = float(report["linear_probe_expected_target_top1_rate"])
        correct_pair_flip = report["linear_probe_correct_pair_flip_rate__v2"]
        within_pair_mass = report["linear_probe_within_pair_mass__v2"]
        source_bin_kl = report["linear_probe_source_bin_kl__v2"]
        disjoint = bool(report["train_eval_disjoint"])
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "auxiliary_probe_fit_seed": int(entry["auxiliary_probe_fit_seed"]),
                "linear_probe_alignment_kl": alignment,
                "linear_probe_expected_target_top1_rate": top1,
                "linear_probe_correct_pair_flip_rate__v2": correct_pair_flip,
                "linear_probe_within_pair_mass__v2": within_pair_mass,
                "linear_probe_source_bin_kl__v2": source_bin_kl,
                "train_eval_disjoint": disjoint,
            }
        )
        alignment_values.append(alignment)
        top1_values.append(top1)
        correct_pair_flip_values.append(correct_pair_flip)
        within_pair_mass_values.append(within_pair_mass)
        source_bin_kl_values.append(source_bin_kl)
        disjoint_values.append(disjoint)
    checks = {
        "all_runs_have_artifacts": all(bool(entry["artifacts_complete"]) for entry in run_entries),
        "required_successes": required_successes,
        "train_eval_disjoint_for_all_runs": all(disjoint_values),
        "linear_probe_alignment_kl_le_0_75_count": _stage4_count_true(
            [value <= LINEAR_PROBE_TRANSPLANT_STRONG_ALIGNMENT_KL_MAX for value in alignment_values]
        ),
        "linear_probe_expected_target_top1_rate_ge_0_75_count": _stage4_count_true(
            [value >= LINEAR_PROBE_TRANSPLANT_STRONG_EXPECTED_TARGET_TOP1_MIN for value in top1_values]
        ),
        "linear_probe_correct_pair_flip_rate__v2_ge_0_75_count": _stage4_count_true(
            [value is not None and float(value) >= LINEAR_PROBE_TRANSPLANT_STRONG_CORRECT_PAIR_FLIP_RATE_MIN for value in correct_pair_flip_values]
        ),
        "linear_probe_within_pair_mass__v2_ge_0_40_count": _stage4_count_true(
            [value is not None and float(value) >= LINEAR_PROBE_TRANSPLANT_STRONG_WITHIN_PAIR_MASS_MIN for value in within_pair_mass_values]
        ),
        "linear_probe_source_bin_kl__v2_ge_2_00_count": _stage4_count_true(
            [value is not None and float(value) >= LINEAR_PROBE_TRANSPLANT_STRONG_SOURCE_BIN_KL_MIN for value in source_bin_kl_values]
        ),
    }
    checks["strong_gate_passes"] = (
        checks["linear_probe_alignment_kl_le_0_75_count"] >= required_successes
        and checks["linear_probe_expected_target_top1_rate_ge_0_75_count"] >= required_successes
        and checks["linear_probe_correct_pair_flip_rate__v2_ge_0_75_count"] >= required_successes
        and checks["linear_probe_within_pair_mass__v2_ge_0_40_count"] >= required_successes
        and checks["linear_probe_source_bin_kl__v2_ge_2_00_count"] >= required_successes
    )
    return {
        "seed_panel": seed_panel,
        "checkpoint": checkpoint_key,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "mean_linear_probe_alignment_kl": _stage4_mean(alignment_values),
            "max_linear_probe_alignment_kl": max(alignment_values) if alignment_values else None,
            "mean_linear_probe_expected_target_top1_rate": _stage4_mean(top1_values),
            "mean_linear_probe_correct_pair_flip_rate__v2": _stage4_mean(correct_pair_flip_values),
            "mean_linear_probe_within_pair_mass__v2": _stage4_mean(within_pair_mass_values),
            "mean_linear_probe_source_bin_kl__v2": _stage4_mean(source_bin_kl_values),
        },
        "checks": checks,
        "passes": checks["all_runs_have_artifacts"] and checks["train_eval_disjoint_for_all_runs"] and checks["strong_gate_passes"],
    }


def _linear_probe_transplant_delta_panel_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    seedwise: list[dict[str, object]] = []
    alignment_deltas: list[float] = []
    top1_deltas: list[float] = []
    correct_pair_flip_deltas: list[float] = []
    within_pair_mass_deltas: list[float] = []
    source_bin_kl_deltas: list[float] = []
    kl_reductions: list[float] = []
    for entry in run_entries:
        checkpoint = entry[checkpoint_key]
        native_alignment = float(checkpoint["probe_context_alignment_report"]["learned_probe_alignment_kl"])
        linear_alignment = float(checkpoint["linear_probe_report"]["linear_probe_alignment_kl"])
        native_top1 = float(checkpoint["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"])
        linear_top1 = float(checkpoint["linear_probe_report"]["linear_probe_expected_target_top1_rate"])
        native_correct_pair_flip = checkpoint["hidden_state_diagnostics"]["probe_correct_pair_flip_rate__v2"]
        linear_correct_pair_flip = checkpoint["linear_probe_report"]["linear_probe_correct_pair_flip_rate__v2"]
        native_within_pair_mass = checkpoint["hidden_state_diagnostics"]["probe_within_pair_mass__v2"]
        linear_within_pair_mass = checkpoint["linear_probe_report"]["linear_probe_within_pair_mass__v2"]
        native_source_bin_kl = checkpoint["hidden_state_diagnostics"]["probe_source_bin_kl__v2"]
        linear_source_bin_kl = checkpoint["linear_probe_report"]["linear_probe_source_bin_kl__v2"]
        alignment_delta = float(linear_alignment - native_alignment)
        kl_reduction = float(native_alignment - linear_alignment)
        top1_delta = float(linear_top1 - native_top1)
        correct_pair_flip_delta = float(linear_correct_pair_flip - native_correct_pair_flip)
        within_pair_mass_delta = float(linear_within_pair_mass - native_within_pair_mass)
        source_bin_kl_delta = float(linear_source_bin_kl - native_source_bin_kl)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "auxiliary_probe_fit_seed": int(entry["auxiliary_probe_fit_seed"]),
                "delta_alignment_kl__linear_minus_native": alignment_delta,
                "delta_expected_target_top1_rate__linear_minus_native": top1_delta,
                "delta_correct_pair_flip_rate__v2__linear_minus_native": correct_pair_flip_delta,
                "delta_within_pair_mass__v2__linear_minus_native": within_pair_mass_delta,
                "delta_source_bin_kl__v2__linear_minus_native": source_bin_kl_delta,
                "alignment_kl_reduction__native_minus_linear": kl_reduction,
            }
        )
        alignment_deltas.append(alignment_delta)
        top1_deltas.append(top1_delta)
        correct_pair_flip_deltas.append(correct_pair_flip_delta)
        within_pair_mass_deltas.append(within_pair_mass_delta)
        source_bin_kl_deltas.append(source_bin_kl_delta)
        kl_reductions.append(kl_reduction)

    def _ci(values: list[float], offset: int) -> dict[str, float] | None:
        return _standard_end_bootstrap_mean_ci(values, seed=LINEAR_PROBE_TRANSPLANT_BOOTSTRAP_SEED + offset)

    return {
        "seed_panel": seed_panel,
        "checkpoint": checkpoint_key,
        "n_runs": len(run_entries),
        "seedwise": seedwise,
        "summary": {
            "mean_delta_alignment_kl__linear_minus_native": _stage4_mean(alignment_deltas),
            "mean_alignment_kl_reduction__native_minus_linear": _stage4_mean(kl_reductions),
            "mean_delta_expected_target_top1_rate__linear_minus_native": _stage4_mean(top1_deltas),
            "mean_delta_correct_pair_flip_rate__v2__linear_minus_native": _stage4_mean(correct_pair_flip_deltas),
            "mean_delta_within_pair_mass__v2__linear_minus_native": _stage4_mean(within_pair_mass_deltas),
            "mean_delta_source_bin_kl__v2__linear_minus_native": _stage4_mean(source_bin_kl_deltas),
            "bootstrap_ci_95": {
                "delta_alignment_kl__linear_minus_native": _ci(alignment_deltas, 11),
                "alignment_kl_reduction__native_minus_linear": _ci(kl_reductions, 12),
                "delta_expected_target_top1_rate__linear_minus_native": _ci(top1_deltas, 13),
                "delta_correct_pair_flip_rate__v2__linear_minus_native": _ci(correct_pair_flip_deltas, 14),
                "delta_within_pair_mass__v2__linear_minus_native": _ci(within_pair_mass_deltas, 15),
                "delta_source_bin_kl__v2__linear_minus_native": _ci(source_bin_kl_deltas, 16),
            },
        },
    }


def _linear_probe_transplant_build_pre_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    native_anchor_summary = _linear_probe_transplant_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_transplant",
    )
    linear_probe_summary = _linear_probe_transplant_linear_probe_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_transplant",
    )
    delta_summary = _linear_probe_transplant_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_transplant",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "native_anchor_fails": not native_anchor_summary["passes"],
        "linear_probe_strong_gate_passes": bool(linear_probe_summary["passes"]),
        "mean_top1_improvement_ge_0_25": (
            delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"] is not None
            and float(delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"])
            >= LINEAR_PROBE_TRANSPLANT_TOP1_IMPROVEMENT_MIN
        ),
        "top1_improvement_ci_lower_gt_0": top1_ci is not None and float(top1_ci["lower"]) > 0.0,
        "mean_kl_reduction_ge_0_50": (
            delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"] is not None
            and float(delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"])
            >= LINEAR_PROBE_TRANSPLANT_KL_REDUCTION_MIN
        ),
        "kl_reduction_ci_lower_gt_0": kl_ci is not None and float(kl_ci["lower"]) > 0.0,
    }
    return {
        **_linear_probe_transplant_metadata(
            metric_versions={"pre_transplant_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "linear_probe_summary": linear_probe_summary,
        "transplant_gap_summary": delta_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _linear_probe_transplant_build_integrity_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = len(run_entries)
    seedwise: list[dict[str, object]] = []
    boolean_fields = {
        "heldout_batch_identity_same_pre_post": [],
        "auxiliary_batch_identity_same_pre_post": [],
        "auxiliary_eval_disjoint_from_heldout": [],
        "recurrent_core_parameter_fingerprint_unchanged": [],
        "precision_head_parameter_fingerprint_unchanged": [],
        "orientation_head_parameter_fingerprint_changed": [],
        "heldout_hidden_states_unchanged": [],
        "auxiliary_hidden_states_unchanged": [],
        "transplanted_native_orientation_head_equals_donor": [],
        "native_orientation_logits_match_standalone_linear_probe": [],
        "predictive_nonregression_passes": [],
        "no_optimization_after_transplant": [],
    }
    for entry in run_entries:
        integrity = entry["transplant_integrity"]
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "auxiliary_probe_fit_seed": int(entry["auxiliary_probe_fit_seed"]),
                **integrity,
                "transplant_logit_match_report": entry["transplant_logit_match_report"],
            }
        )
        for key in boolean_fields:
            boolean_fields[key].append(bool(integrity[key]))
    checks = {
        "required_successes": required_successes,
        "heldout_batch_identity_same_pre_post_count": _stage4_count_true(boolean_fields["heldout_batch_identity_same_pre_post"]),
        "auxiliary_batch_identity_same_pre_post_count": _stage4_count_true(boolean_fields["auxiliary_batch_identity_same_pre_post"]),
        "auxiliary_eval_disjoint_from_heldout_count": _stage4_count_true(boolean_fields["auxiliary_eval_disjoint_from_heldout"]),
        "recurrent_core_parameter_fingerprint_unchanged_count": _stage4_count_true(boolean_fields["recurrent_core_parameter_fingerprint_unchanged"]),
        "precision_head_parameter_fingerprint_unchanged_count": _stage4_count_true(boolean_fields["precision_head_parameter_fingerprint_unchanged"]),
        "orientation_head_parameter_fingerprint_changed_count": _stage4_count_true(boolean_fields["orientation_head_parameter_fingerprint_changed"]),
        "heldout_hidden_states_unchanged_count": _stage4_count_true(boolean_fields["heldout_hidden_states_unchanged"]),
        "auxiliary_hidden_states_unchanged_count": _stage4_count_true(boolean_fields["auxiliary_hidden_states_unchanged"]),
        "transplanted_native_orientation_head_equals_donor_count": _stage4_count_true(boolean_fields["transplanted_native_orientation_head_equals_donor"]),
        "native_orientation_logits_match_standalone_linear_probe_count": _stage4_count_true(boolean_fields["native_orientation_logits_match_standalone_linear_probe"]),
        "predictive_nonregression_count": _stage4_count_true(boolean_fields["predictive_nonregression_passes"]),
        "no_optimization_after_transplant_count": _stage4_count_true(boolean_fields["no_optimization_after_transplant"]),
    }
    checks["passes"] = all(value >= required_successes for key, value in checks.items() if key.endswith("_count"))
    return {
        **_linear_probe_transplant_metadata(
            metric_versions={"transplant_integrity_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "checks": checks,
        "passes": bool(checks["passes"]),
        "skipped": False,
    }


def _linear_probe_transplant_build_post_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    native_anchor_summary = _linear_probe_transplant_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_transplant",
    )
    native_strong_gate_summary = _linear_probe_transplant_native_strong_gate_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_transplant",
    )
    delta_summary = _linear_probe_transplant_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_transplant",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "native_anchor_passes": bool(native_anchor_summary["passes"]),
        "native_strong_gate_passes": bool(native_strong_gate_summary["passes"]),
        "no_material_linear_probe_top1_advantage": top1_ci is not None
        and float(top1_ci["upper"]) < LINEAR_PROBE_TRANSPLANT_TOP1_IMPROVEMENT_NO_ADVANTAGE_MAX,
        "no_material_linear_probe_kl_advantage": kl_ci is not None
        and float(kl_ci["upper"]) < LINEAR_PROBE_TRANSPLANT_KL_REDUCTION_NO_ADVANTAGE_MAX,
    }
    return {
        **_linear_probe_transplant_metadata(
            metric_versions={"post_transplant_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "native_strong_gate_summary": native_strong_gate_summary,
        "transplant_gap_summary": delta_summary,
        "checks": checks,
        "restoration_passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _linear_probe_transplant_build_gap_report(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
) -> dict[str, object]:
    panels: dict[str, object] = {
        "pre_transplant_primary": _linear_probe_transplant_delta_panel_summary(
            seed_panel="primary",
            run_entries=primary_run_entries,
            checkpoint_key="pre_transplant",
        ),
    }
    post_primary_entries = [entry for entry in primary_run_entries if "post_transplant" in entry]
    if post_primary_entries:
        panels["post_transplant_primary"] = _linear_probe_transplant_delta_panel_summary(
            seed_panel="primary",
            run_entries=post_primary_entries,
            checkpoint_key="post_transplant",
        )
    if confirmation_run_entries is not None:
        panels["pre_transplant_confirmation"] = _linear_probe_transplant_delta_panel_summary(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            checkpoint_key="pre_transplant",
        )
        post_confirmation_entries = [entry for entry in confirmation_run_entries if "post_transplant" in entry]
        if post_confirmation_entries:
            panels["post_transplant_confirmation"] = _linear_probe_transplant_delta_panel_summary(
                seed_panel="confirmation",
                run_entries=post_confirmation_entries,
                checkpoint_key="post_transplant",
            )
    return {
        **_linear_probe_transplant_metadata(
            metric_versions={
                "delta_alignment_kl__linear_minus_native": "v1",
                "alignment_kl_reduction__native_minus_linear": "v1",
                "delta_expected_target_top1_rate__linear_minus_native": "v1",
                "delta_correct_pair_flip_rate__v2__linear_minus_native": "v2",
                "delta_within_pair_mass__v2__linear_minus_native": "v2",
                "delta_source_bin_kl__v2__linear_minus_native": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "panels": panels,
        "skipped": False,
    }


def _linear_probe_transplant_build_verdict(
    *,
    nonregression_report: dict[str, object],
    pre_transplant_primary_report: dict[str, object],
    transplant_integrity_primary_report: dict[str, object],
    post_transplant_primary_report: dict[str, object],
    pre_transplant_confirmation_report: dict[str, object] | None,
    transplant_integrity_confirmation_report: dict[str, object] | None,
    post_transplant_confirmation_report: dict[str, object] | None,
    confirmation_executed: bool,
) -> dict[str, object]:
    if not bool(nonregression_report["passes"]):
        return {
            **_linear_probe_transplant_metadata(
                metric_versions={"linear_probe_transplant_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "nonregression",
            "stop_gate": "R1 frozen non-regression",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not bool(pre_transplant_primary_report["passes"]):
        return {
            **_linear_probe_transplant_metadata(
                metric_versions={"linear_probe_transplant_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "pre_transplant_primary",
            "stop_gate": "R2 pre-transplant premise reproduction",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not bool(transplant_integrity_primary_report["passes"]):
        return {
            **_linear_probe_transplant_metadata(
                metric_versions={"linear_probe_transplant_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "transplant_integrity_primary",
            "stop_gate": "R3 transplant integrity / anti-bypass",
            "confirmation_executed": False,
            "package_complete": True,
        }
    restoration_candidate = bool(post_transplant_primary_report["restoration_passes"])
    localization_candidate = (
        not restoration_candidate
        and bool(transplant_integrity_primary_report["passes"])
        and transplant_integrity_primary_report["checks"]["native_orientation_logits_match_standalone_linear_probe_count"]
        >= len(transplant_integrity_primary_report["seedwise"])
    )
    if not restoration_candidate and not localization_candidate:
        return {
            **_linear_probe_transplant_metadata(
                metric_versions={"linear_probe_transplant_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "post_transplant_primary",
            "stop_gate": "R4 post-transplant primary outcome",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not confirmation_executed:
        return {
            **_linear_probe_transplant_metadata(
                metric_versions={"linear_probe_transplant_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation_not_executed",
            "stop_gate": "R5 confirmation",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if pre_transplant_confirmation_report is None or not bool(pre_transplant_confirmation_report["passes"]):
        confirmation_replicates = False
    elif transplant_integrity_confirmation_report is None or not bool(transplant_integrity_confirmation_report["passes"]):
        confirmation_replicates = False
    elif restoration_candidate:
        confirmation_replicates = post_transplant_confirmation_report is not None and bool(
            post_transplant_confirmation_report["restoration_passes"]
        )
    else:
        confirmation_replicates = (
            post_transplant_confirmation_report is not None
            and not bool(post_transplant_confirmation_report["restoration_passes"])
            and transplant_integrity_confirmation_report["checks"]["native_orientation_logits_match_standalone_linear_probe_count"]
            >= len(transplant_integrity_confirmation_report["seedwise"])
        )
    if not confirmation_replicates:
        return {
            **_linear_probe_transplant_metadata(
                metric_versions={"linear_probe_transplant_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation",
            "stop_gate": "R5 confirmation",
            "confirmation_executed": True,
            "package_complete": True,
        }
    return {
        **_linear_probe_transplant_metadata(
            metric_versions={"linear_probe_transplant_verdict": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "classification": "GO-transplant-restored" if restoration_candidate else "GO-localization-native-path-limitation",
        "execution_valid": True,
        "stop_stage": None,
        "stop_gate": None,
        "confirmation_executed": True,
        "package_complete": True,
    }


def run_linear_probe_transplant_package(
    *,
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
    primary_seed_panel: tuple[tuple[int, int], ...] = STAGE3_PRIMARY_SEED_PANEL,
    confirmation_seed_panel: tuple[tuple[int, int], ...] = STAGE3_CONFIRMATION_SEED_PANEL,
    benchmark_artifacts_root: str | Path = "artifacts",
) -> LinearProbeTransplantRunResult:
    resolved_config = _resolve_config(config=config, preset_name=preset_name)
    if resolved_config.name != "phase1_core":
        raise ValueError("linear_probe_transplant is frozen to the phase1_core configuration family.")

    output_root = (
        resolved_config.artifacts.root_dir
        / "linear_probe_transplant"
        / LINEAR_PROBE_TRANSPLANT_PACKAGE_VERSION
    )
    output_root.mkdir(parents=True, exist_ok=True)
    training_config = _stage4_training_config(resolved_config)
    package_manifest = {
        **_linear_probe_transplant_metadata(
            metric_versions={"linear_probe_transplant_manifest": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "changed_files": ["src/lvc_expectation/runner.py"],
        "package_checkpoints": [
            LINEAR_PROBE_TRANSPLANT_PRE_CHECKPOINT_DIRNAME,
            LINEAR_PROBE_TRANSPLANT_POST_CHECKPOINT_DIRNAME,
        ],
        "pretraining": {
            "config_family": "phase1_core",
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "n_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "training_source": "ordinary generate_batch() only",
        },
        "transplant": {
            "type": "exact_linear_probe_affine_copy",
            "parameter_update_scope": list(LINEAR_PROBE_TRANSPLANT_PARAM_UPDATE_SCOPE),
            "no_optimization_after_transplant": True,
            "logit_match_tolerance": LINEAR_PROBE_TRANSPLANT_LOGIT_MATCH_ATOL,
        },
        "linear_probe": {
            "form": LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_FORM,
            "target": LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_TARGET,
            "ridge_lambda": LINEAR_PROBE_TRANSPLANT_LINEAR_PROBE_RIDGE_LAMBDA,
            "fit_mask": "probe_step_mask & probe_valid_mask",
            "hidden_state_tensor_name": LINEAR_PROBE_TRANSPLANT_HIDDEN_STATE_TENSOR_NAME,
            "train_eval_split": "auxiliary_probe_fit_batch vs heldout_fixed_probe_batch",
        },
        "batch_identity_rules": {
            "heldout_eval_batch": "fixed_probe_batch(seed=heldout_seed)",
            "auxiliary_probe_fit_batch": "fixed_probe_batch(seed=heldout_seed + 1)",
        },
        "bootstrap": {
            "seed": LINEAR_PROBE_TRANSPLANT_BOOTSTRAP_SEED,
            "resamples": LINEAR_PROBE_TRANSPLANT_BOOTSTRAP_RESAMPLES,
            "confidence_level": LINEAR_PROBE_TRANSPLANT_BOOTSTRAP_CONFIDENCE_LEVEL,
        },
        "seed_panels": {
            "primary": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in primary_seed_panel],
            "confirmation": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in confirmation_seed_panel],
        },
        "run_order": [
            "write_linear_probe_transplant_manifest",
            "rerun_stage0_to_stage3_nonregression_checks",
            "run_primary_pre_transplant_panel",
            "copy_exact_linear_probe_into_orientation_head",
            "run_primary_post_transplant_panel_if_R2_passes",
            "run_confirmation_panels_if_candidate",
            "write_linear_probe_transplant_reports_and_verdict",
        ],
        "stop_rules": {
            "halt_on_nonregression_failure": True,
            "halt_on_pre_transplant_premise_failure": True,
            "halt_on_transplant_integrity_failure": True,
            "confirmation_only_if_primary_candidate": True,
            "halt_on_confirmation_failure": True,
            "no_harder_evaluation": True,
            "no_second_package": True,
            "no_sweep": True,
        },
        "explicit_statements": {
            "no_sweep": True,
            "no_second_package": True,
            "no_harder_evaluation": True,
            "no_optimization_after_transplant": True,
        },
    }
    _write_json(output_root / LINEAR_PROBE_TRANSPLANT_MANIFEST_V1_ARTIFACT, package_manifest)

    nonregression_report = _linear_probe_transplant_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
    )
    _write_json(output_root / LINEAR_PROBE_TRANSPLANT_NONREGRESSION_REPORT_V1_ARTIFACT, nonregression_report)
    if not bool(nonregression_report["passes"]):
        pre_primary_report = _linear_probe_transplant_build_skipped_panel_report(
            artifact_key="pre_transplant_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        post_primary_report = _linear_probe_transplant_build_skipped_panel_report(
            artifact_key="post_transplant_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        integrity_primary_report = _linear_probe_transplant_build_skipped_panel_report(
            artifact_key="transplant_integrity_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        gap_report = {
            **_linear_probe_transplant_metadata(
                metric_versions={"transplant_gap_report": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "panels": {},
            "skipped": True,
            "stop_reason": "nonregression_failed",
        }
        verdict = _linear_probe_transplant_build_verdict(
            nonregression_report=nonregression_report,
            pre_transplant_primary_report=pre_primary_report,
            transplant_integrity_primary_report=integrity_primary_report,
            post_transplant_primary_report=post_primary_report,
            pre_transplant_confirmation_report=None,
            transplant_integrity_confirmation_report=None,
            post_transplant_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_VERDICT_V1_ARTIFACT, verdict)
        return LinearProbeTransplantRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_transplant_primary_report=pre_primary_report,
            transplant_integrity_primary_report=integrity_primary_report,
            post_transplant_primary_report=post_primary_report,
            transplant_gap_report=gap_report,
            verdict=verdict,
            pre_transplant_confirmation_report=None,
            post_transplant_confirmation_report=None,
            transplant_integrity_confirmation_report=None,
            run_ids=[],
        )

    store = RunStore(resolved_config.artifacts.root_dir)
    generator = Phase1ParadigmGenerator(resolved_config, controlled_sources=STAGE3_FULL_CONTROLLED_SOURCES)
    model = V1ExpectationModel(resolved_config)
    model.eval()
    assay_runner = AssayRunner(resolved_config)

    primary_prepared_runs: list[dict[str, object]] = []
    run_ids: list[str] = []
    for train_seed, heldout_seed in primary_seed_panel:
        prepared_run = _linear_probe_transplant_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="primary",
        )
        primary_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    primary_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["auxiliary_probe_fit_seed"],
            "pre_transplant": {
                key: value for key, value in prepared_run["pre_transplant"].items()
                if key not in ("heldout_hidden_states", "auxiliary_hidden_states", "heldout_native_orientation_logits", "heldout_linear_probe_logits")
            },
            "artifacts_complete": True,
        }
        for prepared_run in primary_prepared_runs
    ]
    pre_primary_report = _linear_probe_transplant_build_pre_report(
        seed_panel="primary",
        run_entries=primary_pre_entries,
    )
    gap_report = _linear_probe_transplant_build_gap_report(
        primary_run_entries=primary_pre_entries,
        confirmation_run_entries=None,
    )
    if not bool(pre_primary_report["passes"]):
        post_primary_report = _linear_probe_transplant_build_skipped_panel_report(
            artifact_key="post_transplant_report",
            seed_panel="primary",
            stop_reason="pre_transplant_failed",
        )
        integrity_primary_report = _linear_probe_transplant_build_skipped_panel_report(
            artifact_key="transplant_integrity_report",
            seed_panel="primary",
            stop_reason="pre_transplant_failed",
        )
        verdict = _linear_probe_transplant_build_verdict(
            nonregression_report=nonregression_report,
            pre_transplant_primary_report=pre_primary_report,
            transplant_integrity_primary_report=integrity_primary_report,
            post_transplant_primary_report=post_primary_report,
            pre_transplant_confirmation_report=None,
            transplant_integrity_confirmation_report=None,
            post_transplant_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_VERDICT_V1_ARTIFACT, verdict)
        return LinearProbeTransplantRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_transplant_primary_report=pre_primary_report,
            transplant_integrity_primary_report=integrity_primary_report,
            post_transplant_primary_report=post_primary_report,
            transplant_gap_report=gap_report,
            verdict=verdict,
            pre_transplant_confirmation_report=None,
            post_transplant_confirmation_report=None,
            transplant_integrity_confirmation_report=None,
            run_ids=run_ids,
        )

    primary_run_entries = [_linear_probe_transplant_complete_run(prepared_run) for prepared_run in primary_prepared_runs]
    integrity_primary_report = _linear_probe_transplant_build_integrity_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    post_primary_report = _linear_probe_transplant_build_post_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    gap_report = _linear_probe_transplant_build_gap_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=None,
    )
    if not bool(integrity_primary_report["passes"]):
        verdict = _linear_probe_transplant_build_verdict(
            nonregression_report=nonregression_report,
            pre_transplant_primary_report=pre_primary_report,
            transplant_integrity_primary_report=integrity_primary_report,
            post_transplant_primary_report=post_primary_report,
            pre_transplant_confirmation_report=None,
            transplant_integrity_confirmation_report=None,
            post_transplant_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_VERDICT_V1_ARTIFACT, verdict)
        return LinearProbeTransplantRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_transplant_primary_report=pre_primary_report,
            transplant_integrity_primary_report=integrity_primary_report,
            post_transplant_primary_report=post_primary_report,
            transplant_gap_report=gap_report,
            verdict=verdict,
            pre_transplant_confirmation_report=None,
            post_transplant_confirmation_report=None,
            transplant_integrity_confirmation_report=None,
            run_ids=run_ids,
        )

    restoration_candidate = bool(post_primary_report["restoration_passes"])
    localization_candidate = (
        not restoration_candidate
        and integrity_primary_report["checks"]["native_orientation_logits_match_standalone_linear_probe_count"]
        >= len(integrity_primary_report["seedwise"])
    )
    if not restoration_candidate and not localization_candidate:
        verdict = _linear_probe_transplant_build_verdict(
            nonregression_report=nonregression_report,
            pre_transplant_primary_report=pre_primary_report,
            transplant_integrity_primary_report=integrity_primary_report,
            post_transplant_primary_report=post_primary_report,
            pre_transplant_confirmation_report=None,
            transplant_integrity_confirmation_report=None,
            post_transplant_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_VERDICT_V1_ARTIFACT, verdict)
        return LinearProbeTransplantRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_transplant_primary_report=pre_primary_report,
            transplant_integrity_primary_report=integrity_primary_report,
            post_transplant_primary_report=post_primary_report,
            transplant_gap_report=gap_report,
            verdict=verdict,
            pre_transplant_confirmation_report=None,
            post_transplant_confirmation_report=None,
            transplant_integrity_confirmation_report=None,
            run_ids=run_ids,
        )

    confirmation_prepared_runs: list[dict[str, object]] = []
    for train_seed, heldout_seed in confirmation_seed_panel:
        prepared_run = _linear_probe_transplant_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="confirmation",
        )
        confirmation_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    confirmation_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["auxiliary_probe_fit_seed"],
            "pre_transplant": {
                key: value for key, value in prepared_run["pre_transplant"].items()
                if key not in ("heldout_hidden_states", "auxiliary_hidden_states", "heldout_native_orientation_logits", "heldout_linear_probe_logits")
            },
            "artifacts_complete": True,
        }
        for prepared_run in confirmation_prepared_runs
    ]
    pre_confirmation_report = _linear_probe_transplant_build_pre_report(
        seed_panel="confirmation",
        run_entries=confirmation_pre_entries,
    )
    confirmation_run_entries: list[dict[str, object]] | None = None
    integrity_confirmation_report: dict[str, object] | None = None
    post_confirmation_report: dict[str, object] | None = None
    if bool(pre_confirmation_report["passes"]):
        confirmation_run_entries = [_linear_probe_transplant_complete_run(prepared_run) for prepared_run in confirmation_prepared_runs]
        integrity_confirmation_report = _linear_probe_transplant_build_integrity_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
        post_confirmation_report = _linear_probe_transplant_build_post_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
        gap_report = _linear_probe_transplant_build_gap_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_run_entries,
        )
    else:
        gap_report = _linear_probe_transplant_build_gap_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_pre_entries,
        )

    verdict = _linear_probe_transplant_build_verdict(
        nonregression_report=nonregression_report,
        pre_transplant_primary_report=pre_primary_report,
        transplant_integrity_primary_report=integrity_primary_report,
        post_transplant_primary_report=post_primary_report,
        pre_transplant_confirmation_report=pre_confirmation_report,
        transplant_integrity_confirmation_report=integrity_confirmation_report,
        post_transplant_confirmation_report=post_confirmation_report,
        confirmation_executed=True,
    )

    _write_json(output_root / LINEAR_PROBE_TRANSPLANT_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
    _write_json(output_root / LINEAR_PROBE_TRANSPLANT_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
    _write_json(output_root / LINEAR_PROBE_TRANSPLANT_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
    _write_json(output_root / LINEAR_PROBE_TRANSPLANT_GAP_REPORT_V1_ARTIFACT, gap_report)
    _write_json(output_root / LINEAR_PROBE_TRANSPLANT_VERDICT_V1_ARTIFACT, verdict)
    _write_json(output_root / LINEAR_PROBE_TRANSPLANT_PRE_CONFIRMATION_REPORT_V1_ARTIFACT, pre_confirmation_report)
    if post_confirmation_report is not None:
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_POST_CONFIRMATION_REPORT_V1_ARTIFACT, post_confirmation_report)
    if integrity_confirmation_report is not None:
        _write_json(output_root / LINEAR_PROBE_TRANSPLANT_INTEGRITY_CONFIRMATION_REPORT_V1_ARTIFACT, integrity_confirmation_report)

    return LinearProbeTransplantRunResult(
        output_root=output_root,
        package_manifest=package_manifest,
        nonregression_report=nonregression_report,
        pre_transplant_primary_report=pre_primary_report,
        transplant_integrity_primary_report=integrity_primary_report,
        post_transplant_primary_report=post_primary_report,
        transplant_gap_report=gap_report,
        verdict=verdict,
        pre_transplant_confirmation_report=pre_confirmation_report,
        post_transplant_confirmation_report=post_confirmation_report,
        transplant_integrity_confirmation_report=integrity_confirmation_report,
        run_ids=run_ids,
    )


def _orientation_head_interpolation_metadata(
    *,
    metric_versions: dict[str, str],
    source_metric_versions: list[str],
) -> dict[str, object]:
    return {
        "metric_schema_version": ORIENTATION_HEAD_INTERPOLATION_METRIC_SCHEMA_VERSION,
        "metric_versions": metric_versions,
        "classification_rule_version": ORIENTATION_HEAD_INTERPOLATION_CLASSIFICATION_RULE_VERSION,
        "source_metric_versions": source_metric_versions,
        "benchmark_registry_version": BENCHMARK_REGISTRY_VERSION,
        "orientation_head_interpolation_package_version": ORIENTATION_HEAD_INTERPOLATION_PACKAGE_VERSION,
    }


def _orientation_head_interpolation_build_nonregression_report(
    *,
    resolved_config: ExperimentConfig,
    output_root: Path,
    benchmark_artifacts_root: str | Path,
) -> dict[str, object]:
    raw_report = _stage4_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
        primary_seed_panel=STAGE3_PRIMARY_SEED_PANEL,
        confirmation_seed_panel=STAGE3_CONFIRMATION_SEED_PANEL,
    )
    stripped = dict(raw_report)
    for key in (
        "metric_schema_version",
        "metric_versions",
        "classification_rule_version",
        "source_metric_versions",
        "benchmark_registry_version",
        "stage3_task_version",
        "stage4_package_version",
    ):
        stripped.pop(key, None)
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={
                "stage0_registry_verification": "v1",
                "stage1_tranche_runner_replay": "v1",
                "stage2_diagnostic_calibration_report": "v2",
                "stage3_oracle_task_definition_verdict": "v2",
                "phase15_continuation_retention": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        **stripped,
    }


def _orientation_head_interpolation_write_hidden_state_artifacts(
    *,
    run_id: str,
    batch: TrialBatch,
    learned_simulation: SimulationOutput,
    oracle_simulation: SimulationOutput,
    symmetry_mate_lookup: dict[int, int],
    output_dir: Path,
) -> dict[str, object]:
    payload = _stage4_probe_run_payload(
        run_id=run_id,
        batch=batch,
        learned_simulation=learned_simulation,
        oracle_simulation=oracle_simulation,
        symmetry_mate_lookup=symmetry_mate_lookup,
    )
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    for row in rows:
        pair_id = int(row["pair_id"])
        row["_symmetry_group_id"] = min(pair_id, int(symmetry_mate_lookup[pair_id]))
    diagnostics = build_hidden_state_diagnostics_v2(rows)
    diagnostics_payload = {
        **_orientation_head_interpolation_metadata(
            metric_versions=metric_versions_v2_payload(),
            source_metric_versions=[DIAGNOSTIC_SCHEMA_VERSION, FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "diagnostic_schema_version": DIAGNOSTIC_SCHEMA_VERSION,
        **diagnostics,
    }
    write_hidden_state_probe_table_v2(rows, output_dir / HIDDEN_STATE_PROBE_TABLE_V2_ARTIFACT)
    write_hidden_state_diagnostics_v2_json(
        diagnostics_payload,
        output_dir / HIDDEN_STATE_DIAGNOSTICS_V2_ARTIFACT,
    )
    return {
        "rows": rows,
        "diagnostics": diagnostics_payload,
    }


def _orientation_head_interpolation_write_linear_probe_artifacts(
    *,
    run_id: str,
    batch: TrialBatch,
    linear_probe_logits: torch.Tensor,
    oracle_prediction: ContextPrediction,
    output_dir: Path,
    auxiliary_seed: int,
) -> dict[str, object]:
    payload = {
        "run_id": run_id,
        "batch": _serialize_batch(batch),
        "learned_logits": linear_probe_logits,
        "oracle_logits": oracle_prediction.orientation_logits,
        "learned_precision": None,
        "oracle_precision": oracle_prediction.precision_logit,
        "l23_readout": None,
        "gaussian_orientation_bank": None,
        "context_comparator": None,
    }
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    diagnostics = build_hidden_state_diagnostics_v2(rows)
    diagnostics_payload = {
        **_orientation_head_interpolation_metadata(
            metric_versions=metric_versions_v2_payload(),
            source_metric_versions=[DIAGNOSTIC_SCHEMA_VERSION, FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "diagnostic_schema_version": DIAGNOSTIC_SCHEMA_VERSION,
        **diagnostics,
    }
    write_hidden_state_probe_table_v2(rows, output_dir / ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_HIDDEN_STATE_TABLE_V2_ARTIFACT)
    write_hidden_state_diagnostics_v2_json(
        diagnostics_payload,
        output_dir / ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_HIDDEN_STATE_DIAGNOSTICS_V2_ARTIFACT,
    )
    probe_mask = _probe_scoring_mask(batch)
    expected_distribution = batch.metadata["expected_distribution"][probe_mask]
    alignment_kl, expected_logprob = _probe_alignment_stats(linear_probe_logits[probe_mask], expected_distribution)
    behavior_metrics = _probe_alignment_behavior_metrics(batch, linear_probe_logits)
    report = {
        **_orientation_head_interpolation_metadata(
            metric_versions={
                "linear_probe_alignment_kl": "v1",
                "linear_probe_expected_logprob": "v1",
                "linear_probe_expected_target_top1_rate": "v1",
                "linear_probe_correct_pair_flip_rate__v2": "v2",
                "linear_probe_within_pair_mass__v2": "v2",
                "linear_probe_source_bin_kl__v2": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "run_id": run_id,
        "heldout_generator_seed": int(batch.metadata["generator_seed"]),
        "auxiliary_generator_seed": int(auxiliary_seed),
        "train_eval_disjoint": int(batch.metadata["generator_seed"]) != int(auxiliary_seed),
        "linear_probe_alignment_kl": alignment_kl,
        "linear_probe_expected_logprob": expected_logprob,
        "linear_probe_expected_target_top1_rate": behavior_metrics["probe_expected_target_top1_rate"],
        "linear_probe_pair_flip_rate": behavior_metrics["probe_pair_flip_rate"],
        "linear_probe_pair_flip_symmetry_consistency": behavior_metrics["probe_pair_flip_symmetry_consistency"],
        "linear_probe_correct_pair_flip_rate__v2": diagnostics["probe_correct_pair_flip_rate__v2"],
        "linear_probe_within_pair_mass__v2": diagnostics["probe_within_pair_mass__v2"],
        "linear_probe_source_bin_kl__v2": diagnostics["probe_source_bin_kl__v2"],
    }
    _write_json(output_dir / ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_REPORT_V1_ARTIFACT, report)
    return {
        "rows": rows,
        "diagnostics": diagnostics_payload,
        "report": report,
    }


def _orientation_head_interpolation_anchor_required_successes(seed_panel: str) -> int:
    if seed_panel == "primary":
        return ORIENTATION_HEAD_INTERPOLATION_NATIVE_PRIMARY_REQUIRED_SUCCESSES
    if seed_panel == "confirmation":
        return ORIENTATION_HEAD_INTERPOLATION_NATIVE_CONFIRMATION_REQUIRED_SUCCESSES
    raise ValueError(f"unknown orientation-head-interpolation seed panel: {seed_panel}")


def _orientation_head_interpolation_strong_gate_required_successes(seed_panel: str) -> int:
    if seed_panel in ("primary", "confirmation"):
        return ORIENTATION_HEAD_INTERPOLATION_STRONG_GATE_REQUIRED_SUCCESSES
    raise ValueError(f"unknown orientation-head-interpolation seed panel: {seed_panel}")


def _orientation_head_interpolation_apply_head(
    hidden_states: torch.Tensor,
    weight: torch.Tensor,
    bias: torch.Tensor,
) -> torch.Tensor:
    return hidden_states.to(dtype=weight.dtype) @ weight.transpose(0, 1) + bias


def _orientation_head_interpolation_state_for_alpha(
    *,
    base_weight: torch.Tensor,
    base_bias: torch.Tensor,
    donor_weight: torch.Tensor,
    donor_bias: torch.Tensor,
    alpha: float,
) -> dict[str, torch.Tensor]:
    alpha_tensor = base_weight.new_tensor(float(alpha))
    one_minus_alpha = base_weight.new_tensor(1.0 - float(alpha))
    return {
        "weight": one_minus_alpha * base_weight + alpha_tensor * donor_weight.to(dtype=base_weight.dtype),
        "bias": one_minus_alpha * base_bias + alpha_tensor * donor_bias.to(dtype=base_bias.dtype),
    }


def _orientation_head_interpolation_probe_bundle(
    *,
    run_id: str,
    batch: TrialBatch,
    learned_prediction: ContextPrediction,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    resolved_config: ExperimentConfig,
) -> dict[str, object]:
    oracle_prediction = _oracle_context_prediction(
        batch,
        use_precision=resolved_config.context.use_precision,
    )
    learned_simulation, learned_window_summaries = _evaluate_single_subcase(
        batch=batch,
        prediction=learned_prediction,
        subcase="dampening",
        model=model,
        config=resolved_config,
    )
    oracle_simulation, oracle_window_summaries = _evaluate_single_subcase(
        batch=batch,
        prediction=oracle_prediction,
        subcase="dampening",
        model=model,
        config=resolved_config,
    )
    probe_metrics = assay_runner.compute_local_global_probe_metrics(learned_simulation, batch)
    oracle_probe_metrics = assay_runner.compute_local_global_probe_metrics(oracle_simulation, batch)
    probe_context_alignment_report = _build_probe_context_alignment_report(
        batch,
        oracle_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=oracle_prediction,
            metadata=batch.metadata,
        ),
        learned_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=learned_prediction,
            metadata=batch.metadata,
        ),
    )
    probe_symmetry_mates = {
        int(pair_id): int(descriptor["symmetry_mate_pair_id"])
        for pair_id, descriptor in batch.metadata["probe_report"]["pair_descriptors"].items()
    }
    payload = _stage4_probe_run_payload(
        run_id=run_id,
        batch=batch,
        learned_simulation=learned_simulation,
        oracle_simulation=oracle_simulation,
        symmetry_mate_lookup=probe_symmetry_mates,
    )
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    for row in rows:
        pair_id = int(row["pair_id"])
        row["_symmetry_group_id"] = min(pair_id, int(probe_symmetry_mates[pair_id]))
    diagnostics = build_hidden_state_diagnostics_v2(rows)
    return {
        "oracle_prediction": oracle_prediction,
        "learned_simulation": learned_simulation,
        "learned_window_summaries": learned_window_summaries,
        "oracle_simulation": oracle_simulation,
        "oracle_window_summaries": oracle_window_summaries,
        "probe_metrics": probe_metrics,
        "oracle_probe_metrics": oracle_probe_metrics,
        "probe_context_alignment_report": probe_context_alignment_report,
        "hidden_state_rows": rows,
        "hidden_state_diagnostics": diagnostics,
        "probe_symmetry_mates": probe_symmetry_mates,
    }


def _orientation_head_interpolation_evaluate_checkpoint(
    *,
    predictor: CausalContextPredictor,
    heldout_batch: TrialBatch,
    donor_fit_batch: TrialBatch,
    predictive_rehearsal_batch: TrialBatch,
    fixed_probe_selection_batch: TrialBatch,
    run_id: str,
    run_dir: Path,
    checkpoint_dirname: str,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    generator: Phase1ParadigmGenerator,
    resolved_config: ExperimentConfig,
    donor_linear_probe: dict[str, object],
    save_interpolation_outputs: bool = False,
    selected_alpha: float | None = None,
) -> dict[str, object]:
    checkpoint_dir = run_dir / checkpoint_dirname
    checkpoint_dir.mkdir(parents=True, exist_ok=True)
    (checkpoint_dir / "eval").mkdir(parents=True, exist_ok=True)
    with torch.no_grad():
        heldout_prediction, heldout_hidden_states = _predict_with_hidden_states(predictor, heldout_batch)
        donor_fit_prediction, donor_fit_hidden_states = _predict_with_hidden_states(predictor, donor_fit_batch)
        predictive_prediction, predictive_hidden_states = _predict_with_hidden_states(predictor, predictive_rehearsal_batch)
        selection_prediction, selection_hidden_states = _predict_with_hidden_states(predictor, fixed_probe_selection_batch)

    heldout_bundle = _orientation_head_interpolation_probe_bundle(
        run_id=run_id,
        batch=heldout_batch,
        learned_prediction=heldout_prediction,
        model=model,
        assay_runner=assay_runner,
        resolved_config=resolved_config,
    )
    predictive_metrics = evaluate_context_predictor(
        predictor,
        predictive_rehearsal_batch,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )
    predictive_sanity = {
        "nuisance_only": asdict(generator.run_nuisance_only_failure_test(predictive_rehearsal_batch)),
        "predictive_structure": asdict(generator.run_predictive_structure_success_test(predictive_rehearsal_batch)),
    }

    torch.save(
        _standard_end_hidden_state_payload(
            batch=heldout_batch,
            hidden_states=heldout_hidden_states,
            batch_role="heldout_eval",
        ),
        checkpoint_dir / ORIENTATION_HEAD_INTERPOLATION_RAW_HIDDEN_STATE_EVAL_ARTIFACT,
    )
    torch.save(
        _standard_end_hidden_state_payload(
            batch=donor_fit_batch,
            hidden_states=donor_fit_hidden_states,
            batch_role="auxiliary_donor_fit",
        ),
        checkpoint_dir / ORIENTATION_HEAD_INTERPOLATION_RAW_HIDDEN_STATE_DONOR_FIT_ARTIFACT,
    )
    torch.save(
        _standard_end_hidden_state_payload(
            batch=predictive_rehearsal_batch,
            hidden_states=predictive_hidden_states,
            batch_role="auxiliary_predictive_rehearsal",
        ),
        checkpoint_dir / ORIENTATION_HEAD_INTERPOLATION_RAW_HIDDEN_STATE_PREDICTIVE_ARTIFACT,
    )
    torch.save(
        _standard_end_hidden_state_payload(
            batch=fixed_probe_selection_batch,
            hidden_states=selection_hidden_states,
            batch_role="auxiliary_fixed_probe_selection",
        ),
        checkpoint_dir / ORIENTATION_HEAD_INTERPOLATION_RAW_HIDDEN_STATE_SELECTION_ARTIFACT,
    )
    torch.save(_serialize_batch(donor_fit_batch), checkpoint_dir / ORIENTATION_HEAD_INTERPOLATION_DONOR_FIT_BATCH_ARTIFACT)
    torch.save(
        _serialize_batch(predictive_rehearsal_batch),
        checkpoint_dir / ORIENTATION_HEAD_INTERPOLATION_PREDICTIVE_BATCH_ARTIFACT,
    )
    torch.save(
        _serialize_batch(fixed_probe_selection_batch),
        checkpoint_dir / ORIENTATION_HEAD_INTERPOLATION_SELECTION_BATCH_ARTIFACT,
    )

    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    probe_design_report = {
        **_orientation_head_interpolation_metadata(
            metric_versions={
                "n_probe_rows": "v1",
                "n_probe_global_expected_rows": "v1",
                "n_probe_global_unexpected_rows": "v1",
                "n_probe_pairs_total": "v1",
                "n_probe_pairs_scored": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **_build_probe_design_report(
            heldout_batch,
            task_mode_fixed_state=task_mode_fixed_state,
            prestim_fixed_state=prestim_fixed_state,
            oracle_simulation=heldout_bundle["oracle_simulation"],
            learned_simulation=heldout_bundle["learned_simulation"],
        ),
    }
    probe_metrics_payload = {
        **_orientation_head_interpolation_metadata(
            metric_versions={metric_name: "v1" for metric_name in sorted(heldout_bundle["probe_metrics"])},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **heldout_bundle["probe_metrics"],
    }
    oracle_probe_metrics_payload = {
        **_orientation_head_interpolation_metadata(
            metric_versions={metric_name: "v1" for metric_name in sorted(heldout_bundle["oracle_probe_metrics"])},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **heldout_bundle["oracle_probe_metrics"],
    }
    probe_context_alignment_payload = {
        **_orientation_head_interpolation_metadata(
            metric_versions={
                "learned_probe_alignment_kl": "v1",
                "oracle_probe_alignment_kl": "v1",
                "learned_probe_expected_logprob": "v1",
                "oracle_probe_expected_logprob": "v1",
                "learned_probe_expected_target_top1_rate": "v1",
                "oracle_probe_expected_target_top1_rate": "v1",
                "learned_probe_pair_flip_rate": "v1",
                "oracle_probe_pair_flip_rate": "v1",
                "learned_probe_pair_flip_symmetry_consistency": "v1",
                "oracle_probe_pair_flip_symmetry_consistency": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **heldout_bundle["probe_context_alignment_report"],
    }
    probe_table_payload = {
        **_orientation_head_interpolation_metadata(
            metric_versions={"probe_table_rows": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "rows": _build_probe_table(
            heldout_batch,
            heldout_bundle["oracle_simulation"],
            heldout_bundle["learned_simulation"],
        ),
    }
    native_hidden_state_outputs = _orientation_head_interpolation_write_hidden_state_artifacts(
        run_id=run_id,
        batch=heldout_batch,
        learned_simulation=heldout_bundle["learned_simulation"],
        oracle_simulation=heldout_bundle["oracle_simulation"],
        symmetry_mate_lookup=heldout_bundle["probe_symmetry_mates"],
        output_dir=checkpoint_dir,
    )
    linear_probe_logits = _standard_end_apply_linear_probe(
        hidden_states=heldout_hidden_states,
        linear_probe=donor_linear_probe,
    )
    linear_probe_outputs = _orientation_head_interpolation_write_linear_probe_artifacts(
        run_id=run_id,
        batch=heldout_batch,
        linear_probe_logits=linear_probe_logits,
        oracle_prediction=heldout_bundle["oracle_prediction"],
        output_dir=checkpoint_dir,
        auxiliary_seed=int(donor_fit_batch.metadata["generator_seed"]),
    )
    torch.save(donor_linear_probe, checkpoint_dir / ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_PARAMETERS_ARTIFACT)

    _write_json(checkpoint_dir / "probe_design_report.json", probe_design_report)
    _write_json(checkpoint_dir / "probe_metrics.json", probe_metrics_payload)
    _write_json(checkpoint_dir / "oracle_probe_metrics.json", oracle_probe_metrics_payload)
    _write_json(checkpoint_dir / "probe_context_alignment_report.json", probe_context_alignment_payload)
    _write_json(checkpoint_dir / "probe_table.json", probe_table_payload)
    torch.save(_serialize_batch(heldout_batch), checkpoint_dir / "eval" / "heldout_batch.pt")
    torch.save({"dampening": heldout_bundle["learned_window_summaries"]}, checkpoint_dir / "eval" / "window_summaries.pt")
    torch.save({"dampening": heldout_bundle["oracle_window_summaries"]}, checkpoint_dir / "eval" / "oracle_window_summaries.pt")
    torch.save(
        {"dampening": _serialize_simulation(heldout_bundle["learned_simulation"])},
        checkpoint_dir / "eval" / "full_trajectories.pt",
    )
    torch.save(
        {"dampening": _serialize_simulation(heldout_bundle["oracle_simulation"])},
        checkpoint_dir / "eval" / "oracle_full_trajectories.pt",
    )

    if save_interpolation_outputs:
        (run_dir / "eval").mkdir(parents=True, exist_ok=True)
        torch.save(
            {
                "selected_alpha": None if selected_alpha is None else float(selected_alpha),
                "native_orientation_logits": heldout_prediction.orientation_logits.detach().cpu(),
                "standalone_linear_probe_logits": linear_probe_logits.detach().cpu(),
                "heldout_generator_seed": int(heldout_batch.metadata["generator_seed"]),
            },
            run_dir / ORIENTATION_HEAD_INTERPOLATION_PREDICTIONS_ARTIFACT,
        )

    return {
        "checkpoint": checkpoint_dirname,
        "probe_metrics": heldout_bundle["probe_metrics"],
        "oracle_probe_metrics": heldout_bundle["oracle_probe_metrics"],
        "probe_context_alignment_report": heldout_bundle["probe_context_alignment_report"],
        "hidden_state_diagnostics": native_hidden_state_outputs["diagnostics"],
        "linear_probe_report": linear_probe_outputs["report"],
        "linear_probe_diagnostics": linear_probe_outputs["diagnostics"],
        "predictive_metrics": predictive_metrics,
        "predictive_sanity": predictive_sanity,
        "heldout_generator_seed": int(heldout_batch.metadata["generator_seed"]),
        "donor_fit_generator_seed": int(donor_fit_batch.metadata["generator_seed"]),
        "predictive_rehearsal_generator_seed": int(predictive_rehearsal_batch.metadata["generator_seed"]),
        "fixed_probe_selection_generator_seed": int(fixed_probe_selection_batch.metadata["generator_seed"]),
        "heldout_hidden_states": heldout_hidden_states.detach().cpu(),
        "donor_fit_hidden_states": donor_fit_hidden_states.detach().cpu(),
        "predictive_hidden_states": predictive_hidden_states.detach().cpu(),
        "selection_hidden_states": selection_hidden_states.detach().cpu(),
        "heldout_precision_logit": None if heldout_prediction.precision_logit is None else heldout_prediction.precision_logit.detach().cpu(),
        "predictive_precision_logit": None if predictive_prediction.precision_logit is None else predictive_prediction.precision_logit.detach().cpu(),
        "selection_precision_logit": None if selection_prediction.precision_logit is None else selection_prediction.precision_logit.detach().cpu(),
        "heldout_native_orientation_logits": heldout_prediction.orientation_logits.detach().cpu(),
        "heldout_linear_probe_logits": linear_probe_logits.detach().cpu(),
        "artifacts_complete": True,
    }


def _orientation_head_interpolation_prepare_run(
    *,
    resolved_config: ExperimentConfig,
    store: RunStore,
    generator: Phase1ParadigmGenerator,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    train_seed: int,
    heldout_seed: int,
    seed_panel: str,
) -> dict[str, object]:
    training_config = _stage4_training_config(resolved_config)
    donor_fit_seed = heldout_seed + ORIENTATION_HEAD_INTERPOLATION_DONOR_FIT_SEED_OFFSET
    predictive_rehearsal_seed = heldout_seed + ORIENTATION_HEAD_INTERPOLATION_PREDICTIVE_BATCH_SEED_OFFSET
    fixed_probe_selection_seed = heldout_seed + ORIENTATION_HEAD_INTERPOLATION_SELECTION_BATCH_SEED_OFFSET
    if len({heldout_seed, donor_fit_seed, predictive_rehearsal_seed, fixed_probe_selection_seed}) != 4:
        raise AssertionError("all orientation-head-interpolation batch identities must be distinct.")
    train_batches = [
        generator.generate_batch(
            batch_size=training_config.batch_size,
            seed=train_seed + epoch,
        )
        for epoch in range(training_config.n_epochs)
    ]
    heldout_batch = generator.generate_local_global_probe_batch(seed=heldout_seed)
    donor_fit_batch = generator.generate_local_global_probe_batch(seed=donor_fit_seed)
    predictive_rehearsal_batch = generator.generate_batch(
        batch_size=training_config.batch_size,
        seed=predictive_rehearsal_seed,
    )
    fixed_probe_selection_batch = generator.generate_local_global_probe_batch(seed=fixed_probe_selection_seed)
    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    manifest, run_dir = store.create_run(
        resolved_config.name,
        train_objectives=[f"{resolved_config.training.predictive_objective}:{EXPECTED_DISTRIBUTION_OBJECTIVE}"],
        heldout_assays=[
            "probe_target_aligned_specificity_contrast",
            "probe_pooled_target_aligned_specificity_contrast",
            "probe_context_comparator_nonuniformity_contrast",
            "linear_probe_alignment_kl",
            "linear_probe_expected_target_top1_rate",
            "linear_probe_correct_pair_flip_rate__v2",
            "linear_probe_within_pair_mass__v2",
            "linear_probe_source_bin_kl__v2",
        ],
        notes={
            "gate": "orientation_head_interpolation",
            "orientation_head_interpolation_package_version": ORIENTATION_HEAD_INTERPOLATION_PACKAGE_VERSION,
            "checkpoints": [
                ORIENTATION_HEAD_INTERPOLATION_PRE_CHECKPOINT_DIRNAME,
                ORIENTATION_HEAD_INTERPOLATION_POST_CHECKPOINT_DIRNAME,
            ],
            "seed_panel": seed_panel,
            "train_seed": int(train_seed),
            "heldout_seed": int(heldout_seed),
            "donor_fit_seed": int(donor_fit_seed),
            "predictive_rehearsal_seed": int(predictive_rehearsal_seed),
            "fixed_probe_selection_seed": int(fixed_probe_selection_seed),
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "initial_standard_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "parameter_update_scope": list(ORIENTATION_HEAD_INTERPOLATION_PARAM_UPDATE_SCOPE),
            "controlled_sources": heldout_batch.metadata["controlled_sources"].tolist(),
            "probe_visible_step_index": int(heldout_batch.metadata["probe_visible_step_index"]),
            "task_mode_fixed_state": task_mode_fixed_state,
            "prestim_fixed_state": prestim_fixed_state,
            "candidate_set": [float(alpha) for alpha in ORIENTATION_HEAD_INTERPOLATION_CANDIDATE_SET],
            "heldout_batch_identity_rule": "fixed_probe_batch(seed=heldout_seed)",
            "donor_fit_batch_identity_rule": "fixed_probe_batch(seed=heldout_seed + 1)",
            "predictive_rehearsal_batch_identity_rule": "predictive_batch(seed=heldout_seed + 2)",
            "fixed_probe_selection_batch_identity_rule": "fixed_probe_batch(seed=heldout_seed + 3)",
            "hidden_state_tensors_exported": [ORIENTATION_HEAD_INTERPOLATION_HIDDEN_STATE_TENSOR_NAME],
            "linear_probe_form": ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_FORM,
            "linear_probe_target": ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_TARGET,
            "linear_probe_ridge_lambda": ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_RIDGE_LAMBDA,
            "linear_probe_train_eval_disjoint": True,
            "selection_uses_auxiliary_only": True,
            "global_alpha_selection_once": True,
            "no_optimization": True,
            "bootstrap_seed": ORIENTATION_HEAD_INTERPOLATION_BOOTSTRAP_SEED,
            "bootstrap_resamples": ORIENTATION_HEAD_INTERPOLATION_BOOTSTRAP_RESAMPLES,
            "no_sweep": True,
            "no_second_package": True,
            "no_harder_evaluation": True,
            "oracle_precision_mode": "neutral_zero_logit" if resolved_config.context.use_precision else "disabled",
        },
    )

    predictor = CausalContextPredictor(resolved_config.geometry, resolved_config.context)
    train_history = train_context_predictor(
        predictor,
        train_batches,
        training_config,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )
    _write_json(run_dir / ORIENTATION_HEAD_INTERPOLATION_PRETRAIN_HISTORY_ARTIFACT, [asdict(item) for item in train_history])
    pre_parameter_snapshot = _linear_probe_transplant_parameter_scope_snapshot(predictor)
    with torch.no_grad():
        _, donor_fit_hidden_states = _predict_with_hidden_states(predictor, donor_fit_batch)
        donor_linear_probe = _standard_end_fit_linear_probe(
            hidden_states=donor_fit_hidden_states,
            batch=donor_fit_batch,
        )
    base_head_state = {
        "weight": predictor.orientation_head.weight.detach().cpu().clone(),
        "bias": predictor.orientation_head.bias.detach().cpu().clone(),
    }
    donor_head_state = {
        "weight": donor_linear_probe["weight"].transpose(0, 1).detach().cpu().clone(),
        "bias": donor_linear_probe["bias"].detach().cpu().clone(),
    }
    _write_json(
        run_dir / ORIENTATION_HEAD_INTERPOLATION_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT,
        {
            **_orientation_head_interpolation_metadata(
                metric_versions={"parameter_scope_fingerprints": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "run_id": manifest.run_id,
            "parameter_update_scope": list(ORIENTATION_HEAD_INTERPOLATION_PARAM_UPDATE_SCOPE),
            "pre_interpolation": pre_parameter_snapshot,
            "post_interpolation": None,
            "checks": {},
        },
    )
    pre_checkpoint = _orientation_head_interpolation_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        donor_fit_batch=donor_fit_batch,
        predictive_rehearsal_batch=predictive_rehearsal_batch,
        fixed_probe_selection_batch=fixed_probe_selection_batch,
        run_id=manifest.run_id,
        run_dir=run_dir,
        checkpoint_dirname=ORIENTATION_HEAD_INTERPOLATION_PRE_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        donor_linear_probe=donor_linear_probe,
        save_interpolation_outputs=False,
    )
    _write_stage0_provenance(store=store, run_dir=run_dir, manifest=manifest, resolved_config=resolved_config)
    return {
        "run_id": manifest.run_id,
        "run_dir": run_dir,
        "seed_panel": seed_panel,
        "train_seed": int(train_seed),
        "heldout_seed": int(heldout_seed),
        "donor_fit_seed": int(donor_fit_seed),
        "predictive_rehearsal_seed": int(predictive_rehearsal_seed),
        "fixed_probe_selection_seed": int(fixed_probe_selection_seed),
        "predictor": predictor,
        "generator": generator,
        "model": model,
        "assay_runner": assay_runner,
        "resolved_config": resolved_config,
        "heldout_batch": heldout_batch,
        "donor_fit_batch": donor_fit_batch,
        "predictive_rehearsal_batch": predictive_rehearsal_batch,
        "fixed_probe_selection_batch": fixed_probe_selection_batch,
        "pre_interpolation": pre_checkpoint,
        "pre_parameter_snapshot": pre_parameter_snapshot,
        "base_head_state": base_head_state,
        "donor_head_state": donor_head_state,
        "donor_linear_probe": donor_linear_probe,
    }


def _orientation_head_interpolation_predictive_rehearsal_metrics(
    *,
    batch: TrialBatch,
    orientation_logits: torch.Tensor,
) -> dict[str, float]:
    losses = predictive_loss(
        ContextPrediction(orientation_logits=orientation_logits, precision_logit=None),
        batch,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )
    return {
        "predictive_loss": float(losses.predictive_loss.item()),
    }


def _orientation_head_interpolation_selection_probe_metrics(
    *,
    run_id: str,
    batch: TrialBatch,
    orientation_logits: torch.Tensor,
    precision_logit: torch.Tensor | None,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    resolved_config: ExperimentConfig,
) -> dict[str, object]:
    bundle = _orientation_head_interpolation_probe_bundle(
        run_id=run_id,
        batch=batch,
        learned_prediction=ContextPrediction(
            orientation_logits=orientation_logits,
            precision_logit=precision_logit,
        ),
        model=model,
        assay_runner=assay_runner,
        resolved_config=resolved_config,
    )
    latent = float(bundle["probe_metrics"]["probe_target_aligned_specificity_contrast"])
    pooled = float(bundle["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"])
    oracle_latent = float(bundle["oracle_probe_metrics"]["probe_target_aligned_specificity_contrast"])
    latent_ratio = _stage4_probe_ratio(latent, oracle_latent)
    learned_symmetry = (
        float(bundle["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]) >= 1.0
    )
    no_sign_reversal = _stage4_no_sign_reversal(latent, pooled)
    diagnostics = bundle["hidden_state_diagnostics"]
    conditions = {
        "latent_positive": latent > 0.0,
        "pooled_positive": pooled > 0.0,
        "learned_symmetry_consistency": learned_symmetry,
        "no_latent_pooled_sign_reversal": no_sign_reversal,
        "learned_oracle_latent_ratio_ge_0_25": latent_ratio is not None and latent_ratio >= ORIENTATION_HEAD_INTERPOLATION_ANCHOR_LATENT_RATIO_FLOOR,
        "alignment_kl_le_0_75": float(bundle["probe_context_alignment_report"]["learned_probe_alignment_kl"])
        <= ORIENTATION_HEAD_INTERPOLATION_STRONG_ALIGNMENT_KL_MAX,
        "expected_target_top1_ge_0_75": float(
            bundle["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"]
        ) >= ORIENTATION_HEAD_INTERPOLATION_STRONG_EXPECTED_TARGET_TOP1_MIN,
        "correct_pair_flip_ge_0_75": float(diagnostics["probe_correct_pair_flip_rate__v2"])
        >= ORIENTATION_HEAD_INTERPOLATION_STRONG_CORRECT_PAIR_FLIP_RATE_MIN,
        "within_pair_mass_ge_0_40": float(diagnostics["probe_within_pair_mass__v2"])
        >= ORIENTATION_HEAD_INTERPOLATION_STRONG_WITHIN_PAIR_MASS_MIN,
        "source_bin_kl_ge_2_00": float(diagnostics["probe_source_bin_kl__v2"])
        >= ORIENTATION_HEAD_INTERPOLATION_STRONG_SOURCE_BIN_KL_MIN,
    }
    return {
        "probe_metrics": bundle["probe_metrics"],
        "oracle_probe_metrics": bundle["oracle_probe_metrics"],
        "probe_context_alignment_report": bundle["probe_context_alignment_report"],
        "hidden_state_diagnostics": diagnostics,
        "conditions": conditions,
        "aggregate_condition_score": sum(int(value) for value in conditions.values()),
        "learned_oracle_latent_ratio": latent_ratio,
    }


def _orientation_head_interpolation_selection_sort_key(candidate_payload: dict[str, object]) -> tuple[float, float, float, float]:
    return (
        -float(candidate_payload["aggregate_score"]),
        -float(candidate_payload["mean_aux_fixed_probe_expected_target_top1"]),
        float(candidate_payload["mean_aux_fixed_probe_alignment_kl"]),
        float(candidate_payload["alpha"]),
    )


def _orientation_head_interpolation_select_alpha_payload(
    candidates: list[dict[str, object]],
) -> dict[str, object]:
    feasible_candidates = [candidate for candidate in candidates if bool(candidate["feasible"])]
    if not feasible_candidates:
        return {
            "selected_alpha": None,
            "no_feasible_alpha": True,
            "selected_candidate": None,
            "candidates": candidates,
        }
    selected_candidate = min(feasible_candidates, key=_orientation_head_interpolation_selection_sort_key)
    selected_alpha = float(selected_candidate["alpha"])
    best_score = int(selected_candidate["aggregate_score"])
    best_top1 = float(selected_candidate["mean_aux_fixed_probe_expected_target_top1"])
    best_kl = float(selected_candidate["mean_aux_fixed_probe_alignment_kl"])
    for candidate in candidates:
        if float(candidate["alpha"]) == selected_alpha:
            candidate["selected"] = True
            candidate["elimination_reason"] = None
            continue
        candidate["selected"] = False
        if not bool(candidate["feasible"]):
            candidate["elimination_reason"] = "predictive_feasibility_failed"
        elif int(candidate["aggregate_score"]) < best_score:
            candidate["elimination_reason"] = "lower_aggregate_score"
        elif float(candidate["mean_aux_fixed_probe_expected_target_top1"]) < best_top1:
            candidate["elimination_reason"] = "lower_mean_aux_fixed_probe_expected_target_top1"
        elif float(candidate["mean_aux_fixed_probe_alignment_kl"]) > best_kl:
            candidate["elimination_reason"] = "higher_mean_aux_fixed_probe_alignment_kl"
        else:
            candidate["elimination_reason"] = "larger_alpha_tiebreak"
    return {
        "selected_alpha": selected_alpha,
        "no_feasible_alpha": False,
        "selected_candidate": selected_candidate,
        "candidates": candidates,
    }


def _orientation_head_interpolation_build_selection_table(
    *,
    prepared_runs: list[dict[str, object]],
) -> dict[str, object]:
    candidates: list[dict[str, object]] = []
    for alpha in ORIENTATION_HEAD_INTERPOLATION_CANDIDATE_SET:
        per_seed: list[dict[str, object]] = []
        predictive_feasible_all = True
        aggregate_score = 0
        top1_values: list[float] = []
        alignment_values: list[float] = []
        for prepared_run in prepared_runs:
            base_weight = prepared_run["base_head_state"]["weight"]
            base_bias = prepared_run["base_head_state"]["bias"]
            donor_weight = prepared_run["donor_head_state"]["weight"]
            donor_bias = prepared_run["donor_head_state"]["bias"]
            interpolated_state = _orientation_head_interpolation_state_for_alpha(
                base_weight=base_weight,
                base_bias=base_bias,
                donor_weight=donor_weight,
                donor_bias=donor_bias,
                alpha=float(alpha),
            )
            predictive_logits = _orientation_head_interpolation_apply_head(
                prepared_run["pre_interpolation"]["predictive_hidden_states"],
                interpolated_state["weight"],
                interpolated_state["bias"],
            )
            predictive_metrics = _orientation_head_interpolation_predictive_rehearsal_metrics(
                batch=prepared_run["predictive_rehearsal_batch"],
                orientation_logits=predictive_logits,
            )
            predictive_baseline = prepared_run["pre_interpolation"]["predictive_metrics"]
            predictive_sanity = prepared_run["pre_interpolation"]["predictive_sanity"]
            predictive_checks = {
                "delta_predictive_loss_le_0_05": (
                    float(predictive_metrics["predictive_loss"]) - float(predictive_baseline["predictive_loss"])
                    <= ORIENTATION_HEAD_INTERPOLATION_PREDICTIVE_LOSS_DELTA_MAX
                ),
                "delta_predictive_structure_accuracy_ge_minus_0_05": True,
                "delta_nuisance_only_accuracy_le_0_05": True,
                "nuisance_only_accuracy_post_lt_0_5": (
                    float(predictive_sanity["nuisance_only"]["accuracy"]) < ORIENTATION_HEAD_INTERPOLATION_NUISANCE_ONLY_POST_MAX
                ),
            }
            predictive_feasible = all(bool(value) for value in predictive_checks.values())
            predictive_feasible_all = predictive_feasible_all and predictive_feasible

            selection_logits = _orientation_head_interpolation_apply_head(
                prepared_run["pre_interpolation"]["selection_hidden_states"],
                interpolated_state["weight"],
                interpolated_state["bias"],
            )
            selection_metrics = _orientation_head_interpolation_selection_probe_metrics(
                run_id=str(prepared_run["run_id"]),
                batch=prepared_run["fixed_probe_selection_batch"],
                orientation_logits=selection_logits,
                precision_logit=prepared_run["pre_interpolation"]["selection_precision_logit"],
                model=prepared_run["model"],
                assay_runner=prepared_run["assay_runner"],
                resolved_config=prepared_run["resolved_config"],
            )
            aggregate_score += int(selection_metrics["aggregate_condition_score"])
            top1_values.append(
                float(selection_metrics["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"])
            )
            alignment_values.append(float(selection_metrics["probe_context_alignment_report"]["learned_probe_alignment_kl"]))
            per_seed.append(
                {
                    "run_id": prepared_run["run_id"],
                    "train_seed": int(prepared_run["train_seed"]),
                    "heldout_seed": int(prepared_run["heldout_seed"]),
                    "donor_fit_seed": int(prepared_run["donor_fit_seed"]),
                    "predictive_rehearsal_seed": int(prepared_run["predictive_rehearsal_seed"]),
                    "fixed_probe_selection_seed": int(prepared_run["fixed_probe_selection_seed"]),
                    "predictive_rehearsal": {
                        "predictive_loss_pre": float(predictive_baseline["predictive_loss"]),
                        "predictive_loss_post": float(predictive_metrics["predictive_loss"]),
                        "delta_predictive_loss": float(predictive_metrics["predictive_loss"]) - float(predictive_baseline["predictive_loss"]),
                        "predictive_structure_accuracy_pre": float(
                            predictive_sanity["predictive_structure"]["accuracy"]
                        ),
                        "predictive_structure_accuracy_post": float(
                            predictive_sanity["predictive_structure"]["accuracy"]
                        ),
                        "delta_predictive_structure_accuracy": 0.0,
                        "nuisance_only_accuracy_pre": float(predictive_sanity["nuisance_only"]["accuracy"]),
                        "nuisance_only_accuracy_post": float(predictive_sanity["nuisance_only"]["accuracy"]),
                        "delta_nuisance_only_accuracy": 0.0,
                        "checks": predictive_checks,
                        "feasible": predictive_feasible,
                    },
                    "fixed_probe_selection": {
                        "probe_target_aligned_specificity_contrast": float(
                            selection_metrics["probe_metrics"]["probe_target_aligned_specificity_contrast"]
                        ),
                        "probe_pooled_target_aligned_specificity_contrast": float(
                            selection_metrics["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"]
                        ),
                        "learned_oracle_latent_ratio": selection_metrics["learned_oracle_latent_ratio"],
                        "learned_probe_alignment_kl": float(
                            selection_metrics["probe_context_alignment_report"]["learned_probe_alignment_kl"]
                        ),
                        "learned_probe_expected_target_top1_rate": float(
                            selection_metrics["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"]
                        ),
                        "probe_correct_pair_flip_rate__v2": float(
                            selection_metrics["hidden_state_diagnostics"]["probe_correct_pair_flip_rate__v2"]
                        ),
                        "probe_within_pair_mass__v2": float(
                            selection_metrics["hidden_state_diagnostics"]["probe_within_pair_mass__v2"]
                        ),
                        "probe_source_bin_kl__v2": float(
                            selection_metrics["hidden_state_diagnostics"]["probe_source_bin_kl__v2"]
                        ),
                        "conditions": selection_metrics["conditions"],
                        "aggregate_condition_score": int(selection_metrics["aggregate_condition_score"]),
                    },
                }
            )
        candidates.append(
            {
                "alpha": float(alpha),
                "feasible": bool(predictive_feasible_all),
                "aggregate_score": int(aggregate_score),
                "mean_aux_fixed_probe_expected_target_top1": _stage4_mean(top1_values),
                "mean_aux_fixed_probe_alignment_kl": _stage4_mean(alignment_values),
                "per_seed": per_seed,
            }
        )
    selection = _orientation_head_interpolation_select_alpha_payload(candidates)
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={"interpolation_selection_table": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "candidate_set": [float(alpha) for alpha in ORIENTATION_HEAD_INTERPOLATION_CANDIDATE_SET],
        "selection_rule": {
            "predictive_feasibility_filter": [
                "delta_predictive_loss <= 0.05 in 5/5",
                "delta_predictive_structure_accuracy >= -0.05 in 5/5",
                "delta_nuisance_only_accuracy <= 0.05 in 5/5",
                "nuisance_only_accuracy_post < 0.5 in 5/5",
            ],
            "aggregate_score": "sum across 5 primary seeds x 10 binary fixed-probe conditions",
            "tie_break_order": [
                "higher mean auxiliary fixed-probe expected-target top1",
                "lower mean auxiliary fixed-probe alignment KL",
                "smaller alpha",
            ],
        },
        "heldout_eval_not_used_in_selection": True,
        "selection_uses_auxiliary_only": True,
        "global_alpha_selection_once": True,
        "candidates": selection["candidates"],
        "selected_alpha": selection["selected_alpha"],
        "no_feasible_alpha": selection["no_feasible_alpha"],
    }


def _orientation_head_interpolation_apply_alpha(
    *,
    predictor: CausalContextPredictor,
    base_head_state: dict[str, torch.Tensor],
    donor_head_state: dict[str, torch.Tensor],
    alpha: float,
    run_dir: Path,
) -> dict[str, object]:
    interpolated_state = _orientation_head_interpolation_state_for_alpha(
        base_weight=base_head_state["weight"],
        base_bias=base_head_state["bias"],
        donor_weight=donor_head_state["weight"],
        donor_bias=donor_head_state["bias"],
        alpha=float(alpha),
    )
    with torch.no_grad():
        predictor.orientation_head.weight.copy_(interpolated_state["weight"].to(dtype=predictor.orientation_head.weight.dtype))
        predictor.orientation_head.bias.copy_(interpolated_state["bias"].to(dtype=predictor.orientation_head.bias.dtype))
    copied_weight = predictor.orientation_head.weight.detach().cpu()
    copied_bias = predictor.orientation_head.bias.detach().cpu()
    max_abs_weight_diff = float((copied_weight - interpolated_state["weight"]).abs().max().item())
    max_abs_bias_diff = float((copied_bias - interpolated_state["bias"]).abs().max().item())
    torch.save(
        {
            "selected_alpha": float(alpha),
            "weight": copied_weight,
            "bias": copied_bias,
            "base_weight": base_head_state["weight"],
            "base_bias": base_head_state["bias"],
            "donor_weight": donor_head_state["weight"],
            "donor_bias": donor_head_state["bias"],
        },
        run_dir / ORIENTATION_HEAD_INTERPOLATION_STATE_ARTIFACT,
    )
    return {
        "selected_alpha": float(alpha),
        "selected_head_matches_formula": max_abs_weight_diff == 0.0 and max_abs_bias_diff == 0.0,
        "max_abs_weight_diff_after_copy": max_abs_weight_diff,
        "max_abs_bias_diff_after_copy": max_abs_bias_diff,
    }


def _orientation_head_interpolation_complete_run(
    prepared_run: dict[str, object],
    *,
    selected_alpha: float,
    selection_table: dict[str, object],
) -> dict[str, object]:
    predictor = prepared_run["predictor"]
    run_dir = prepared_run["run_dir"]
    interpolation_report = _orientation_head_interpolation_apply_alpha(
        predictor=predictor,
        base_head_state=prepared_run["base_head_state"],
        donor_head_state=prepared_run["donor_head_state"],
        alpha=float(selected_alpha),
        run_dir=run_dir,
    )
    post_parameter_snapshot = _linear_probe_transplant_parameter_scope_snapshot(predictor)
    post_checkpoint = _orientation_head_interpolation_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=prepared_run["heldout_batch"],
        donor_fit_batch=prepared_run["donor_fit_batch"],
        predictive_rehearsal_batch=prepared_run["predictive_rehearsal_batch"],
        fixed_probe_selection_batch=prepared_run["fixed_probe_selection_batch"],
        run_id=prepared_run["run_id"],
        run_dir=run_dir,
        checkpoint_dirname=ORIENTATION_HEAD_INTERPOLATION_POST_CHECKPOINT_DIRNAME,
        model=prepared_run["model"],
        assay_runner=prepared_run["assay_runner"],
        generator=prepared_run["generator"],
        resolved_config=prepared_run["resolved_config"],
        donor_linear_probe=prepared_run["donor_linear_probe"],
        save_interpolation_outputs=True,
        selected_alpha=float(selected_alpha),
    )
    pre_checkpoint = prepared_run["pre_interpolation"]
    heldout_hidden_state_max_abs_diff = float(
        (pre_checkpoint["heldout_hidden_states"] - post_checkpoint["heldout_hidden_states"]).abs().max().item()
    )
    donor_fit_hidden_state_max_abs_diff = float(
        (pre_checkpoint["donor_fit_hidden_states"] - post_checkpoint["donor_fit_hidden_states"]).abs().max().item()
    )
    predictive_hidden_state_max_abs_diff = float(
        (pre_checkpoint["predictive_hidden_states"] - post_checkpoint["predictive_hidden_states"]).abs().max().item()
    )
    selection_hidden_state_max_abs_diff = float(
        (pre_checkpoint["selection_hidden_states"] - post_checkpoint["selection_hidden_states"]).abs().max().item()
    )
    integrity = {
        "heldout_batch_identity_same_pre_post": int(pre_checkpoint["heldout_generator_seed"]) == int(post_checkpoint["heldout_generator_seed"]),
        "donor_fit_batch_identity_same_pre_post": int(pre_checkpoint["donor_fit_generator_seed"]) == int(post_checkpoint["donor_fit_generator_seed"]),
        "predictive_rehearsal_batch_identity_same_pre_post": int(
            pre_checkpoint["predictive_rehearsal_generator_seed"]
        ) == int(post_checkpoint["predictive_rehearsal_generator_seed"]),
        "fixed_probe_selection_batch_identity_same_pre_post": int(
            pre_checkpoint["fixed_probe_selection_generator_seed"]
        ) == int(post_checkpoint["fixed_probe_selection_generator_seed"]),
        "all_batch_identities_disjoint": len(
            {
                int(prepared_run["heldout_seed"]),
                int(prepared_run["donor_fit_seed"]),
                int(prepared_run["predictive_rehearsal_seed"]),
                int(prepared_run["fixed_probe_selection_seed"]),
            }
        ) == 4,
        "recurrent_core_parameter_fingerprint_unchanged": (
            prepared_run["pre_parameter_snapshot"]["recurrent_core_fingerprint"]
            == post_parameter_snapshot["recurrent_core_fingerprint"]
        ),
        "precision_head_parameter_fingerprint_unchanged": (
            prepared_run["pre_parameter_snapshot"]["precision_head_fingerprint"]
            == post_parameter_snapshot["precision_head_fingerprint"]
        ),
        "orientation_head_parameter_fingerprint_changed": (
            prepared_run["pre_parameter_snapshot"]["orientation_head_fingerprint"]
            != post_parameter_snapshot["orientation_head_fingerprint"]
        ),
        "heldout_hidden_states_unchanged": bool(
            torch.allclose(
                pre_checkpoint["heldout_hidden_states"],
                post_checkpoint["heldout_hidden_states"],
                atol=ORIENTATION_HEAD_INTERPOLATION_HIDDEN_STATE_ATOL,
                rtol=0.0,
            )
        ),
        "donor_fit_hidden_states_unchanged": bool(
            torch.allclose(
                pre_checkpoint["donor_fit_hidden_states"],
                post_checkpoint["donor_fit_hidden_states"],
                atol=ORIENTATION_HEAD_INTERPOLATION_HIDDEN_STATE_ATOL,
                rtol=0.0,
            )
        ),
        "predictive_rehearsal_hidden_states_unchanged": bool(
            torch.allclose(
                pre_checkpoint["predictive_hidden_states"],
                post_checkpoint["predictive_hidden_states"],
                atol=ORIENTATION_HEAD_INTERPOLATION_HIDDEN_STATE_ATOL,
                rtol=0.0,
            )
        ),
        "fixed_probe_selection_hidden_states_unchanged": bool(
            torch.allclose(
                pre_checkpoint["selection_hidden_states"],
                post_checkpoint["selection_hidden_states"],
                atol=ORIENTATION_HEAD_INTERPOLATION_HIDDEN_STATE_ATOL,
                rtol=0.0,
            )
        ),
        "heldout_hidden_state_max_abs_diff": heldout_hidden_state_max_abs_diff,
        "donor_fit_hidden_state_max_abs_diff": donor_fit_hidden_state_max_abs_diff,
        "predictive_rehearsal_hidden_state_max_abs_diff": predictive_hidden_state_max_abs_diff,
        "fixed_probe_selection_hidden_state_max_abs_diff": selection_hidden_state_max_abs_diff,
        "selected_head_matches_interpolation_formula": bool(interpolation_report["selected_head_matches_formula"]),
        "predictive_feasibility_filter_recorded": bool(selection_table["candidates"]),
        "alpha_selection_table_recorded": selection_table["selected_alpha"] is not None,
        "no_optimization": True,
        "optimization_steps": 0,
        "predictive_loss_pre": float(pre_checkpoint["predictive_metrics"]["predictive_loss"]),
        "predictive_loss_post": float(post_checkpoint["predictive_metrics"]["predictive_loss"]),
        "predictive_structure_accuracy_pre": float(pre_checkpoint["predictive_sanity"]["predictive_structure"]["accuracy"]),
        "predictive_structure_accuracy_post": float(post_checkpoint["predictive_sanity"]["predictive_structure"]["accuracy"]),
        "nuisance_only_accuracy_pre": float(pre_checkpoint["predictive_sanity"]["nuisance_only"]["accuracy"]),
        "nuisance_only_accuracy_post": float(post_checkpoint["predictive_sanity"]["nuisance_only"]["accuracy"]),
        "selected_alpha": float(selected_alpha),
    }
    integrity["delta_predictive_loss"] = integrity["predictive_loss_post"] - integrity["predictive_loss_pre"]
    integrity["delta_predictive_structure_accuracy"] = (
        integrity["predictive_structure_accuracy_post"] - integrity["predictive_structure_accuracy_pre"]
    )
    integrity["delta_nuisance_only_accuracy"] = (
        integrity["nuisance_only_accuracy_post"] - integrity["nuisance_only_accuracy_pre"]
    )
    integrity["predictive_nonregression_passes"] = (
        integrity["delta_predictive_loss"] <= ORIENTATION_HEAD_INTERPOLATION_PREDICTIVE_LOSS_DELTA_MAX
        and integrity["delta_predictive_structure_accuracy"] >= ORIENTATION_HEAD_INTERPOLATION_PREDICTIVE_STRUCTURE_DELTA_MIN
        and integrity["delta_nuisance_only_accuracy"] <= ORIENTATION_HEAD_INTERPOLATION_NUISANCE_ONLY_DELTA_MAX
        and integrity["nuisance_only_accuracy_post"] < ORIENTATION_HEAD_INTERPOLATION_NUISANCE_ONLY_POST_MAX
    )
    parameter_scope_payload = {
        **_orientation_head_interpolation_metadata(
            metric_versions={"parameter_scope_fingerprints": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": prepared_run["run_id"],
        "parameter_update_scope": list(ORIENTATION_HEAD_INTERPOLATION_PARAM_UPDATE_SCOPE),
        "pre_interpolation": prepared_run["pre_parameter_snapshot"],
        "post_interpolation": post_parameter_snapshot,
        "checks": {
            "recurrent_core_parameter_fingerprint_unchanged": integrity["recurrent_core_parameter_fingerprint_unchanged"],
            "precision_head_parameter_fingerprint_unchanged": integrity["precision_head_parameter_fingerprint_unchanged"],
            "orientation_head_parameter_fingerprint_changed": integrity["orientation_head_parameter_fingerprint_changed"],
            "selected_head_matches_interpolation_formula": integrity["selected_head_matches_interpolation_formula"],
            "no_optimization": True,
        },
    }
    _write_json(run_dir / ORIENTATION_HEAD_INTERPOLATION_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT, parameter_scope_payload)
    return {
        "run_id": prepared_run["run_id"],
        "run_dir": run_dir,
        "seed_panel": prepared_run["seed_panel"],
        "train_seed": int(prepared_run["train_seed"]),
        "heldout_seed": int(prepared_run["heldout_seed"]),
        "auxiliary_probe_fit_seed": int(prepared_run["donor_fit_seed"]),
        "donor_fit_seed": int(prepared_run["donor_fit_seed"]),
        "predictive_rehearsal_seed": int(prepared_run["predictive_rehearsal_seed"]),
        "fixed_probe_selection_seed": int(prepared_run["fixed_probe_selection_seed"]),
        "selected_alpha": float(selected_alpha),
        "pre_interpolation": {
            key: value
            for key, value in pre_checkpoint.items()
            if key
            not in (
                "heldout_hidden_states",
                "donor_fit_hidden_states",
                "predictive_hidden_states",
                "selection_hidden_states",
                "heldout_precision_logit",
                "predictive_precision_logit",
                "selection_precision_logit",
                "heldout_native_orientation_logits",
                "heldout_linear_probe_logits",
            )
        },
        "post_interpolation": {
            key: value
            for key, value in post_checkpoint.items()
            if key
            not in (
                "heldout_hidden_states",
                "donor_fit_hidden_states",
                "predictive_hidden_states",
                "selection_hidden_states",
                "heldout_precision_logit",
                "predictive_precision_logit",
                "selection_precision_logit",
                "heldout_native_orientation_logits",
                "heldout_linear_probe_logits",
            )
        },
        "interpolation_integrity": integrity,
        "interpolation_state_report": interpolation_report,
        "artifacts_complete": True,
    }


def _orientation_head_interpolation_build_skipped_panel_report(
    *,
    artifact_key: str,
    seed_panel: str,
    stop_reason: str,
) -> dict[str, object]:
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={artifact_key: "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "skipped": True,
        "stop_reason": stop_reason,
        "passes": False,
    }


def _orientation_head_interpolation_predictive_integrity_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = len(run_entries)
    seedwise: list[dict[str, object]] = []
    loss_checks: list[bool] = []
    structure_checks: list[bool] = []
    nuisance_delta_checks: list[bool] = []
    nuisance_post_checks: list[bool] = []
    for entry in run_entries:
        integrity = entry["interpolation_integrity"]
        loss_check = integrity["delta_predictive_loss"] <= ORIENTATION_HEAD_INTERPOLATION_PREDICTIVE_LOSS_DELTA_MAX
        structure_check = (
            integrity["delta_predictive_structure_accuracy"] >= ORIENTATION_HEAD_INTERPOLATION_PREDICTIVE_STRUCTURE_DELTA_MIN
        )
        nuisance_delta_check = (
            integrity["delta_nuisance_only_accuracy"] <= ORIENTATION_HEAD_INTERPOLATION_NUISANCE_ONLY_DELTA_MAX
        )
        nuisance_post_check = integrity["nuisance_only_accuracy_post"] < ORIENTATION_HEAD_INTERPOLATION_NUISANCE_ONLY_POST_MAX
        loss_checks.append(loss_check)
        structure_checks.append(structure_check)
        nuisance_delta_checks.append(nuisance_delta_check)
        nuisance_post_checks.append(nuisance_post_check)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "delta_predictive_loss": float(integrity["delta_predictive_loss"]),
                "delta_predictive_structure_accuracy": float(integrity["delta_predictive_structure_accuracy"]),
                "delta_nuisance_only_accuracy": float(integrity["delta_nuisance_only_accuracy"]),
                "nuisance_only_accuracy_post": float(integrity["nuisance_only_accuracy_post"]),
            }
        )
    checks = {
        "required_successes": required_successes,
        "delta_predictive_loss_le_0_05_count": _stage4_count_true(loss_checks),
        "delta_predictive_structure_accuracy_ge_minus_0_05_count": _stage4_count_true(structure_checks),
        "delta_nuisance_only_accuracy_le_0_05_count": _stage4_count_true(nuisance_delta_checks),
        "nuisance_only_accuracy_post_lt_0_5_count": _stage4_count_true(nuisance_post_checks),
    }
    checks["passes"] = all(value >= required_successes for key, value in checks.items() if key.endswith("_count"))
    return {
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "summary": {
            "mean_delta_predictive_loss": _stage4_mean([float(item["delta_predictive_loss"]) for item in seedwise]),
            "mean_delta_predictive_structure_accuracy": _stage4_mean(
                [float(item["delta_predictive_structure_accuracy"]) for item in seedwise]
            ),
            "mean_delta_nuisance_only_accuracy": _stage4_mean(
                [float(item["delta_nuisance_only_accuracy"]) for item in seedwise]
            ),
            "mean_nuisance_only_accuracy_post": _stage4_mean(
                [float(item["nuisance_only_accuracy_post"]) for item in seedwise]
            ),
        },
        "checks": checks,
        "passes": bool(checks["passes"]),
    }


def _orientation_head_interpolation_build_pre_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    native_anchor_summary = _linear_probe_transplant_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_interpolation",
    )
    linear_probe_summary = _linear_probe_transplant_linear_probe_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_interpolation",
    )
    delta_summary = _linear_probe_transplant_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_interpolation",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "native_anchor_fails": not native_anchor_summary["passes"],
        "linear_probe_strong_gate_passes": bool(linear_probe_summary["passes"]),
        "mean_top1_improvement_ge_0_25": (
            delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"] is not None
            and float(delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"])
            >= ORIENTATION_HEAD_INTERPOLATION_TOP1_IMPROVEMENT_MIN
        ),
        "top1_improvement_ci_lower_gt_0": top1_ci is not None and float(top1_ci["lower"]) > 0.0,
        "mean_kl_reduction_ge_0_50": (
            delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"] is not None
            and float(delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"])
            >= ORIENTATION_HEAD_INTERPOLATION_KL_REDUCTION_MIN
        ),
        "kl_reduction_ci_lower_gt_0": kl_ci is not None and float(kl_ci["lower"]) > 0.0,
    }
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={"pre_interpolation_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "linear_probe_summary": linear_probe_summary,
        "interpolation_gap_summary": delta_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _orientation_head_interpolation_build_integrity_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = len(run_entries)
    seedwise: list[dict[str, object]] = []
    boolean_fields = {
        "heldout_batch_identity_same_pre_post": [],
        "donor_fit_batch_identity_same_pre_post": [],
        "predictive_rehearsal_batch_identity_same_pre_post": [],
        "fixed_probe_selection_batch_identity_same_pre_post": [],
        "all_batch_identities_disjoint": [],
        "recurrent_core_parameter_fingerprint_unchanged": [],
        "precision_head_parameter_fingerprint_unchanged": [],
        "heldout_hidden_states_unchanged": [],
        "selected_head_matches_interpolation_formula": [],
        "predictive_feasibility_filter_recorded": [],
        "alpha_selection_table_recorded": [],
        "no_optimization": [],
        "predictive_nonregression_passes": [],
    }
    for entry in run_entries:
        integrity = entry["interpolation_integrity"]
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "selected_alpha": float(entry["selected_alpha"]),
                **integrity,
                "interpolation_state_report": entry["interpolation_state_report"],
            }
        )
        for key in boolean_fields:
            boolean_fields[key].append(bool(integrity[key]))
    checks = {
        "required_successes": required_successes,
        "heldout_batch_identity_same_pre_post_count": _stage4_count_true(boolean_fields["heldout_batch_identity_same_pre_post"]),
        "donor_fit_batch_identity_same_pre_post_count": _stage4_count_true(boolean_fields["donor_fit_batch_identity_same_pre_post"]),
        "predictive_rehearsal_batch_identity_same_pre_post_count": _stage4_count_true(boolean_fields["predictive_rehearsal_batch_identity_same_pre_post"]),
        "fixed_probe_selection_batch_identity_same_pre_post_count": _stage4_count_true(boolean_fields["fixed_probe_selection_batch_identity_same_pre_post"]),
        "all_batch_identities_disjoint_count": _stage4_count_true(boolean_fields["all_batch_identities_disjoint"]),
        "recurrent_core_parameter_fingerprint_unchanged_count": _stage4_count_true(boolean_fields["recurrent_core_parameter_fingerprint_unchanged"]),
        "precision_head_parameter_fingerprint_unchanged_count": _stage4_count_true(boolean_fields["precision_head_parameter_fingerprint_unchanged"]),
        "heldout_hidden_states_unchanged_count": _stage4_count_true(boolean_fields["heldout_hidden_states_unchanged"]),
        "selected_head_matches_interpolation_formula_count": _stage4_count_true(boolean_fields["selected_head_matches_interpolation_formula"]),
        "predictive_feasibility_filter_recorded_count": _stage4_count_true(boolean_fields["predictive_feasibility_filter_recorded"]),
        "alpha_selection_table_recorded_count": _stage4_count_true(boolean_fields["alpha_selection_table_recorded"]),
        "no_optimization_count": _stage4_count_true(boolean_fields["no_optimization"]),
        "predictive_nonregression_count": _stage4_count_true(boolean_fields["predictive_nonregression_passes"]),
    }
    checks["passes"] = all(value >= required_successes for key, value in checks.items() if key.endswith("_count"))
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={"interpolation_integrity_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "checks": checks,
        "passes": bool(checks["passes"]),
        "skipped": False,
    }


def _orientation_head_interpolation_build_post_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    native_anchor_summary = _linear_probe_transplant_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_interpolation",
    )
    native_strong_gate_summary = _linear_probe_transplant_native_strong_gate_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_interpolation",
    )
    predictive_integrity_summary = _orientation_head_interpolation_predictive_integrity_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
    )
    delta_summary = _linear_probe_transplant_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_interpolation",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    selected_alpha = None if not run_entries else float(run_entries[0]["selected_alpha"])
    checks = {
        "native_anchor_passes": bool(native_anchor_summary["passes"]),
        "native_strong_gate_passes": bool(native_strong_gate_summary["passes"]),
        "predictive_integrity_passes": bool(predictive_integrity_summary["passes"]),
        "no_material_linear_probe_top1_advantage": top1_ci is not None
        and float(top1_ci["upper"]) < ORIENTATION_HEAD_INTERPOLATION_TOP1_IMPROVEMENT_NO_ADVANTAGE_MAX,
        "no_material_linear_probe_kl_advantage": kl_ci is not None
        and float(kl_ci["upper"]) < ORIENTATION_HEAD_INTERPOLATION_KL_REDUCTION_NO_ADVANTAGE_MAX,
    }
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={"post_interpolation_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "selected_alpha": selected_alpha,
        "native_anchor_summary": native_anchor_summary,
        "native_strong_gate_summary": native_strong_gate_summary,
        "predictive_integrity_summary": predictive_integrity_summary,
        "interpolation_gap_summary": delta_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _orientation_head_interpolation_build_gap_report(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
) -> dict[str, object]:
    panels: dict[str, object] = {
        "pre_interpolation_primary": _linear_probe_transplant_delta_panel_summary(
            seed_panel="primary",
            run_entries=primary_run_entries,
            checkpoint_key="pre_interpolation",
        ),
    }
    post_primary_entries = [entry for entry in primary_run_entries if "post_interpolation" in entry]
    if post_primary_entries:
        panels["post_interpolation_primary"] = _linear_probe_transplant_delta_panel_summary(
            seed_panel="primary",
            run_entries=post_primary_entries,
            checkpoint_key="post_interpolation",
        )
    if confirmation_run_entries is not None:
        panels["pre_interpolation_confirmation"] = _linear_probe_transplant_delta_panel_summary(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            checkpoint_key="pre_interpolation",
        )
        post_confirmation_entries = [entry for entry in confirmation_run_entries if "post_interpolation" in entry]
        if post_confirmation_entries:
            panels["post_interpolation_confirmation"] = _linear_probe_transplant_delta_panel_summary(
                seed_panel="confirmation",
                run_entries=post_confirmation_entries,
                checkpoint_key="post_interpolation",
            )
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={
                "delta_alignment_kl__linear_minus_native": "v1",
                "alignment_kl_reduction__native_minus_linear": "v1",
                "delta_expected_target_top1_rate__linear_minus_native": "v1",
                "delta_correct_pair_flip_rate__v2__linear_minus_native": "v2",
                "delta_within_pair_mass__v2__linear_minus_native": "v2",
                "delta_source_bin_kl__v2__linear_minus_native": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "panels": panels,
        "skipped": False,
    }


def _orientation_head_interpolation_build_overall_confirmation_summary(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]],
) -> dict[str, object]:
    combined_entries = primary_run_entries + confirmation_run_entries
    latent_values: list[float] = []
    pooled_values: list[float] = []
    learned_symmetry_values: list[bool] = []
    latent_ratio_values: list[float | None] = []
    for entry in combined_entries:
        checkpoint = entry["post_interpolation"]
        latent = float(checkpoint["probe_metrics"]["probe_target_aligned_specificity_contrast"])
        pooled = float(checkpoint["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"])
        oracle_latent = float(checkpoint["oracle_probe_metrics"]["probe_target_aligned_specificity_contrast"])
        latent_ratio = _stage4_probe_ratio(latent, oracle_latent)
        learned_symmetry = (
            float(checkpoint["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]) >= 1.0
        )
        latent_values.append(latent)
        pooled_values.append(pooled)
        learned_symmetry_values.append(learned_symmetry)
        latent_ratio_values.append(latent_ratio)
    checks = {
        "latent_positive_count_ge_9_of_10": _stage4_count_true([value > 0.0 for value in latent_values]) >= 9,
        "pooled_positive_count_ge_9_of_10": _stage4_count_true([value > 0.0 for value in pooled_values]) >= 9,
        "learned_symmetry_consistency_count_ge_9_of_10": _stage4_count_true(learned_symmetry_values) >= 9,
        "learned_oracle_latent_ratio_ge_0_25_count_ge_9_of_10": _stage4_count_true(
            [value is not None and value >= ORIENTATION_HEAD_INTERPOLATION_ANCHOR_LATENT_RATIO_FLOOR for value in latent_ratio_values]
        ) >= 9,
    }
    return {
        "n_runs": len(combined_entries),
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
    }


def _orientation_head_interpolation_build_selection_skipped_report(
    *,
    stop_reason: str,
) -> dict[str, object]:
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={"interpolation_selection_table": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "candidate_set": [float(alpha) for alpha in ORIENTATION_HEAD_INTERPOLATION_CANDIDATE_SET],
        "candidates": [],
        "selected_alpha": None,
        "no_feasible_alpha": False,
        "selection_uses_auxiliary_only": True,
        "heldout_eval_not_used_in_selection": True,
        "global_alpha_selection_once": True,
        "skipped": True,
        "stop_reason": stop_reason,
    }


def _orientation_head_interpolation_build_verdict(
    *,
    nonregression_report: dict[str, object],
    pre_interpolation_primary_report: dict[str, object],
    interpolation_selection_table: dict[str, object],
    interpolation_integrity_primary_report: dict[str, object],
    post_interpolation_primary_report: dict[str, object],
    interpolation_integrity_confirmation_report: dict[str, object] | None,
    post_interpolation_confirmation_report: dict[str, object] | None,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
    confirmation_executed: bool,
) -> dict[str, object]:
    if not bool(nonregression_report["passes"]):
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "nonregression",
            "stop_gate": "R1 frozen non-regression",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not bool(pre_interpolation_primary_report["passes"]):
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "pre_interpolation_primary",
            "stop_gate": "R2 pre-interpolation premise reproduction",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if bool(interpolation_selection_table.get("skipped")):
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "selection_skipped",
            "stop_gate": "R3 interpolation integrity / anti-bypass",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if bool(interpolation_selection_table["no_feasible_alpha"]):
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "selection",
            "stop_gate": "no feasible alpha",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not bool(interpolation_integrity_primary_report["passes"]):
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "interpolation_integrity_primary",
            "stop_gate": "R3 interpolation integrity / anti-bypass",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not bool(post_interpolation_primary_report["passes"]):
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "post_interpolation_primary",
            "stop_gate": "R4 primary held-out success",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if not confirmation_executed:
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation_not_executed",
            "stop_gate": "R5 confirmation",
            "confirmation_executed": False,
            "package_complete": True,
        }
    if (
        interpolation_integrity_confirmation_report is None
        or not bool(interpolation_integrity_confirmation_report["passes"])
        or post_interpolation_confirmation_report is None
        or not bool(post_interpolation_confirmation_report["passes"])
        or confirmation_run_entries is None
    ):
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation",
            "stop_gate": "R5 confirmation",
            "confirmation_executed": True,
            "package_complete": True,
        }
    overall_summary = _orientation_head_interpolation_build_overall_confirmation_summary(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=confirmation_run_entries,
    )
    if not bool(overall_summary["passes"]):
        return {
            **_orientation_head_interpolation_metadata(
                metric_versions={"orientation_head_interpolation_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation",
            "stop_gate": "R5 confirmation overall closure",
            "confirmation_executed": True,
            "overall_summary": overall_summary,
            "package_complete": True,
        }
    return {
        **_orientation_head_interpolation_metadata(
            metric_versions={"orientation_head_interpolation_verdict": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "classification": "GO-orientation-head-compromise-aligned",
        "execution_valid": True,
        "stop_stage": None,
        "stop_gate": None,
        "confirmation_executed": True,
        "overall_summary": overall_summary,
        "selected_alpha": interpolation_selection_table["selected_alpha"],
        "package_complete": True,
    }


def run_orientation_head_interpolation_package(
    *,
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
    primary_seed_panel: tuple[tuple[int, int], ...] = STAGE3_PRIMARY_SEED_PANEL,
    confirmation_seed_panel: tuple[tuple[int, int], ...] = STAGE3_CONFIRMATION_SEED_PANEL,
    benchmark_artifacts_root: str | Path = "artifacts",
) -> OrientationHeadInterpolationRunResult:
    resolved_config = _resolve_config(config=config, preset_name=preset_name)
    if resolved_config.name != "phase1_core":
        raise ValueError("orientation_head_interpolation is frozen to the phase1_core configuration family.")

    output_root = (
        resolved_config.artifacts.root_dir
        / "orientation_head_interpolation"
        / ORIENTATION_HEAD_INTERPOLATION_PACKAGE_VERSION
    )
    output_root.mkdir(parents=True, exist_ok=True)
    training_config = _stage4_training_config(resolved_config)
    package_manifest = {
        **_orientation_head_interpolation_metadata(
            metric_versions={"orientation_head_interpolation_manifest": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "changed_files": ["src/lvc_expectation/runner.py"],
        "package_checkpoints": [
            ORIENTATION_HEAD_INTERPOLATION_PRE_CHECKPOINT_DIRNAME,
            ORIENTATION_HEAD_INTERPOLATION_POST_CHECKPOINT_DIRNAME,
        ],
        "pretraining": {
            "config_family": "phase1_core",
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "n_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "training_source": "ordinary generate_batch() only",
        },
        "candidate_set": [float(alpha) for alpha in ORIENTATION_HEAD_INTERPOLATION_CANDIDATE_SET],
        "selection_rule": {
            "description": "global alpha selected once from primary-panel auxiliary evidence only",
            "predictive_feasibility_filter": [
                "delta_predictive_loss <= 0.05 in 5/5",
                "delta_predictive_structure_accuracy >= -0.05 in 5/5",
                "delta_nuisance_only_accuracy <= 0.05 in 5/5",
                "nuisance_only_accuracy_post < 0.5 in 5/5",
            ],
            "fixed_probe_score": "sum across 5 seeds x 10 binary fixed-probe conditions",
            "tie_break_order": [
                "higher mean auxiliary fixed-probe expected-target top1",
                "lower mean auxiliary fixed-probe alignment KL",
                "smaller alpha",
            ],
        },
        "batch_identity_rules": {
            "heldout_eval_batch": "fixed_probe_batch(seed=heldout_seed)",
            "donor_fit_batch": "fixed_probe_batch(seed=heldout_seed + 1)",
            "predictive_rehearsal_batch": "predictive_batch(seed=heldout_seed + 2)",
            "fixed_probe_selection_batch": "fixed_probe_batch(seed=heldout_seed + 3)",
        },
        "linear_probe": {
            "form": ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_FORM,
            "target": ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_TARGET,
            "ridge_lambda": ORIENTATION_HEAD_INTERPOLATION_LINEAR_PROBE_RIDGE_LAMBDA,
            "fit_mask": "probe_step_mask & probe_valid_mask",
            "hidden_state_tensor_name": ORIENTATION_HEAD_INTERPOLATION_HIDDEN_STATE_TENSOR_NAME,
            "train_eval_split": "donor_fit_auxiliary_batch vs heldout_fixed_probe_batch",
        },
        "interpolation": {
            "formula": "W(alpha)=(1-alpha)W0 + alpha Wd; b(alpha)=(1-alpha)b0 + alpha bd",
            "parameter_update_scope": list(ORIENTATION_HEAD_INTERPOLATION_PARAM_UPDATE_SCOPE),
        },
        "bootstrap": {
            "seed": ORIENTATION_HEAD_INTERPOLATION_BOOTSTRAP_SEED,
            "resamples": ORIENTATION_HEAD_INTERPOLATION_BOOTSTRAP_RESAMPLES,
            "confidence_level": ORIENTATION_HEAD_INTERPOLATION_BOOTSTRAP_CONFIDENCE_LEVEL,
        },
        "seed_panels": {
            "primary": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in primary_seed_panel],
            "confirmation": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in confirmation_seed_panel],
        },
        "run_order": [
            "write_orientation_head_interpolation_manifest",
            "rerun_stage0_to_stage3_nonregression_checks",
            "run_primary_pre_interpolation_panel",
            "score_alpha_candidates_on_auxiliary_only_batches",
            "lock_global_alpha_once",
            "run_primary_post_interpolation_panel",
            "run_confirmation_panel_if_primary_passes",
            "write_orientation_head_interpolation_reports_and_verdict",
        ],
        "stop_rules": {
            "halt_on_nonregression_failure": True,
            "halt_on_pre_interpolation_premise_failure": True,
            "halt_on_interpolation_integrity_failure": True,
            "halt_if_no_feasible_alpha": True,
            "halt_on_primary_failure": True,
            "confirmation_only_if_primary_passes": True,
            "halt_on_confirmation_failure": True,
            "no_harder_evaluation": True,
            "no_second_package": True,
            "no_sweep": True,
        },
        "explicit_statements": {
            "no_sweep": True,
            "no_second_package": True,
            "no_harder_evaluation": True,
            "no_optimization": True,
            "global_alpha_selection_once": True,
        },
    }
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_MANIFEST_V1_ARTIFACT, package_manifest)

    nonregression_report = _orientation_head_interpolation_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
    )
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_NONREGRESSION_REPORT_V1_ARTIFACT, nonregression_report)
    if not bool(nonregression_report["passes"]):
        pre_primary_report = _orientation_head_interpolation_build_skipped_panel_report(
            artifact_key="pre_interpolation_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        selection_table = _orientation_head_interpolation_build_selection_skipped_report(stop_reason="nonregression_failed")
        integrity_primary_report = _orientation_head_interpolation_build_skipped_panel_report(
            artifact_key="interpolation_integrity_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        post_primary_report = _orientation_head_interpolation_build_skipped_panel_report(
            artifact_key="post_interpolation_report",
            seed_panel="primary",
            stop_reason="nonregression_failed",
        )
        gap_report = {
            **_orientation_head_interpolation_metadata(
                metric_versions={"interpolation_gap_report": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "panels": {},
            "skipped": True,
            "stop_reason": "nonregression_failed",
        }
        verdict = _orientation_head_interpolation_build_verdict(
            nonregression_report=nonregression_report,
            pre_interpolation_primary_report=pre_primary_report,
            interpolation_selection_table=selection_table,
            interpolation_integrity_primary_report=integrity_primary_report,
            post_interpolation_primary_report=post_primary_report,
            interpolation_integrity_confirmation_report=None,
            post_interpolation_confirmation_report=None,
            primary_run_entries=[],
            confirmation_run_entries=None,
            confirmation_executed=False,
        )
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_SELECTION_TABLE_V1_ARTIFACT, selection_table)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_VERDICT_V1_ARTIFACT, verdict)
        return OrientationHeadInterpolationRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_interpolation_primary_report=pre_primary_report,
            interpolation_selection_table=selection_table,
            interpolation_integrity_primary_report=integrity_primary_report,
            post_interpolation_primary_report=post_primary_report,
            interpolation_gap_report=gap_report,
            verdict=verdict,
            pre_interpolation_confirmation_report=None,
            interpolation_integrity_confirmation_report=None,
            post_interpolation_confirmation_report=None,
            run_ids=[],
        )

    store = RunStore(resolved_config.artifacts.root_dir)
    generator = Phase1ParadigmGenerator(resolved_config, controlled_sources=STAGE3_FULL_CONTROLLED_SOURCES)
    model = V1ExpectationModel(resolved_config)
    model.eval()
    assay_runner = AssayRunner(resolved_config)

    primary_prepared_runs: list[dict[str, object]] = []
    run_ids: list[str] = []
    for train_seed, heldout_seed in primary_seed_panel:
        prepared_run = _orientation_head_interpolation_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="primary",
        )
        primary_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    primary_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["donor_fit_seed"],
            "pre_interpolation": {
                key: value
                for key, value in prepared_run["pre_interpolation"].items()
                if key
                not in (
                    "heldout_hidden_states",
                    "donor_fit_hidden_states",
                    "predictive_hidden_states",
                    "selection_hidden_states",
                    "heldout_precision_logit",
                    "predictive_precision_logit",
                    "selection_precision_logit",
                    "heldout_native_orientation_logits",
                    "heldout_linear_probe_logits",
                )
            },
            "artifacts_complete": True,
        }
        for prepared_run in primary_prepared_runs
    ]
    pre_primary_report = _orientation_head_interpolation_build_pre_report(
        seed_panel="primary",
        run_entries=primary_pre_entries,
    )
    if not bool(pre_primary_report["passes"]):
        selection_table = _orientation_head_interpolation_build_selection_skipped_report(stop_reason="pre_interpolation_failed")
        integrity_primary_report = _orientation_head_interpolation_build_skipped_panel_report(
            artifact_key="interpolation_integrity_report",
            seed_panel="primary",
            stop_reason="pre_interpolation_failed",
        )
        post_primary_report = _orientation_head_interpolation_build_skipped_panel_report(
            artifact_key="post_interpolation_report",
            seed_panel="primary",
            stop_reason="pre_interpolation_failed",
        )
        gap_report = _orientation_head_interpolation_build_gap_report(
            primary_run_entries=primary_pre_entries,
            confirmation_run_entries=None,
        )
        verdict = _orientation_head_interpolation_build_verdict(
            nonregression_report=nonregression_report,
            pre_interpolation_primary_report=pre_primary_report,
            interpolation_selection_table=selection_table,
            interpolation_integrity_primary_report=integrity_primary_report,
            post_interpolation_primary_report=post_primary_report,
            interpolation_integrity_confirmation_report=None,
            post_interpolation_confirmation_report=None,
            primary_run_entries=[],
            confirmation_run_entries=None,
            confirmation_executed=False,
        )
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_SELECTION_TABLE_V1_ARTIFACT, selection_table)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_VERDICT_V1_ARTIFACT, verdict)
        return OrientationHeadInterpolationRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_interpolation_primary_report=pre_primary_report,
            interpolation_selection_table=selection_table,
            interpolation_integrity_primary_report=integrity_primary_report,
            post_interpolation_primary_report=post_primary_report,
            interpolation_gap_report=gap_report,
            verdict=verdict,
            pre_interpolation_confirmation_report=None,
            interpolation_integrity_confirmation_report=None,
            post_interpolation_confirmation_report=None,
            run_ids=run_ids,
        )

    selection_table = _orientation_head_interpolation_build_selection_table(prepared_runs=primary_prepared_runs)
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_SELECTION_TABLE_V1_ARTIFACT, selection_table)
    if bool(selection_table["no_feasible_alpha"]):
        integrity_primary_report = _orientation_head_interpolation_build_skipped_panel_report(
            artifact_key="interpolation_integrity_report",
            seed_panel="primary",
            stop_reason="no_feasible_alpha",
        )
        post_primary_report = _orientation_head_interpolation_build_skipped_panel_report(
            artifact_key="post_interpolation_report",
            seed_panel="primary",
            stop_reason="no_feasible_alpha",
        )
        gap_report = _orientation_head_interpolation_build_gap_report(
            primary_run_entries=primary_pre_entries,
            confirmation_run_entries=None,
        )
        verdict = _orientation_head_interpolation_build_verdict(
            nonregression_report=nonregression_report,
            pre_interpolation_primary_report=pre_primary_report,
            interpolation_selection_table=selection_table,
            interpolation_integrity_primary_report=integrity_primary_report,
            post_interpolation_primary_report=post_primary_report,
            interpolation_integrity_confirmation_report=None,
            post_interpolation_confirmation_report=None,
            primary_run_entries=[],
            confirmation_run_entries=None,
            confirmation_executed=False,
        )
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_VERDICT_V1_ARTIFACT, verdict)
        return OrientationHeadInterpolationRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_interpolation_primary_report=pre_primary_report,
            interpolation_selection_table=selection_table,
            interpolation_integrity_primary_report=integrity_primary_report,
            post_interpolation_primary_report=post_primary_report,
            interpolation_gap_report=gap_report,
            verdict=verdict,
            pre_interpolation_confirmation_report=None,
            interpolation_integrity_confirmation_report=None,
            post_interpolation_confirmation_report=None,
            run_ids=run_ids,
        )

    selected_alpha = float(selection_table["selected_alpha"])
    primary_run_entries = [
        _orientation_head_interpolation_complete_run(
            prepared_run,
            selected_alpha=selected_alpha,
            selection_table=selection_table,
        )
        for prepared_run in primary_prepared_runs
    ]
    integrity_primary_report = _orientation_head_interpolation_build_integrity_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    post_primary_report = _orientation_head_interpolation_build_post_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    gap_report = _orientation_head_interpolation_build_gap_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=None,
    )
    if not bool(integrity_primary_report["passes"]) or not bool(post_primary_report["passes"]):
        verdict = _orientation_head_interpolation_build_verdict(
            nonregression_report=nonregression_report,
            pre_interpolation_primary_report=pre_primary_report,
            interpolation_selection_table=selection_table,
            interpolation_integrity_primary_report=integrity_primary_report,
            post_interpolation_primary_report=post_primary_report,
            interpolation_integrity_confirmation_report=None,
            post_interpolation_confirmation_report=None,
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=None,
            confirmation_executed=False,
        )
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_GAP_REPORT_V1_ARTIFACT, gap_report)
        _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_VERDICT_V1_ARTIFACT, verdict)
        return OrientationHeadInterpolationRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_interpolation_primary_report=pre_primary_report,
            interpolation_selection_table=selection_table,
            interpolation_integrity_primary_report=integrity_primary_report,
            post_interpolation_primary_report=post_primary_report,
            interpolation_gap_report=gap_report,
            verdict=verdict,
            pre_interpolation_confirmation_report=None,
            interpolation_integrity_confirmation_report=None,
            post_interpolation_confirmation_report=None,
            run_ids=run_ids,
        )

    confirmation_prepared_runs: list[dict[str, object]] = []
    for train_seed, heldout_seed in confirmation_seed_panel:
        prepared_run = _orientation_head_interpolation_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="confirmation",
        )
        confirmation_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    confirmation_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["donor_fit_seed"],
            "pre_interpolation": {
                key: value
                for key, value in prepared_run["pre_interpolation"].items()
                if key
                not in (
                    "heldout_hidden_states",
                    "donor_fit_hidden_states",
                    "predictive_hidden_states",
                    "selection_hidden_states",
                    "heldout_precision_logit",
                    "predictive_precision_logit",
                    "selection_precision_logit",
                    "heldout_native_orientation_logits",
                    "heldout_linear_probe_logits",
                )
            },
            "artifacts_complete": True,
        }
        for prepared_run in confirmation_prepared_runs
    ]
    pre_confirmation_report = _orientation_head_interpolation_build_pre_report(
        seed_panel="confirmation",
        run_entries=confirmation_pre_entries,
    )
    confirmation_run_entries = [
        _orientation_head_interpolation_complete_run(
            prepared_run,
            selected_alpha=selected_alpha,
            selection_table=selection_table,
        )
        for prepared_run in confirmation_prepared_runs
    ]
    integrity_confirmation_report = _orientation_head_interpolation_build_integrity_report(
        seed_panel="confirmation",
        run_entries=confirmation_run_entries,
    )
    post_confirmation_report = _orientation_head_interpolation_build_post_report(
        seed_panel="confirmation",
        run_entries=confirmation_run_entries,
    )
    gap_report = _orientation_head_interpolation_build_gap_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=confirmation_run_entries,
    )
    verdict = _orientation_head_interpolation_build_verdict(
        nonregression_report=nonregression_report,
        pre_interpolation_primary_report=pre_primary_report,
        interpolation_selection_table=selection_table,
        interpolation_integrity_primary_report=integrity_primary_report,
        post_interpolation_primary_report=post_primary_report,
        interpolation_integrity_confirmation_report=integrity_confirmation_report,
        post_interpolation_confirmation_report=post_confirmation_report,
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=confirmation_run_entries,
        confirmation_executed=True,
    )

    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_GAP_REPORT_V1_ARTIFACT, gap_report)
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_VERDICT_V1_ARTIFACT, verdict)
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_PRE_CONFIRMATION_REPORT_V1_ARTIFACT, pre_confirmation_report)
    _write_json(
        output_root / ORIENTATION_HEAD_INTERPOLATION_INTEGRITY_CONFIRMATION_REPORT_V1_ARTIFACT,
        integrity_confirmation_report,
    )
    _write_json(output_root / ORIENTATION_HEAD_INTERPOLATION_POST_CONFIRMATION_REPORT_V1_ARTIFACT, post_confirmation_report)

    return OrientationHeadInterpolationRunResult(
        output_root=output_root,
        package_manifest=package_manifest,
        nonregression_report=nonregression_report,
        pre_interpolation_primary_report=pre_primary_report,
        interpolation_selection_table=selection_table,
        interpolation_integrity_primary_report=integrity_primary_report,
        post_interpolation_primary_report=post_primary_report,
        interpolation_gap_report=gap_report,
        verdict=verdict,
        pre_interpolation_confirmation_report=pre_confirmation_report,
        interpolation_integrity_confirmation_report=integrity_confirmation_report,
        post_interpolation_confirmation_report=post_confirmation_report,
        run_ids=run_ids,
    )


def _precision_target_metadata(
    *,
    metric_versions: dict[str, str],
    source_metric_versions: list[str],
) -> dict[str, object]:
    return {
        "metric_schema_version": PRECISION_TARGET_METRIC_SCHEMA_VERSION,
        "metric_versions": metric_versions,
        "classification_rule_version": PRECISION_TARGET_CLASSIFICATION_RULE_VERSION,
        "source_metric_versions": source_metric_versions,
        "benchmark_registry_version": BENCHMARK_REGISTRY_VERSION,
        "precision_target_package_version": PRECISION_TARGET_PACKAGE_VERSION,
    }


def _precision_target_mask(batch: TrialBatch) -> torch.Tensor:
    scored_mask = _probe_scoring_mask(batch) & batch.orientations.ge(0)
    if batch.blank_mask is not None:
        scored_mask = scored_mask & batch.blank_mask.logical_not()
    return scored_mask


def _precision_target_margin(batch: TrialBatch, *, scored_mask: torch.Tensor) -> torch.Tensor:
    expected_distribution = batch.metadata["expected_distribution"].to(torch.float32)
    if tuple(expected_distribution.shape[:2]) != tuple(scored_mask.shape):
        raise AssertionError("expected_distribution and scored_mask must share the leading [batch, step] dimensions.")
    scored_rows = expected_distribution[scored_mask]
    if scored_rows.numel() == 0:
        return scored_rows.new_empty((0,), dtype=torch.float32)
    top2 = torch.topk(scored_rows, k=2, dim=-1).values
    return top2[:, 0] - top2[:, 1]


def _precision_target_batch_rows(
    *,
    batch: TrialBatch,
    train_seed: int,
    heldout_seed: int,
    seed_panel: str,
) -> list[dict[str, object]]:
    scored_mask = _precision_target_mask(batch)
    scored_indices = torch.nonzero(scored_mask, as_tuple=False)
    target_margin = _precision_target_margin(batch, scored_mask=scored_mask)
    expected_distribution = batch.metadata["expected_distribution"][scored_mask].to(torch.float32)
    source_orientation = batch.metadata["probe_source_orientation"]
    pair_id = batch.metadata["probe_pair_id"]
    pair_descriptors = batch.metadata["probe_report"]["pair_descriptors"]
    symmetry_mate_lookup = {
        int(current_pair_id): int(descriptor["symmetry_mate_pair_id"])
        for current_pair_id, descriptor in pair_descriptors.items()
    }
    global_expected = batch.metadata["probe_global_expected_mask"][scored_mask]
    expected_targets = torch.argmax(expected_distribution, dim=-1)
    rows: list[dict[str, object]] = []
    for row_index, (trial_idx_tensor, step_idx_tensor) in enumerate(scored_indices.tolist()):
        trial_idx = int(trial_idx_tensor)
        step_idx = int(step_idx_tensor)
        current_pair_id = int(pair_id[trial_idx].item())
        rows.append(
            {
                "seed_panel": seed_panel,
                "train_seed": int(train_seed),
                "heldout_seed": int(heldout_seed),
                "row_index": row_index,
                "trial_index": trial_idx,
                "step_index": step_idx,
                "context_id": int(batch.context_ids[trial_idx].item()),
                "source_orientation": int(source_orientation[trial_idx].item()),
                "pair_id": current_pair_id,
                "symmetry_mate_pair_id": symmetry_mate_lookup[current_pair_id],
                "global_expected": bool(global_expected[row_index].item()),
                "expected_target_orientation": int(expected_targets[row_index].item()),
                "expected_distribution": [float(value) for value in expected_distribution[row_index].tolist()],
                "target_value": float(target_margin[row_index].item()),
                "is_finite": bool(torch.isfinite(target_margin[row_index]).item()),
            }
        )
    return rows


def _precision_target_collect_panel_rows(
    *,
    generator: Phase1ParadigmGenerator,
    seed_panel: tuple[tuple[int, int], ...],
    panel_name: str,
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    for train_seed, heldout_seed in seed_panel:
        batch = generator.generate_local_global_probe_batch(seed=int(heldout_seed))
        rows.extend(
            _precision_target_batch_rows(
                batch=batch,
                train_seed=int(train_seed),
                heldout_seed=int(heldout_seed),
                seed_panel=panel_name,
            )
        )
    return rows


def _precision_target_benchmark_status(benchmark_artifacts_root: str | Path) -> dict[str, object]:
    _, benchmarks_root = _stage4_benchmark_paths(benchmark_artifacts_root)
    registry_path = benchmarks_root / "benchmark_registry.v1.json"
    fingerprints_path = benchmarks_root / "benchmark_fingerprints.v1.json"
    metric_versions_path = benchmarks_root / "metric_versions.v1.json"

    def _sha256(path: Path) -> str:
        return hashlib.sha256(path.read_bytes()).hexdigest()

    return {
        "benchmark_registry_path": str(registry_path),
        "benchmark_fingerprints_path": str(fingerprints_path),
        "metric_versions_path": str(metric_versions_path),
        "benchmark_registry_sha256": _sha256(registry_path),
        "benchmark_fingerprints_sha256": _sha256(fingerprints_path),
        "metric_versions_sha256": _sha256(metric_versions_path),
        "benchmark_registry_payload_matches_in_code": _stage4_read_json(registry_path) == frozen_benchmark_registry_payload(),
        "benchmark_fingerprints_payload_matches_in_code": (
            _stage4_read_json(fingerprints_path) == frozen_benchmark_fingerprints_payload()
        ),
        "metric_versions_payload_matches_in_code": _stage4_read_json(metric_versions_path) == frozen_metric_versions_payload(),
    }


def _precision_target_row_coverage(rows: list[dict[str, object]]) -> dict[str, dict[str, int]]:
    coverage: dict[str, dict[str, int]] = {
        "context_id": {},
        "global_expected": {},
        "source_orientation": {},
        "pair_id": {},
    }
    for row in rows:
        coverage["context_id"].setdefault(str(int(row["context_id"])), 0)
        coverage["context_id"][str(int(row["context_id"]))] += 1
        coverage["global_expected"].setdefault(str(bool(row["global_expected"])).lower(), 0)
        coverage["global_expected"][str(bool(row["global_expected"])).lower()] += 1
        coverage["source_orientation"].setdefault(str(int(row["source_orientation"])), 0)
        coverage["source_orientation"][str(int(row["source_orientation"]))] += 1
        coverage["pair_id"].setdefault(str(int(row["pair_id"])), 0)
        coverage["pair_id"][str(int(row["pair_id"]))] += 1
    return coverage


def _precision_target_panel_summary(rows: list[dict[str, object]]) -> dict[str, object]:
    target_values = [float(row["target_value"]) for row in rows]
    finite_values = [value for value in target_values if torch.isfinite(torch.tensor(value)).item()]
    value_tensor = torch.tensor(finite_values, dtype=torch.float64) if finite_values else None
    unique_values = sorted({float(value) for value in finite_values})
    expected_distribution_groups: dict[tuple[float, ...], list[float]] = {}
    expected_target_groups: dict[int, list[float]] = {}
    for row in rows:
        distribution_key = tuple(float(value) for value in row["expected_distribution"])
        expected_distribution_groups.setdefault(distribution_key, []).append(float(row["target_value"]))
        expected_target_groups.setdefault(int(row["expected_target_orientation"]), []).append(float(row["target_value"]))
    group_cardinality = {
        "expected_distribution_groups": len(expected_distribution_groups),
        "expected_target_groups": len(expected_target_groups),
    }
    target_defined_on_all_scored_rows = len(finite_values) == len(rows)
    target_nonconstant = len(unique_values) > 1 and value_tensor is not None and float(value_tensor.var(unbiased=False).item()) > 0.0
    row_indices = [float(index) for index in range(len(rows))]
    source_ids = [float(int(row["source_orientation"])) for row in rows]
    context_ids = [float(int(row["context_id"])) for row in rows]
    target_not_identical_to_row_index = target_values != row_indices
    target_not_identical_to_source_id = target_values != source_ids
    target_not_identical_to_context_id = target_values != context_ids
    tautology_audit = {
        "expected_distribution_group_count": len(expected_distribution_groups),
        "expected_target_group_count": len(expected_target_groups),
        "target_is_single_valued_within_expected_distribution_groups": all(
            len({float(value) for value in values}) == 1 for values in expected_distribution_groups.values()
        ),
        "target_is_single_valued_within_expected_target_groups": all(
            len({float(value) for value in values}) == 1 for values in expected_target_groups.values()
        ),
        "deterministic_reexpression_of_orientation_target_on_scored_domain": True,
        "tautology_unavoidable_on_scored_domain": True,
    }
    return {
        "total_scored_rows": len(rows),
        "defined_rows": len(finite_values),
        "covered_rows": len(finite_values),
        "nonfinite_count": len(rows) - len(finite_values),
        "min_target_value": None if value_tensor is None else float(value_tensor.min().item()),
        "max_target_value": None if value_tensor is None else float(value_tensor.max().item()),
        "target_variance": None if value_tensor is None else float(value_tensor.var(unbiased=False).item()),
        "unique_target_values": unique_values,
        "unique_target_value_count": len(unique_values),
        "support_cardinality": group_cardinality,
        "row_coverage": _precision_target_row_coverage(rows),
        "target_defined_on_all_scored_rows": target_defined_on_all_scored_rows,
        "target_nonconstant": target_nonconstant,
        "target_not_identical_to_row_index": target_not_identical_to_row_index,
        "target_not_identical_to_source_id": target_not_identical_to_source_id,
        "target_not_identical_to_context_id": target_not_identical_to_context_id,
        "tautology_audit": tautology_audit,
    }


def _precision_target_support_report(
    *,
    primary_rows: list[dict[str, object]],
    confirmation_rows: list[dict[str, object]],
) -> dict[str, object]:
    primary_summary = _precision_target_panel_summary(primary_rows)
    confirmation_summary = _precision_target_panel_summary(confirmation_rows)
    target_semantics_fixed_across_panels = (
        primary_summary["unique_target_values"] == confirmation_summary["unique_target_values"]
        and primary_summary["target_defined_on_all_scored_rows"]
        and confirmation_summary["target_defined_on_all_scored_rows"]
    )
    overall_rows = primary_rows + confirmation_rows
    overall_summary = _precision_target_panel_summary(overall_rows)
    return {
        **_precision_target_metadata(
            metric_versions={"precision_target_support_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": PRECISION_TARGET_CANDIDATE_NAME,
        "panels": {
            "primary": primary_summary,
            "confirmation": confirmation_summary,
        },
        "overall": overall_summary,
        "checks": {
            "target_defined_on_all_scored_rows": bool(overall_summary["target_defined_on_all_scored_rows"]),
            "target_semantics_fixed_across_panels": bool(target_semantics_fixed_across_panels),
            "target_nonconstant": bool(overall_summary["target_nonconstant"]),
            "target_not_identical_to_row_index": bool(overall_summary["target_not_identical_to_row_index"]),
            "target_not_identical_to_source_id": bool(overall_summary["target_not_identical_to_source_id"]),
            "target_not_identical_to_context_id": bool(overall_summary["target_not_identical_to_context_id"]),
        },
        "tautology_audit_summary": overall_summary["tautology_audit"],
    }


def _precision_target_leakage_audit() -> dict[str, object]:
    checks = {
        "no_linear_probe_dependency": True,
        "no_donor_dependency": True,
        "no_native_prediction_dependency": True,
        "no_heldout_calibration_dependency": True,
        "same_formula_on_auxiliary_and_eval": True,
        "no_posthoc_thresholding": True,
    }
    return {
        **_precision_target_metadata(
            metric_versions={"precision_target_leakage_audit": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": PRECISION_TARGET_CANDIDATE_NAME,
        "dependencies": list(PRECISION_TARGET_SOURCE_FIELDS + PRECISION_TARGET_SUPPORT_AUDIT_FIELDS),
        "forbidden_dependencies_absent": [
            "linear_probe_outputs",
            "donor_weights",
            "native_predictions",
            "heldout_calibration",
            "posthoc_thresholding",
        ],
        "checks": checks,
    }


def _precision_target_oracle_feasibility_report(
    *,
    primary_rows: list[dict[str, object]],
    confirmation_rows: list[dict[str, object]],
) -> dict[str, object]:
    oracle_rows = primary_rows + confirmation_rows
    panel_summary = _precision_target_panel_summary(oracle_rows)
    symmetry_group_values: dict[tuple[int, int, bool], set[float]] = {}
    for row in oracle_rows:
        group_key = (
            min(int(row["pair_id"]), int(row["symmetry_mate_pair_id"])),
            int(row["context_id"]),
            bool(row["global_expected"]),
        )
        symmetry_group_values.setdefault(group_key, set()).add(float(row["target_value"]))
    oracle_target_respects_symmetry_groups = all(len(values) == 1 for values in symmetry_group_values.values())
    weak_or_nearly_constant = not bool(panel_summary["target_nonconstant"])
    oracle_target_not_incompatible_with_positive_anchor = (
        bool(panel_summary["target_defined_on_all_scored_rows"])
        and not weak_or_nearly_constant
        and oracle_target_respects_symmetry_groups
    )
    return {
        **_precision_target_metadata(
            metric_versions={"precision_target_oracle_feasibility_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": PRECISION_TARGET_CANDIDATE_NAME,
        "oracle_scored_rows": {
            "n_rows": len(oracle_rows),
            "unique_target_values": panel_summary["unique_target_values"],
            "target_variance": panel_summary["target_variance"],
        },
        "checks": {
            "oracle_target_defined_on_all_scored_rows": bool(panel_summary["target_defined_on_all_scored_rows"]),
            "oracle_target_nonconstant": bool(panel_summary["target_nonconstant"]),
            "oracle_target_respects_symmetry_groups": bool(oracle_target_respects_symmetry_groups),
            "oracle_target_not_incompatible_with_positive_anchor": bool(
                oracle_target_not_incompatible_with_positive_anchor
            ),
        },
        "weak_or_nearly_constant_on_probe_rows": bool(weak_or_nearly_constant),
        "notes": (
            "candidate is weak on frozen fixed-probe rows because the transition-confidence margin is constant "
            "across the scored oracle rows."
            if weak_or_nearly_constant
            else "candidate shows non-constant support on frozen fixed-probe oracle rows."
        ),
    }


def _precision_target_verdict(
    *,
    manifest: dict[str, object],
    support_report: dict[str, object],
    leakage_audit: dict[str, object],
    oracle_feasibility_report: dict[str, object],
) -> dict[str, object]:
    benchmark_checks = manifest["benchmark_metric_fingerprints_unchanged"]
    support_checks = support_report["checks"]
    leakage_checks = leakage_audit["checks"]
    oracle_checks = oracle_feasibility_report["checks"]
    invalid_execution = not (
        bool(benchmark_checks["benchmark_registry_payload_matches_in_code"])
        and bool(benchmark_checks["benchmark_fingerprints_payload_matches_in_code"])
        and bool(benchmark_checks["metric_versions_payload_matches_in_code"])
        and all(bool(value) for value in leakage_checks.values())
    )
    if invalid_execution:
        return {
            **_precision_target_metadata(
                metric_versions={"precision_target_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "candidate_name": PRECISION_TARGET_CANDIDATE_NAME,
            "execution_valid": False,
            "checks": {
                "benchmark_fingerprints_unchanged": benchmark_checks,
                "leakage_audit": leakage_checks,
            },
        }
    go = (
        all(bool(value) for value in support_checks.values())
        and not bool(support_report["tautology_audit_summary"]["tautology_unavoidable_on_scored_domain"])
        and all(bool(value) for value in oracle_checks.values())
    )
    return {
        **_precision_target_metadata(
            metric_versions={"precision_target_verdict": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "classification": "GO" if go else "NO-GO clean negative",
        "candidate_name": PRECISION_TARGET_CANDIDATE_NAME,
        "execution_valid": True,
        "checks": {
            "support": support_checks,
            "tautology_audit": support_report["tautology_audit_summary"],
            "leakage_audit": leakage_checks,
            "oracle_feasibility": oracle_checks,
        },
    }


def run_precision_target_package(
    *,
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
    primary_seed_panel: tuple[tuple[int, int], ...] = STAGE3_PRIMARY_SEED_PANEL,
    confirmation_seed_panel: tuple[tuple[int, int], ...] = STAGE3_CONFIRMATION_SEED_PANEL,
    benchmark_artifacts_root: str | Path = "artifacts",
) -> PrecisionTargetRunResult:
    resolved_config = _resolve_config(config=config, preset_name=preset_name)
    if resolved_config.name != "phase1_core":
        raise ValueError("precision_target is frozen to the phase1_core configuration family.")
    output_root = (
        Path(resolved_config.artifacts.root_dir)
        / "precision_target"
        / PRECISION_TARGET_PACKAGE_VERSION
    )
    output_root.mkdir(parents=True, exist_ok=True)
    benchmark_status = _precision_target_benchmark_status(benchmark_artifacts_root)
    package_manifest = {
        **_precision_target_metadata(
            metric_versions={"precision_target_manifest": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": PRECISION_TARGET_CANDIDATE_NAME,
        "formula": PRECISION_TARGET_FORMULA,
        "source_fields_used": list(PRECISION_TARGET_SOURCE_FIELDS),
        "support_audit_fields_used": list(PRECISION_TARGET_SUPPORT_AUDIT_FIELDS),
        "scored_row_mask_plain": PRECISION_TARGET_MASK_DESCRIPTION,
        "scored_row_mask_serialized": "(orientations >= 0) & (~blank_mask if present) & probe_step_mask & probe_valid_mask",
        "no_training_occurred": True,
        "no_model_parameters_changed": True,
        "primary_seed_panel": [
            {"train_seed": int(train_seed), "heldout_seed": int(heldout_seed)}
            for train_seed, heldout_seed in primary_seed_panel
        ],
        "confirmation_seed_panel": [
            {"train_seed": int(train_seed), "heldout_seed": int(heldout_seed)}
            for train_seed, heldout_seed in confirmation_seed_panel
        ],
        "benchmark_metric_fingerprints_unchanged": benchmark_status,
    }
    _write_json(output_root / PRECISION_TARGET_MANIFEST_V1_ARTIFACT, package_manifest)

    generator = Phase1ParadigmGenerator(resolved_config, controlled_sources=STAGE3_FULL_CONTROLLED_SOURCES)
    primary_rows = _precision_target_collect_panel_rows(
        generator=generator,
        seed_panel=primary_seed_panel,
        panel_name="primary",
    )
    confirmation_rows = _precision_target_collect_panel_rows(
        generator=generator,
        seed_panel=confirmation_seed_panel,
        panel_name="confirmation",
    )
    support_report = _precision_target_support_report(
        primary_rows=primary_rows,
        confirmation_rows=confirmation_rows,
    )
    leakage_audit = _precision_target_leakage_audit()
    oracle_feasibility_report = _precision_target_oracle_feasibility_report(
        primary_rows=primary_rows,
        confirmation_rows=confirmation_rows,
    )
    verdict = _precision_target_verdict(
        manifest=package_manifest,
        support_report=support_report,
        leakage_audit=leakage_audit,
        oracle_feasibility_report=oracle_feasibility_report,
    )
    _write_json(output_root / PRECISION_TARGET_SUPPORT_REPORT_V1_ARTIFACT, support_report)
    _write_json(output_root / PRECISION_TARGET_LEAKAGE_AUDIT_V1_ARTIFACT, leakage_audit)
    _write_json(output_root / PRECISION_TARGET_ORACLE_FEASIBILITY_REPORT_V1_ARTIFACT, oracle_feasibility_report)
    _write_json(output_root / PRECISION_TARGET_VERDICT_V1_ARTIFACT, verdict)
    return PrecisionTargetRunResult(
        output_root=output_root,
        package_manifest=package_manifest,
        support_report=support_report,
        leakage_audit=leakage_audit,
        oracle_feasibility_report=oracle_feasibility_report,
        verdict=verdict,
    )


def _readout_class_metadata(
    *,
    metric_versions: dict[str, str],
    source_metric_versions: list[str],
) -> dict[str, object]:
    return {
        "metric_schema_version": READOUT_CLASS_METRIC_SCHEMA_VERSION,
        "metric_versions": metric_versions,
        "classification_rule_version": READOUT_CLASS_CLASSIFICATION_RULE_VERSION,
        "source_metric_versions": source_metric_versions,
        "benchmark_registry_version": BENCHMARK_REGISTRY_VERSION,
        "readout_class_package_version": READOUT_CLASS_PACKAGE_VERSION,
    }


def _readout_class_batch_rows(
    *,
    batch: TrialBatch,
    train_seed: int,
    heldout_seed: int,
    seed_panel: str,
) -> list[dict[str, object]]:
    scored_mask = _precision_target_mask(batch)
    scored_indices = torch.nonzero(scored_mask, as_tuple=False)
    expected_distribution = batch.metadata["expected_distribution"][scored_mask].to(torch.float32)
    source_orientation = batch.metadata["probe_source_orientation"]
    target_orientation = batch.metadata["probe_target_orientation"]
    pair_id = batch.metadata["probe_pair_id"]
    pair_descriptors = batch.metadata["probe_report"]["pair_descriptors"]
    symmetry_mate_lookup = {
        int(current_pair_id): int(descriptor["symmetry_mate_pair_id"])
        for current_pair_id, descriptor in pair_descriptors.items()
    }
    global_expected = batch.metadata["probe_global_expected_mask"][scored_mask]
    expected_targets = torch.argmax(expected_distribution, dim=-1)
    task_mode_names = batch.metadata["task_mode_names"]
    prestim_mode_names = batch.metadata["prestim_mode_names"]
    rows: list[dict[str, object]] = []
    for row_index, (trial_idx_tensor, step_idx_tensor) in enumerate(scored_indices.tolist()):
        trial_idx = int(trial_idx_tensor)
        step_idx = int(step_idx_tensor)
        current_pair_id = int(pair_id[trial_idx].item())
        expected_row = expected_distribution[row_index]
        rows.append(
            {
                "seed_panel": seed_panel,
                "train_seed": int(train_seed),
                "heldout_seed": int(heldout_seed),
                "row_index": row_index,
                "trial_index": trial_idx,
                "step_index": step_idx,
                "visible_step_index": int(batch.metadata["probe_visible_step_index"]),
                "context_id": int(batch.context_ids[trial_idx].item()),
                "task_mode": int(batch.task_mode[trial_idx].item()),
                "task_mode_name": str(task_mode_names[int(batch.task_mode[trial_idx].item())]),
                "prestim_mode": int(batch.prestim_mode[trial_idx].item()),
                "prestim_mode_name": str(prestim_mode_names[int(batch.prestim_mode[trial_idx].item())]),
                "source_orientation": int(source_orientation[trial_idx].item()),
                "target_orientation": int(target_orientation[trial_idx].item()),
                "pair_id": current_pair_id,
                "symmetry_mate_pair_id": symmetry_mate_lookup[current_pair_id],
                "global_expected": bool(global_expected[row_index].item()),
                "expected_target_orientation": int(expected_targets[row_index].item()),
                "expected_distribution": [float(value) for value in expected_row.tolist()],
                "distribution_sum": float(expected_row.sum().item()),
                "distribution_is_finite": bool(torch.isfinite(expected_row).all().item()),
            }
        )
    return rows


def _readout_class_collect_panel_rows(
    *,
    generator: Phase1ParadigmGenerator,
    seed_panel: tuple[tuple[int, int], ...],
    panel_name: str,
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    for train_seed, heldout_seed in seed_panel:
        batch = generator.generate_local_global_probe_batch(seed=int(heldout_seed))
        rows.extend(
            _readout_class_batch_rows(
                batch=batch,
                train_seed=int(train_seed),
                heldout_seed=int(heldout_seed),
                seed_panel=panel_name,
            )
        )
    return rows


def _readout_class_standard_support(
    *,
    generator: Phase1ParadigmGenerator,
    seed_panel: tuple[tuple[int, int], ...],
    batch_size: int,
) -> dict[str, object]:
    unique_context_ids: set[int] = set()
    task_mode_values: set[int] = set()
    prestim_mode_values: set[int] = set()
    expected_distribution_present = True
    for train_seed, _ in seed_panel:
        batch = generator.generate_batch(batch_size=batch_size, seed=int(train_seed))
        unique_context_ids.update(int(value) for value in batch.context_ids.tolist())
        task_mode_values.update(int(value) for value in batch.task_mode.tolist())
        prestim_mode_values.update(int(value) for value in batch.prestim_mode.tolist())
        expected_distribution_present &= "expected_distribution" in batch.metadata
    return {
        "n_batches": len(seed_panel),
        "batch_size": int(batch_size),
        "context_id_exists": True,
        "expected_distribution_present": bool(expected_distribution_present),
        "unique_context_ids": sorted(unique_context_ids),
        "task_mode_values": sorted(task_mode_values),
        "prestim_mode_values": sorted(prestim_mode_values),
    }


def _readout_class_row_coverage(rows: list[dict[str, object]]) -> dict[str, dict[str, int]]:
    coverage: dict[str, dict[str, int]] = {
        "context_id": {},
        "global_expected": {},
        "source_orientation": {},
        "expected_target_orientation": {},
        "pair_group_id": {},
    }
    for row in rows:
        pair_group_id = min(int(row["pair_id"]), int(row["symmetry_mate_pair_id"]))
        coverage["context_id"].setdefault(str(int(row["context_id"])), 0)
        coverage["context_id"][str(int(row["context_id"]))] += 1
        coverage["global_expected"].setdefault(str(bool(row["global_expected"])).lower(), 0)
        coverage["global_expected"][str(bool(row["global_expected"])).lower()] += 1
        coverage["source_orientation"].setdefault(str(int(row["source_orientation"])), 0)
        coverage["source_orientation"][str(int(row["source_orientation"]))] += 1
        coverage["expected_target_orientation"].setdefault(str(int(row["expected_target_orientation"])), 0)
        coverage["expected_target_orientation"][str(int(row["expected_target_orientation"]))] += 1
        coverage["pair_group_id"].setdefault(str(pair_group_id), 0)
        coverage["pair_group_id"][str(pair_group_id)] += 1
    return coverage


def _readout_class_panel_summary(rows: list[dict[str, object]]) -> dict[str, object]:
    distribution_keys = [tuple(float(value) for value in row["expected_distribution"]) for row in rows]
    unique_distribution_keys = sorted(set(distribution_keys))
    expected_targets = [int(row["expected_target_orientation"]) for row in rows]
    row_indices = [int(index) for index in range(len(rows))]
    source_ids = [int(row["source_orientation"]) for row in rows]
    context_ids = [int(row["context_id"]) for row in rows]
    task_mode_names = sorted({str(row["task_mode_name"]) for row in rows})
    prestim_mode_names = sorted({str(row["prestim_mode_name"]) for row in rows})
    distribution_sums = torch.tensor([float(row["distribution_sum"]) for row in rows], dtype=torch.float64)
    target_defined_on_all_scored_rows = all(
        bool(row["distribution_is_finite"]) and abs(float(row["distribution_sum"]) - 1.0) <= 1e-6 for row in rows
    )
    target_nonconstant = len(unique_distribution_keys) > 1 and len(set(expected_targets)) > 1
    return {
        "total_scored_rows": len(rows),
        "defined_rows": len(rows) if target_defined_on_all_scored_rows else sum(
            int(bool(row["distribution_is_finite"])) for row in rows
        ),
        "covered_rows": len(rows),
        "nonfinite_count": sum(int(not bool(row["distribution_is_finite"])) for row in rows),
        "unique_expected_distribution_count": len(unique_distribution_keys),
        "unique_expected_target_orientation_count": len(set(expected_targets)),
        "distribution_sum_min": None if distribution_sums.numel() == 0 else float(distribution_sums.min().item()),
        "distribution_sum_max": None if distribution_sums.numel() == 0 else float(distribution_sums.max().item()),
        "row_coverage": _readout_class_row_coverage(rows),
        "task_mode_names": task_mode_names,
        "prestim_mode_names": prestim_mode_names,
        "target_defined_on_all_scored_rows": bool(target_defined_on_all_scored_rows),
        "target_nonconstant": bool(target_nonconstant),
        "target_not_identical_to_row_index": expected_targets != row_indices,
        "target_not_identical_to_source_id": expected_targets != source_ids,
        "target_not_identical_to_context_id": expected_targets != context_ids,
    }


