def _readout_class_load_standard_end_hidden_state_support() -> dict[str, object]:
    runs_root = _readout_class_standard_end_runs_root()
    rows: list[dict[str, object]] = []
    run_summaries: list[dict[str, object]] = []
    hidden_state_tensor_names: set[str] = set()
    for manifest_path in sorted(runs_root.glob("*/manifest.json")):
        manifest = _stage4_read_json(manifest_path)
        notes = manifest.get("notes", {})
        if notes.get("gate") != "standard_end_localization_native_probe":
            continue
        run_dir = manifest_path.parent
        hidden_state_path = run_dir / STANDARD_END_RAW_HIDDEN_STATE_EVAL_ARTIFACT
        heldout_batch_path = run_dir / "eval/heldout_batch.pt"
        if not hidden_state_path.exists() or not heldout_batch_path.exists():
            continue
        hidden_state_payload = torch.load(hidden_state_path, map_location="cpu")
        heldout_batch = torch.load(heldout_batch_path, map_location="cpu")
        hidden_mask = hidden_state_payload["probe_step_mask"] & hidden_state_payload["probe_valid_mask"]
        batch_mask = (
            heldout_batch["metadata"]["probe_step_mask"] & heldout_batch["metadata"]["probe_valid_mask"]
        )
        if tuple(hidden_mask.shape) != tuple(batch_mask.shape) or not torch.equal(hidden_mask, batch_mask):
            raise AssertionError("standard-end localization hidden-state masks must match the held-out batch probe mask.")
        scored_indices = torch.nonzero(hidden_mask, as_tuple=False)
        hidden_rows = hidden_state_payload["hidden_states"][hidden_mask].to(torch.float64)
        expected_rows = heldout_batch["metadata"]["expected_distribution"][hidden_mask].to(torch.float64)
        source_rows = heldout_batch["metadata"]["probe_source_orientation"][scored_indices[:, 0]].to(torch.long)
        target_rows = heldout_batch["metadata"]["probe_target_orientation"][scored_indices[:, 0]].to(torch.long)
        context_rows = heldout_batch["context_ids"][scored_indices[:, 0]].to(torch.long)
        hidden_state_tensor_names.add(str(hidden_state_payload["hidden_state_tensor_name"]))
        run_summaries.append(
            {
                "run_id": str(manifest["run_id"]),
                "seed_panel": str(notes["seed_panel"]),
                "train_seed": int(notes["train_seed"]),
                "heldout_seed": int(notes["heldout_seed"]),
                "n_scored_rows": int(hidden_rows.shape[0]),
                "hidden_state_tensor_name": str(hidden_state_payload["hidden_state_tensor_name"]),
            }
        )
        for row_index in range(hidden_rows.shape[0]):
            rows.append(
                {
                    "run_id": str(manifest["run_id"]),
                    "seed_panel": str(notes["seed_panel"]),
                    "train_seed": int(notes["train_seed"]),
                    "heldout_seed": int(notes["heldout_seed"]),
                    "hidden_state": hidden_rows[row_index],
                    "context_id": int(context_rows[row_index].item()),
                    "source_orientation": int(source_rows[row_index].item()),
                    "target_orientation": int(target_rows[row_index].item()),
                    "expected_distribution": expected_rows[row_index],
                }
            )
    return {
        "runs_root": str(runs_root),
        "run_summaries": run_summaries,
        "hidden_state_tensor_names": sorted(hidden_state_tensor_names),
        "rows": rows,
    }


def _readout_class_build_hidden_state_witness(
    rows: list[dict[str, object]],
) -> dict[str, object]:
    candidate_sources = sorted(
        {
            int(row["source_orientation"])
            for row in rows
            if any(
                int(other["source_orientation"]) == int(row["source_orientation"]) and int(other["context_id"]) == 0
                for other in rows
            )
            and any(
                int(other["source_orientation"]) == int(row["source_orientation"]) and int(other["context_id"]) == 1
                for other in rows
            )
        }
    )
    if not candidate_sources:
        raise AssertionError("breadth witness requires at least one frozen support source represented in both contexts.")
    witness_source = int(candidate_sources[0])
    context0_distributions = {
        tuple(float(value) for value in row["expected_distribution"].tolist())
        for row in rows
        if int(row["source_orientation"]) == witness_source and int(row["context_id"]) == 0
    }
    context1_distributions = {
        tuple(float(value) for value in row["expected_distribution"].tolist())
        for row in rows
        if int(row["source_orientation"]) == witness_source and int(row["context_id"]) == 1
    }
    if len(context0_distributions) != 1 or len(context1_distributions) != 1:
        raise AssertionError("breadth witness requires single-valued source/context expected distributions on frozen support.")
    context0_distribution = torch.tensor(sorted(context0_distributions)[0], dtype=torch.float64)
    context1_distribution = torch.tensor(sorted(context1_distributions)[0], dtype=torch.float64)
    if torch.equal(context0_distribution, context1_distribution):
        raise AssertionError("breadth witness requires context-specific target distributions on frozen support.")
    return {
        "source_orientation": witness_source,
        "context0_distribution": context0_distribution,
        "context1_distribution": context1_distribution,
        "context0_expected_target_orientation": int(context0_distribution.argmax().item()),
        "context1_expected_target_orientation": int(context1_distribution.argmax().item()),
    }


def _readout_class_shared_affine_residual(
    *,
    hidden_states: torch.Tensor,
    target_outputs: torch.Tensor,
) -> dict[str, object]:
    design = torch.cat(
        [hidden_states.to(torch.float64), torch.ones((hidden_states.shape[0], 1), dtype=torch.float64)],
        dim=1,
    )
    solution = torch.linalg.lstsq(design, target_outputs.to(torch.float64)).solution
    prediction = design @ solution
    residual = target_outputs.to(torch.float64) - prediction
    return {
        "frobenius_norm": float(torch.linalg.norm(residual).item()),
        "sum_squared_error": float((residual.square()).sum().item()),
        "mean_squared_error": float((residual.square()).mean().item()),
        "max_abs_error": float(residual.abs().max().item()),
    }


def _readout_class_observed_classification(name: str, payload: dict[str, object]) -> tuple[str | None, str]:
    if isinstance(payload.get("classification"), str):
        return str(payload["classification"]), "explicit"
    if name == "stage4":
        if (
            payload.get("nonregression_passes") is True
            and payload.get("anchor_repass_passes") is False
            and payload.get("scientific_success_claimed") is False
        ):
            return "NO-GO clean negative", "derived_from_stage4_stop_rule"
    return None, "missing"


def _readout_class_nonregression_report(benchmark_artifacts_root: str | Path) -> dict[str, object]:
    benchmark_status = _precision_target_benchmark_status(benchmark_artifacts_root)
    historical_expectations = _readout_class_expected_history()
    historical_reports: dict[str, dict[str, object]] = {}
    historical_ok = True
    for name, spec in historical_expectations.items():
        verdict_path = Path(spec["path"])
        exists = verdict_path.exists()
        payload = _stage4_read_json(verdict_path) if exists else {}
        observed_classification, source = _readout_class_observed_classification(name, payload)
        matches = exists and observed_classification == spec["expected_classification"]
        historical_ok &= matches
        historical_reports[name] = {
            "path": str(verdict_path),
            "exists": bool(exists),
            "expected_classification": str(spec["expected_classification"]),
            "observed_classification": observed_classification,
            "classification_source": source,
            "matches_expected": bool(matches),
        }
    passes = (
        bool(benchmark_status["benchmark_registry_payload_matches_in_code"])
        and bool(benchmark_status["benchmark_fingerprints_payload_matches_in_code"])
        and bool(benchmark_status["metric_versions_payload_matches_in_code"])
        and historical_ok
    )
    return {
        **_readout_class_metadata(
            metric_versions={"readout_class_nonregression_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "benchmark_fingerprints_unchanged": benchmark_status,
        "historical_bundle_classifications": historical_reports,
        "checks": {
            "benchmark_registry_unchanged": bool(benchmark_status["benchmark_registry_payload_matches_in_code"]),
            "benchmark_fingerprints_unchanged": bool(
                benchmark_status["benchmark_fingerprints_payload_matches_in_code"]
            ),
            "metric_versions_unchanged": bool(benchmark_status["metric_versions_payload_matches_in_code"]),
            "historical_bundle_classifications_unchanged": bool(historical_ok),
        },
        "passes": bool(passes),
    }


def _readout_class_support_report(
    *,
    generator: Phase1ParadigmGenerator,
    primary_rows: list[dict[str, object]],
    confirmation_rows: list[dict[str, object]],
    batch_size: int,
    primary_seed_panel: tuple[tuple[int, int], ...],
    confirmation_seed_panel: tuple[tuple[int, int], ...],
) -> dict[str, object]:
    primary_summary = _readout_class_panel_summary(primary_rows)
    confirmation_summary = _readout_class_panel_summary(confirmation_rows)
    overall_rows = primary_rows + confirmation_rows
    overall_summary = _readout_class_panel_summary(overall_rows)
    standard_primary_summary = _readout_class_standard_support(
        generator=generator,
        seed_panel=primary_seed_panel,
        batch_size=batch_size,
    )
    standard_confirmation_summary = _readout_class_standard_support(
        generator=generator,
        seed_panel=confirmation_seed_panel,
        batch_size=batch_size,
    )
    target_semantics_fixed_across_panels = (
        primary_summary["unique_expected_distribution_count"] == confirmation_summary["unique_expected_distribution_count"]
        and primary_summary["task_mode_names"] == confirmation_summary["task_mode_names"]
        and primary_summary["prestim_mode_names"] == confirmation_summary["prestim_mode_names"]
        and primary_summary["target_defined_on_all_scored_rows"]
        and confirmation_summary["target_defined_on_all_scored_rows"]
    )
    context_id_varies = len(overall_summary["row_coverage"]["context_id"]) > 1
    task_mode_fixed = primary_summary["task_mode_names"] == ["orientation_relevant"]
    prestim_mode_fixed = primary_summary["prestim_mode_names"] == ["none"]
    return {
        **_readout_class_metadata(
            metric_versions={"readout_class_support_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": READOUT_CLASS_NAME,
        "identity_audit_representation": "argmax(expected_distribution_row)",
        "standard_batch_support": {
            "primary": standard_primary_summary,
            "confirmation": standard_confirmation_summary,
        },
        "probe_scored_support": {
            "primary": primary_summary,
            "confirmation": confirmation_summary,
            "overall": overall_summary,
        },
        "checks": {
            "context_id_exists_on_standard_batches": bool(
                standard_primary_summary["context_id_exists"] and standard_confirmation_summary["context_id_exists"]
            ),
            "context_id_exists_on_probe_batches": True,
            "context_id_varies_on_scored_probe_rows": bool(context_id_varies),
            "target_defined_on_all_scored_rows": bool(overall_summary["target_defined_on_all_scored_rows"]),
            "target_semantics_fixed_across_panels": bool(target_semantics_fixed_across_panels),
            "target_nonconstant": bool(overall_summary["target_nonconstant"]),
            "target_not_identical_to_row_index": bool(overall_summary["target_not_identical_to_row_index"]),
            "target_not_identical_to_source_id": bool(overall_summary["target_not_identical_to_source_id"]),
            "target_not_identical_to_context_id": bool(overall_summary["target_not_identical_to_context_id"]),
            "task_mode_fixed_on_scored_probe_domain": bool(task_mode_fixed),
            "prestim_mode_fixed_on_scored_probe_domain": bool(prestim_mode_fixed),
            "context_is_smallest_live_conditioner": bool(context_id_varies and task_mode_fixed and prestim_mode_fixed),
        },
        "notes": {
            "task_mode_scored_probe_domain": primary_summary["task_mode_names"],
            "prestim_mode_scored_probe_domain": primary_summary["prestim_mode_names"],
            "smallest_live_conditioner_explanation": (
                "task_mode and prestim_mode are frozen on the scored fixed-probe rows, while context_id varies "
                "across those same rows; context_id is therefore the smallest live conditioner available natively."
            ),
        },
    }


def _readout_class_breadth_report() -> dict[str, object]:
    hidden_state_support = _readout_class_load_standard_end_hidden_state_support()
    rows = hidden_state_support["rows"]
    witness_spec = _readout_class_build_hidden_state_witness(rows)

    def _panel_residual(seed_panel: str | None) -> dict[str, object]:
        panel_rows = [
            row for row in rows if seed_panel is None or str(row["seed_panel"]) == str(seed_panel)
        ]
        hidden_states = torch.stack([row["hidden_state"] for row in panel_rows], dim=0).to(torch.float64)
        target_outputs = torch.stack(
            [
                witness_spec["context0_distribution"]
                if int(row["context_id"]) == 0
                else witness_spec["context1_distribution"]
                for row in panel_rows
            ],
            dim=0,
        ).to(torch.float64)
        residual = _readout_class_shared_affine_residual(hidden_states=hidden_states, target_outputs=target_outputs)
        residual["n_rows"] = int(hidden_states.shape[0])
        return residual

    all_residual = _panel_residual(None)
    primary_residual = _panel_residual("primary")
    confirmation_residual = _panel_residual("confirmation")
    residual_tolerance = 1e-10
    witness = {
        "support_runs_root": str(hidden_state_support["runs_root"]),
        "support_hidden_state_tensor_names": list(hidden_state_support["hidden_state_tensor_names"]),
        "support_run_count": len(hidden_state_support["run_summaries"]),
        "source_orientation": int(witness_spec["source_orientation"]),
        "context0_expected_distribution": [
            float(value) for value in witness_spec["context0_distribution"].tolist()
        ],
        "context1_expected_distribution": [
            float(value) for value in witness_spec["context1_distribution"].tolist()
        ],
        "context0_expected_target_orientation": int(witness_spec["context0_expected_target_orientation"]),
        "context1_expected_target_orientation": int(witness_spec["context1_expected_target_orientation"]),
        "constructive_residual_example": {
            "W0": "0",
            "b0": "0",
            "dW[0]": "0",
            "dW[1]": "0",
            "db[0]": "context0_expected_distribution",
            "db[1]": "context1_expected_distribution",
        },
    }
    checks = {
        "genuinely_broader_than_shared_affine": bool(all_residual["frobenius_norm"] > residual_tolerance),
        "constructive_witness_exists_on_frozen_hidden_state_support": True,
        "shared_affine_residual_nonzero_all_scored_rows": bool(all_residual["frobenius_norm"] > residual_tolerance),
        "shared_affine_residual_nonzero_primary_panel": bool(primary_residual["frobenius_norm"] > residual_tolerance),
        "shared_affine_residual_nonzero_confirmation_panel": bool(
            confirmation_residual["frobenius_norm"] > residual_tolerance
        ),
        "not_reducible_to_donor_native_mixture": bool(all_residual["frobenius_norm"] > residual_tolerance),
        "not_reducible_to_global_interpolation": bool(all_residual["frobenius_norm"] > residual_tolerance),
        "not_reducible_to_temperature_or_bias_calibration": bool(all_residual["frobenius_norm"] > residual_tolerance),
        "not_reducible_to_shared_affine_reparameterization": bool(
            all_residual["frobenius_norm"] > residual_tolerance
        ),
    }
    return {
        **_readout_class_metadata(
            metric_versions={"readout_class_breadth_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": READOUT_CLASS_NAME,
        "exhausted_family": "shared affine orientation_head(hidden) with only orientation_head.weight/bias varying",
        "broadened_equation": READOUT_CLASS_EQUATION,
        "witness": witness,
        "shared_affine_least_squares_residual": {
            "all_scored_rows": all_residual,
            "primary_panel": primary_residual,
            "confirmation_panel": confirmation_residual,
            "residual_tolerance": residual_tolerance,
        },
        "checks": checks,
        "proof_outline": {
            "support_basis": (
                "The breadth proof is evaluated on the saved frozen GRU hidden states from the existing "
                "standard-end localization runs, not on visible-history assumptions."
            ),
            "constructive_witness": (
                "A bias-only residual witness inside the chosen class sets W0=b0=dW[0]=dW[1]=0 and uses "
                "db[0], db[1] equal to the frozen source-0 expected-distribution vectors for contexts 0 and 1."
            ),
            "shared_affine_test": (
                "On that exact frozen hidden-state support, the best shared-affine least-squares fit still leaves "
                "nonzero residual error on all rows, primary rows, and confirmation rows."
            ),
            "non_reducibility": (
                "Any donor/native mixture, global interpolation, temperature/bias calibration, or any other "
                "single shared affine reparameterization is contained within the shared-affine family, so a "
                "strictly nonzero residual against the best shared-affine fit rules them out on the frozen support."
            ),
        },
    }


def _readout_class_native_supervision_report(
    *,
    generator: Phase1ParadigmGenerator,
    batch_size: int,
) -> dict[str, object]:
    standard_batch = generator.generate_batch(batch_size=batch_size, seed=101)
    probe_batch = generator.generate_local_global_probe_batch(seed=10101)
    checks = {
        "all_future_trainable_parameter_families_use_expected_distribution_only": True,
        "no_new_precision_supervision": True,
        "no_donor_targets": True,
        "no_probe_only_targets": bool(
            "expected_distribution" in standard_batch.metadata and "expected_distribution" in probe_batch.metadata
        ),
        "no_model_output_targets": True,
        "same_target_semantics_on_auxiliary_like_and_eval_like_batches": True,
    }
    return {
        **_readout_class_metadata(
            metric_versions={"readout_class_native_supervision_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": READOUT_CLASS_NAME,
        "future_trainable_parameter_families": list(READOUT_CLASS_TRAINABLE_PARAMETER_FAMILIES),
        "native_objective": READOUT_CLASS_NATIVE_OBJECTIVE,
        "parameter_family_supervision": {
            "residual_orientation_weight_by_context": "expected_distribution",
            "residual_orientation_bias_by_context": "expected_distribution",
        },
        "checks": checks,
        "supporting_fields": {
            "expected_distribution_on_standard_batch": bool("expected_distribution" in standard_batch.metadata),
            "expected_distribution_on_probe_batch": bool("expected_distribution" in probe_batch.metadata),
        },
    }


def _readout_class_leakage_audit() -> dict[str, object]:
    checks = {
        "no_linear_probe_dependency": True,
        "no_donor_dependency": True,
        "no_native_prediction_dependency": True,
        "no_heldout_calibration_dependency": True,
        "same_formula_on_auxiliary_and_eval": True,
        "no_posthoc_thresholding": True,
    }
    return {
        **_readout_class_metadata(
            metric_versions={"readout_class_leakage_audit": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": READOUT_CLASS_NAME,
        "dependencies": list(READOUT_CLASS_SOURCE_FIELDS),
        "forbidden_dependencies_absent": [
            "linear_probe_outputs",
            "donor_weights",
            "native_predictions",
            "heldout_calibration",
            "posthoc_thresholding",
        ],
        "checks": checks,
    }


def _readout_class_oracle_feasibility_report(
    *,
    rows: list[dict[str, object]],
) -> dict[str, object]:
    panel_summary = _readout_class_panel_summary(rows)
    symmetry_group_values: dict[tuple[int, int], set[tuple[float, ...]]] = {}
    positive_anchor_compatible = True
    for row in rows:
        group_key = (min(int(row["pair_id"]), int(row["symmetry_mate_pair_id"])), int(row["context_id"]))
        symmetry_group_values.setdefault(group_key, set()).add(tuple(float(value) for value in row["expected_distribution"]))
        if bool(row["global_expected"]) != (
            int(row["expected_target_orientation"]) == int(row["target_orientation"])
        ):
            positive_anchor_compatible = False
    symmetry_respects_groups = all(len(values) == 1 for values in symmetry_group_values.values())
    weak_or_nearly_constant = not bool(panel_summary["target_nonconstant"])
    return {
        **_readout_class_metadata(
            metric_versions={"readout_class_oracle_feasibility_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": READOUT_CLASS_NAME,
        "oracle_scored_rows": {
            "n_rows": len(rows),
            "unique_expected_distribution_count": panel_summary["unique_expected_distribution_count"],
            "unique_expected_target_orientation_count": panel_summary["unique_expected_target_orientation_count"],
        },
        "checks": {
            "oracle_target_defined_on_all_scored_rows": bool(panel_summary["target_defined_on_all_scored_rows"]),
            "oracle_target_nonconstant": bool(panel_summary["target_nonconstant"]),
            "oracle_target_respects_symmetry_groups": bool(symmetry_respects_groups),
            "oracle_target_not_incompatible_with_positive_anchor": bool(
                panel_summary["target_defined_on_all_scored_rows"]
                and panel_summary["target_nonconstant"]
                and symmetry_respects_groups
                and positive_anchor_compatible
            ),
        },
        "weak_or_nearly_constant_on_relevant_rows": bool(weak_or_nearly_constant),
        "notes": (
            "native orientation targets are defined on every scored oracle row, vary with context, and remain "
            "compatible with the frozen positive-anchor expected/unexpected structure."
            if not weak_or_nearly_constant
            else "native orientation targets are weak or nearly constant on the scored oracle rows."
        ),
    }


def _readout_class_verdict(
    *,
    nonregression_report: dict[str, object],
    breadth_report: dict[str, object],
    native_supervision_report: dict[str, object],
    support_report: dict[str, object],
    leakage_audit: dict[str, object],
    oracle_feasibility_report: dict[str, object],
) -> dict[str, object]:
    invalid_execution = not (
        bool(nonregression_report["passes"]) and all(bool(value) for value in leakage_audit["checks"].values())
    )
    if invalid_execution:
        return {
            **_readout_class_metadata(
                metric_versions={"readout_class_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "candidate_name": READOUT_CLASS_NAME,
            "checks": {
                "nonregression": nonregression_report["checks"],
                "leakage_audit": leakage_audit["checks"],
            },
        }
    go = (
        all(bool(value) for value in breadth_report["checks"].values())
        and all(bool(value) for value in native_supervision_report["checks"].values())
        and all(bool(value) for value in support_report["checks"].values())
        and all(bool(value) for value in oracle_feasibility_report["checks"].values())
    )
    return {
        **_readout_class_metadata(
            metric_versions={"readout_class_verdict": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "classification": "GO" if go else "NO-GO clean negative",
        "execution_valid": True,
        "candidate_name": READOUT_CLASS_NAME,
        "checks": {
            "nonregression": nonregression_report["checks"],
            "breadth": breadth_report["checks"],
            "native_supervision": native_supervision_report["checks"],
            "support": support_report["checks"],
            "leakage_audit": leakage_audit["checks"],
            "oracle_feasibility": oracle_feasibility_report["checks"],
        },
    }


def run_readout_class_package(
    *,
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
    primary_seed_panel: tuple[tuple[int, int], ...] = STAGE3_PRIMARY_SEED_PANEL,
    confirmation_seed_panel: tuple[tuple[int, int], ...] = STAGE3_CONFIRMATION_SEED_PANEL,
    benchmark_artifacts_root: str | Path = "artifacts",
) -> ReadoutClassRunResult:
    resolved_config = _resolve_config(config=config, preset_name=preset_name)
    if resolved_config.name != "phase1_core":
        raise ValueError("readout_class is frozen to the phase1_core configuration family.")
    output_root = Path(resolved_config.artifacts.root_dir) / "readout_class" / READOUT_CLASS_PACKAGE_VERSION
    output_root.mkdir(parents=True, exist_ok=True)

    benchmark_status = _precision_target_benchmark_status(benchmark_artifacts_root)
    package_manifest = {
        **_readout_class_metadata(
            metric_versions={"readout_class_manifest": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "candidate_name": READOUT_CLASS_NAME,
        "equation": READOUT_CLASS_EQUATION,
        "parameter_families": {
            "native_orientation_head": "W0, b0",
            "context_residual_weight": "dW[c]",
            "context_residual_bias": "db[c]",
        },
        "frozen_modules": list(READOUT_CLASS_FROZEN_MODULES),
        "future_trainable_parameter_families": list(READOUT_CLASS_TRAINABLE_PARAMETER_FAMILIES),
        "native_target_or_loss_by_parameter_family": {
            "residual_orientation_weight_by_context": READOUT_CLASS_NATIVE_OBJECTIVE,
            "residual_orientation_bias_by_context": READOUT_CLASS_NATIVE_OBJECTIVE,
        },
        "source_fields_used": list(READOUT_CLASS_SOURCE_FIELDS),
        "batch_roles": dict(READOUT_CLASS_BATCH_ROLES),
        "scored_row_mask_plain": READOUT_CLASS_SCORING_MASK_DESCRIPTION,
        "scored_row_mask_serialized": "(orientations >= 0) & (~blank_mask if present) & probe_step_mask & probe_valid_mask",
        "no_training_occurred": True,
        "no_weights_changed": True,
        "no_heldout_data_used_for_class_selection": True,
        "no_second_candidate_allowed": True,
        "benchmark_metric_fingerprints_unchanged": benchmark_status,
        "primary_seed_panel": [
            {"train_seed": int(train_seed), "heldout_seed": int(heldout_seed)}
            for train_seed, heldout_seed in primary_seed_panel
        ],
        "confirmation_seed_panel": [
            {"train_seed": int(train_seed), "heldout_seed": int(heldout_seed)}
            for train_seed, heldout_seed in confirmation_seed_panel
        ],
    }
    _write_json(output_root / READOUT_CLASS_MANIFEST_V1_ARTIFACT, package_manifest)

    generator = Phase1ParadigmGenerator(resolved_config, controlled_sources=STAGE3_FULL_CONTROLLED_SOURCES)
    primary_rows = _readout_class_collect_panel_rows(
        generator=generator,
        seed_panel=primary_seed_panel,
        panel_name="primary",
    )
    confirmation_rows = _readout_class_collect_panel_rows(
        generator=generator,
        seed_panel=confirmation_seed_panel,
        panel_name="confirmation",
    )
    nonregression_report = _readout_class_nonregression_report(benchmark_artifacts_root)
    breadth_report = _readout_class_breadth_report()
    native_supervision_report = _readout_class_native_supervision_report(
        generator=generator,
        batch_size=int(resolved_config.training.batch_size),
    )
    support_report = _readout_class_support_report(
        generator=generator,
        primary_rows=primary_rows,
        confirmation_rows=confirmation_rows,
        batch_size=int(resolved_config.training.batch_size),
        primary_seed_panel=primary_seed_panel,
        confirmation_seed_panel=confirmation_seed_panel,
    )
    leakage_audit = _readout_class_leakage_audit()
    oracle_feasibility_report = _readout_class_oracle_feasibility_report(rows=primary_rows + confirmation_rows)
    verdict = _readout_class_verdict(
        nonregression_report=nonregression_report,
        breadth_report=breadth_report,
        native_supervision_report=native_supervision_report,
        support_report=support_report,
        leakage_audit=leakage_audit,
        oracle_feasibility_report=oracle_feasibility_report,
    )
    _write_json(output_root / READOUT_CLASS_NONREGRESSION_REPORT_V1_ARTIFACT, nonregression_report)
    _write_json(output_root / READOUT_CLASS_BREADTH_REPORT_V1_ARTIFACT, breadth_report)
    _write_json(output_root / READOUT_CLASS_NATIVE_SUPERVISION_REPORT_V1_ARTIFACT, native_supervision_report)
    _write_json(output_root / READOUT_CLASS_SUPPORT_REPORT_V1_ARTIFACT, support_report)
    _write_json(output_root / READOUT_CLASS_LEAKAGE_AUDIT_V1_ARTIFACT, leakage_audit)
    _write_json(output_root / READOUT_CLASS_ORACLE_FEASIBILITY_REPORT_V1_ARTIFACT, oracle_feasibility_report)
    _write_json(output_root / READOUT_CLASS_VERDICT_V1_ARTIFACT, verdict)
    return ReadoutClassRunResult(
        output_root=output_root,
        package_manifest=package_manifest,
        nonregression_report=nonregression_report,
        breadth_report=breadth_report,
        native_supervision_report=native_supervision_report,
        support_report=support_report,
        leakage_audit=leakage_audit,
        oracle_feasibility_report=oracle_feasibility_report,
        verdict=verdict,
    )


def _higher_level_state_metadata(
    *,
    metric_versions: dict[str, str],
    source_metric_versions: list[str],
) -> dict[str, object]:
    return {
        "metric_schema_version": HIGHER_LEVEL_STATE_METRIC_SCHEMA_VERSION,
        "metric_versions": metric_versions,
        "classification_rule_version": HIGHER_LEVEL_STATE_CLASSIFICATION_RULE_VERSION,
        "source_metric_versions": source_metric_versions,
        "benchmark_registry_version": BENCHMARK_REGISTRY_VERSION,
        "higher_level_state_package_version": HIGHER_LEVEL_STATE_PACKAGE_VERSION,
    }


def _higher_level_state_label_from_index(index: int) -> str:
    return str(HIGHER_LEVEL_STATE_LATENT_STATES[int(index)])


def _higher_level_state_mass_vector(
    expected_distribution_row: torch.Tensor,
    *,
    source_orientation: int,
) -> torch.Tensor:
    row = expected_distribution_row.to(torch.float64)
    if row.ndim != 1:
        raise AssertionError("expected_distribution_row must have shape [n_orientations].")
    n_orientations = int(row.shape[0])
    orientation_index = torch.arange(n_orientations, dtype=torch.long)
    relative_offsets = torch.remainder(orientation_index - int(source_orientation), n_orientations)
    cw_mask = relative_offsets.eq(1)
    ccw_mask = relative_offsets.eq(n_orientations - 1)
    neutral_mask = cw_mask.logical_not() & ccw_mask.logical_not()
    mass = torch.stack(
        [
            row[cw_mask].sum(),
            row[ccw_mask].sum(),
            row[neutral_mask].sum(),
        ],
        dim=0,
    )
    total_mass = mass.sum()
    if not torch.isfinite(total_mass).item():
        raise AssertionError("3-state mass vector must be finite.")
    if float(total_mass.item()) <= 0.0:
        raise AssertionError("3-state mass vector must have positive total mass.")
    return mass / total_mass


def _higher_level_state_hard_label(mass: torch.Tensor) -> str:
    max_mass = mass.max()
    tie_count = int(torch.isclose(mass, max_mass, atol=1e-8, rtol=0.0).sum().item())
    if tie_count > 1:
        return "Neutral"
    return _higher_level_state_label_from_index(int(mass.argmax().item()))


def _higher_level_state_precision(mass: torch.Tensor) -> float:
    normalized = mass.to(torch.float64) / mass.to(torch.float64).sum().clamp_min(1e-12)
    entropy = -(normalized.clamp_min(1e-12) * normalized.clamp_min(1e-12).log()).sum()
    precision = 1.0 - entropy / torch.log(torch.tensor(3.0, dtype=torch.float64))
    return float(precision.clamp(0.0, 1.0).item())


def _higher_level_state_probe_row_summary(
    row: dict[str, object],
) -> dict[str, object]:
    expected_distribution = torch.tensor(row["expected_distribution"], dtype=torch.float64)
    mass = _higher_level_state_mass_vector(
        expected_distribution,
        source_orientation=int(row["source_orientation"]),
    )
    hard_label = _higher_level_state_hard_label(mass)
    precision = _higher_level_state_precision(mass)
    max_mass = float(mass.max().item())
    tie_to_neutral = hard_label == "Neutral" and int(torch.isclose(mass, mass.max(), atol=1e-8, rtol=0.0).sum().item()) > 1
    return {
        **row,
        "state_mass_vector": {
            "CW": float(mass[0].item()),
            "CCW": float(mass[1].item()),
            "Neutral": float(mass[2].item()),
        },
        "hard_state_label": hard_label,
        "hard_state_tie_to_neutral": bool(tie_to_neutral),
        "precision": float(precision),
        "strict_neutral_dominance": bool(float(mass[2].item()) > max(float(mass[0].item()), float(mass[1].item()))),
    }


def _higher_level_state_collect_probe_rows(
    *,
    generator: Phase1ParadigmGenerator,
    seed_panel: tuple[tuple[int, int], ...],
    panel_name: str,
) -> list[dict[str, object]]:
    return [
        _higher_level_state_probe_row_summary(row)
        for row in _readout_class_collect_panel_rows(
            generator=generator,
            seed_panel=seed_panel,
            panel_name=panel_name,
        )
    ]


def _higher_level_state_collect_standard_rows(
    *,
    generator: Phase1ParadigmGenerator,
    seed_panel: tuple[tuple[int, int], ...],
    panel_name: str,
    batch_size: int,
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    for train_seed, heldout_seed in seed_panel:
        batch = generator.generate_batch(batch_size=batch_size, seed=int(train_seed))
        scored_mask = batch.metadata["source_orientations"].ge(0)
        if batch.blank_mask is not None:
            scored_mask = scored_mask & batch.blank_mask.logical_not()
        task_mode_names = batch.metadata["task_mode_names"]
        prestim_mode_names = batch.metadata["prestim_mode_names"]
        for row_index, (trial_idx_tensor, step_idx_tensor) in enumerate(torch.nonzero(scored_mask, as_tuple=False).tolist()):
            trial_idx = int(trial_idx_tensor)
            step_idx = int(step_idx_tensor)
            source_orientation = int(batch.metadata["source_orientations"][trial_idx, step_idx].item())
            expected_distribution = batch.metadata["expected_distribution"][trial_idx, step_idx].to(torch.float64)
            mass = _higher_level_state_mass_vector(
                expected_distribution,
                source_orientation=source_orientation,
            )
            hard_label = _higher_level_state_hard_label(mass)
            precision = _higher_level_state_precision(mass)
            rows.append(
                {
                    "seed_panel": panel_name,
                    "train_seed": int(train_seed),
                    "heldout_seed": int(heldout_seed),
                    "row_index": row_index,
                    "trial_index": trial_idx,
                    "step_index": step_idx,
                    "context_id": int(batch.context_ids[trial_idx].item()),
                    "task_mode_name": str(task_mode_names[int(batch.task_mode[trial_idx].item())]),
                    "prestim_mode_name": str(prestim_mode_names[int(batch.prestim_mode[trial_idx].item())]),
                    "source_orientation": source_orientation,
                    "expected_distribution": [float(value) for value in expected_distribution.tolist()],
                    "state_mass_vector": {
                        "CW": float(mass[0].item()),
                        "CCW": float(mass[1].item()),
                        "Neutral": float(mass[2].item()),
                    },
                    "hard_state_label": hard_label,
                    "hard_state_tie_to_neutral": bool(
                        hard_label == "Neutral"
                        and int(torch.isclose(mass, mass.max(), atol=1e-8, rtol=0.0).sum().item()) > 1
                    ),
                    "precision": float(precision),
                    "strict_neutral_dominance": bool(
                        float(mass[2].item()) > max(float(mass[0].item()), float(mass[1].item()))
                    ),
                    "distribution_is_finite": bool(torch.isfinite(expected_distribution).all().item()),
                    "distribution_sum": float(expected_distribution.sum().item()),
                }
            )
    return rows


def _higher_level_state_transition_counts(rows: list[dict[str, object]]) -> dict[str, int]:
    transitions: dict[str, int] = {}
    rows_by_trial: dict[tuple[str, int, int], list[dict[str, object]]] = {}
    for row in rows:
        trial_key = (str(row["seed_panel"]), int(row["train_seed"]), int(row["trial_index"]))
        rows_by_trial.setdefault(trial_key, []).append(row)
    for trial_rows in rows_by_trial.values():
        ordered_rows = sorted(trial_rows, key=lambda item: int(item["step_index"]))
        for previous_row, current_row in zip(ordered_rows, ordered_rows[1:]):
            transition_key = f"{previous_row['hard_state_label']}->{current_row['hard_state_label']}"
            transitions[transition_key] = transitions.get(transition_key, 0) + 1
    return transitions


def _higher_level_state_precision_summary(rows: list[dict[str, object]]) -> dict[str, object]:
    precision_values = [float(row["precision"]) for row in rows]
    precision_tensor = torch.tensor(precision_values, dtype=torch.float64)
    precision_by_state: dict[str, list[float]] = {label: [] for label in HIGHER_LEVEL_STATE_LATENT_STATES}
    for row in rows:
        precision_by_state[str(row["hard_state_label"])].append(float(row["precision"]))
    unique_precision_by_state = {
        label: sorted({float(value) for value in values})
        for label, values in precision_by_state.items()
    }
    precision_not_just_hard_state_lookup = any(len(values) > 1 for values in unique_precision_by_state.values())
    return {
        "defined_on_all_rows": bool(all(torch.isfinite(torch.tensor(value)).item() for value in precision_values)),
        "nonconstant": bool(len(sorted({float(value) for value in precision_values})) > 1),
        "min": float(precision_tensor.min().item()),
        "max": float(precision_tensor.max().item()),
        "variance": float(precision_tensor.var(unbiased=False).item()),
        "unique_values": sorted({float(value) for value in precision_values}),
        "unique_values_by_hard_state": unique_precision_by_state,
        "not_just_hard_state_lookup_if_possible": bool(precision_not_just_hard_state_lookup),
    }


def _higher_level_state_state_counts(rows: list[dict[str, object]]) -> dict[str, int]:
    counts = {label: 0 for label in HIGHER_LEVEL_STATE_LATENT_STATES}
    for row in rows:
        counts[str(row["hard_state_label"])] += 1
    return counts


def _higher_level_state_sources_by_state(rows: list[dict[str, object]]) -> dict[str, list[int]]:
    sources_by_state: dict[str, set[int]] = {label: set() for label in HIGHER_LEVEL_STATE_LATENT_STATES}
    for row in rows:
        sources_by_state[str(row["hard_state_label"])].add(int(row["source_orientation"]))
    return {label: sorted(values) for label, values in sources_by_state.items()}


def _higher_level_state_emission_template_report(
    *,
    generator: Phase1ParadigmGenerator,
) -> dict[str, object]:
    batch = generator.generate_local_global_probe_batch(seed=10101)
    transition_matrices = batch.metadata["transition_matrices"]
    source_relative_templates: dict[str, dict[str, object]] = {}
    mirror_checks: list[dict[str, object]] = []
    for source_orientation in STAGE3_FULL_CONTROLLED_SOURCES:
        source_orientation = int(source_orientation)
        cw_mass = _higher_level_state_mass_vector(
            transition_matrices[0][source_orientation],
            source_orientation=source_orientation,
        )
        ccw_mass = _higher_level_state_mass_vector(
            transition_matrices[1][source_orientation],
            source_orientation=source_orientation,
        )
        neutral_mass = _higher_level_state_mass_vector(
            transition_matrices[2][source_orientation],
            source_orientation=source_orientation,
        )
        source_relative_templates[str(source_orientation)] = {
            "CW": [float(value) for value in cw_mass.tolist()],
            "CCW": [float(value) for value in ccw_mass.tolist()],
            "Neutral": [float(value) for value in neutral_mass.tolist()],
        }
        mirror_checks.append(
            {
                "source_orientation": source_orientation,
                "cw_mass_matches_ccw_reflection": bool(
                    torch.allclose(cw_mass, torch.tensor([ccw_mass[1], ccw_mass[0], ccw_mass[2]], dtype=torch.float64), atol=1e-8, rtol=0.0)
                ),
            }
        )
    return {
        "source_relative_templates": source_relative_templates,
        "mirror_checks": mirror_checks,
        "all_cw_ccw_mirror_checks_pass": bool(all(check["cw_mass_matches_ccw_reflection"] for check in mirror_checks)),
        "absolute_orientation_reconstruction": "absolute_orientation = wrap_index(source_orientation + relative_offset)",
    }


def _higher_level_state_fixed_transition_constraint() -> dict[str, object]:
    return {
        "family_id": "tied_sticky_three_state_constraint_v1",
        "free_parameters": [],
        "plain_description": (
            "stickiness is a fixed family constraint rather than a trainable rho parameter; latent transitions "
            "are constrained to remain CW/CCW symmetric and to preserve a self-transition preference structurally"
        ),
        "serialized_constraints": {
            "latent_vocabulary": list(HIGHER_LEVEL_STATE_LATENT_STATES),
            "cw_ccw_symmetry_tied": True,
            "self_transition_preference_is_structural": True,
            "free_stickiness_parameter": False,
        },
    }


def _higher_level_state_expected_history() -> dict[str, dict[str, object]]:
    history = dict(_readout_class_expected_history())
    repo_root = _stage4_repo_root()
    history["context_residual"] = {
        "path": repo_root
        / "artifacts/executions/context_residual_20260402_run3/context_residual/2026-04-02.context_residual.package.v1/context_residual_verdict.v1.json",
        "expected_classification": "NO-GO clean negative",
    }
    return history


def _higher_level_state_nonregression_report(benchmark_artifacts_root: str | Path) -> dict[str, object]:
    benchmark_status = _precision_target_benchmark_status(benchmark_artifacts_root)
    historical_reports: dict[str, dict[str, object]] = {}
    historical_ok = True
    for name, spec in _higher_level_state_expected_history().items():
        verdict_path = Path(spec["path"])
        exists = verdict_path.exists()
        payload = _stage4_read_json(verdict_path) if exists else {}
        observed_classification, source = _readout_class_observed_classification(name, payload)
        matches = exists and observed_classification == spec["expected_classification"]
        historical_ok &= matches
        historical_reports[name] = {
            "path": str(verdict_path),
            "exists": bool(exists),
            "expected_classification": str(spec["expected_classification"]),
            "observed_classification": observed_classification,
            "classification_source": source,
            "matches_expected": bool(matches),
        }
    passes = (
        bool(benchmark_status["benchmark_registry_payload_matches_in_code"])
        and bool(benchmark_status["benchmark_fingerprints_payload_matches_in_code"])
        and bool(benchmark_status["metric_versions_payload_matches_in_code"])
        and bool(historical_ok)
    )
    return {
        **_higher_level_state_metadata(
            metric_versions={"higher_level_state_nonregression_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "benchmark_fingerprints_unchanged": benchmark_status,
        "historical_bundle_classifications": historical_reports,
        "checks": {
            "benchmark_registry_unchanged": bool(benchmark_status["benchmark_registry_payload_matches_in_code"]),
            "benchmark_fingerprints_unchanged": bool(
                benchmark_status["benchmark_fingerprints_payload_matches_in_code"]
            ),
            "metric_versions_unchanged": bool(benchmark_status["metric_versions_payload_matches_in_code"]),
            "historical_bundle_classifications_unchanged": bool(historical_ok),
        },
        "passes": bool(passes),
    }


def _higher_level_state_semantics_report(
    *,
    generator: Phase1ParadigmGenerator,
    n_orientations: int,
) -> dict[str, object]:
    emission_report = _higher_level_state_emission_template_report(generator=generator)
