def _higher_level_state_train_collapse_serialized(n_orientations: int) -> dict[str, object]:
    return {
        "relative_offset": "(absolute_orientation - source_orientation) mod n_orientations",
        "CW_bin": [1],
        "CCW_bin": [int(n_orientations - 1)],
        "Neutral_bin": [
            int(offset)
            for offset in range(int(n_orientations))
            if offset not in (1, int(n_orientations - 1))
        ],
    }


def _higher_level_state_train_standard_mask(batch: TrialBatch) -> torch.Tensor:
    mask = batch.metadata["source_orientations"].ge(0)
    if batch.blank_mask is not None:
        mask = mask & batch.blank_mask.logical_not()
    return mask


def _higher_level_state_train_parameter_scope_snapshot(
    predictor: CausalContextPredictor,
) -> dict[str, object]:
    recurrent_core_parameters = [(name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("gru.")]
    precision_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("precision_head.")
    ]
    orientation_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("orientation_head.")
    ]
    latent_state_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("latent_state_head.")
    ]
    trainable_parameter_names = [name for name, parameter in predictor.named_parameters() if parameter.requires_grad]
    return {
        "trainable_parameter_names": trainable_parameter_names,
        "recurrent_core_parameter_names": [name for name, _ in recurrent_core_parameters],
        "orientation_head_parameter_names": [name for name, _ in orientation_parameters],
        "precision_head_parameter_names": [name for name, _ in precision_parameters],
        "latent_state_head_parameter_names": [name for name, _ in latent_state_parameters],
        "recurrent_core_fingerprint": _named_parameter_fingerprint(recurrent_core_parameters),
        "orientation_head_fingerprint": _named_parameter_fingerprint(orientation_parameters),
        "precision_head_fingerprint": (
            _named_parameter_fingerprint(precision_parameters) if precision_parameters else "disabled"
        ),
        "latent_state_head_fingerprint": _named_parameter_fingerprint(latent_state_parameters),
    }


def _higher_level_state_train_freeze_state_head_only(
    predictor: CausalContextPredictor,
) -> list[str]:
    for name, parameter in predictor.named_parameters():
        parameter.requires_grad = name in HIGHER_LEVEL_STATE_TRAIN_PARAM_UPDATE_SCOPE
    trainable_parameter_names = [name for name, parameter in predictor.named_parameters() if parameter.requires_grad]
    if trainable_parameter_names != list(HIGHER_LEVEL_STATE_TRAIN_PARAM_UPDATE_SCOPE):
        raise AssertionError(
            "higher_level_state_train may only train predictor.latent_state_head.{weight,bias}."
        )
    return trainable_parameter_names


def _higher_level_state_train_target_state_mass(
    batch: TrialBatch,
) -> dict[str, object]:
    expected_distribution = batch.metadata["expected_distribution"].to(torch.float32)
    source_orientations = batch.metadata["source_orientations"]
    batch_size, n_steps, _ = expected_distribution.shape
    state_mass = torch.zeros((batch_size, n_steps, 3), dtype=expected_distribution.dtype)
    hard_state_index = torch.full((batch_size, n_steps), -1, dtype=torch.long)
    hard_state_label: list[list[str]] = [[""] * n_steps for _ in range(batch_size)]
    strict_neutral_mask = torch.zeros((batch_size, n_steps), dtype=torch.bool)
    valid_source_mask = source_orientations.ge(0)
    for trial_idx_tensor, step_idx_tensor in torch.nonzero(valid_source_mask, as_tuple=False):
        trial_idx = int(trial_idx_tensor.item())
        step_idx = int(step_idx_tensor.item())
        source_orientation = int(source_orientations[trial_idx, step_idx].item())
        mass = _higher_level_state_mass_vector(
            expected_distribution[trial_idx, step_idx].to(torch.float64),
            source_orientation=source_orientation,
        ).to(dtype=expected_distribution.dtype)
        state_mass[trial_idx, step_idx] = mass
        label = _higher_level_state_hard_label(mass.to(torch.float64))
        hard_state_label[trial_idx][step_idx] = label
        hard_state_index[trial_idx, step_idx] = int(HIGHER_LEVEL_STATE_LATENT_STATES.index(label))
        strict_neutral_mask[trial_idx, step_idx] = bool(
            float(mass[2].item()) > max(float(mass[0].item()), float(mass[1].item()))
        )
    return {
        "state_mass": state_mass,
        "hard_state_index": hard_state_index,
        "hard_state_label": hard_state_label,
        "strict_neutral_mask": strict_neutral_mask,
        "valid_source_mask": valid_source_mask,
    }


def _higher_level_state_train_reconstruct_from_posterior(
    *,
    batch: TrialBatch,
    posterior: torch.Tensor,
) -> dict[str, object]:
    if posterior.ndim != 3 or int(posterior.shape[-1]) != len(HIGHER_LEVEL_STATE_LATENT_STATES):
        raise ValueError("posterior must have shape [batch, step, 3].")
    expected_distribution = batch.metadata["expected_distribution"].to(
        device=posterior.device,
        dtype=posterior.dtype,
    )
    orientations = batch.orientations.to(device=posterior.device)
    source_orientations = batch.metadata["source_orientations"].to(device=posterior.device)
    transition_matrices = {
        key: value.to(device=posterior.device, dtype=posterior.dtype)
        for key, value in batch.metadata["transition_matrices"].items()
    }
    n_orientations = int(expected_distribution.shape[-1])
    reconstructed = torch.zeros_like(expected_distribution)
    effective_source = source_orientations.clone()
    anchor_completion_mask = source_orientations.lt(0) & orientations.ge(0)
    effective_source[anchor_completion_mask] = orientations[anchor_completion_mask]
    valid_reconstruction_mask = effective_source.ge(0)
    safe_source = effective_source.clamp_min(0)
    templates = torch.stack(
        [
            transition_matrices[0][safe_source],
            transition_matrices[1][safe_source],
            transition_matrices[2][safe_source],
        ],
        dim=-2,
    )
    reconstructed_from_posterior = (posterior.unsqueeze(-1) * templates).sum(dim=-2)
    reconstructed[valid_reconstruction_mask] = reconstructed_from_posterior[valid_reconstruction_mask]
    blank_no_source_mask = valid_reconstruction_mask.logical_not()
    if blank_no_source_mask.any():
        reconstructed[blank_no_source_mask] = 1.0 / float(n_orientations)
    row_sums = reconstructed.sum(dim=-1)
    if not torch.allclose(
        row_sums,
        torch.ones_like(row_sums),
        atol=1e-6,
        rtol=0.0,
    ):
        raise AssertionError("reconstructed orientation distributions must be normalized.")
    precision = 1.0 - (
        -(posterior.clamp_min(1e-8) * posterior.clamp_min(1e-8).log()).sum(dim=-1) / torch.log(posterior.new_tensor(3.0))
    )
    precision = precision.clamp(0.0, 1.0)
    safe_precision = precision.clamp(1e-6, 1.0 - 1e-6)
    precision_logit = torch.log(safe_precision) - torch.log1p(-safe_precision)
    return {
        "reconstructed_distribution": reconstructed,
        "precision": precision.unsqueeze(-1),
        "precision_logit": precision_logit.unsqueeze(-1),
        "effective_source_orientation": effective_source,
        "anchor_completion_mask": anchor_completion_mask,
        "blank_no_source_mask": blank_no_source_mask,
    }


def _higher_level_state_train_prediction_from_hidden_states(
    *,
    predictor: CausalContextPredictor,
    batch: TrialBatch,
    hidden_states: torch.Tensor,
) -> tuple[ContextPrediction, dict[str, object]]:
    latent_state_logits = predictor.latent_state_logits_from_hidden_states(hidden_states)
    posterior = torch.softmax(latent_state_logits, dim=-1)
    reconstruction = _higher_level_state_train_reconstruct_from_posterior(
        batch=batch,
        posterior=posterior,
    )
    prediction = ContextPrediction(
        orientation_logits=torch.log(reconstruction["reconstructed_distribution"].clamp_min(1e-8)),
        precision_logit=reconstruction["precision_logit"],
    )
    payload = {
        "latent_state_logits": latent_state_logits.detach().cpu(),
        "predicted_state_mass": posterior.detach().cpu(),
        "reconstructed_orientation_distribution": reconstruction["reconstructed_distribution"].detach().cpu(),
        "posterior_derived_precision": reconstruction["precision"].detach().cpu(),
        "effective_source_orientation": reconstruction["effective_source_orientation"].detach().cpu(),
        "anchor_completion_mask": reconstruction["anchor_completion_mask"].detach().cpu(),
        "blank_no_source_mask": reconstruction["blank_no_source_mask"].detach().cpu(),
        "scientific_scoring_uses_reconstructed_emissions_only": True,
    }
    return prediction, payload


def _higher_level_state_train_loss_components(
    *,
    predictor: CausalContextPredictor,
    batch: TrialBatch,
    scoring_mask: torch.Tensor,
) -> dict[str, object]:
    if not bool(scoring_mask.any()):
        raise ValueError("higher_level_state_train requires at least one scored row in every training batch.")
    with torch.no_grad():
        inputs = predictor._build_inputs(batch)
        hidden_states, _ = predictor.gru(inputs)
    hidden_states = hidden_states.detach()
    latent_state_logits = predictor.latent_state_logits_from_hidden_states(hidden_states)
    posterior = torch.softmax(latent_state_logits, dim=-1)
    target_payload = _higher_level_state_train_target_state_mass(batch)
    reconstruction = _higher_level_state_train_reconstruct_from_posterior(
        batch=batch,
        posterior=posterior,
    )
    target_state_mass = target_payload["state_mass"].to(device=posterior.device, dtype=posterior.dtype)
    expected_distribution = batch.metadata["expected_distribution"].to(device=posterior.device, dtype=posterior.dtype)
    log_q = torch.log_softmax(latent_state_logits, dim=-1)
    state_kl = (
        target_state_mass.clamp_min(1e-8) * (target_state_mass.clamp_min(1e-8).log() - log_q)
    ).sum(dim=-1)
    log_reconstructed = torch.log(reconstruction["reconstructed_distribution"].clamp_min(1e-8))
    emit_kl = (
        expected_distribution.clamp_min(1e-8)
        * (expected_distribution.clamp_min(1e-8).log() - log_reconstructed)
    ).sum(dim=-1)
    score_mask = scoring_mask.to(device=posterior.device)
    row_count = int(score_mask.sum().item())
    state_sum = state_kl[score_mask].sum()
    emit_sum = emit_kl[score_mask].sum()
    return {
        "state_sum": state_sum,
        "emit_sum": emit_sum,
        "row_count": row_count,
    }


def _higher_level_state_train_refit_state_head(
    *,
    predictor: CausalContextPredictor,
    generator: Phase1ParadigmGenerator,
    heldout_seed: int,
    training_config,
) -> tuple[list[dict[str, object]], list[int], list[int]]:
    trainable_parameter_names = _higher_level_state_train_freeze_state_head_only(predictor)
    if trainable_parameter_names != list(HIGHER_LEVEL_STATE_TRAIN_PARAM_UPDATE_SCOPE):
        raise AssertionError("unexpected higher_level_state_train parameter scope.")
    optimizer = torch.optim.Adam(
        predictor.latent_state_head.parameters(),
        lr=training_config.learning_rate,
        weight_decay=training_config.weight_decay,
    )
    probe_train_seeds = [
        int(heldout_seed) + HIGHER_LEVEL_STATE_TRAIN_PROBE_TRAIN_SEED_BASE_OFFSET + step_index
        for step_index in range(int(training_config.n_epochs))
    ]
    predictive_train_seeds = [
        int(heldout_seed) + HIGHER_LEVEL_STATE_TRAIN_PREDICTIVE_TRAIN_SEED_BASE_OFFSET + step_index
        for step_index in range(int(training_config.n_epochs))
    ]
    history: list[dict[str, object]] = []
    predictor.train()
    for epoch_index, (probe_seed, predictive_seed) in enumerate(
        zip(probe_train_seeds, predictive_train_seeds),
        start=1,
    ):
        probe_batch = generator.generate_local_global_probe_batch(seed=int(probe_seed))
        predictive_batch = generator.generate_batch(
            batch_size=training_config.batch_size,
            seed=int(predictive_seed),
        )
        optimizer.zero_grad(set_to_none=True)
        probe_components = _higher_level_state_train_loss_components(
            predictor=predictor,
            batch=probe_batch,
            scoring_mask=_probe_scoring_mask(probe_batch),
        )
        predictive_components = _higher_level_state_train_loss_components(
            predictor=predictor,
            batch=predictive_batch,
            scoring_mask=_higher_level_state_train_standard_mask(predictive_batch),
        )
        total_row_count = int(probe_components["row_count"]) + int(predictive_components["row_count"])
        if total_row_count <= 0:
            raise AssertionError("higher_level_state_train must score at least one row per refit step.")
        state_loss = (probe_components["state_sum"] + predictive_components["state_sum"]) / total_row_count
        emit_loss = (probe_components["emit_sum"] + predictive_components["emit_sum"]) / total_row_count
        total_loss = state_loss + emit_loss
        total_loss.backward()
        optimizer.step()
        history.append(
            {
                "epoch": epoch_index,
                "total": float(total_loss.item()),
                "state_kl": float(state_loss.item()),
                "emission_kl": float(emit_loss.item()),
                "probe_train_seed": int(probe_seed),
                "predictive_train_seed": int(predictive_seed),
                "probe_row_count": int(probe_components["row_count"]),
                "predictive_row_count": int(predictive_components["row_count"]),
            }
        )
    predictor.eval()
    return history, probe_train_seeds, predictive_train_seeds


def _higher_level_state_train_probe_state_metrics(
    *,
    batch: TrialBatch,
    target_payload: dict[str, object],
    predicted_state_mass: torch.Tensor,
) -> dict[str, object]:
    probe_mask = _probe_scoring_mask(batch)
    target_state_mass = target_payload["state_mass"][probe_mask].to(torch.float64)
    predicted_mass = predicted_state_mass[probe_mask].to(torch.float64)
    target_labels = target_payload["hard_state_index"][probe_mask]
    predicted_labels = predicted_mass.argmax(dim=-1).to(torch.long)
    state_kl = (
        target_state_mass.clamp_min(1e-8)
        * (target_state_mass.clamp_min(1e-8).log() - predicted_mass.clamp_min(1e-8).log())
    ).sum(dim=-1)
    pair_ids = batch.metadata["probe_pair_id"][torch.nonzero(probe_mask, as_tuple=False)[:, 0]]
    contexts = batch.context_ids[torch.nonzero(probe_mask, as_tuple=False)[:, 0]]
    mirror_map = {0: 1, 1: 0, 2: 2}
    pair_context_predictions: dict[int, dict[int, int]] = {}
    for row_index, pair_id in enumerate(pair_ids.tolist()):
        pair_context_predictions.setdefault(int(pair_id), {})[int(contexts[row_index].item())] = int(
            predicted_labels[row_index].item()
        )
    mirror_errors: list[float] = []
    for predictions in pair_context_predictions.values():
        if 0 in predictions and 1 in predictions:
            mirror_errors.append(float(predictions[1] != mirror_map[predictions[0]]))
    hard_state_accuracy = float(predicted_labels.eq(target_labels).to(torch.float32).mean().item())
    return {
        "mean_state_kl": float(state_kl.mean().item()),
        "hard_state_accuracy": hard_state_accuracy,
        "mirror_error": float(sum(mirror_errors) / len(mirror_errors)) if mirror_errors else 1.0,
        "predicted_state_counts": {
            label: int(predicted_labels.eq(index).sum().item())
            for index, label in enumerate(HIGHER_LEVEL_STATE_LATENT_STATES)
        },
    }


def _higher_level_state_train_standard_transition_metrics(
    *,
    batch: TrialBatch,
    target_payload: dict[str, object],
    predicted_state_mass: torch.Tensor,
    posterior_precision: torch.Tensor,
) -> dict[str, object]:
    standard_mask = _higher_level_state_train_standard_mask(batch)
    scored_indices = torch.nonzero(standard_mask, as_tuple=False)
    target_labels = target_payload["hard_state_index"][standard_mask]
    predicted_labels = predicted_state_mass[standard_mask].argmax(dim=-1).to(torch.long)
    hard_state_accuracy = float(predicted_labels.eq(target_labels).to(torch.float32).mean().item())
    strict_neutral_mask = target_payload["strict_neutral_mask"][standard_mask]
    if bool(strict_neutral_mask.any()):
        strict_neutral_recall = float(
            predicted_labels[strict_neutral_mask].eq(HIGHER_LEVEL_STATE_LATENT_STATES.index("Neutral")).to(torch.float32).mean().item()
        )
    else:
        strict_neutral_recall = 0.0
    predicted_state_counts = {
        label: int(predicted_labels.eq(index).sum().item())
        for index, label in enumerate(HIGHER_LEVEL_STATE_LATENT_STATES)
    }
    transition_hits: list[float] = []
    trial_rows: dict[int, list[tuple[int, int, int]]] = {}
    for row_index, (trial_idx_tensor, step_idx_tensor) in enumerate(scored_indices.tolist()):
        trial_idx = int(trial_idx_tensor)
        step_idx = int(step_idx_tensor)
        trial_rows.setdefault(trial_idx, []).append(
            (
                step_idx,
                int(target_labels[row_index].item()),
                int(predicted_labels[row_index].item()),
            )
        )
    for rows in trial_rows.values():
        rows = sorted(rows, key=lambda item: item[0])
        for previous_row, current_row in zip(rows, rows[1:]):
            if current_row[0] != previous_row[0] + 1:
                continue
            transition_hits.append(
                float(previous_row[1] == previous_row[2] and current_row[1] == current_row[2])
            )
    transition_hard_accuracy = (
        float(sum(transition_hits) / len(transition_hits)) if transition_hits else 0.0
    )
    precision_values = posterior_precision[standard_mask].squeeze(-1)
    precision_defined = bool(torch.isfinite(precision_values).all().item())
    precision_nonconstant = bool(torch.unique(torch.round(precision_values * 1e6)).numel() > 1)
    return {
        "hard_state_accuracy": hard_state_accuracy,
        "strict_neutral_recall": strict_neutral_recall,
        "transition_hard_accuracy": transition_hard_accuracy,
        "all_three_predicted_states_present": bool(all(count > 0 for count in predicted_state_counts.values())),
        "posterior_precision_defined": precision_defined,
        "posterior_precision_nonconstant": precision_nonconstant,
        "predicted_state_counts": predicted_state_counts,
        "strict_neutral_row_count": int(strict_neutral_mask.sum().item()),
    }


def _higher_level_state_train_transition_audit_payload(
    *,
    batch: TrialBatch,
    target_payload: dict[str, object],
    predicted_state_mass: torch.Tensor,
) -> dict[str, object]:
    standard_mask = _higher_level_state_train_standard_mask(batch)
    scored_indices = torch.nonzero(standard_mask, as_tuple=False)
    predicted_labels = predicted_state_mass[standard_mask].argmax(dim=-1).to(torch.long)
    target_labels = target_payload["hard_state_index"][standard_mask]
    rows: list[dict[str, object]] = []
    transition_hits: list[float] = []
    trial_rows: dict[int, list[tuple[int, int, int, int]]] = {}
    for row_index, (trial_idx_tensor, step_idx_tensor) in enumerate(scored_indices.tolist()):
        trial_idx = int(trial_idx_tensor)
        step_idx = int(step_idx_tensor)
        trial_rows.setdefault(trial_idx, []).append(
            (
                step_idx,
                row_index,
                int(target_labels[row_index].item()),
                int(predicted_labels[row_index].item()),
            )
        )
    for trial_idx, ordered_rows in trial_rows.items():
        ordered_rows = sorted(ordered_rows, key=lambda item: item[0])
        for previous_row, current_row in zip(ordered_rows, ordered_rows[1:]):
            if current_row[0] != previous_row[0] + 1:
                continue
            hit = previous_row[2] == previous_row[3] and current_row[2] == current_row[3]
            transition_hits.append(float(hit))
            rows.append(
                {
                    "trial_index": int(trial_idx),
                    "previous_step_index": int(previous_row[0]),
                    "current_step_index": int(current_row[0]),
                    "target_transition": [
                        _higher_level_state_label_from_index(previous_row[2]),
                        _higher_level_state_label_from_index(current_row[2]),
                    ],
                    "predicted_transition": [
                        _higher_level_state_label_from_index(previous_row[3]),
                        _higher_level_state_label_from_index(current_row[3]),
                    ],
                    "correct": bool(hit),
                }
            )
    return {
        "transition_rows": rows,
        "transition_hard_accuracy": float(sum(transition_hits) / len(transition_hits)) if transition_hits else 0.0,
        "n_transition_pairs": len(rows),
    }


def _higher_level_state_train_checkpoint_state_metrics(
    *,
    heldout_batch: TrialBatch,
    standard_heldout_batch: TrialBatch,
    heldout_target_payload: dict[str, object],
    standard_target_payload: dict[str, object],
    heldout_outputs: dict[str, object],
    standard_outputs: dict[str, object],
) -> dict[str, object]:
    probe_metrics = _higher_level_state_train_probe_state_metrics(
        batch=heldout_batch,
        target_payload=heldout_target_payload,
        predicted_state_mass=heldout_outputs["predicted_state_mass"],
    )
    standard_metrics = _higher_level_state_train_standard_transition_metrics(
        batch=standard_heldout_batch,
        target_payload=standard_target_payload,
        predicted_state_mass=standard_outputs["predicted_state_mass"],
        posterior_precision=standard_outputs["posterior_derived_precision"],
    )
    probe_mask = _probe_scoring_mask(heldout_batch)
    probe_directional_mask = probe_mask & heldout_target_payload["hard_state_index"].ne(HIGHER_LEVEL_STATE_LATENT_STATES.index("Neutral"))
    standard_mask = _higher_level_state_train_standard_mask(standard_heldout_batch)
    strict_neutral_mask = standard_mask & standard_target_payload["strict_neutral_mask"]
    probe_precision = heldout_outputs["posterior_derived_precision"][probe_directional_mask].squeeze(-1)
    standard_neutral_precision = standard_outputs["posterior_derived_precision"][strict_neutral_mask].squeeze(-1)
    precision_difference = (
        float(probe_precision.mean().item() - standard_neutral_precision.mean().item())
        if probe_precision.numel() > 0 and standard_neutral_precision.numel() > 0
        else None
    )
    return {
        "probe": probe_metrics,
        "standard": standard_metrics,
        "probe_directional_precision_minus_strict_neutral_standard": precision_difference,
    }


def _higher_level_state_train_write_state_artifacts(
    *,
    checkpoint_dir: Path,
    heldout_batch: TrialBatch,
    standard_heldout_batch: TrialBatch,
    heldout_target_payload: dict[str, object],
    standard_target_payload: dict[str, object],
    heldout_outputs: dict[str, object],
    standard_outputs: dict[str, object],
) -> dict[str, object]:
    torch.save(
        {
            "probe_scoring_mask": _probe_scoring_mask(heldout_batch),
            "state_mass": heldout_target_payload["state_mass"],
            "hard_state_index": heldout_target_payload["hard_state_index"],
            "strict_neutral_mask": heldout_target_payload["strict_neutral_mask"],
        },
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_PROBE_TARGET_STATE_ARTIFACT,
    )
    torch.save(
        {
            "standard_scoring_mask": _higher_level_state_train_standard_mask(standard_heldout_batch),
            "state_mass": standard_target_payload["state_mass"],
            "hard_state_index": standard_target_payload["hard_state_index"],
            "strict_neutral_mask": standard_target_payload["strict_neutral_mask"],
        },
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_STANDARD_TARGET_STATE_ARTIFACT,
    )
    torch.save(
        {
            "probe_scoring_mask": _probe_scoring_mask(heldout_batch),
            "predicted_state_mass": heldout_outputs["predicted_state_mass"],
            "latent_state_logits": heldout_outputs["latent_state_logits"],
        },
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_PROBE_PREDICTED_STATE_ARTIFACT,
    )
    torch.save(
        {
            "standard_scoring_mask": _higher_level_state_train_standard_mask(standard_heldout_batch),
            "predicted_state_mass": standard_outputs["predicted_state_mass"],
            "latent_state_logits": standard_outputs["latent_state_logits"],
        },
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_STANDARD_PREDICTED_STATE_ARTIFACT,
    )
    torch.save(
        {
            "probe_scoring_mask": _probe_scoring_mask(heldout_batch),
            "orientation_distribution": heldout_outputs["reconstructed_orientation_distribution"],
        },
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_PROBE_RECONSTRUCTED_ORIENTATION_ARTIFACT,
    )
    torch.save(
        {
            "standard_scoring_mask": _higher_level_state_train_standard_mask(standard_heldout_batch),
            "orientation_distribution": standard_outputs["reconstructed_orientation_distribution"],
        },
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_STANDARD_RECONSTRUCTED_ORIENTATION_ARTIFACT,
    )
    torch.save(
        {
            "probe_scoring_mask": _probe_scoring_mask(heldout_batch),
            "posterior_precision": heldout_outputs["posterior_derived_precision"],
        },
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_PROBE_PRECISION_ARTIFACT,
    )
    torch.save(
        {
            "standard_scoring_mask": _higher_level_state_train_standard_mask(standard_heldout_batch),
            "posterior_precision": standard_outputs["posterior_derived_precision"],
        },
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_STANDARD_PRECISION_ARTIFACT,
    )
    transition_audit = _higher_level_state_train_transition_audit_payload(
        batch=standard_heldout_batch,
        target_payload=standard_target_payload,
        predicted_state_mass=standard_outputs["predicted_state_mass"],
    )
    torch.save(transition_audit, checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_STANDARD_TRANSITION_AUDIT_ARTIFACT)
    return transition_audit


def _higher_level_state_train_write_auxiliary_support_artifacts(
    *,
    predictor: CausalContextPredictor,
    donor_fit_batch: TrialBatch,
    probe_train_batch: TrialBatch,
    predictive_train_batch: TrialBatch,
    run_dir: Path,
) -> None:
    with torch.no_grad():
        _, donor_fit_hidden_states = _predict_with_hidden_states(predictor, donor_fit_batch)
        _, probe_train_hidden_states = _predict_with_hidden_states(predictor, probe_train_batch)
        _, predictive_train_hidden_states = _predict_with_hidden_states(predictor, predictive_train_batch)
    torch.save(
        _standard_end_hidden_state_payload(
            batch=donor_fit_batch,
            hidden_states=donor_fit_hidden_states,
            batch_role="auxiliary_donor_fit",
        ),
        run_dir / HIGHER_LEVEL_STATE_TRAIN_RAW_HIDDEN_STATE_DONOR_FIT_ARTIFACT,
    )
    torch.save(
        _standard_end_hidden_state_payload(
            batch=probe_train_batch,
            hidden_states=probe_train_hidden_states,
            batch_role="auxiliary_probe_train",
        ),
        run_dir / HIGHER_LEVEL_STATE_TRAIN_RAW_HIDDEN_STATE_PROBE_TRAIN_ARTIFACT,
    )
    torch.save(
        _standard_end_hidden_state_payload(
            batch=predictive_train_batch,
            hidden_states=predictive_train_hidden_states,
            batch_role="auxiliary_predictive_train",
        ),
        run_dir / HIGHER_LEVEL_STATE_TRAIN_RAW_HIDDEN_STATE_PREDICTIVE_TRAIN_ARTIFACT,
    )
    torch.save(_serialize_batch(donor_fit_batch), run_dir / HIGHER_LEVEL_STATE_TRAIN_DONOR_FIT_BATCH_ARTIFACT)
    torch.save(_serialize_batch(probe_train_batch), run_dir / HIGHER_LEVEL_STATE_TRAIN_PROBE_TRAIN_BATCH_ARTIFACT)
    torch.save(_serialize_batch(predictive_train_batch), run_dir / HIGHER_LEVEL_STATE_TRAIN_PREDICTIVE_TRAIN_BATCH_ARTIFACT)


def _higher_level_state_train_write_linear_probe_artifacts(
    *,
    run_id: str,
    batch: TrialBatch,
    linear_probe_logits: torch.Tensor,
    oracle_prediction: ContextPrediction,
    output_dir: Path,
    auxiliary_seed: int,
) -> dict[str, object]:
    payload = {
        "run_id": run_id,
        "batch": _serialize_batch(batch),
        "learned_logits": linear_probe_logits,
        "oracle_logits": oracle_prediction.orientation_logits,
        "learned_precision": None,
        "oracle_precision": oracle_prediction.precision_logit,
        "l23_readout": None,
        "gaussian_orientation_bank": None,
        "context_comparator": None,
    }
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    diagnostics = build_hidden_state_diagnostics_v2(rows)
    diagnostics_payload = {
        **_higher_level_state_train_metadata(
            metric_versions=metric_versions_v2_payload(),
            source_metric_versions=[DIAGNOSTIC_SCHEMA_VERSION, FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "diagnostic_schema_version": DIAGNOSTIC_SCHEMA_VERSION,
        **diagnostics,
    }
    write_hidden_state_probe_table_v2(rows, output_dir / HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_HIDDEN_STATE_TABLE_V2_ARTIFACT)
    write_hidden_state_diagnostics_v2_json(
        diagnostics_payload,
        output_dir / HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_HIDDEN_STATE_DIAGNOSTICS_V2_ARTIFACT,
    )
    probe_mask = _probe_scoring_mask(batch)
    expected_distribution = batch.metadata["expected_distribution"][probe_mask]
    alignment_kl, expected_logprob = _probe_alignment_stats(linear_probe_logits[probe_mask], expected_distribution)
    behavior_metrics = _probe_alignment_behavior_metrics(batch, linear_probe_logits)
    report = {
        **_higher_level_state_train_metadata(
            metric_versions={
                "linear_probe_alignment_kl": "v1",
                "linear_probe_expected_logprob": "v1",
                "linear_probe_expected_target_top1_rate": "v1",
                "linear_probe_correct_pair_flip_rate__v2": "v2",
                "linear_probe_within_pair_mass__v2": "v2",
                "linear_probe_source_bin_kl__v2": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "run_id": run_id,
        "heldout_generator_seed": int(batch.metadata["generator_seed"]),
        "auxiliary_generator_seed": int(auxiliary_seed),
        "train_eval_disjoint": int(batch.metadata["generator_seed"]) != int(auxiliary_seed),
        "linear_probe_alignment_kl": alignment_kl,
        "linear_probe_expected_logprob": expected_logprob,
        "linear_probe_expected_target_top1_rate": behavior_metrics["probe_expected_target_top1_rate"],
        "linear_probe_pair_flip_rate": behavior_metrics["probe_pair_flip_rate"],
        "linear_probe_pair_flip_symmetry_consistency": behavior_metrics["probe_pair_flip_symmetry_consistency"],
        "linear_probe_correct_pair_flip_rate__v2": diagnostics["probe_correct_pair_flip_rate__v2"],
        "linear_probe_within_pair_mass__v2": diagnostics["probe_within_pair_mass__v2"],
        "linear_probe_source_bin_kl__v2": diagnostics["probe_source_bin_kl__v2"],
    }
    _write_json(output_dir / HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_REPORT_V1_ARTIFACT, report)
    return {
        "rows": rows,
        "diagnostics": diagnostics_payload,
        "report": report,
    }


def _higher_level_state_train_evaluate_checkpoint(
    *,
    predictor: CausalContextPredictor,
    heldout_batch: TrialBatch,
    donor_fit_batch: TrialBatch,
    standard_heldout_batch: TrialBatch,
    run_id: str,
    run_dir: Path,
    checkpoint_dirname: str,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    generator: Phase1ParadigmGenerator,
    resolved_config: ExperimentConfig,
    scoring_mode: str,
    linear_probe: dict[str, object] | None = None,
    save_prediction_artifact: str | None = None,
) -> dict[str, object]:
    checkpoint_dir = run_dir / checkpoint_dirname
    checkpoint_dir.mkdir(parents=True, exist_ok=True)
    (checkpoint_dir / "eval").mkdir(parents=True, exist_ok=True)
    with torch.no_grad():
        native_probe_prediction, heldout_hidden_states = _predict_with_hidden_states(predictor, heldout_batch)
        _, donor_fit_hidden_states = _predict_with_hidden_states(predictor, donor_fit_batch)
        _, predictive_hidden_states = _predict_with_hidden_states(predictor, standard_heldout_batch)
        if scoring_mode == "native":
            learned_prediction = native_probe_prediction
            heldout_outputs = {
                "latent_state_logits": predictor.latent_state_logits_from_hidden_states(heldout_hidden_states).detach().cpu(),
                "predicted_state_mass": torch.softmax(
                    predictor.latent_state_logits_from_hidden_states(heldout_hidden_states), dim=-1
                ).detach().cpu(),
                "reconstructed_orientation_distribution": torch.softmax(
                    native_probe_prediction.orientation_logits,
                    dim=-1,
                ).detach().cpu(),
                "posterior_derived_precision": (
                    torch.sigmoid(native_probe_prediction.precision_logit).detach().cpu()
                    if native_probe_prediction.precision_logit is not None
                    else torch.ones((*native_probe_prediction.orientation_logits.shape[:2], 1), dtype=torch.float32)
                ),
                "scientific_scoring_uses_reconstructed_emissions_only": False,
            }
            standard_prediction, _ = _predict_with_hidden_states(predictor, standard_heldout_batch)
            standard_outputs = {
                "latent_state_logits": predictor.latent_state_logits_from_hidden_states(predictive_hidden_states).detach().cpu(),
                "predicted_state_mass": torch.softmax(
                    predictor.latent_state_logits_from_hidden_states(predictive_hidden_states), dim=-1
                ).detach().cpu(),
                "reconstructed_orientation_distribution": torch.softmax(
                    standard_prediction.orientation_logits,
                    dim=-1,
                ).detach().cpu(),
                "posterior_derived_precision": (
                    torch.sigmoid(standard_prediction.precision_logit).detach().cpu()
                    if standard_prediction.precision_logit is not None
                    else torch.ones((*standard_prediction.orientation_logits.shape[:2], 1), dtype=torch.float32)
                ),
                "scientific_scoring_uses_reconstructed_emissions_only": False,
            }
        elif scoring_mode == "higher_level_state":
            learned_prediction, heldout_outputs = _higher_level_state_train_prediction_from_hidden_states(
                predictor=predictor,
                batch=heldout_batch,
                hidden_states=heldout_hidden_states.detach(),
            )
            standard_prediction, standard_outputs = _higher_level_state_train_prediction_from_hidden_states(
                predictor=predictor,
                batch=standard_heldout_batch,
                hidden_states=predictive_hidden_states.detach(),
            )
        else:
            raise ValueError(f"unknown higher_level_state_train scoring_mode: {scoring_mode}")
        oracle_prediction = _oracle_context_prediction(
            heldout_batch,
            use_precision=resolved_config.context.use_precision,
        )
        learned_simulation, learned_window_summaries = _evaluate_single_subcase(
            batch=heldout_batch,
            prediction=learned_prediction,
            subcase="dampening",
            model=model,
            config=resolved_config,
        )
        oracle_simulation, oracle_window_summaries = _evaluate_single_subcase(
            batch=heldout_batch,
            prediction=oracle_prediction,
            subcase="dampening",
            model=model,
            config=resolved_config,
        )
    standard_target_payload = _higher_level_state_train_target_state_mass(standard_heldout_batch)
    heldout_target_payload = _higher_level_state_train_target_state_mass(heldout_batch)
    standard_sanity = {
        "nuisance_only": asdict(generator.run_nuisance_only_failure_test(standard_heldout_batch)),
        "predictive_structure": asdict(generator.run_predictive_structure_success_test(standard_heldout_batch)),
    }
    standard_predictive_metrics = {
        "total": float(
            predictive_loss(
                standard_prediction,
                standard_heldout_batch,
                objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
                loss_mask=_higher_level_state_train_standard_mask(standard_heldout_batch),
            ).total.item()
        ),
        "predictive_loss": float(
            predictive_loss(
                standard_prediction,
                standard_heldout_batch,
                objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
                loss_mask=_higher_level_state_train_standard_mask(standard_heldout_batch),
            ).predictive_loss.item()
        ),
        "energy_penalty": 0.0,
        "homeostasis_penalty": 0.0,
    }

    torch.save(
        _standard_end_hidden_state_payload(
            batch=heldout_batch,
            hidden_states=heldout_hidden_states,
            batch_role="heldout_eval",
        ),
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_RAW_HIDDEN_STATE_EVAL_ARTIFACT,
    )
    torch.save(
        _standard_end_hidden_state_payload(
            batch=standard_heldout_batch,
            hidden_states=predictive_hidden_states,
            batch_role="heldout_predictive_eval",
        ),
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_RAW_HIDDEN_STATE_PREDICTIVE_ARTIFACT,
    )
    torch.save(_serialize_batch(heldout_batch), checkpoint_dir / "eval" / "heldout_batch.pt")
    torch.save(
        _serialize_batch(standard_heldout_batch),
        checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_HELDOUT_PREDICTIVE_BATCH_ARTIFACT,
    )

    probe_metrics = assay_runner.compute_local_global_probe_metrics(learned_simulation, heldout_batch)
    oracle_probe_metrics = assay_runner.compute_local_global_probe_metrics(oracle_simulation, heldout_batch)
    probe_context_alignment_report = _build_probe_context_alignment_report(
        heldout_batch,
        oracle_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=oracle_prediction,
            metadata=heldout_batch.metadata,
        ),
        learned_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=learned_prediction,
            metadata=heldout_batch.metadata,
        ),
    )
    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    probe_design_report = {
        **_higher_level_state_train_metadata(
            metric_versions={
                "n_probe_rows": "v1",
                "n_probe_global_expected_rows": "v1",
                "n_probe_global_unexpected_rows": "v1",
                "n_probe_pairs_total": "v1",
                "n_probe_pairs_scored": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **_build_probe_design_report(
            heldout_batch,
            task_mode_fixed_state=task_mode_fixed_state,
            prestim_fixed_state=prestim_fixed_state,
            oracle_simulation=oracle_simulation,
            learned_simulation=learned_simulation,
        ),
    }
    probe_metrics_payload = {
        **_higher_level_state_train_metadata(
            metric_versions={metric_name: "v1" for metric_name in sorted(probe_metrics)},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **probe_metrics,
    }
    oracle_probe_metrics_payload = {
        **_higher_level_state_train_metadata(
            metric_versions={metric_name: "v1" for metric_name in sorted(oracle_probe_metrics)},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **oracle_probe_metrics,
    }
    probe_context_alignment_payload = {
        **_higher_level_state_train_metadata(
            metric_versions={
                "learned_probe_alignment_kl": "v1",
                "oracle_probe_alignment_kl": "v1",
                "learned_probe_expected_logprob": "v1",
                "oracle_probe_expected_logprob": "v1",
                "learned_probe_expected_target_top1_rate": "v1",
                "oracle_probe_expected_target_top1_rate": "v1",
                "learned_probe_pair_flip_rate": "v1",
                "oracle_probe_pair_flip_rate": "v1",
                "learned_probe_pair_flip_symmetry_consistency": "v1",
                "oracle_probe_pair_flip_symmetry_consistency": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        **probe_context_alignment_report,
    }
    probe_table_payload = {
        **_higher_level_state_train_metadata(
            metric_versions={"probe_table_rows": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "rows": _build_probe_table(heldout_batch, oracle_simulation, learned_simulation),
    }
    probe_symmetry_mates = {
        int(pair_id): int(descriptor["symmetry_mate_pair_id"])
        for pair_id, descriptor in heldout_batch.metadata["probe_report"]["pair_descriptors"].items()
    }
    native_hidden_state_outputs = _readout_alignment_write_hidden_state_artifacts(
        run_id=run_id,
        batch=heldout_batch,
        learned_simulation=learned_simulation,
        oracle_simulation=oracle_simulation,
        symmetry_mate_lookup=probe_symmetry_mates,
        output_dir=checkpoint_dir,
    )
    resolved_linear_probe = linear_probe
    if resolved_linear_probe is None:
        resolved_linear_probe = _standard_end_fit_linear_probe(
            hidden_states=donor_fit_hidden_states,
            batch=donor_fit_batch,
        )
    linear_probe_logits = _standard_end_apply_linear_probe(
        hidden_states=heldout_hidden_states,
        linear_probe=resolved_linear_probe,
    )
    linear_probe_outputs = _higher_level_state_train_write_linear_probe_artifacts(
        run_id=run_id,
        batch=heldout_batch,
        linear_probe_logits=linear_probe_logits,
        oracle_prediction=oracle_prediction,
        output_dir=checkpoint_dir,
        auxiliary_seed=int(donor_fit_batch.metadata["generator_seed"]),
    )
    torch.save(resolved_linear_probe, checkpoint_dir / HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_PARAMETERS_ARTIFACT)

    _write_json(checkpoint_dir / "probe_design_report.json", probe_design_report)
    _write_json(checkpoint_dir / "probe_metrics.json", probe_metrics_payload)
    _write_json(checkpoint_dir / "oracle_probe_metrics.json", oracle_probe_metrics_payload)
    _write_json(checkpoint_dir / "probe_context_alignment_report.json", probe_context_alignment_payload)
    _write_json(checkpoint_dir / "probe_table.json", probe_table_payload)
    torch.save({"dampening": learned_window_summaries}, checkpoint_dir / "eval" / "window_summaries.pt")
    torch.save({"dampening": oracle_window_summaries}, checkpoint_dir / "eval" / "oracle_window_summaries.pt")
    torch.save({"dampening": _serialize_simulation(learned_simulation)}, checkpoint_dir / "eval" / "full_trajectories.pt")
    torch.save({"dampening": _serialize_simulation(oracle_simulation)}, checkpoint_dir / "eval" / "oracle_full_trajectories.pt")

    transition_audit = _higher_level_state_train_write_state_artifacts(
        checkpoint_dir=checkpoint_dir,
        heldout_batch=heldout_batch,
        standard_heldout_batch=standard_heldout_batch,
        heldout_target_payload=heldout_target_payload,
        standard_target_payload=standard_target_payload,
        heldout_outputs=heldout_outputs,
        standard_outputs=standard_outputs,
    )
    state_metrics = _higher_level_state_train_checkpoint_state_metrics(
        heldout_batch=heldout_batch,
        standard_heldout_batch=standard_heldout_batch,
        heldout_target_payload=heldout_target_payload,
        standard_target_payload=standard_target_payload,
        heldout_outputs=heldout_outputs,
        standard_outputs=standard_outputs,
    )

    if save_prediction_artifact is not None:
        (run_dir / "eval").mkdir(parents=True, exist_ok=True)
        torch.save(_serialize_context_prediction(learned_prediction), run_dir / save_prediction_artifact)

    return {
        "checkpoint": checkpoint_dirname,
        "scoring_mode": scoring_mode,
        "probe_metrics": probe_metrics,
        "oracle_probe_metrics": oracle_probe_metrics,
        "probe_context_alignment_report": probe_context_alignment_report,
        "hidden_state_diagnostics": native_hidden_state_outputs["diagnostics"],
        "linear_probe_report": linear_probe_outputs["report"],
        "linear_probe_diagnostics": linear_probe_outputs["diagnostics"],
        "standard_predictive_metrics": standard_predictive_metrics,
        "standard_sanity": standard_sanity,
        "heldout_generator_seed": int(heldout_batch.metadata["generator_seed"]),
        "predictive_generator_seed": int(standard_heldout_batch.metadata["generator_seed"]),
        "auxiliary_generator_seed": int(donor_fit_batch.metadata["generator_seed"]),
        "heldout_hidden_state_fingerprint": _tensor_fingerprint(heldout_hidden_states),
        "predictive_hidden_state_fingerprint": _tensor_fingerprint(predictive_hidden_states),
        "auxiliary_hidden_state_fingerprint": _tensor_fingerprint(donor_fit_hidden_states),
        "heldout_hidden_states": heldout_hidden_states.detach().cpu(),
        "predictive_hidden_states": predictive_hidden_states.detach().cpu(),
        "auxiliary_hidden_states": donor_fit_hidden_states.detach().cpu(),
        "latent_state_logits": heldout_outputs["latent_state_logits"],
        "probe_scoring_mask": _probe_scoring_mask(heldout_batch).detach().cpu(),
        "standard_scoring_mask": _higher_level_state_train_standard_mask(standard_heldout_batch).detach().cpu(),
        "state_metrics": state_metrics,
        "transition_audit": transition_audit,
        "artifacts_complete": True,
        "scientific_scoring_uses_reconstructed_emissions_only": bool(
            scoring_mode == "higher_level_state"
        ),
    }


def _higher_level_state_train_build_nonregression_report(
    benchmark_artifacts_root: str | Path,
) -> dict[str, object]:
    raw_report = _higher_level_state_nonregression_report(benchmark_artifacts_root)
    stripped = dict(raw_report)
    for key in (
        "metric_schema_version",
        "metric_versions",
        "classification_rule_version",
        "source_metric_versions",
        "benchmark_registry_version",
        "higher_level_state_package_version",
    ):
        stripped.pop(key, None)
    return {
        **_higher_level_state_train_metadata(
            metric_versions={"higher_level_state_train_nonregression_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        **stripped,
    }


def _higher_level_state_train_manifest_validity(
    package_manifest: dict[str, object],
) -> dict[str, object]:
    definition_root = _higher_level_state_train_definition_bundle_root()
    definition_manifest_path = definition_root / HIGHER_LEVEL_STATE_MANIFEST_V1_ARTIFACT
    definition_verdict_path = definition_root / HIGHER_LEVEL_STATE_VERDICT_V1_ARTIFACT
    definition_manifest = _stage4_read_json(definition_manifest_path) if definition_manifest_path.exists() else {}
    definition_verdict = _stage4_read_json(definition_verdict_path) if definition_verdict_path.exists() else {}
    checks = {
        "approved_definition_manifest_exists": bool(definition_manifest_path.exists()),
        "approved_definition_verdict_exists": bool(definition_verdict_path.exists()),
        "approved_definition_classification_is_go": definition_verdict.get("classification") == "GO",
        "family_name_matches_definition": package_manifest.get("family_name") == definition_manifest.get("candidate_name"),
        "latent_state_vocabulary_matches_definition": package_manifest.get("latent_state_vocabulary")
        == definition_manifest.get("latent_state_vocabulary"),
        "collapse_operator_matches_definition": package_manifest.get("collapse_operator_serialized")
        == definition_manifest.get("collapse_operator_serialized"),
        "emission_templates_match_definition": package_manifest.get("emission_templates")
        == definition_manifest.get("emission_templates"),
        "fixed_transition_constraint_matches_definition": package_manifest.get("fixed_family_constraints")
        == definition_manifest.get("fixed_family_constraints"),
    }
    return {
        "approved_definition_bundle_root": str(definition_root),
        "definition_manifest_path": str(definition_manifest_path),
        "definition_verdict_path": str(definition_verdict_path),
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
    }


def _higher_level_state_train_build_pre_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    native_anchor_summary = _readout_alignment_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_refit",
    )
    linear_probe_summary = _readout_alignment_linear_probe_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_refit",
    )
    delta_summary = _readout_alignment_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_refit",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "baseline_native_anchor_fails": not native_anchor_summary["passes"],
        "linear_probe_strong_gate_passes": bool(linear_probe_summary["passes"]),
        "mean_top1_improvement_ge_0_25": (
            delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"] is not None
            and float(delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"])
            >= HIGHER_LEVEL_STATE_TRAIN_TOP1_IMPROVEMENT_MIN
        ),
        "top1_improvement_ci_lower_gt_0": top1_ci is not None and float(top1_ci["lower"]) > 0.0,
        "mean_kl_reduction_ge_0_50": (
            delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"] is not None
            and float(delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"])
            >= HIGHER_LEVEL_STATE_TRAIN_KL_REDUCTION_MIN
        ),
        "kl_reduction_ci_lower_gt_0": kl_ci is not None and float(kl_ci["lower"]) > 0.0,
    }
    return {
        **_higher_level_state_train_metadata(
            metric_versions={"pre_refit_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "linear_probe_summary": linear_probe_summary,
        "readout_gap_summary": delta_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _higher_level_state_train_build_skipped_panel_report(
    *,
    artifact_key: str,
    seed_panel: str,
    stop_reason: str,
) -> dict[str, object]:
    return {
        **_higher_level_state_train_metadata(
            metric_versions={artifact_key: "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "skipped": True,
        "stop_reason": stop_reason,
        "passes": False,
    }


def _higher_level_state_train_build_integrity_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = len(run_entries)
    seedwise: list[dict[str, object]] = []
    boolean_fields = {
        "heldout_probe_batch_identity_same_pre_post": [],
        "heldout_predictive_batch_identity_same_pre_post": [],
        "auxiliary_batch_identity_same_pre_post": [],
        "auxiliary_eval_disjoint_from_heldout": [],
        "recurrent_core_parameter_fingerprint_unchanged": [],
        "orientation_head_parameter_fingerprint_unchanged": [],
        "precision_head_parameter_fingerprint_unchanged": [],
        "heldout_probe_hidden_states_unchanged": [],
        "heldout_predictive_hidden_states_unchanged": [],
        "exact_trainable_parameter_scope_during_refit": [],
        "scientific_scoring_uses_reconstructed_emissions_only": [],
    }
    state_head_changes: list[bool] = []
    for entry in run_entries:
        integrity = entry["refit_integrity"]
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                **integrity,
            }
        )
        for key in boolean_fields:
            boolean_fields[key].append(bool(integrity[key]))
        state_head_changes.append(bool(integrity["state_head_parameter_fingerprint_changed"]))
    checks = {
        "required_successes": required_successes,
        "heldout_probe_batch_identity_same_pre_post_count": _stage4_count_true(
            boolean_fields["heldout_probe_batch_identity_same_pre_post"]
        ),
        "heldout_predictive_batch_identity_same_pre_post_count": _stage4_count_true(
            boolean_fields["heldout_predictive_batch_identity_same_pre_post"]
        ),
        "auxiliary_batch_identity_same_pre_post_count": _stage4_count_true(
            boolean_fields["auxiliary_batch_identity_same_pre_post"]
        ),
        "auxiliary_eval_disjoint_from_heldout_count": _stage4_count_true(
            boolean_fields["auxiliary_eval_disjoint_from_heldout"]
        ),
        "recurrent_core_parameter_fingerprint_unchanged_count": _stage4_count_true(
            boolean_fields["recurrent_core_parameter_fingerprint_unchanged"]
        ),
        "orientation_head_parameter_fingerprint_unchanged_count": _stage4_count_true(
            boolean_fields["orientation_head_parameter_fingerprint_unchanged"]
        ),
        "precision_head_parameter_fingerprint_unchanged_count": _stage4_count_true(
            boolean_fields["precision_head_parameter_fingerprint_unchanged"]
        ),
        "heldout_probe_hidden_states_unchanged_count": _stage4_count_true(
            boolean_fields["heldout_probe_hidden_states_unchanged"]
        ),
        "heldout_predictive_hidden_states_unchanged_count": _stage4_count_true(
            boolean_fields["heldout_predictive_hidden_states_unchanged"]
        ),
        "exact_trainable_parameter_scope_during_refit_count": _stage4_count_true(
            boolean_fields["exact_trainable_parameter_scope_during_refit"]
        ),
        "scientific_scoring_uses_reconstructed_emissions_only_count": _stage4_count_true(
            boolean_fields["scientific_scoring_uses_reconstructed_emissions_only"]
        ),
        "state_head_parameter_fingerprint_changed_count": _stage4_count_true(state_head_changes),
    }
    count_checks_pass = all(
        value >= required_successes
        for key, value in checks.items()
        if key.endswith("_count") and key != "state_head_parameter_fingerprint_changed_count"
    )
    checks["passes"] = count_checks_pass and checks["state_head_parameter_fingerprint_changed_count"] >= 1
    return {
        **_higher_level_state_train_metadata(
            metric_versions={"higher_level_state_integrity_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "checks": checks,
        "passes": bool(checks["passes"]),
        "skipped": False,
    }


def _higher_level_state_train_predictive_integrity_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = len(run_entries)
    seedwise: list[dict[str, object]] = []
    loss_checks: list[bool] = []
    structure_checks: list[bool] = []
    nuisance_delta_checks: list[bool] = []
    nuisance_post_checks: list[bool] = []
    for entry in run_entries:
        integrity = entry["refit_integrity"]
        loss_check = integrity["delta_predictive_loss"] <= HIGHER_LEVEL_STATE_TRAIN_PREDICTIVE_LOSS_DELTA_MAX
        structure_check = (
            integrity["delta_predictive_structure_accuracy"] >= HIGHER_LEVEL_STATE_TRAIN_PREDICTIVE_STRUCTURE_DELTA_MIN
        )
        nuisance_delta_check = (
            integrity["delta_nuisance_only_accuracy"] <= HIGHER_LEVEL_STATE_TRAIN_NUISANCE_ONLY_DELTA_MAX
        )
        nuisance_post_check = integrity["nuisance_only_accuracy_post"] < HIGHER_LEVEL_STATE_TRAIN_NUISANCE_ONLY_POST_MAX
        loss_checks.append(loss_check)
        structure_checks.append(structure_check)
        nuisance_delta_checks.append(nuisance_delta_check)
        nuisance_post_checks.append(nuisance_post_check)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "delta_predictive_loss": float(integrity["delta_predictive_loss"]),
                "delta_predictive_structure_accuracy": float(integrity["delta_predictive_structure_accuracy"]),
                "delta_nuisance_only_accuracy": float(integrity["delta_nuisance_only_accuracy"]),
                "nuisance_only_accuracy_post": float(integrity["nuisance_only_accuracy_post"]),
            }
        )
    checks = {
        "required_successes": required_successes,
        "delta_predictive_loss_le_0_05_count": _stage4_count_true(loss_checks),
        "delta_predictive_structure_accuracy_ge_minus_0_05_count": _stage4_count_true(structure_checks),
        "delta_nuisance_only_accuracy_le_0_05_count": _stage4_count_true(nuisance_delta_checks),
        "nuisance_only_accuracy_post_lt_0_5_count": _stage4_count_true(nuisance_post_checks),
    }
    checks["passes"] = all(value >= required_successes for key, value in checks.items() if key.endswith("_count"))
    return {
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "summary": {
            "mean_delta_predictive_loss": _stage4_mean([item["delta_predictive_loss"] for item in seedwise]),
            "mean_delta_predictive_structure_accuracy": _stage4_mean(
                [item["delta_predictive_structure_accuracy"] for item in seedwise]
            ),
            "mean_delta_nuisance_only_accuracy": _stage4_mean(
                [item["delta_nuisance_only_accuracy"] for item in seedwise]
            ),
            "mean_nuisance_only_accuracy_post": _stage4_mean(
                [item["nuisance_only_accuracy_post"] for item in seedwise]
            ),
        },
        "checks": checks,
        "passes": bool(checks["passes"]),
    }


def _higher_level_state_train_build_post_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    overall_entries: list[dict[str, object]] | None = None,
) -> dict[str, object]:
    native_anchor_summary = _readout_alignment_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_refit",
    )
    native_strong_gate_summary = _readout_alignment_native_strong_gate_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_refit",
    )
    predictive_integrity_summary = _higher_level_state_train_predictive_integrity_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
    )
    delta_summary = _readout_alignment_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_refit",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "native_anchor_passes": bool(native_anchor_summary["passes"]),
        "native_strong_gate_passes": bool(native_strong_gate_summary["passes"]),
        "predictive_integrity_passes": bool(predictive_integrity_summary["passes"]),
        "no_residual_linear_probe_top1_advantage": top1_ci is not None
        and float(top1_ci["upper"]) < HIGHER_LEVEL_STATE_TRAIN_TOP1_IMPROVEMENT_NO_ADVANTAGE_MAX,
        "no_residual_linear_probe_kl_advantage": kl_ci is not None
        and float(kl_ci["upper"]) < HIGHER_LEVEL_STATE_TRAIN_KL_REDUCTION_NO_ADVANTAGE_MAX,
    }
    overall_summary = None
    if overall_entries is not None:
        post_latent_values = [
            float(entry["post_refit"]["probe_metrics"]["probe_target_aligned_specificity_contrast"])
            for entry in overall_entries
        ]
        post_pooled_values = [
            float(entry["post_refit"]["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"])
            for entry in overall_entries
        ]
        post_symmetry_values = [
            float(entry["post_refit"]["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]) >= 1.0
            for entry in overall_entries
        ]
        post_ratio_values = [
            _stage4_probe_ratio(
                float(entry["post_refit"]["probe_metrics"]["probe_target_aligned_specificity_contrast"]),
                float(entry["post_refit"]["oracle_probe_metrics"]["probe_target_aligned_specificity_contrast"]),
            )
            for entry in overall_entries
        ]
        overall_summary = {
            "latent_positive_count": _stage4_count_true([value > 0.0 for value in post_latent_values]),
            "pooled_positive_count": _stage4_count_true([value > 0.0 for value in post_pooled_values]),
            "learned_symmetry_consistency_count": _stage4_count_true(post_symmetry_values),
            "learned_oracle_latent_ratio_ge_0_25_count": _stage4_count_true(
                [value is not None and value >= HIGHER_LEVEL_STATE_TRAIN_ANCHOR_LATENT_RATIO_FLOOR for value in post_ratio_values]
            ),
            "passes": (
                _stage4_count_true([value > 0.0 for value in post_latent_values]) >= HIGHER_LEVEL_STATE_TRAIN_OVERALL_REQUIRED_SUCCESSES
                and _stage4_count_true([value > 0.0 for value in post_pooled_values]) >= HIGHER_LEVEL_STATE_TRAIN_OVERALL_REQUIRED_SUCCESSES
                and _stage4_count_true(post_symmetry_values) >= HIGHER_LEVEL_STATE_TRAIN_OVERALL_REQUIRED_SUCCESSES
                and _stage4_count_true(
                    [value is not None and value >= HIGHER_LEVEL_STATE_TRAIN_ANCHOR_LATENT_RATIO_FLOOR for value in post_ratio_values]
                ) >= HIGHER_LEVEL_STATE_TRAIN_OVERALL_REQUIRED_SUCCESSES
            ),
        }
        checks["overall_10_seed_post_refit_closure"] = bool(overall_summary["passes"])
    return {
        **_higher_level_state_train_metadata(
            metric_versions={"post_refit_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "native_strong_gate_summary": native_strong_gate_summary,
        "predictive_integrity_summary": predictive_integrity_summary,
        "readout_gap_summary": delta_summary,
        "overall_post_refit_summary": overall_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _higher_level_state_train_build_structure_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    overall_entries: list[dict[str, object]] | None = None,
) -> dict[str, object]:
    probe_required_successes = len(run_entries)
    standard_required_successes = len(run_entries) if seed_panel == "primary" else HIGHER_LEVEL_STATE_TRAIN_STRONG_GATE_REQUIRED_SUCCESSES
    seedwise: list[dict[str, object]] = []
    hidden_rows: list[torch.Tensor] = []
    output_rows: list[torch.Tensor] = []
    probe_state_kl_checks: list[bool] = []
    probe_hard_accuracy_checks: list[bool] = []
    probe_mirror_error_checks: list[bool] = []
    standard_hard_accuracy_checks: list[bool] = []
    strict_neutral_recall_checks: list[bool] = []
    transition_accuracy_checks: list[bool] = []
    all_three_states_checks: list[bool] = []
    precision_defined_checks: list[bool] = []
    precision_nonconstant_checks: list[bool] = []
    precision_advantage_checks: list[bool] = []
    for entry in run_entries:
        probe_metrics = entry["post_refit"]["state_metrics"]["probe"]
        standard_metrics = entry["post_refit"]["state_metrics"]["standard"]
        precision_advantage = entry["post_refit"]["state_metrics"]["probe_directional_precision_minus_strict_neutral_standard"]
        probe_state_kl_check = float(probe_metrics["mean_state_kl"]) <= HIGHER_LEVEL_STATE_TRAIN_PROBE_STATE_KL_MAX
        probe_hard_accuracy_check = float(probe_metrics["hard_state_accuracy"]) >= HIGHER_LEVEL_STATE_TRAIN_PROBE_HARD_STATE_ACCURACY_MIN
        probe_mirror_error_check = float(probe_metrics["mirror_error"]) <= HIGHER_LEVEL_STATE_TRAIN_PROBE_MIRROR_ERROR_MAX
        standard_hard_accuracy_check = float(standard_metrics["hard_state_accuracy"]) >= HIGHER_LEVEL_STATE_TRAIN_STANDARD_HARD_STATE_ACCURACY_MIN
        strict_neutral_recall_check = float(standard_metrics["strict_neutral_recall"]) >= HIGHER_LEVEL_STATE_TRAIN_STRICT_NEUTRAL_RECALL_MIN
        transition_accuracy_check = float(standard_metrics["transition_hard_accuracy"]) >= HIGHER_LEVEL_STATE_TRAIN_TRANSITION_HARD_ACCURACY_MIN
        all_three_states_check = bool(standard_metrics["all_three_predicted_states_present"])
        precision_defined_check = bool(standard_metrics["posterior_precision_defined"])
        precision_nonconstant_check = bool(standard_metrics["posterior_precision_nonconstant"])
        precision_advantage_check = precision_advantage is not None and float(precision_advantage) >= HIGHER_LEVEL_STATE_TRAIN_PRECISION_DIRECTIONAL_ADVANTAGE_MIN
        probe_state_kl_checks.append(probe_state_kl_check)
        probe_hard_accuracy_checks.append(probe_hard_accuracy_check)
        probe_mirror_error_checks.append(probe_mirror_error_check)
        standard_hard_accuracy_checks.append(standard_hard_accuracy_check)
        strict_neutral_recall_checks.append(strict_neutral_recall_check)
        transition_accuracy_checks.append(transition_accuracy_check)
        all_three_states_checks.append(all_three_states_check)
        precision_defined_checks.append(precision_defined_check)
        precision_nonconstant_checks.append(precision_nonconstant_check)
        precision_advantage_checks.append(precision_advantage_check)
        mask = entry["post_refit"]["probe_scoring_mask"]
        hidden_rows.append(entry["post_refit"]["heldout_hidden_states"][mask].to(torch.float64))
        output_rows.append(entry["post_refit"]["latent_state_logits"][mask].to(torch.float64))
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "probe_mean_state_kl": float(probe_metrics["mean_state_kl"]),
                "probe_hard_state_accuracy": float(probe_metrics["hard_state_accuracy"]),
                "probe_mirror_error": float(probe_metrics["mirror_error"]),
                "standard_hard_state_accuracy": float(standard_metrics["hard_state_accuracy"]),
                "strict_neutral_recall": float(standard_metrics["strict_neutral_recall"]),
                "transition_hard_accuracy": float(standard_metrics["transition_hard_accuracy"]),
                "all_three_predicted_states_present": bool(standard_metrics["all_three_predicted_states_present"]),
                "posterior_precision_defined": bool(standard_metrics["posterior_precision_defined"]),
                "posterior_precision_nonconstant": bool(standard_metrics["posterior_precision_nonconstant"]),
                "probe_directional_precision_minus_strict_neutral_standard": precision_advantage,
            }
        )
    hidden_states = torch.cat(hidden_rows, dim=0)
    target_outputs = torch.cat(output_rows, dim=0)
    shared_affine_residual = _readout_class_shared_affine_residual(
        hidden_states=hidden_states,
        target_outputs=target_outputs,
    )
    shared_affine_residual["n_rows"] = int(hidden_states.shape[0])
    checks = {
        "probe_mean_state_kl_le_0_10_count": _stage4_count_true(probe_state_kl_checks),
        "probe_hard_state_accuracy_ge_0_95_count": _stage4_count_true(probe_hard_accuracy_checks),
        "probe_mirror_error_le_0_05_count": _stage4_count_true(probe_mirror_error_checks),
        "standard_hard_state_accuracy_ge_0_75_count": _stage4_count_true(standard_hard_accuracy_checks),
        "strict_neutral_recall_ge_0_75_count": _stage4_count_true(strict_neutral_recall_checks),
        "transition_hard_accuracy_ge_0_70_count": _stage4_count_true(transition_accuracy_checks),
        "all_three_predicted_states_present_count": _stage4_count_true(all_three_states_checks),
        "posterior_precision_defined_count": _stage4_count_true(precision_defined_checks),
        "posterior_precision_nonconstant_count": _stage4_count_true(precision_nonconstant_checks),
        "probe_directional_precision_minus_strict_neutral_standard_ge_0_05_count": _stage4_count_true(
            precision_advantage_checks
        ),
        "shared_affine_residual_frobenius_norm_gt_1e_10": float(shared_affine_residual["frobenius_norm"]) > 1e-10,
    }
    checks["passes"] = (
        checks["probe_mean_state_kl_le_0_10_count"] >= probe_required_successes
        and checks["probe_hard_state_accuracy_ge_0_95_count"] >= probe_required_successes
        and checks["probe_mirror_error_le_0_05_count"] >= probe_required_successes
        and checks["standard_hard_state_accuracy_ge_0_75_count"] >= standard_required_successes
        and checks["strict_neutral_recall_ge_0_75_count"] >= standard_required_successes
        and checks["transition_hard_accuracy_ge_0_70_count"] >= standard_required_successes
        and checks["all_three_predicted_states_present_count"] >= standard_required_successes
        and checks["posterior_precision_defined_count"] >= standard_required_successes
        and checks["posterior_precision_nonconstant_count"] >= standard_required_successes
        and checks["probe_directional_precision_minus_strict_neutral_standard_ge_0_05_count"] >= standard_required_successes
        and checks["shared_affine_residual_frobenius_norm_gt_1e_10"]
    )
    overall_summary = None
    if overall_entries is not None:
        overall_summary = {
            "probe_hard_state_accuracy_ge_0_95_count": _stage4_count_true(
                [
                    float(entry["post_refit"]["state_metrics"]["probe"]["hard_state_accuracy"])
                    >= HIGHER_LEVEL_STATE_TRAIN_PROBE_HARD_STATE_ACCURACY_MIN
                    for entry in overall_entries
                ]
            ),
            "strict_neutral_recall_ge_0_75_count": _stage4_count_true(
                [
                    float(entry["post_refit"]["state_metrics"]["standard"]["strict_neutral_recall"])
                    >= HIGHER_LEVEL_STATE_TRAIN_STRICT_NEUTRAL_RECALL_MIN
                    for entry in overall_entries
                ]
            ),
        }
        overall_summary["passes"] = (
            overall_summary["probe_hard_state_accuracy_ge_0_95_count"] >= HIGHER_LEVEL_STATE_TRAIN_OVERALL_REQUIRED_SUCCESSES
            and overall_summary["strict_neutral_recall_ge_0_75_count"] >= HIGHER_LEVEL_STATE_TRAIN_OVERALL_STRICT_NEUTRAL_REQUIRED_SUCCESSES
        )
        checks["overall_10_seed_state_closure"] = bool(overall_summary["passes"])
        checks["passes"] = checks["passes"] and bool(overall_summary["passes"])
    return {
        **_higher_level_state_train_metadata(
            metric_versions={"higher_level_state_structure_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "shared_affine_least_squares_residual": shared_affine_residual,
        "overall_post_refit_summary": overall_summary,
        "checks": checks,
        "passes": bool(checks["passes"]),
        "skipped": False,
    }


def _higher_level_state_train_build_advantage_gap_report(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
) -> dict[str, object]:
    panels: dict[str, object] = {
        "pre_refit_primary": _readout_alignment_delta_panel_summary(
            seed_panel="primary",
            run_entries=primary_run_entries,
            checkpoint_key="pre_refit",
        ),
    }
    if all("post_refit" in entry for entry in primary_run_entries):
        panels["post_refit_primary"] = _readout_alignment_delta_panel_summary(
            seed_panel="primary",
            run_entries=primary_run_entries,
            checkpoint_key="post_refit",
        )
    if confirmation_run_entries is not None:
        panels["pre_refit_confirmation"] = _readout_alignment_delta_panel_summary(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            checkpoint_key="pre_refit",
        )
        if all("post_refit" in entry for entry in confirmation_run_entries):
            panels["post_refit_confirmation"] = _readout_alignment_delta_panel_summary(
                seed_panel="confirmation",
                run_entries=confirmation_run_entries,
                checkpoint_key="post_refit",
            )
    return {
        **_higher_level_state_train_metadata(
            metric_versions={"higher_level_state_advantage_gap_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "panels": panels,
    }


def _higher_level_state_train_build_verdict(
    *,
    package_manifest: dict[str, object],
    manifest_validity: dict[str, object],
    nonregression_report: dict[str, object],
    pre_refit_primary_report: dict[str, object],
    integrity_primary_report: dict[str, object],
    post_refit_primary_report: dict[str, object],
    structure_primary_report: dict[str, object],
    pre_refit_confirmation_report: dict[str, object] | None,
    integrity_confirmation_report: dict[str, object] | None,
    post_refit_confirmation_report: dict[str, object] | None,
    structure_confirmation_report: dict[str, object] | None,
    confirmation_executed: bool,
) -> dict[str, object]:
    if not bool(manifest_validity["passes"]):
        return {
            **_higher_level_state_train_metadata(
                metric_versions={"higher_level_state_train_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "manifest",
            "stop_gate": "P0 manifest fidelity",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": False,
                "R1_nonregression": None,
                "R2_baseline_premise_reproduction": None,
            },
        }
    if not bool(nonregression_report["passes"]):
        return {
            **_higher_level_state_train_metadata(
                metric_versions={"higher_level_state_train_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "nonregression",
            "stop_gate": "R1 frozen non-regression",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": False,
                "R2_baseline_premise_reproduction": None,
            },
        }
    if not bool(pre_refit_primary_report["passes"]):
        return {
            **_higher_level_state_train_metadata(
                metric_versions={"higher_level_state_train_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "pre_refit_primary",
            "stop_gate": "R2 baseline premise reproduction",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_baseline_premise_reproduction": False,
            },
        }
    if not bool(integrity_primary_report["passes"]):
        return {
            **_higher_level_state_train_metadata(
                metric_versions={"higher_level_state_train_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "integrity_primary",
            "stop_gate": "R3 integrity",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_baseline_premise_reproduction": True,
            },
        }
    if not bool(post_refit_primary_report["passes"]) or not bool(structure_primary_report["passes"]):
        return {
            **_higher_level_state_train_metadata(
                metric_versions={"higher_level_state_train_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "post_refit_primary",
            "stop_gate": "R4 primary scientific success",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_baseline_premise_reproduction": True,
            },
        }
    confirmation_passes = (
        confirmation_executed
        and pre_refit_confirmation_report is not None
        and bool(pre_refit_confirmation_report["passes"])
        and integrity_confirmation_report is not None
        and bool(integrity_confirmation_report["passes"])
        and post_refit_confirmation_report is not None
        and bool(post_refit_confirmation_report["passes"])
        and structure_confirmation_report is not None
        and bool(structure_confirmation_report["passes"])
    )
    if not confirmation_passes:
        return {
            **_higher_level_state_train_metadata(
                metric_versions={"higher_level_state_train_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation",
            "stop_gate": "R5 confirmation replication",
            "confirmation_executed": bool(confirmation_executed),
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_baseline_premise_reproduction": True,
            },
        }
    return {
        **_higher_level_state_train_metadata(
            metric_versions={"higher_level_state_train_verdict": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "classification": "GO-higher-level-state-aligned",
        "execution_valid": True,
        "stop_stage": None,
        "stop_gate": None,
        "confirmation_executed": True,
        "package_complete": True,
        "precondition_checks": {
            "P0_manifest_validity": True,
            "R1_nonregression": True,
            "R2_baseline_premise_reproduction": True,
        },
    }


def _higher_level_state_train_prepare_run(
    *,
    resolved_config: ExperimentConfig,
    store: RunStore,
    generator: Phase1ParadigmGenerator,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    train_seed: int,
    heldout_seed: int,
    seed_panel: str,
) -> dict[str, object]:
    training_config = _stage4_training_config(resolved_config)
    auxiliary_probe_fit_seed = heldout_seed + HIGHER_LEVEL_STATE_TRAIN_AUXILIARY_PROBE_FIT_SEED_OFFSET
    if auxiliary_probe_fit_seed == heldout_seed:
        raise AssertionError("auxiliary probe-fit seed must differ from held-out seed.")
    train_batches = [
        generator.generate_batch(
            batch_size=training_config.batch_size,
            seed=train_seed + epoch,
        )
        for epoch in range(training_config.n_epochs)
    ]
    heldout_batch = generator.generate_local_global_probe_batch(seed=heldout_seed)
    donor_fit_batch = generator.generate_local_global_probe_batch(seed=auxiliary_probe_fit_seed)
    standard_heldout_batch = generator.generate_batch(
        batch_size=training_config.batch_size,
        seed=heldout_seed,
    )
    probe_train_seeds = [
        int(heldout_seed) + HIGHER_LEVEL_STATE_TRAIN_PROBE_TRAIN_SEED_BASE_OFFSET + step_index
        for step_index in range(int(training_config.n_epochs))
    ]
    predictive_train_seeds = [
        int(heldout_seed) + HIGHER_LEVEL_STATE_TRAIN_PREDICTIVE_TRAIN_SEED_BASE_OFFSET + step_index
        for step_index in range(int(training_config.n_epochs))
    ]
    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    manifest, run_dir = store.create_run(
        resolved_config.name,
        train_objectives=[f"{resolved_config.training.predictive_objective}:{EXPECTED_DISTRIBUTION_OBJECTIVE}"],
        heldout_assays=[
            "probe_target_aligned_specificity_contrast",
            "probe_pooled_target_aligned_specificity_contrast",
            "probe_context_comparator_nonuniformity_contrast",
            "linear_probe_alignment_kl",
            "linear_probe_expected_target_top1_rate",
            "linear_probe_correct_pair_flip_rate__v2",
            "linear_probe_within_pair_mass__v2",
            "linear_probe_source_bin_kl__v2",
        ],
        notes={
            "gate": "higher_level_state_train",
            "higher_level_state_train_package_version": HIGHER_LEVEL_STATE_TRAIN_PACKAGE_VERSION,
            "family_name": HIGHER_LEVEL_STATE_NAME,
            "checkpoint_dirnames": [
                HIGHER_LEVEL_STATE_TRAIN_PRE_CHECKPOINT_DIRNAME,
                HIGHER_LEVEL_STATE_TRAIN_POST_CHECKPOINT_DIRNAME,
            ],
            "seed_panel": seed_panel,
            "train_seed": int(train_seed),
            "heldout_seed": int(heldout_seed),
            "auxiliary_probe_fit_seed": int(auxiliary_probe_fit_seed),
            "probe_train_batch_seeds": probe_train_seeds,
            "predictive_train_batch_seeds": predictive_train_seeds,
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "initial_standard_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "refit_optimizer": "Adam",
            "refit_step_count": training_config.n_epochs,
            "parameter_update_scope": list(HIGHER_LEVEL_STATE_TRAIN_PARAM_UPDATE_SCOPE_FULL),
            "frozen_scope": [
                "predictor.gru.*",
                "predictor.orientation_head.*",
                "predictor.precision_head.*",
            ],
            "controlled_sources": heldout_batch.metadata["controlled_sources"].tolist(),
            "probe_visible_step_index": int(heldout_batch.metadata["probe_visible_step_index"]),
            "task_mode_fixed_state": task_mode_fixed_state,
            "prestim_fixed_state": prestim_fixed_state,
            "heldout_fixed_probe_eval_rule": "fixed_probe_batch(seed=heldout_seed)",
            "heldout_predictive_eval_rule": "generate_batch(batch_size=32, seed=heldout_seed), scored on standard transition rows only",
            "auxiliary_probe_fit_rule": "fixed_probe_batch(seed=heldout_seed + 1)",
            "auxiliary_probe_train_rule": "fixed_probe_batch(seed=heldout_seed + 100 + step_index)",
            "auxiliary_predictive_train_rule": "generate_batch(batch_size=32, seed=heldout_seed + 200 + step_index)",
            "hidden_state_tensors_exported": [HIGHER_LEVEL_STATE_TRAIN_HIDDEN_STATE_TENSOR_NAME],
            "linear_probe_form": HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_FORM,
            "linear_probe_target": HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_TARGET,
            "linear_probe_ridge_lambda": HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_RIDGE_LAMBDA,
            "linear_probe_train_eval_disjoint": True,
            "linear_probe_fit_mask": "probe_step_mask & probe_valid_mask",
            "bootstrap_seed": HIGHER_LEVEL_STATE_TRAIN_BOOTSTRAP_SEED,
            "bootstrap_resamples": HIGHER_LEVEL_STATE_TRAIN_BOOTSTRAP_RESAMPLES,
            "no_sweep": True,
            "no_second_package": True,
            "no_teacher_targets": True,
            "no_heldout_selection": True,
            "state_precision_formula": "1 - H(q_t) / log(3)",
        },
    )

    predictor = CausalContextPredictor(resolved_config.geometry, resolved_config.context)
    train_history = train_context_predictor(
        predictor,
        train_batches,
        training_config,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )
    _write_json(run_dir / HIGHER_LEVEL_STATE_TRAIN_PRETRAIN_HISTORY_ARTIFACT, [asdict(item) for item in train_history])
    pre_parameter_snapshot = _higher_level_state_train_parameter_scope_snapshot(predictor)
    _write_json(
        run_dir / HIGHER_LEVEL_STATE_TRAIN_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT,
        {
            **_higher_level_state_train_metadata(
                metric_versions={"parameter_scope_fingerprints": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "run_id": manifest.run_id,
            "parameter_update_scope": list(HIGHER_LEVEL_STATE_TRAIN_PARAM_UPDATE_SCOPE_FULL),
            "pre_refit": pre_parameter_snapshot,
            "post_refit": None,
            "checks": {},
        },
    )
    first_probe_train_batch = generator.generate_local_global_probe_batch(seed=probe_train_seeds[0])
    first_predictive_train_batch = generator.generate_batch(
        batch_size=training_config.batch_size,
        seed=predictive_train_seeds[0],
    )
    _higher_level_state_train_write_auxiliary_support_artifacts(
        predictor=predictor,
        donor_fit_batch=donor_fit_batch,
        probe_train_batch=first_probe_train_batch,
        predictive_train_batch=first_predictive_train_batch,
        run_dir=run_dir,
    )
    pre_checkpoint = _higher_level_state_train_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        donor_fit_batch=donor_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=manifest.run_id,
        run_dir=run_dir,
        checkpoint_dirname=HIGHER_LEVEL_STATE_TRAIN_PRE_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        scoring_mode="native",
        linear_probe=None,
        save_prediction_artifact=HIGHER_LEVEL_STATE_TRAIN_NATIVE_PREDICTIONS_PRE_ARTIFACT,
    )
    _write_stage0_provenance(store=store, run_dir=run_dir, manifest=manifest, resolved_config=resolved_config)
    return {
        "run_id": manifest.run_id,
        "run_dir": run_dir,
        "seed_panel": seed_panel,
        "train_seed": int(train_seed),
        "heldout_seed": int(heldout_seed),
        "auxiliary_probe_fit_seed": int(auxiliary_probe_fit_seed),
        "probe_train_seeds": probe_train_seeds,
        "predictive_train_seeds": predictive_train_seeds,
        "predictor": predictor,
        "generator": generator,
        "model": model,
        "assay_runner": assay_runner,
        "resolved_config": resolved_config,
        "heldout_batch": heldout_batch,
        "donor_fit_batch": donor_fit_batch,
        "standard_heldout_batch": standard_heldout_batch,
        "pre_refit": pre_checkpoint,
        "pre_parameter_snapshot": pre_parameter_snapshot,
        "donor_linear_probe": torch.load(
            run_dir / HIGHER_LEVEL_STATE_TRAIN_PRE_CHECKPOINT_DIRNAME / HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_PARAMETERS_ARTIFACT,
            map_location="cpu",
        ),
    }


def _higher_level_state_train_complete_run(
    prepared_run: dict[str, object],
) -> dict[str, object]:
    predictor = prepared_run["predictor"]
    generator = prepared_run["generator"]
    model = prepared_run["model"]
    assay_runner = prepared_run["assay_runner"]
    resolved_config = prepared_run["resolved_config"]
    heldout_batch = prepared_run["heldout_batch"]
    donor_fit_batch = prepared_run["donor_fit_batch"]
    standard_heldout_batch = prepared_run["standard_heldout_batch"]
    run_dir = prepared_run["run_dir"]
    run_id = prepared_run["run_id"]
    training_config = _stage4_training_config(resolved_config)

    refit_history, probe_train_seeds, predictive_train_seeds = _higher_level_state_train_refit_state_head(
        predictor=predictor,
        generator=generator,
        heldout_seed=int(prepared_run["heldout_seed"]),
        training_config=training_config,
    )
    _write_json(run_dir / HIGHER_LEVEL_STATE_TRAIN_REFIT_HISTORY_ARTIFACT, refit_history)
    post_parameter_snapshot = _higher_level_state_train_parameter_scope_snapshot(predictor)
    post_checkpoint = _higher_level_state_train_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        donor_fit_batch=donor_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=run_id,
        run_dir=run_dir,
        checkpoint_dirname=HIGHER_LEVEL_STATE_TRAIN_POST_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        scoring_mode="higher_level_state",
        linear_probe=prepared_run["donor_linear_probe"],
        save_prediction_artifact=HIGHER_LEVEL_STATE_TRAIN_NATIVE_PREDICTIONS_POST_ARTIFACT,
    )
    torch.save(
        {key: value.detach().cpu() for key, value in predictor.latent_state_head.state_dict().items()},
        run_dir / HIGHER_LEVEL_STATE_TRAIN_STATE_HEAD_STATE_ARTIFACT,
    )
    pre_checkpoint = prepared_run["pre_refit"]
    heldout_hidden_state_max_abs_diff = float(
        (pre_checkpoint["heldout_hidden_states"] - post_checkpoint["heldout_hidden_states"]).abs().max().item()
    )
    predictive_hidden_state_max_abs_diff = float(
        (pre_checkpoint["predictive_hidden_states"] - post_checkpoint["predictive_hidden_states"]).abs().max().item()
    )
    integrity = {
        "heldout_probe_batch_identity_same_pre_post": (
            int(pre_checkpoint["heldout_generator_seed"]) == int(post_checkpoint["heldout_generator_seed"])
        ),
        "heldout_predictive_batch_identity_same_pre_post": (
            int(pre_checkpoint["predictive_generator_seed"]) == int(post_checkpoint["predictive_generator_seed"])
        ),
        "auxiliary_batch_identity_same_pre_post": (
            int(pre_checkpoint["auxiliary_generator_seed"]) == int(post_checkpoint["auxiliary_generator_seed"])
        ),
        "auxiliary_eval_disjoint_from_heldout": (
            int(prepared_run["heldout_seed"]) != int(prepared_run["auxiliary_probe_fit_seed"])
        ),
        "recurrent_core_parameter_fingerprint_unchanged": (
            prepared_run["pre_parameter_snapshot"]["recurrent_core_fingerprint"]
            == post_parameter_snapshot["recurrent_core_fingerprint"]
        ),
        "orientation_head_parameter_fingerprint_unchanged": (
            prepared_run["pre_parameter_snapshot"]["orientation_head_fingerprint"]
            == post_parameter_snapshot["orientation_head_fingerprint"]
        ),
        "precision_head_parameter_fingerprint_unchanged": (
            prepared_run["pre_parameter_snapshot"]["precision_head_fingerprint"]
            == post_parameter_snapshot["precision_head_fingerprint"]
        ),
        "state_head_parameter_fingerprint_changed": (
            prepared_run["pre_parameter_snapshot"]["latent_state_head_fingerprint"]
            != post_parameter_snapshot["latent_state_head_fingerprint"]
        ),
        "heldout_probe_hidden_states_unchanged": bool(
            torch.allclose(
                pre_checkpoint["heldout_hidden_states"],
                post_checkpoint["heldout_hidden_states"],
                atol=HIGHER_LEVEL_STATE_TRAIN_HIDDEN_STATE_ATOL,
                rtol=0.0,
            )
        ),
        "heldout_predictive_hidden_states_unchanged": bool(
            torch.allclose(
                pre_checkpoint["predictive_hidden_states"],
                post_checkpoint["predictive_hidden_states"],
                atol=HIGHER_LEVEL_STATE_TRAIN_HIDDEN_STATE_ATOL,
                rtol=0.0,
            )
        ),
        "heldout_probe_hidden_state_max_abs_diff": heldout_hidden_state_max_abs_diff,
        "heldout_predictive_hidden_state_max_abs_diff": predictive_hidden_state_max_abs_diff,
        "delta_predictive_loss": float(
            post_checkpoint["standard_predictive_metrics"]["predictive_loss"]
            - pre_checkpoint["standard_predictive_metrics"]["predictive_loss"]
        ),
        "delta_predictive_structure_accuracy": float(
            post_checkpoint["standard_sanity"]["predictive_structure"]["accuracy"]
            - pre_checkpoint["standard_sanity"]["predictive_structure"]["accuracy"]
        ),
        "delta_nuisance_only_accuracy": float(
            post_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"]
            - pre_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"]
        ),
        "nuisance_only_accuracy_post": float(post_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"]),
        "exact_trainable_parameter_scope_during_refit": (
            post_parameter_snapshot["trainable_parameter_names"] == list(HIGHER_LEVEL_STATE_TRAIN_PARAM_UPDATE_SCOPE)
        ),
        "scientific_scoring_uses_reconstructed_emissions_only": bool(
            post_checkpoint["scientific_scoring_uses_reconstructed_emissions_only"]
        ),
    }
    parameter_scope_payload = {
        **_higher_level_state_train_metadata(
            metric_versions={"parameter_scope_fingerprints": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "parameter_update_scope": list(HIGHER_LEVEL_STATE_TRAIN_PARAM_UPDATE_SCOPE_FULL),
        "probe_train_seeds": probe_train_seeds,
        "predictive_train_seeds": predictive_train_seeds,
        "pre_refit": prepared_run["pre_parameter_snapshot"],
        "post_refit": post_parameter_snapshot,
        "checks": {
            "exact_trainable_parameter_scope_during_refit": integrity["exact_trainable_parameter_scope_during_refit"],
            "recurrent_core_parameter_fingerprint_unchanged": integrity["recurrent_core_parameter_fingerprint_unchanged"],
            "orientation_head_parameter_fingerprint_unchanged": integrity["orientation_head_parameter_fingerprint_unchanged"],
            "precision_head_parameter_fingerprint_unchanged": integrity["precision_head_parameter_fingerprint_unchanged"],
            "state_head_parameter_fingerprint_changed": integrity["state_head_parameter_fingerprint_changed"],
        },
    }
    _write_json(run_dir / HIGHER_LEVEL_STATE_TRAIN_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT, parameter_scope_payload)
    return {
        "run_id": run_id,
        "run_dir": run_dir,
        "seed_panel": prepared_run["seed_panel"],
        "train_seed": int(prepared_run["train_seed"]),
        "heldout_seed": int(prepared_run["heldout_seed"]),
        "auxiliary_probe_fit_seed": int(prepared_run["auxiliary_probe_fit_seed"]),
        "probe_train_seeds": probe_train_seeds,
        "predictive_train_seeds": predictive_train_seeds,
        "pre_refit": {
            key: value
            for key, value in pre_checkpoint.items()
            if key not in ("heldout_hidden_states", "predictive_hidden_states", "auxiliary_hidden_states")
        },
        "post_refit": {
            key: value
            for key, value in post_checkpoint.items()
            if key not in ("predictive_hidden_states", "auxiliary_hidden_states")
        },
        "refit_integrity": integrity,
        "artifacts_complete": True,
    }


def run_higher_level_state_train_package(
    *,
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
    primary_seed_panel: tuple[tuple[int, int], ...] = STAGE3_PRIMARY_SEED_PANEL,
    confirmation_seed_panel: tuple[tuple[int, int], ...] = STAGE3_CONFIRMATION_SEED_PANEL,
    benchmark_artifacts_root: str | Path = "artifacts",
) -> HigherLevelStateTrainRunResult:
    resolved_config = _resolve_config(config=config, preset_name=preset_name)
    if resolved_config.name != "phase1_core":
        raise ValueError("higher_level_state_train is frozen to the phase1_core configuration family.")
    output_root = resolved_config.artifacts.root_dir / "higher_level_state_train" / HIGHER_LEVEL_STATE_TRAIN_PACKAGE_VERSION
    output_root.mkdir(parents=True, exist_ok=True)
    training_config = _stage4_training_config(resolved_config)
    package_manifest = {
        **_higher_level_state_train_metadata(
            metric_versions={"higher_level_state_train_manifest": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "family_name": HIGHER_LEVEL_STATE_NAME,
        "family_equation": "q_t = softmax(W h_t + b); y_hat_t = q_t(CW) T_CW[source_t] + q_t(CCW) T_CCW[source_t] + q_t(Neutral) T_Neutral[source_t]",
        "latent_state_vocabulary": list(HIGHER_LEVEL_STATE_LATENT_STATES),
        "trainable_scope": list(HIGHER_LEVEL_STATE_TRAIN_PARAM_UPDATE_SCOPE_FULL),
        "frozen_scope": [
            "predictor.gru.*",
            "predictor.orientation_head.*",
            "predictor.precision_head.*",
            "scaffold.*",
            "task/generator/assays/benchmarks/thresholds/seed panels",
        ],
        "collapse_operator_serialized": _higher_level_state_train_collapse_serialized(
            int(resolved_config.geometry.n_orientations)
        ),
        "emission_templates": {
            "CW": "transition_matrices[0][source_orientation]",
            "CCW": "transition_matrices[1][source_orientation]",
            "Neutral": "transition_matrices[2][source_orientation]",
        },
        "emission_reconstruction_rule": {
            "scored_rows": "weighted mixture of fixed source-relative transition templates by learned 3-state posterior",
            "visible_anchor_rows_without_valid_source": "use current visible orientation as the fixed source index for non-trainable reconstruction",
            "blank_rows_without_valid_source": "uniform orientation prior for rollout continuity only",
        },
        "precision_definition": "1 - H(q_t) / log(3)",
        "objective": {
            "total": "L_state + L_emit",
            "L_state": "mean KL(collapse(expected_distribution_t, source_orientation_t) || q_t)",
            "L_emit": "mean KL(expected_distribution_t || y_hat_t)",
            "loss_weights": {"L_state": 1.0, "L_emit": 1.0},
        },
        "optimizer": {
            "name": "Adam",
            "step_count": int(training_config.n_epochs),
            "learning_rate": float(training_config.learning_rate),
            "weight_decay": float(training_config.weight_decay),
        },
        "batch_mix": {
            "auxiliary_probe_train_batch_per_step": 1,
            "auxiliary_predictive_train_batch_per_step": 1,
        },
        "batch_identity_rules": {
            "heldout_fixed_probe_eval": "fixed_probe_batch(seed=heldout_seed)",
            "heldout_predictive_eval": "generate_batch(batch_size=32, seed=heldout_seed), scored on standard transition rows only",
            "auxiliary_probe_fit": "fixed_probe_batch(seed=heldout_seed + 1)",
            "auxiliary_probe_train": "fixed_probe_batch(seed=heldout_seed + 100 + step_index)",
            "auxiliary_predictive_train": "generate_batch(batch_size=32, seed=heldout_seed + 200 + step_index)",
        },
        "linear_probe": {
            "form": HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_FORM,
            "target": HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_TARGET,
            "ridge_lambda": HIGHER_LEVEL_STATE_TRAIN_LINEAR_PROBE_RIDGE_LAMBDA,
            "fit_mask": "probe_step_mask & probe_valid_mask",
            "train_eval_split": "auxiliary_probe_fit_batch vs heldout_fixed_probe_batch",
        },
        "seed_panels": {
            "primary": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in primary_seed_panel],
            "confirmation": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in confirmation_seed_panel],
        },
        "heldout_eval_rules": {
            "fixed_probe": "same held-out fixed-probe batch pre and post",
            "predictive": "same held-out predictive batch pre and post, evaluated on standard transition rows only",
        },
        "bootstrap": {
            "seed": HIGHER_LEVEL_STATE_TRAIN_BOOTSTRAP_SEED,
            "resamples": HIGHER_LEVEL_STATE_TRAIN_BOOTSTRAP_RESAMPLES,
            "confidence_level": HIGHER_LEVEL_STATE_TRAIN_BOOTSTRAP_CONFIDENCE_LEVEL,
        },
        "run_order": [
            "write_higher_level_state_train_manifest",
            "run_P0_manifest_fidelity_to_approved_higher_level_state_bundle",
            "run_R1_frozen_nonregression",
            "run_R2_pre_refit_primary",
            "run_primary_refit_and_R3_R4_reports_if_R2_passes",
            "run_confirmation_if_R4_passes",
            "write_higher_level_state_train_reports_and_verdict",
        ],
        "stop_rules": {
            "halt_on_manifest_invalidity": True,
            "halt_on_nonregression_failure": True,
            "halt_on_pre_refit_premise_failure": True,
            "halt_on_integrity_failure": True,
            "halt_on_primary_scientific_failure": True,
            "confirmation_only_if_primary_passes": True,
            "halt_on_confirmation_failure": True,
            "no_harder_evaluation": True,
            "no_second_package": True,
            "no_sweep": True,
        },
        "explicit_statements": {
            "no_sweep": True,
            "no_second_package": True,
            "no_teacher_targets": True,
            "no_heldout_selection": True,
            "state_head_zero_initialized": True,
        },
        "fixed_family_constraints": {
            "state_transition_family": _higher_level_state_fixed_transition_constraint(),
        },
        "approved_definition_bundle_root": str(_higher_level_state_train_definition_bundle_root()),
        "changed_files": list(HIGHER_LEVEL_STATE_TRAIN_CHANGED_FILES),
    }
    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_MANIFEST_V1_ARTIFACT, package_manifest)

    manifest_validity = _higher_level_state_train_manifest_validity(package_manifest)
    nonregression_report = _higher_level_state_train_build_nonregression_report(benchmark_artifacts_root)
    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_NONREGRESSION_REPORT_V1_ARTIFACT, nonregression_report)
    if not bool(manifest_validity["passes"]) or not bool(nonregression_report["passes"]):
        pre_primary_report = _higher_level_state_train_build_skipped_panel_report(
            artifact_key="pre_refit_report",
            seed_panel="primary",
            stop_reason="preconditions_failed",
        )
        integrity_primary_report = _higher_level_state_train_build_skipped_panel_report(
            artifact_key="higher_level_state_integrity_report",
            seed_panel="primary",
            stop_reason="preconditions_failed",
        )
        post_primary_report = _higher_level_state_train_build_skipped_panel_report(
            artifact_key="post_refit_report",
            seed_panel="primary",
            stop_reason="preconditions_failed",
        )
        structure_primary_report = _higher_level_state_train_build_skipped_panel_report(
            artifact_key="higher_level_state_structure_report",
            seed_panel="primary",
            stop_reason="preconditions_failed",
        )
        advantage_gap_report = {
            **_higher_level_state_train_metadata(
                metric_versions={"higher_level_state_advantage_gap_report": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "panels": {},
            "skipped": True,
            "stop_reason": "preconditions_failed",
        }
        verdict = _higher_level_state_train_build_verdict(
            package_manifest=package_manifest,
            manifest_validity=manifest_validity,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_primary_report=structure_primary_report,
            pre_refit_confirmation_report=None,
            integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            structure_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_STRUCTURE_PRIMARY_REPORT_V1_ARTIFACT, structure_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_ADVANTAGE_GAP_REPORT_V1_ARTIFACT, advantage_gap_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_VERDICT_V1_ARTIFACT, verdict)
        return HigherLevelStateTrainRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_primary_report=structure_primary_report,
            advantage_gap_report=advantage_gap_report,
            verdict=verdict,
            pre_refit_confirmation_report=None,
            integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            structure_confirmation_report=None,
            run_ids=[],
        )

    store = RunStore(resolved_config.artifacts.root_dir)
    generator = Phase1ParadigmGenerator(resolved_config, controlled_sources=STAGE3_FULL_CONTROLLED_SOURCES)
    model = V1ExpectationModel(resolved_config)
    model.eval()
    assay_runner = AssayRunner(resolved_config)
    primary_prepared_runs: list[dict[str, object]] = []
    run_ids: list[str] = []
    for train_seed, heldout_seed in primary_seed_panel:
        prepared_run = _higher_level_state_train_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="primary",
        )
        primary_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    primary_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["auxiliary_probe_fit_seed"],
            "pre_refit": {
                key: value
                for key, value in prepared_run["pre_refit"].items()
                if key not in ("heldout_hidden_states", "predictive_hidden_states", "auxiliary_hidden_states")
            },
            "artifacts_complete": True,
        }
        for prepared_run in primary_prepared_runs
    ]
    pre_primary_report = _higher_level_state_train_build_pre_report(
        seed_panel="primary",
        run_entries=primary_pre_entries,
    )
    advantage_gap_report = _higher_level_state_train_build_advantage_gap_report(
        primary_run_entries=primary_pre_entries,
        confirmation_run_entries=None,
    )
    if not bool(pre_primary_report["passes"]):
        integrity_primary_report = _higher_level_state_train_build_skipped_panel_report(
            artifact_key="higher_level_state_integrity_report",
            seed_panel="primary",
            stop_reason="pre_refit_failed",
        )
        post_primary_report = _higher_level_state_train_build_skipped_panel_report(
            artifact_key="post_refit_report",
            seed_panel="primary",
            stop_reason="pre_refit_failed",
        )
        structure_primary_report = _higher_level_state_train_build_skipped_panel_report(
            artifact_key="higher_level_state_structure_report",
            seed_panel="primary",
            stop_reason="pre_refit_failed",
        )
        verdict = _higher_level_state_train_build_verdict(
            package_manifest=package_manifest,
            manifest_validity=manifest_validity,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_primary_report=structure_primary_report,
            pre_refit_confirmation_report=None,
            integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            structure_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_STRUCTURE_PRIMARY_REPORT_V1_ARTIFACT, structure_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_ADVANTAGE_GAP_REPORT_V1_ARTIFACT, advantage_gap_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_VERDICT_V1_ARTIFACT, verdict)
        return HigherLevelStateTrainRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_primary_report=structure_primary_report,
            advantage_gap_report=advantage_gap_report,
            verdict=verdict,
            pre_refit_confirmation_report=None,
            integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            structure_confirmation_report=None,
            run_ids=run_ids,
        )

    primary_run_entries = [_higher_level_state_train_complete_run(prepared_run) for prepared_run in primary_prepared_runs]
    integrity_primary_report = _higher_level_state_train_build_integrity_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    post_primary_report = _higher_level_state_train_build_post_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
        overall_entries=None,
    )
    structure_primary_report = _higher_level_state_train_build_structure_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
        overall_entries=None,
    )
    advantage_gap_report = _higher_level_state_train_build_advantage_gap_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=None,
    )
    if not bool(integrity_primary_report["passes"]) or not bool(post_primary_report["passes"]) or not bool(
        structure_primary_report["passes"]
    ):
        verdict = _higher_level_state_train_build_verdict(
            package_manifest=package_manifest,
            manifest_validity=manifest_validity,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_primary_report=structure_primary_report,
            pre_refit_confirmation_report=None,
            integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            structure_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_STRUCTURE_PRIMARY_REPORT_V1_ARTIFACT, structure_primary_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_ADVANTAGE_GAP_REPORT_V1_ARTIFACT, advantage_gap_report)
        _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_VERDICT_V1_ARTIFACT, verdict)
        return HigherLevelStateTrainRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_primary_report=structure_primary_report,
            advantage_gap_report=advantage_gap_report,
            verdict=verdict,
            pre_refit_confirmation_report=None,
            integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            structure_confirmation_report=None,
            run_ids=run_ids,
        )

    confirmation_prepared_runs: list[dict[str, object]] = []
    for train_seed, heldout_seed in confirmation_seed_panel:
        prepared_run = _higher_level_state_train_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="confirmation",
        )
        confirmation_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    confirmation_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["auxiliary_probe_fit_seed"],
            "pre_refit": {
                key: value
                for key, value in prepared_run["pre_refit"].items()
                if key not in ("heldout_hidden_states", "predictive_hidden_states", "auxiliary_hidden_states")
            },
            "artifacts_complete": True,
        }
        for prepared_run in confirmation_prepared_runs
    ]
    pre_confirmation_report = _higher_level_state_train_build_pre_report(
        seed_panel="confirmation",
        run_entries=confirmation_pre_entries,
    )
    confirmation_run_entries: list[dict[str, object]] | None = None
    integrity_confirmation_report: dict[str, object] | None = None
    post_confirmation_report: dict[str, object] | None = None
    structure_confirmation_report: dict[str, object] | None = None
    if bool(pre_confirmation_report["passes"]):
        confirmation_run_entries = [
            _higher_level_state_train_complete_run(prepared_run) for prepared_run in confirmation_prepared_runs
        ]
        integrity_confirmation_report = _higher_level_state_train_build_integrity_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
        post_confirmation_report = _higher_level_state_train_build_post_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            overall_entries=primary_run_entries + confirmation_run_entries,
        )
        structure_confirmation_report = _higher_level_state_train_build_structure_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            overall_entries=primary_run_entries + confirmation_run_entries,
        )
        advantage_gap_report = _higher_level_state_train_build_advantage_gap_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_run_entries,
        )
    else:
        advantage_gap_report = _higher_level_state_train_build_advantage_gap_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_pre_entries,
        )

    verdict = _higher_level_state_train_build_verdict(
        package_manifest=package_manifest,
        manifest_validity=manifest_validity,
        nonregression_report=nonregression_report,
        pre_refit_primary_report=pre_primary_report,
        integrity_primary_report=integrity_primary_report,
        post_refit_primary_report=post_primary_report,
        structure_primary_report=structure_primary_report,
        pre_refit_confirmation_report=pre_confirmation_report,
        integrity_confirmation_report=integrity_confirmation_report,
        post_refit_confirmation_report=post_confirmation_report,
        structure_confirmation_report=structure_confirmation_report,
        confirmation_executed=True,
    )

    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_STRUCTURE_PRIMARY_REPORT_V1_ARTIFACT, structure_primary_report)
    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_ADVANTAGE_GAP_REPORT_V1_ARTIFACT, advantage_gap_report)
    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_VERDICT_V1_ARTIFACT, verdict)
    _write_json(output_root / HIGHER_LEVEL_STATE_TRAIN_PRE_CONFIRMATION_REPORT_V1_ARTIFACT, pre_confirmation_report)
    if integrity_confirmation_report is not None:
        _write_json(
            output_root / HIGHER_LEVEL_STATE_TRAIN_INTEGRITY_CONFIRMATION_REPORT_V1_ARTIFACT,
            integrity_confirmation_report,
        )
    if post_confirmation_report is not None:
        _write_json(
            output_root / HIGHER_LEVEL_STATE_TRAIN_POST_CONFIRMATION_REPORT_V1_ARTIFACT,
            post_confirmation_report,
        )
    if structure_confirmation_report is not None:
        _write_json(
            output_root / HIGHER_LEVEL_STATE_TRAIN_STRUCTURE_CONFIRMATION_REPORT_V1_ARTIFACT,
            structure_confirmation_report,
        )

    return HigherLevelStateTrainRunResult(
        output_root=output_root,
        package_manifest=package_manifest,
        nonregression_report=nonregression_report,
        pre_refit_primary_report=pre_primary_report,
        integrity_primary_report=integrity_primary_report,
        post_refit_primary_report=post_primary_report,
        structure_primary_report=structure_primary_report,
        advantage_gap_report=advantage_gap_report,
        verdict=verdict,
        pre_refit_confirmation_report=pre_confirmation_report,
        integrity_confirmation_report=integrity_confirmation_report,
        post_refit_confirmation_report=post_confirmation_report,
        structure_confirmation_report=structure_confirmation_report,
        run_ids=run_ids,
    )


