def _context_residual_metadata(
    *,
    metric_versions: dict[str, str],
    source_metric_versions: list[str],
) -> dict[str, object]:
    return {
        "metric_schema_version": CONTEXT_RESIDUAL_METRIC_SCHEMA_VERSION,
        "metric_versions": metric_versions,
        "classification_rule_version": CONTEXT_RESIDUAL_CLASSIFICATION_RULE_VERSION,
        "source_metric_versions": source_metric_versions,
        "benchmark_registry_version": BENCHMARK_REGISTRY_VERSION,
        "context_residual_package_version": CONTEXT_RESIDUAL_PACKAGE_VERSION,
    }


def _context_residual_build_nonregression_report(
    *,
    resolved_config: ExperimentConfig,
    output_root: Path,
    benchmark_artifacts_root: str | Path,
) -> dict[str, object]:
    raw_report = _stage4_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
        primary_seed_panel=STAGE3_PRIMARY_SEED_PANEL,
        confirmation_seed_panel=STAGE3_CONFIRMATION_SEED_PANEL,
    )
    historical_expectations = _readout_class_expected_history()
    historical_reports: dict[str, dict[str, object]] = {}
    historical_ok = True
    for name, spec in historical_expectations.items():
        verdict_path = Path(spec["path"])
        exists = verdict_path.exists()
        payload = _stage4_read_json(verdict_path) if exists else {}
        observed_classification, source = _readout_class_observed_classification(name, payload)
        matches = exists and observed_classification == spec["expected_classification"]
        historical_ok &= matches
        historical_reports[name] = {
            "path": str(verdict_path),
            "exists": bool(exists),
            "expected_classification": str(spec["expected_classification"]),
            "observed_classification": observed_classification,
            "classification_source": source,
            "matches_expected": bool(matches),
        }
    stripped = dict(raw_report)
    for key in (
        "metric_schema_version",
        "metric_versions",
        "classification_rule_version",
        "source_metric_versions",
        "benchmark_registry_version",
        "stage3_task_version",
        "stage4_package_version",
    ):
        stripped.pop(key, None)
    checks = dict(stripped["checks"])
    checks["historical_bundle_classifications_unchanged"] = bool(historical_ok)
    passes = bool(stripped["passes"]) and bool(historical_ok)
    return {
        **_context_residual_metadata(
            metric_versions={
                "stage0_registry_verification": "v1",
                "stage1_tranche_runner_replay": "v1",
                "stage2_diagnostic_calibration_report": "v2",
                "stage3_oracle_task_definition_verdict": "v2",
                "phase15_continuation_retention": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        **stripped,
        "historical_bundle_classifications": historical_reports,
        "checks": checks,
        "passes": passes,
        "complete": passes,
    }


def _context_residual_parameter_scope_snapshot(
    predictor: CausalContextPredictor,
) -> dict[str, object]:
    recurrent_core_parameters = [(name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("gru.")]
    precision_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("precision_head.")
    ]
    orientation_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name.startswith("orientation_head.")
    ]
    residual_parameters = [
        (name, parameter) for name, parameter in predictor.named_parameters() if name in CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE
    ]
    trainable_parameter_names = [name for name, parameter in predictor.named_parameters() if parameter.requires_grad]
    return {
        "trainable_parameter_names": trainable_parameter_names,
        "trainable_parameter_full_paths": [
            f"predictor.{name}" for name in trainable_parameter_names
        ],
        "recurrent_core_parameter_names": [name for name, _ in recurrent_core_parameters],
        "orientation_head_parameter_names": [name for name, _ in orientation_parameters],
        "precision_head_parameter_names": [name for name, _ in precision_parameters],
        "residual_parameter_names": [name for name, _ in residual_parameters],
        "recurrent_core_fingerprint": _named_parameter_fingerprint(recurrent_core_parameters),
        "orientation_head_fingerprint": _named_parameter_fingerprint(orientation_parameters),
        "precision_head_fingerprint": (
            _named_parameter_fingerprint(precision_parameters) if precision_parameters else "disabled"
        ),
        "residual_parameter_fingerprint": _named_parameter_fingerprint(residual_parameters),
    }


def _context_residual_freeze_residual_only(
    predictor: CausalContextPredictor,
) -> list[str]:
    for name, parameter in predictor.named_parameters():
        parameter.requires_grad = name in CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE
    trainable_parameter_names = [name for name, parameter in predictor.named_parameters() if parameter.requires_grad]
    if trainable_parameter_names != list(CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE):
        raise AssertionError(
            "context_residual may only train predictor.context_residual_orientation_{weight,bias}."
        )
    return trainable_parameter_names


def _context_residual_refit_seeds(
    *,
    heldout_seed: int,
    n_steps: int,
) -> list[int]:
    return [
        int(heldout_seed) + CONTEXT_RESIDUAL_REFIT_SEED_BASE_OFFSET + step_index
        for step_index in range(int(n_steps))
    ]


def _context_residual_evaluate_checkpoint(
    *,
    predictor: CausalContextPredictor,
    heldout_batch: TrialBatch,
    auxiliary_probe_fit_batch: TrialBatch,
    standard_heldout_batch: TrialBatch,
    run_id: str,
    run_dir: Path,
    checkpoint_dirname: str,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    generator: Phase1ParadigmGenerator,
    resolved_config: ExperimentConfig,
    save_prediction_artifact: str | None = None,
) -> dict[str, object]:
    checkpoint = _readout_alignment_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        auxiliary_probe_fit_batch=auxiliary_probe_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=run_id,
        run_dir=run_dir,
        checkpoint_dirname=checkpoint_dirname,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        save_native_refit_outputs=False,
    )
    checkpoint_dir = run_dir / checkpoint_dirname
    with torch.no_grad():
        heldout_prediction, heldout_hidden_states = _predict_with_hidden_states(predictor, heldout_batch)
        predictive_prediction, predictive_hidden_states = _predict_with_hidden_states(predictor, standard_heldout_batch)
    if checkpoint["heldout_hidden_state_fingerprint"] != _tensor_fingerprint(heldout_hidden_states):
        raise AssertionError("checkpoint held-out hidden-state fingerprint drifted within a single evaluation call.")
    torch.save(
        _standard_end_hidden_state_payload(
            batch=standard_heldout_batch,
            hidden_states=predictive_hidden_states,
            batch_role="heldout_predictive_eval",
        ),
        checkpoint_dir / CONTEXT_RESIDUAL_RAW_HIDDEN_STATE_PREDICTIVE_ARTIFACT,
    )
    torch.save(_serialize_batch(standard_heldout_batch), checkpoint_dir / CONTEXT_RESIDUAL_HELDOUT_PREDICTIVE_BATCH_ARTIFACT)
    if save_prediction_artifact is not None:
        (run_dir / "eval").mkdir(parents=True, exist_ok=True)
        torch.save(_serialize_context_prediction(heldout_prediction), run_dir / save_prediction_artifact)
    checkpoint["learned_orientation_logits"] = heldout_prediction.orientation_logits.detach().cpu()
    checkpoint["predictive_hidden_states"] = predictive_hidden_states.detach().cpu()
    checkpoint["predictive_hidden_state_fingerprint"] = _tensor_fingerprint(predictive_hidden_states)
    checkpoint["predictive_generator_seed"] = int(standard_heldout_batch.metadata["generator_seed"])
    checkpoint["probe_scoring_mask"] = _probe_scoring_mask(heldout_batch).detach().cpu()
    return checkpoint


def _context_residual_probe_only_checkpoint(
    *,
    predictor: CausalContextPredictor,
    heldout_batch: TrialBatch,
    run_id: str,
    run_dir: Path,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    resolved_config: ExperimentConfig,
    prediction_artifact: str,
) -> dict[str, object]:
    with torch.no_grad():
        learned_prediction, heldout_hidden_states = _predict_with_hidden_states(predictor, heldout_batch)
        oracle_prediction = _oracle_context_prediction(
            heldout_batch,
            use_precision=resolved_config.context.use_precision,
        )
        learned_simulation, _ = _evaluate_single_subcase(
            batch=heldout_batch,
            prediction=learned_prediction,
            subcase="dampening",
            model=model,
            config=resolved_config,
        )
        oracle_simulation, _ = _evaluate_single_subcase(
            batch=heldout_batch,
            prediction=oracle_prediction,
            subcase="dampening",
            model=model,
            config=resolved_config,
        )
    probe_metrics = assay_runner.compute_local_global_probe_metrics(learned_simulation, heldout_batch)
    oracle_probe_metrics = assay_runner.compute_local_global_probe_metrics(oracle_simulation, heldout_batch)
    probe_context_alignment_report = _build_probe_context_alignment_report(
        heldout_batch,
        oracle_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=oracle_prediction,
            metadata=heldout_batch.metadata,
        ),
        learned_simulation=SimulationOutput(
            states={},
            observations={},
            context_prediction=learned_prediction,
            metadata=heldout_batch.metadata,
        ),
    )
    probe_symmetry_mates = {
        int(pair_id): int(descriptor["symmetry_mate_pair_id"])
        for pair_id, descriptor in heldout_batch.metadata["probe_report"]["pair_descriptors"].items()
    }
    payload = _stage4_probe_run_payload(
        run_id=run_id,
        batch=heldout_batch,
        learned_simulation=learned_simulation,
        oracle_simulation=oracle_simulation,
        symmetry_mate_lookup=probe_symmetry_mates,
    )
    rows = build_hidden_state_probe_table_rows_from_payload(payload)
    for row in rows:
        pair_id = int(row["pair_id"])
        row["_symmetry_group_id"] = min(pair_id, int(probe_symmetry_mates[pair_id]))
    hidden_state_diagnostics = build_hidden_state_diagnostics_v2(rows)
    (run_dir / "eval").mkdir(parents=True, exist_ok=True)
    torch.save(_serialize_context_prediction(learned_prediction), run_dir / prediction_artifact)
    return {
        "probe_metrics": probe_metrics,
        "oracle_probe_metrics": oracle_probe_metrics,
        "probe_context_alignment_report": probe_context_alignment_report,
        "hidden_state_diagnostics": hidden_state_diagnostics,
        "heldout_hidden_states": heldout_hidden_states.detach().cpu(),
        "learned_orientation_logits": learned_prediction.orientation_logits.detach().cpu(),
        "probe_scoring_mask": _probe_scoring_mask(heldout_batch).detach().cpu(),
    }


def _context_residual_prepare_run(
    *,
    resolved_config: ExperimentConfig,
    store: RunStore,
    generator: Phase1ParadigmGenerator,
    model: V1ExpectationModel,
    assay_runner: AssayRunner,
    train_seed: int,
    heldout_seed: int,
    seed_panel: str,
) -> dict[str, object]:
    training_config = _stage4_training_config(resolved_config)
    auxiliary_probe_fit_seed = heldout_seed + CONTEXT_RESIDUAL_AUXILIARY_PROBE_FIT_SEED_OFFSET
    if auxiliary_probe_fit_seed == heldout_seed:
        raise AssertionError("auxiliary probe-fit seed must differ from held-out seed.")
    train_batches = [
        generator.generate_batch(
            batch_size=training_config.batch_size,
            seed=train_seed + epoch,
        )
        for epoch in range(training_config.n_epochs)
    ]
    heldout_batch = generator.generate_local_global_probe_batch(seed=heldout_seed)
    auxiliary_probe_fit_batch = generator.generate_local_global_probe_batch(seed=auxiliary_probe_fit_seed)
    standard_heldout_batch = generator.generate_batch(
        batch_size=training_config.batch_size,
        seed=heldout_seed,
    )
    task_mode_fixed_state = _fixed_state_name(heldout_batch.task_mode, heldout_batch.metadata["task_mode_names"])
    prestim_fixed_state = _fixed_state_name(heldout_batch.prestim_mode, heldout_batch.metadata["prestim_mode_names"])
    refit_batch_seeds = _context_residual_refit_seeds(
        heldout_seed=int(heldout_seed),
        n_steps=int(training_config.n_epochs),
    )
    manifest, run_dir = store.create_run(
        resolved_config.name,
        train_objectives=[f"{resolved_config.training.predictive_objective}:{EXPECTED_DISTRIBUTION_OBJECTIVE}"],
        heldout_assays=[
            "probe_target_aligned_specificity_contrast",
            "probe_pooled_target_aligned_specificity_contrast",
            "probe_context_comparator_nonuniformity_contrast",
            "linear_probe_alignment_kl",
            "linear_probe_expected_target_top1_rate",
            "linear_probe_correct_pair_flip_rate__v2",
            "linear_probe_within_pair_mass__v2",
            "linear_probe_source_bin_kl__v2",
        ],
        notes={
            "gate": "context_residual",
            "context_residual_package_version": CONTEXT_RESIDUAL_PACKAGE_VERSION,
            "class_name": READOUT_CLASS_NAME,
            "equation": READOUT_CLASS_EQUATION,
            "checkpoints": [CONTEXT_RESIDUAL_PRE_CHECKPOINT_DIRNAME, CONTEXT_RESIDUAL_POST_CHECKPOINT_DIRNAME],
            "seed_panel": seed_panel,
            "train_seed": int(train_seed),
            "heldout_seed": int(heldout_seed),
            "auxiliary_probe_fit_seed": int(auxiliary_probe_fit_seed),
            "refit_batch_seeds": refit_batch_seeds,
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "initial_standard_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "refit_optimizer": "Adam",
            "refit_step_count": training_config.n_epochs,
            "parameter_update_scope": list(CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE_FULL),
            "frozen_scope": [
                "predictor.gru.*",
                "predictor.orientation_head.*",
                "predictor.precision_head.*",
            ],
            "controlled_sources": heldout_batch.metadata["controlled_sources"].tolist(),
            "probe_visible_step_index": int(heldout_batch.metadata["probe_visible_step_index"]),
            "task_mode_fixed_state": task_mode_fixed_state,
            "prestim_fixed_state": prestim_fixed_state,
            "heldout_fixed_probe_eval_rule": "fixed_probe_batch(seed=heldout_seed)",
            "heldout_predictive_eval_rule": "generate_batch(batch_size=32, seed=heldout_seed)",
            "auxiliary_probe_fit_rule": "fixed_probe_batch(seed=heldout_seed + 1)",
            "refit_batch_identity_rule": "generate_batch(batch_size=32, seed=heldout_seed + 100 + step_index)",
            "hidden_state_tensors_exported": [
                CONTEXT_RESIDUAL_HIDDEN_STATE_TENSOR_NAME,
            ],
            "linear_probe_form": CONTEXT_RESIDUAL_LINEAR_PROBE_FORM,
            "linear_probe_target": CONTEXT_RESIDUAL_LINEAR_PROBE_TARGET,
            "linear_probe_ridge_lambda": CONTEXT_RESIDUAL_LINEAR_PROBE_RIDGE_LAMBDA,
            "linear_probe_train_eval_disjoint": True,
            "linear_probe_fit_mask": "probe_step_mask & probe_valid_mask",
            "bootstrap_seed": CONTEXT_RESIDUAL_BOOTSTRAP_SEED,
            "bootstrap_resamples": CONTEXT_RESIDUAL_BOOTSTRAP_RESAMPLES,
            "no_sweep": True,
            "no_second_package": True,
            "no_teacher_targets": True,
            "no_heldout_selection": True,
            "oracle_precision_mode": "neutral_zero_logit" if resolved_config.context.use_precision else "disabled",
        },
    )

    predictor = CausalContextPredictor(resolved_config.geometry, resolved_config.context)
    train_history = train_context_predictor(
        predictor,
        train_batches,
        training_config,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )
    _write_json(run_dir / CONTEXT_RESIDUAL_PRETRAIN_HISTORY_ARTIFACT, [asdict(item) for item in train_history])

    pre_parameter_snapshot = _context_residual_parameter_scope_snapshot(predictor)
    _write_json(
        run_dir / CONTEXT_RESIDUAL_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT,
        {
            **_context_residual_metadata(
                metric_versions={"parameter_scope_fingerprints": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "run_id": manifest.run_id,
            "parameter_update_scope": list(CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE_FULL),
            "pre_refit": pre_parameter_snapshot,
            "post_refit": None,
            "checks": {},
        },
    )
    pre_checkpoint = _context_residual_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        auxiliary_probe_fit_batch=auxiliary_probe_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=manifest.run_id,
        run_dir=run_dir,
        checkpoint_dirname=CONTEXT_RESIDUAL_PRE_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        save_prediction_artifact=CONTEXT_RESIDUAL_NATIVE_PREDICTIONS_PRE_ARTIFACT,
    )
    _write_stage0_provenance(store=store, run_dir=run_dir, manifest=manifest, resolved_config=resolved_config)
    return {
        "run_id": manifest.run_id,
        "run_dir": run_dir,
        "seed_panel": seed_panel,
        "train_seed": int(train_seed),
        "heldout_seed": int(heldout_seed),
        "auxiliary_probe_fit_seed": int(auxiliary_probe_fit_seed),
        "predictor": predictor,
        "generator": generator,
        "model": model,
        "assay_runner": assay_runner,
        "resolved_config": resolved_config,
        "heldout_batch": heldout_batch,
        "auxiliary_probe_fit_batch": auxiliary_probe_fit_batch,
        "standard_heldout_batch": standard_heldout_batch,
        "pre_refit": pre_checkpoint,
        "pre_parameter_snapshot": pre_parameter_snapshot,
    }


def _context_residual_refit_residual_only(
    *,
    predictor: CausalContextPredictor,
    generator: Phase1ParadigmGenerator,
    heldout_seed: int,
    training_config,
) -> tuple[list[EpochMetrics], list[int]]:
    trainable_parameter_names = _context_residual_freeze_residual_only(predictor)
    if trainable_parameter_names != list(CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE):
        raise AssertionError("unexpected context_residual parameter scope.")
    refit_batch_seeds = _context_residual_refit_seeds(
        heldout_seed=int(heldout_seed),
        n_steps=int(training_config.n_epochs),
    )
    refit_batches = [
        generator.generate_batch(
            batch_size=training_config.batch_size,
            seed=batch_seed,
        )
        for batch_seed in refit_batch_seeds
    ]
    history = train_context_predictor(
        predictor,
        refit_batches,
        training_config,
        objective_mode=EXPECTED_DISTRIBUTION_OBJECTIVE,
    )
    predictor.eval()
    return history, refit_batch_seeds


def _context_residual_complete_run(
    prepared_run: dict[str, object],
) -> dict[str, object]:
    predictor = prepared_run["predictor"]
    generator = prepared_run["generator"]
    model = prepared_run["model"]
    assay_runner = prepared_run["assay_runner"]
    resolved_config = prepared_run["resolved_config"]
    heldout_batch = prepared_run["heldout_batch"]
    auxiliary_probe_fit_batch = prepared_run["auxiliary_probe_fit_batch"]
    standard_heldout_batch = prepared_run["standard_heldout_batch"]
    run_dir = prepared_run["run_dir"]
    run_id = prepared_run["run_id"]
    training_config = _stage4_training_config(resolved_config)

    refit_history, refit_batch_seeds = _context_residual_refit_residual_only(
        predictor=predictor,
        generator=generator,
        heldout_seed=int(prepared_run["heldout_seed"]),
        training_config=training_config,
    )
    _write_json(run_dir / CONTEXT_RESIDUAL_REFIT_HISTORY_ARTIFACT, [asdict(item) for item in refit_history])
    post_parameter_snapshot = _context_residual_parameter_scope_snapshot(predictor)
    post_checkpoint = _context_residual_evaluate_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        auxiliary_probe_fit_batch=auxiliary_probe_fit_batch,
        standard_heldout_batch=standard_heldout_batch,
        run_id=run_id,
        run_dir=run_dir,
        checkpoint_dirname=CONTEXT_RESIDUAL_POST_CHECKPOINT_DIRNAME,
        model=model,
        assay_runner=assay_runner,
        generator=generator,
        resolved_config=resolved_config,
        save_prediction_artifact=CONTEXT_RESIDUAL_NATIVE_PREDICTIONS_POST_ARTIFACT,
    )
    residual_state = {
        "weight": predictor.context_residual_orientation_weight.detach().cpu().clone(),
        "bias": predictor.context_residual_orientation_bias.detach().cpu().clone(),
    }
    torch.save(residual_state, run_dir / CONTEXT_RESIDUAL_STATE_ARTIFACT)

    with torch.no_grad():
        predictor.context_residual_orientation_weight.zero_()
        predictor.context_residual_orientation_bias.zero_()
    residual_ablated = _context_residual_probe_only_checkpoint(
        predictor=predictor,
        heldout_batch=heldout_batch,
        run_id=run_id,
        run_dir=run_dir,
        model=model,
        assay_runner=assay_runner,
        resolved_config=resolved_config,
        prediction_artifact=CONTEXT_RESIDUAL_ABLATION_PREDICTIONS_ARTIFACT,
    )
    with torch.no_grad():
        predictor.context_residual_orientation_weight.copy_(
            residual_state["weight"].to(
                device=predictor.context_residual_orientation_weight.device,
                dtype=predictor.context_residual_orientation_weight.dtype,
            )
        )
        predictor.context_residual_orientation_bias.copy_(
            residual_state["bias"].to(
                device=predictor.context_residual_orientation_bias.device,
                dtype=predictor.context_residual_orientation_bias.dtype,
            )
        )

    pre_checkpoint = prepared_run["pre_refit"]
    heldout_fixed_batch_same_pre_post = (
        int(pre_checkpoint["heldout_generator_seed"]) == int(post_checkpoint["heldout_generator_seed"])
    )
    heldout_predictive_batch_same_pre_post = (
        int(pre_checkpoint["predictive_generator_seed"]) == int(post_checkpoint["predictive_generator_seed"])
    )
    auxiliary_batch_same_pre_post = (
        int(pre_checkpoint["auxiliary_generator_seed"]) == int(post_checkpoint["auxiliary_generator_seed"])
    )
    heldout_hidden_state_max_abs_diff = float(
        (pre_checkpoint["heldout_hidden_states"] - post_checkpoint["heldout_hidden_states"]).abs().max().item()
    )
    predictive_hidden_state_max_abs_diff = float(
        (pre_checkpoint["predictive_hidden_states"] - post_checkpoint["predictive_hidden_states"]).abs().max().item()
    )
    heldout_hidden_states_unchanged = bool(
        torch.allclose(
            pre_checkpoint["heldout_hidden_states"],
            post_checkpoint["heldout_hidden_states"],
            atol=CONTEXT_RESIDUAL_HIDDEN_STATE_ATOL,
            rtol=0.0,
        )
    )
    predictive_hidden_states_unchanged = bool(
        torch.allclose(
            pre_checkpoint["predictive_hidden_states"],
            post_checkpoint["predictive_hidden_states"],
            atol=CONTEXT_RESIDUAL_HIDDEN_STATE_ATOL,
            rtol=0.0,
        )
    )
    recurrent_core_parameter_fingerprint_unchanged = (
        prepared_run["pre_parameter_snapshot"]["recurrent_core_fingerprint"]
        == post_parameter_snapshot["recurrent_core_fingerprint"]
    )
    orientation_head_parameter_fingerprint_unchanged = (
        prepared_run["pre_parameter_snapshot"]["orientation_head_fingerprint"]
        == post_parameter_snapshot["orientation_head_fingerprint"]
    )
    precision_head_parameter_fingerprint_unchanged = (
        prepared_run["pre_parameter_snapshot"]["precision_head_fingerprint"]
        == post_parameter_snapshot["precision_head_fingerprint"]
    )
    residual_parameter_fingerprint_changed = (
        prepared_run["pre_parameter_snapshot"]["residual_parameter_fingerprint"]
        != post_parameter_snapshot["residual_parameter_fingerprint"]
    )
    predictive_loss_pre = float(pre_checkpoint["standard_predictive_metrics"]["predictive_loss"])
    predictive_loss_post = float(post_checkpoint["standard_predictive_metrics"]["predictive_loss"])
    predictive_structure_accuracy_pre = float(pre_checkpoint["standard_sanity"]["predictive_structure"]["accuracy"])
    predictive_structure_accuracy_post = float(post_checkpoint["standard_sanity"]["predictive_structure"]["accuracy"])
    nuisance_only_accuracy_pre = float(pre_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"])
    nuisance_only_accuracy_post = float(post_checkpoint["standard_sanity"]["nuisance_only"]["accuracy"])
    integrity = {
        "heldout_fixed_probe_batch_identity_same_pre_post": heldout_fixed_batch_same_pre_post,
        "heldout_predictive_batch_identity_same_pre_post": heldout_predictive_batch_same_pre_post,
        "auxiliary_batch_identity_same_pre_post": auxiliary_batch_same_pre_post,
        "auxiliary_eval_disjoint_from_heldout": int(prepared_run["heldout_seed"]) != int(prepared_run["auxiliary_probe_fit_seed"]),
        "recurrent_core_parameter_fingerprint_unchanged": recurrent_core_parameter_fingerprint_unchanged,
        "orientation_head_parameter_fingerprint_unchanged": orientation_head_parameter_fingerprint_unchanged,
        "precision_head_parameter_fingerprint_unchanged": precision_head_parameter_fingerprint_unchanged,
        "residual_parameter_fingerprint_changed": residual_parameter_fingerprint_changed,
        "heldout_fixed_probe_hidden_states_unchanged": heldout_hidden_states_unchanged,
        "heldout_predictive_hidden_states_unchanged": predictive_hidden_states_unchanged,
        "heldout_fixed_probe_hidden_state_max_abs_diff": heldout_hidden_state_max_abs_diff,
        "heldout_predictive_hidden_state_max_abs_diff": predictive_hidden_state_max_abs_diff,
        "delta_predictive_loss": predictive_loss_post - predictive_loss_pre,
        "delta_predictive_structure_accuracy": predictive_structure_accuracy_post - predictive_structure_accuracy_pre,
        "delta_nuisance_only_accuracy": nuisance_only_accuracy_post - nuisance_only_accuracy_pre,
        "nuisance_only_accuracy_post": nuisance_only_accuracy_post,
        "exact_trainable_parameter_scope_during_refit": (
            post_parameter_snapshot["trainable_parameter_names"] == list(CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE)
        ),
        "no_linear_probe_dependency_in_refit": True,
    }
    parameter_scope_payload = {
        **_context_residual_metadata(
            metric_versions={"parameter_scope_fingerprints": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "run_id": run_id,
        "parameter_update_scope": list(CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE_FULL),
        "refit_batch_seeds": refit_batch_seeds,
        "pre_refit": prepared_run["pre_parameter_snapshot"],
        "post_refit": post_parameter_snapshot,
        "checks": {
            "exact_trainable_parameter_scope_during_refit": integrity["exact_trainable_parameter_scope_during_refit"],
            "recurrent_core_parameter_fingerprint_unchanged": recurrent_core_parameter_fingerprint_unchanged,
            "orientation_head_parameter_fingerprint_unchanged": orientation_head_parameter_fingerprint_unchanged,
            "precision_head_parameter_fingerprint_unchanged": precision_head_parameter_fingerprint_unchanged,
            "residual_parameter_fingerprint_changed": residual_parameter_fingerprint_changed,
        },
    }
    _write_json(run_dir / CONTEXT_RESIDUAL_PARAMETER_SCOPE_FINGERPRINTS_ARTIFACT, parameter_scope_payload)

    return {
        "run_id": run_id,
        "run_dir": run_dir,
        "seed_panel": prepared_run["seed_panel"],
        "train_seed": int(prepared_run["train_seed"]),
        "heldout_seed": int(prepared_run["heldout_seed"]),
        "auxiliary_probe_fit_seed": int(prepared_run["auxiliary_probe_fit_seed"]),
        "refit_batch_seeds": refit_batch_seeds,
        "pre_refit": pre_checkpoint,
        "post_refit": post_checkpoint,
        "residual_ablated": residual_ablated,
        "refit_integrity": integrity,
        "artifacts_complete": True,
    }


def _context_residual_predictive_integrity_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = len(run_entries)
    seedwise: list[dict[str, object]] = []
    loss_checks: list[bool] = []
    structure_checks: list[bool] = []
    nuisance_delta_checks: list[bool] = []
    nuisance_post_checks: list[bool] = []
    for entry in run_entries:
        integrity = entry["refit_integrity"]
        loss_check = integrity["delta_predictive_loss"] <= CONTEXT_RESIDUAL_PREDICTIVE_LOSS_DELTA_MAX
        structure_check = integrity["delta_predictive_structure_accuracy"] >= CONTEXT_RESIDUAL_PREDICTIVE_STRUCTURE_DELTA_MIN
        nuisance_delta_check = integrity["delta_nuisance_only_accuracy"] <= CONTEXT_RESIDUAL_NUISANCE_ONLY_DELTA_MAX
        nuisance_post_check = integrity["nuisance_only_accuracy_post"] < CONTEXT_RESIDUAL_NUISANCE_ONLY_POST_MAX
        loss_checks.append(loss_check)
        structure_checks.append(structure_check)
        nuisance_delta_checks.append(nuisance_delta_check)
        nuisance_post_checks.append(nuisance_post_check)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "delta_predictive_loss": float(integrity["delta_predictive_loss"]),
                "delta_predictive_structure_accuracy": float(integrity["delta_predictive_structure_accuracy"]),
                "delta_nuisance_only_accuracy": float(integrity["delta_nuisance_only_accuracy"]),
                "nuisance_only_accuracy_post": float(integrity["nuisance_only_accuracy_post"]),
            }
        )
    checks = {
        "required_successes": required_successes,
        "delta_predictive_loss_le_0_05_count": _stage4_count_true(loss_checks),
        "delta_predictive_structure_accuracy_ge_minus_0_05_count": _stage4_count_true(structure_checks),
        "delta_nuisance_only_accuracy_le_0_05_count": _stage4_count_true(nuisance_delta_checks),
        "nuisance_only_accuracy_post_lt_0_5_count": _stage4_count_true(nuisance_post_checks),
    }
    checks["passes"] = all(value >= required_successes for key, value in checks.items() if key.endswith("_count"))
    return {
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "summary": {
            "mean_delta_predictive_loss": _stage4_mean([float(item["delta_predictive_loss"]) for item in seedwise]),
            "mean_delta_predictive_structure_accuracy": _stage4_mean(
                [float(item["delta_predictive_structure_accuracy"]) for item in seedwise]
            ),
            "mean_delta_nuisance_only_accuracy": _stage4_mean(
                [float(item["delta_nuisance_only_accuracy"]) for item in seedwise]
            ),
            "mean_nuisance_only_accuracy_post": _stage4_mean(
                [float(item["nuisance_only_accuracy_post"]) for item in seedwise]
            ),
        },
        "checks": checks,
        "passes": bool(checks["passes"]),
    }


def _context_residual_delta_panel_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    checkpoint_key: str,
) -> dict[str, object]:
    return _readout_alignment_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key=checkpoint_key,
    )


def _context_residual_build_pre_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    native_anchor_summary = _readout_alignment_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_refit",
    )
    linear_probe_summary = _readout_alignment_linear_probe_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_refit",
    )
    delta_summary = _context_residual_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="pre_refit",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "native_anchor_fails": not native_anchor_summary["passes"],
        "linear_probe_strong_gate_passes": bool(linear_probe_summary["passes"]),
        "mean_top1_improvement_ge_0_25": (
            delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"] is not None
            and float(delta_summary["summary"]["mean_delta_expected_target_top1_rate__linear_minus_native"])
            >= CONTEXT_RESIDUAL_TOP1_IMPROVEMENT_MIN
        ),
        "top1_improvement_ci_lower_gt_0": top1_ci is not None and float(top1_ci["lower"]) > 0.0,
        "mean_kl_reduction_ge_0_50": (
            delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"] is not None
            and float(delta_summary["summary"]["mean_alignment_kl_reduction__native_minus_linear"])
            >= CONTEXT_RESIDUAL_KL_REDUCTION_MIN
        ),
        "kl_reduction_ci_lower_gt_0": kl_ci is not None and float(kl_ci["lower"]) > 0.0,
    }
    return {
        **_context_residual_metadata(
            metric_versions={"pre_refit_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "linear_probe_summary": linear_probe_summary,
        "readout_gap_summary": delta_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _context_residual_build_skipped_panel_report(
    *,
    artifact_key: str,
    seed_panel: str,
    stop_reason: str,
) -> dict[str, object]:
    return {
        **_context_residual_metadata(
            metric_versions={artifact_key: "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "skipped": True,
        "stop_reason": stop_reason,
        "passes": False,
    }


def _context_residual_build_integrity_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    required_successes = len(run_entries)
    seedwise: list[dict[str, object]] = []
    boolean_fields = {
        "heldout_fixed_probe_batch_identity_same_pre_post": [],
        "heldout_predictive_batch_identity_same_pre_post": [],
        "auxiliary_batch_identity_same_pre_post": [],
        "auxiliary_eval_disjoint_from_heldout": [],
        "recurrent_core_parameter_fingerprint_unchanged": [],
        "orientation_head_parameter_fingerprint_unchanged": [],
        "precision_head_parameter_fingerprint_unchanged": [],
        "heldout_fixed_probe_hidden_states_unchanged": [],
        "heldout_predictive_hidden_states_unchanged": [],
        "exact_trainable_parameter_scope_during_refit": [],
    }
    residual_parameter_changes: list[bool] = []
    predictive_nonregression: list[bool] = []
    no_linear_probe_dependency: list[bool] = []
    for entry in run_entries:
        integrity = entry["refit_integrity"]
        predictive_pass = (
            integrity["delta_predictive_loss"] <= CONTEXT_RESIDUAL_PREDICTIVE_LOSS_DELTA_MAX
            and integrity["delta_predictive_structure_accuracy"] >= CONTEXT_RESIDUAL_PREDICTIVE_STRUCTURE_DELTA_MIN
            and integrity["delta_nuisance_only_accuracy"] <= CONTEXT_RESIDUAL_NUISANCE_ONLY_DELTA_MAX
            and integrity["nuisance_only_accuracy_post"] < CONTEXT_RESIDUAL_NUISANCE_ONLY_POST_MAX
        )
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                **integrity,
                "predictive_nonregression_passes": predictive_pass,
            }
        )
        for key in boolean_fields:
            boolean_fields[key].append(bool(integrity[key]))
        residual_parameter_changes.append(bool(integrity["residual_parameter_fingerprint_changed"]))
        predictive_nonregression.append(bool(predictive_pass))
        no_linear_probe_dependency.append(bool(integrity["no_linear_probe_dependency_in_refit"]))
    checks = {
        "required_successes": required_successes,
        "heldout_fixed_probe_batch_identity_same_pre_post_count": _stage4_count_true(
            boolean_fields["heldout_fixed_probe_batch_identity_same_pre_post"]
        ),
        "heldout_predictive_batch_identity_same_pre_post_count": _stage4_count_true(
            boolean_fields["heldout_predictive_batch_identity_same_pre_post"]
        ),
        "auxiliary_batch_identity_same_pre_post_count": _stage4_count_true(
            boolean_fields["auxiliary_batch_identity_same_pre_post"]
        ),
        "auxiliary_eval_disjoint_from_heldout_count": _stage4_count_true(
            boolean_fields["auxiliary_eval_disjoint_from_heldout"]
        ),
        "recurrent_core_parameter_fingerprint_unchanged_count": _stage4_count_true(
            boolean_fields["recurrent_core_parameter_fingerprint_unchanged"]
        ),
        "orientation_head_parameter_fingerprint_unchanged_count": _stage4_count_true(
            boolean_fields["orientation_head_parameter_fingerprint_unchanged"]
        ),
        "precision_head_parameter_fingerprint_unchanged_count": _stage4_count_true(
            boolean_fields["precision_head_parameter_fingerprint_unchanged"]
        ),
        "heldout_fixed_probe_hidden_states_unchanged_count": _stage4_count_true(
            boolean_fields["heldout_fixed_probe_hidden_states_unchanged"]
        ),
        "heldout_predictive_hidden_states_unchanged_count": _stage4_count_true(
            boolean_fields["heldout_predictive_hidden_states_unchanged"]
        ),
        "exact_trainable_parameter_scope_during_refit_count": _stage4_count_true(
            boolean_fields["exact_trainable_parameter_scope_during_refit"]
        ),
        "residual_parameter_fingerprint_changed_count": _stage4_count_true(residual_parameter_changes),
        "predictive_nonregression_count": _stage4_count_true(predictive_nonregression),
        "no_linear_probe_dependency_in_refit_count": _stage4_count_true(no_linear_probe_dependency),
    }
    count_checks_pass = all(
        value >= required_successes
        for key, value in checks.items()
        if key.endswith("_count")
        and key not in ("residual_parameter_fingerprint_changed_count",)
    )
    checks["passes"] = (
        count_checks_pass
        and checks["residual_parameter_fingerprint_changed_count"] >= 1
    )
    return {
        **_context_residual_metadata(
            metric_versions={"refit_integrity_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
        ),
        "seed_panel": seed_panel,
        "seedwise": seedwise,
        "checks": checks,
        "passes": bool(checks["passes"]),
        "skipped": False,
    }


def _context_residual_build_post_report(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
    overall_entries: list[dict[str, object]] | None = None,
) -> dict[str, object]:
    native_anchor_summary = _readout_alignment_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_refit",
    )
    native_strong_gate_summary = _readout_alignment_native_strong_gate_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_refit",
    )
    predictive_integrity_summary = _context_residual_predictive_integrity_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
    )
    delta_summary = _context_residual_delta_panel_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="post_refit",
    )
    top1_ci = delta_summary["summary"]["bootstrap_ci_95"]["delta_expected_target_top1_rate__linear_minus_native"]
    kl_ci = delta_summary["summary"]["bootstrap_ci_95"]["alignment_kl_reduction__native_minus_linear"]
    checks = {
        "native_anchor_passes": bool(native_anchor_summary["passes"]),
        "native_strong_gate_passes": bool(native_strong_gate_summary["passes"]),
        "predictive_integrity_passes": bool(predictive_integrity_summary["passes"]),
        "no_material_linear_probe_top1_advantage": top1_ci is not None
        and float(top1_ci["upper"]) < CONTEXT_RESIDUAL_TOP1_IMPROVEMENT_NO_ADVANTAGE_MAX,
        "no_material_linear_probe_kl_advantage": kl_ci is not None
        and float(kl_ci["upper"]) < CONTEXT_RESIDUAL_KL_REDUCTION_NO_ADVANTAGE_MAX,
    }
    overall_post_refit_summary = None
    if overall_entries is not None:
        post_latent_values = [
            float(entry["post_refit"]["probe_metrics"]["probe_target_aligned_specificity_contrast"])
            for entry in overall_entries
        ]
        post_pooled_values = [
            float(entry["post_refit"]["probe_metrics"]["probe_pooled_target_aligned_specificity_contrast"])
            for entry in overall_entries
        ]
        post_symmetry_values = [
            float(entry["post_refit"]["probe_context_alignment_report"]["learned_probe_pair_flip_symmetry_consistency"]) >= 1.0
            for entry in overall_entries
        ]
        post_ratio_values = [
            _stage4_probe_ratio(
                float(entry["post_refit"]["probe_metrics"]["probe_target_aligned_specificity_contrast"]),
                float(entry["post_refit"]["oracle_probe_metrics"]["probe_target_aligned_specificity_contrast"]),
            )
            for entry in overall_entries
        ]
        overall_post_refit_summary = {
            "latent_positive_count": _stage4_count_true([value > 0.0 for value in post_latent_values]),
            "pooled_positive_count": _stage4_count_true([value > 0.0 for value in post_pooled_values]),
            "learned_symmetry_consistency_count": _stage4_count_true(post_symmetry_values),
            "learned_oracle_latent_ratio_ge_0_25_count": _stage4_count_true(
                [value is not None and value >= CONTEXT_RESIDUAL_ANCHOR_LATENT_RATIO_FLOOR for value in post_ratio_values]
            ),
            "passes": (
                _stage4_count_true([value > 0.0 for value in post_latent_values]) >= 9
                and _stage4_count_true([value > 0.0 for value in post_pooled_values]) >= 9
                and _stage4_count_true(post_symmetry_values) >= 9
                and _stage4_count_true(
                    [value is not None and value >= CONTEXT_RESIDUAL_ANCHOR_LATENT_RATIO_FLOOR for value in post_ratio_values]
                ) >= 9
            ),
        }
        checks["overall_10_seed_post_refit_closure"] = bool(overall_post_refit_summary["passes"])
    return {
        **_context_residual_metadata(
            metric_versions={"post_refit_report": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "seed_panel": seed_panel,
        "native_anchor_summary": native_anchor_summary,
        "native_strong_gate_summary": native_strong_gate_summary,
        "predictive_integrity_summary": predictive_integrity_summary,
        "readout_gap_summary": delta_summary,
        "overall_post_refit_summary": overall_post_refit_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
        "skipped": False,
    }


def _context_residual_structure_panel_summary(
    *,
    seed_panel: str,
    run_entries: list[dict[str, object]],
) -> dict[str, object]:
    hidden_rows: list[torch.Tensor] = []
    output_rows: list[torch.Tensor] = []
    for entry in run_entries:
        mask = entry["post_refit"]["probe_scoring_mask"]
        hidden_rows.append(entry["post_refit"]["heldout_hidden_states"][mask].to(torch.float64))
        output_rows.append(entry["post_refit"]["learned_orientation_logits"][mask].to(torch.float64))
    hidden_states = torch.cat(hidden_rows, dim=0)
    target_outputs = torch.cat(output_rows, dim=0)
    shared_affine_residual = _readout_class_shared_affine_residual(
        hidden_states=hidden_states,
        target_outputs=target_outputs,
    )
    shared_affine_residual["n_rows"] = int(hidden_states.shape[0])

    seedwise: list[dict[str, object]] = []
    top1_reopen_values: list[float] = []
    kl_reopen_values: list[float] = []
    for entry in run_entries:
        post_top1 = float(entry["post_refit"]["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"])
        ablated_top1 = float(entry["residual_ablated"]["probe_context_alignment_report"]["learned_probe_expected_target_top1_rate"])
        post_kl = float(entry["post_refit"]["probe_context_alignment_report"]["learned_probe_alignment_kl"])
        ablated_kl = float(entry["residual_ablated"]["probe_context_alignment_report"]["learned_probe_alignment_kl"])
        top1_reopen = float(post_top1 - ablated_top1)
        kl_reopen = float(ablated_kl - post_kl)
        seedwise.append(
            {
                "run_id": entry["run_id"],
                "train_seed": int(entry["train_seed"]),
                "heldout_seed": int(entry["heldout_seed"]),
                "top1_post_minus_ablated": top1_reopen,
                "kl_ablated_minus_post": kl_reopen,
            }
        )
        top1_reopen_values.append(top1_reopen)
        kl_reopen_values.append(kl_reopen)

    def _ci(values: list[float], offset: int) -> dict[str, float] | None:
        return _standard_end_bootstrap_mean_ci(values, seed=CONTEXT_RESIDUAL_BOOTSTRAP_SEED + offset)

    ablated_anchor_summary = _readout_alignment_native_anchor_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="residual_ablated",
    )
    ablated_strong_gate_summary = _readout_alignment_native_strong_gate_summary(
        seed_panel=seed_panel,
        run_entries=run_entries,
        checkpoint_key="residual_ablated",
    )
    top1_ci = _ci(top1_reopen_values, 21)
    kl_ci = _ci(kl_reopen_values, 22)
    checks = {
        "shared_affine_residual_frobenius_norm_gt_1e-10": (
            float(shared_affine_residual["frobenius_norm"]) > CONTEXT_RESIDUAL_SHARED_AFFINE_RESIDUAL_TOLERANCE
        ),
        "mean_top1_post_minus_ablated_ge_0_25": (
            _stage4_mean(top1_reopen_values) is not None
            and float(_stage4_mean(top1_reopen_values)) >= CONTEXT_RESIDUAL_ZERO_ABLATION_TOP1_REOPEN_MIN
        ),
        "top1_post_minus_ablated_ci_lower_gt_0": top1_ci is not None and float(top1_ci["lower"]) > 0.0,
        "mean_kl_ablated_minus_post_ge_0_50": (
            _stage4_mean(kl_reopen_values) is not None
            and float(_stage4_mean(kl_reopen_values)) >= CONTEXT_RESIDUAL_ZERO_ABLATION_KL_REOPEN_MIN
        ),
        "kl_ablated_minus_post_ci_lower_gt_0": kl_ci is not None and float(kl_ci["lower"]) > 0.0,
        "ablated_model_fails_anchor_or_strong_gate": not (
            bool(ablated_anchor_summary["passes"]) and bool(ablated_strong_gate_summary["passes"])
        ),
    }
    return {
        "seed_panel": seed_panel,
        "shared_affine_least_squares_residual": {
            **shared_affine_residual,
            "residual_tolerance": CONTEXT_RESIDUAL_SHARED_AFFINE_RESIDUAL_TOLERANCE,
        },
        "zero_ablation_gap_summary": {
            "seedwise": seedwise,
            "summary": {
                "mean_top1_post_minus_ablated": _stage4_mean(top1_reopen_values),
                "mean_kl_ablated_minus_post": _stage4_mean(kl_reopen_values),
                "bootstrap_ci_95": {
                    "top1_post_minus_ablated": top1_ci,
                    "kl_ablated_minus_post": kl_ci,
                },
            },
        },
        "ablated_native_anchor_summary": ablated_anchor_summary,
        "ablated_native_strong_gate_summary": ablated_strong_gate_summary,
        "checks": checks,
        "passes": all(bool(value) for value in checks.values()),
    }


def _context_residual_build_structure_report(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
) -> dict[str, object]:
    panels = {
        "primary": _context_residual_structure_panel_summary(
            seed_panel="primary",
            run_entries=primary_run_entries,
        )
    }
    if confirmation_run_entries is not None:
        panels["confirmation"] = _context_residual_structure_panel_summary(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
    return {
        **_context_residual_metadata(
            metric_versions={
                "shared_affine_residual_frobenius_norm": "v1",
                "top1_post_minus_ablated": "v1",
                "kl_ablated_minus_post": "v1",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "panels": panels,
        "skipped": False,
    }


def _context_residual_build_advantage_gap_report(
    *,
    primary_run_entries: list[dict[str, object]],
    confirmation_run_entries: list[dict[str, object]] | None,
) -> dict[str, object]:
    panels: dict[str, object] = {
        "pre_refit_primary": _context_residual_delta_panel_summary(
            seed_panel="primary",
            run_entries=primary_run_entries,
            checkpoint_key="pre_refit",
        ),
    }
    post_primary_entries = [entry for entry in primary_run_entries if "post_refit" in entry]
    if post_primary_entries:
        panels["post_refit_primary"] = _context_residual_delta_panel_summary(
            seed_panel="primary",
            run_entries=post_primary_entries,
            checkpoint_key="post_refit",
        )
    if confirmation_run_entries is not None:
        panels["pre_refit_confirmation"] = _context_residual_delta_panel_summary(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            checkpoint_key="pre_refit",
        )
        post_confirmation_entries = [entry for entry in confirmation_run_entries if "post_refit" in entry]
        if post_confirmation_entries:
            panels["post_refit_confirmation"] = _context_residual_delta_panel_summary(
                seed_panel="confirmation",
                run_entries=post_confirmation_entries,
                checkpoint_key="post_refit",
            )
    return {
        **_context_residual_metadata(
            metric_versions={
                "delta_alignment_kl__linear_minus_native": "v1",
                "alignment_kl_reduction__native_minus_linear": "v1",
                "delta_expected_target_top1_rate__linear_minus_native": "v1",
                "delta_correct_pair_flip_rate__v2__linear_minus_native": "v2",
                "delta_within_pair_mass__v2__linear_minus_native": "v2",
                "delta_source_bin_kl__v2__linear_minus_native": "v2",
            },
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "panels": panels,
        "skipped": False,
    }


def _context_residual_manifest_validity(
    package_manifest: dict[str, object],
) -> bool:
    expected_trainable_scope = list(CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE_FULL)
    return (
        package_manifest.get("class_name") == READOUT_CLASS_NAME
        and package_manifest.get("equation") == READOUT_CLASS_EQUATION
        and package_manifest.get("objective", {}).get("name") == EXPECTED_DISTRIBUTION_OBJECTIVE
        and package_manifest.get("trainable_scope") == expected_trainable_scope
        and package_manifest.get("explicit_statements", {}).get("no_sweep") is True
        and package_manifest.get("explicit_statements", {}).get("no_second_package") is True
        and package_manifest.get("explicit_statements", {}).get("no_teacher_targets") is True
        and package_manifest.get("explicit_statements", {}).get("no_heldout_selection") is True
    )


def _context_residual_build_verdict(
    *,
    package_manifest: dict[str, object],
    nonregression_report: dict[str, object],
    pre_refit_primary_report: dict[str, object],
    refit_integrity_primary_report: dict[str, object],
    post_refit_primary_report: dict[str, object],
    structure_report: dict[str, object],
    pre_refit_confirmation_report: dict[str, object] | None,
    refit_integrity_confirmation_report: dict[str, object] | None,
    post_refit_confirmation_report: dict[str, object] | None,
    confirmation_executed: bool,
) -> dict[str, object]:
    manifest_valid = _context_residual_manifest_validity(package_manifest)
    if not manifest_valid:
        return {
            **_context_residual_metadata(
                metric_versions={"context_residual_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "manifest",
            "stop_gate": "P0 manifest validity",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": False,
                "R1_nonregression": bool(nonregression_report["passes"]),
                "R2_pre_refit_premise": bool(pre_refit_primary_report["passes"]),
            },
        }
    if not bool(nonregression_report["passes"]):
        return {
            **_context_residual_metadata(
                metric_versions={"context_residual_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "nonregression",
            "stop_gate": "R1 frozen non-regression",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": False,
                "R2_pre_refit_premise": bool(pre_refit_primary_report["passes"]),
            },
        }
    if not bool(pre_refit_primary_report["passes"]):
        return {
            **_context_residual_metadata(
                metric_versions={"context_residual_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "pre_refit_primary",
            "stop_gate": "R2 pre-refit premise reproduction",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_pre_refit_premise": False,
            },
        }
    if not bool(refit_integrity_primary_report["passes"]):
        return {
            **_context_residual_metadata(
                metric_versions={"context_residual_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO invalid execution",
            "execution_valid": False,
            "stop_stage": "refit_integrity_primary",
            "stop_gate": "R3 integrity",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_pre_refit_premise": True,
            },
        }
    primary_structure = structure_report["panels"]["primary"]
    if not (bool(post_refit_primary_report["passes"]) and bool(primary_structure["passes"])):
        return {
            **_context_residual_metadata(
                metric_versions={"context_residual_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "post_refit_primary",
            "stop_gate": "R4 primary scientific success",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_pre_refit_premise": True,
            },
        }
    if not confirmation_executed:
        return {
            **_context_residual_metadata(
                metric_versions={"context_residual_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation_not_executed",
            "stop_gate": "R5 confirmation replication",
            "confirmation_executed": False,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_pre_refit_premise": True,
            },
        }
    confirmation_structure = structure_report["panels"].get("confirmation")
    confirmation_passes = (
        pre_refit_confirmation_report is not None
        and bool(pre_refit_confirmation_report["passes"])
        and refit_integrity_confirmation_report is not None
        and bool(refit_integrity_confirmation_report["passes"])
        and post_refit_confirmation_report is not None
        and bool(post_refit_confirmation_report["passes"])
        and confirmation_structure is not None
        and bool(confirmation_structure["passes"])
    )
    if not confirmation_passes:
        return {
            **_context_residual_metadata(
                metric_versions={"context_residual_verdict": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
            ),
            "classification": "NO-GO clean negative",
            "execution_valid": True,
            "stop_stage": "confirmation",
            "stop_gate": "R5 confirmation replication",
            "confirmation_executed": True,
            "package_complete": True,
            "precondition_checks": {
                "P0_manifest_validity": True,
                "R1_nonregression": True,
                "R2_pre_refit_premise": True,
            },
        }
    return {
        **_context_residual_metadata(
            metric_versions={"context_residual_verdict": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "classification": "GO-context-residual-aligned",
        "execution_valid": True,
        "stop_stage": None,
        "stop_gate": None,
        "confirmation_executed": True,
        "package_complete": True,
        "precondition_checks": {
            "P0_manifest_validity": True,
            "R1_nonregression": True,
            "R2_pre_refit_premise": True,
        },
    }


def run_context_residual_package(
    *,
    config: ExperimentConfig | None = None,
    preset_name: str = "phase1_core",
    primary_seed_panel: tuple[tuple[int, int], ...] = STAGE3_PRIMARY_SEED_PANEL,
    confirmation_seed_panel: tuple[tuple[int, int], ...] = STAGE3_CONFIRMATION_SEED_PANEL,
    benchmark_artifacts_root: str | Path = "artifacts",
) -> ContextResidualRunResult:
    resolved_config = _resolve_config(config=config, preset_name=preset_name)
    if resolved_config.name != "phase1_core":
        raise ValueError("context_residual is frozen to the phase1_core configuration family.")
    output_root = resolved_config.artifacts.root_dir / "context_residual" / CONTEXT_RESIDUAL_PACKAGE_VERSION
    output_root.mkdir(parents=True, exist_ok=True)
    training_config = _stage4_training_config(resolved_config)
    package_manifest = {
        **_context_residual_metadata(
            metric_versions={"context_residual_manifest": "v1"},
            source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION, DIAGNOSTIC_SCHEMA_VERSION],
        ),
        "class_name": READOUT_CLASS_NAME,
        "equation": READOUT_CLASS_EQUATION,
        "changed_files": list(CONTEXT_RESIDUAL_CHANGED_FILES),
        "trainable_scope": list(CONTEXT_RESIDUAL_PARAM_UPDATE_SCOPE_FULL),
        "frozen_scope": [
            "predictor.gru.*",
            "predictor.orientation_head.*",
            "predictor.precision_head.*",
            "scaffold.*",
            "task/generator/assays/benchmarks/thresholds/seed panels",
        ],
        "objective": {
            "name": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "loss": "existing expected_distribution loss only",
        },
        "pretraining": {
            "config_family": "phase1_core",
            "objective_mode": EXPECTED_DISTRIBUTION_OBJECTIVE,
            "n_epochs": training_config.n_epochs,
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "training_source": "ordinary generate_batch() only",
        },
        "refit_phase": {
            "optimizer": "Adam",
            "step_count": training_config.n_epochs,
            "batch_mix": {"ordinary_predictive_batch": 1.0},
            "batch_size": training_config.batch_size,
            "learning_rate": training_config.learning_rate,
            "weight_decay": training_config.weight_decay,
            "identity_rules": {
                "heldout_fixed_probe_eval": "fixed_probe_batch(seed=heldout_seed)",
                "heldout_predictive_eval": "generate_batch(batch_size=32, seed=heldout_seed)",
                "auxiliary_probe_fit": "fixed_probe_batch(seed=heldout_seed + 1)",
                "refit_batches": "generate_batch(batch_size=32, seed=heldout_seed + 100 + step_index)",
            },
        },
        "linear_probe": {
            "form": CONTEXT_RESIDUAL_LINEAR_PROBE_FORM,
            "target": CONTEXT_RESIDUAL_LINEAR_PROBE_TARGET,
            "ridge_lambda": CONTEXT_RESIDUAL_LINEAR_PROBE_RIDGE_LAMBDA,
            "fit_mask": "probe_step_mask & probe_valid_mask",
            "train_eval_split": "auxiliary_probe_fit_batch vs heldout_fixed_probe_batch",
        },
        "seed_panels": {
            "primary": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in primary_seed_panel],
            "confirmation": [{"train_seed": int(train_seed), "heldout_seed": int(eval_seed)} for train_seed, eval_seed in confirmation_seed_panel],
        },
        "heldout_eval_rules": {
            "fixed_probe": "same held-out fixed-probe batch pre and post",
            "predictive": "same held-out predictive batch pre and post",
        },
        "bootstrap": {
            "seed": CONTEXT_RESIDUAL_BOOTSTRAP_SEED,
            "resamples": CONTEXT_RESIDUAL_BOOTSTRAP_RESAMPLES,
            "confidence_level": CONTEXT_RESIDUAL_BOOTSTRAP_CONFIDENCE_LEVEL,
        },
        "run_order": [
            "write_context_residual_manifest",
            "run_P0_manifest_validity",
            "run_R1_frozen_nonregression",
            "run_R2_pre_refit_primary",
            "run_primary_refit_and_R3_R4_reports_if_R2_passes",
            "run_confirmation_if_R4_passes",
            "write_context_residual_reports_and_verdict",
        ],
        "stop_rules": {
            "halt_on_manifest_invalidity": True,
            "halt_on_nonregression_failure": True,
            "halt_on_pre_refit_premise_failure": True,
            "halt_on_integrity_failure": True,
            "halt_on_primary_scientific_failure": True,
            "confirmation_only_if_primary_passes": True,
            "halt_on_confirmation_failure": True,
            "no_harder_evaluation": True,
            "no_second_package": True,
            "no_sweep": True,
        },
        "explicit_statements": {
            "no_sweep": True,
            "no_second_package": True,
            "no_teacher_targets": True,
            "no_heldout_selection": True,
            "residual_zero_initialized": True,
        },
    }
    _write_json(output_root / CONTEXT_RESIDUAL_MANIFEST_V1_ARTIFACT, package_manifest)

    nonregression_report = _context_residual_build_nonregression_report(
        resolved_config=resolved_config,
        output_root=output_root,
        benchmark_artifacts_root=benchmark_artifacts_root,
    )
    _write_json(output_root / CONTEXT_RESIDUAL_NONREGRESSION_REPORT_V1_ARTIFACT, nonregression_report)
    if not _context_residual_manifest_validity(package_manifest) or not bool(nonregression_report["passes"]):
        pre_primary_report = _context_residual_build_skipped_panel_report(
            artifact_key="pre_refit_report",
            seed_panel="primary",
            stop_reason="preconditions_failed",
        )
        integrity_primary_report = _context_residual_build_skipped_panel_report(
            artifact_key="refit_integrity_report",
            seed_panel="primary",
            stop_reason="preconditions_failed",
        )
        post_primary_report = _context_residual_build_skipped_panel_report(
            artifact_key="post_refit_report",
            seed_panel="primary",
            stop_reason="preconditions_failed",
        )
        structure_report = {
            **_context_residual_metadata(
                metric_versions={"context_residual_structure_report": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "panels": {},
            "skipped": True,
            "stop_reason": "preconditions_failed",
        }
        advantage_gap_report = {
            **_context_residual_metadata(
                metric_versions={"context_residual_advantage_gap_report": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "panels": {},
            "skipped": True,
            "stop_reason": "preconditions_failed",
        }
        verdict = _context_residual_build_verdict(
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            refit_integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_report=structure_report,
            pre_refit_confirmation_report=None,
            refit_integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / CONTEXT_RESIDUAL_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_STRUCTURE_REPORT_V1_ARTIFACT, structure_report)
        _write_json(output_root / CONTEXT_RESIDUAL_ADVANTAGE_GAP_REPORT_V1_ARTIFACT, advantage_gap_report)
        _write_json(output_root / CONTEXT_RESIDUAL_VERDICT_V1_ARTIFACT, verdict)
        return ContextResidualRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            refit_integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_report=structure_report,
            advantage_gap_report=advantage_gap_report,
            verdict=verdict,
            pre_refit_confirmation_report=None,
            refit_integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            run_ids=[],
        )

    store = RunStore(resolved_config.artifacts.root_dir)
    generator = Phase1ParadigmGenerator(resolved_config, controlled_sources=STAGE3_FULL_CONTROLLED_SOURCES)
    model = V1ExpectationModel(resolved_config)
    model.eval()
    assay_runner = AssayRunner(resolved_config)

    primary_prepared_runs: list[dict[str, object]] = []
    run_ids: list[str] = []
    for train_seed, heldout_seed in primary_seed_panel:
        prepared_run = _context_residual_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="primary",
        )
        primary_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    primary_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["auxiliary_probe_fit_seed"],
            "pre_refit": {
                key: value
                for key, value in prepared_run["pre_refit"].items()
                if key
                not in (
                    "heldout_hidden_states",
                    "predictive_hidden_states",
                    "auxiliary_hidden_states",
                    "learned_orientation_logits",
                    "probe_scoring_mask",
                )
            },
            "artifacts_complete": True,
        }
        for prepared_run in primary_prepared_runs
    ]
    pre_primary_report = _context_residual_build_pre_report(
        seed_panel="primary",
        run_entries=primary_pre_entries,
    )
    advantage_gap_report = _context_residual_build_advantage_gap_report(
        primary_run_entries=primary_pre_entries,
        confirmation_run_entries=None,
    )
    if not bool(pre_primary_report["passes"]):
        integrity_primary_report = _context_residual_build_skipped_panel_report(
            artifact_key="refit_integrity_report",
            seed_panel="primary",
            stop_reason="pre_refit_failed",
        )
        post_primary_report = _context_residual_build_skipped_panel_report(
            artifact_key="post_refit_report",
            seed_panel="primary",
            stop_reason="pre_refit_failed",
        )
        structure_report = {
            **_context_residual_metadata(
                metric_versions={"context_residual_structure_report": "v1"},
                source_metric_versions=[FROZEN_BENCHMARK_METRIC_VERSION],
            ),
            "panels": {},
            "skipped": True,
            "stop_reason": "pre_refit_failed",
        }
        verdict = _context_residual_build_verdict(
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            refit_integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_report=structure_report,
            pre_refit_confirmation_report=None,
            refit_integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / CONTEXT_RESIDUAL_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_STRUCTURE_REPORT_V1_ARTIFACT, structure_report)
        _write_json(output_root / CONTEXT_RESIDUAL_ADVANTAGE_GAP_REPORT_V1_ARTIFACT, advantage_gap_report)
        _write_json(output_root / CONTEXT_RESIDUAL_VERDICT_V1_ARTIFACT, verdict)
        return ContextResidualRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            refit_integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_report=structure_report,
            advantage_gap_report=advantage_gap_report,
            verdict=verdict,
            pre_refit_confirmation_report=None,
            refit_integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            run_ids=run_ids,
        )

    primary_run_entries = [_context_residual_complete_run(prepared_run) for prepared_run in primary_prepared_runs]
    integrity_primary_report = _context_residual_build_integrity_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
    )
    post_primary_report = _context_residual_build_post_report(
        seed_panel="primary",
        run_entries=primary_run_entries,
        overall_entries=None,
    )
    structure_report = _context_residual_build_structure_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=None,
    )
    advantage_gap_report = _context_residual_build_advantage_gap_report(
        primary_run_entries=primary_run_entries,
        confirmation_run_entries=None,
    )
    if not bool(integrity_primary_report["passes"]) or not bool(post_primary_report["passes"]) or not bool(
        structure_report["panels"]["primary"]["passes"]
    ):
        verdict = _context_residual_build_verdict(
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            refit_integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_report=structure_report,
            pre_refit_confirmation_report=None,
            refit_integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            confirmation_executed=False,
        )
        _write_json(output_root / CONTEXT_RESIDUAL_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
        _write_json(output_root / CONTEXT_RESIDUAL_STRUCTURE_REPORT_V1_ARTIFACT, structure_report)
        _write_json(output_root / CONTEXT_RESIDUAL_ADVANTAGE_GAP_REPORT_V1_ARTIFACT, advantage_gap_report)
        _write_json(output_root / CONTEXT_RESIDUAL_VERDICT_V1_ARTIFACT, verdict)
        return ContextResidualRunResult(
            output_root=output_root,
            package_manifest=package_manifest,
            nonregression_report=nonregression_report,
            pre_refit_primary_report=pre_primary_report,
            refit_integrity_primary_report=integrity_primary_report,
            post_refit_primary_report=post_primary_report,
            structure_report=structure_report,
            advantage_gap_report=advantage_gap_report,
            verdict=verdict,
            pre_refit_confirmation_report=None,
            refit_integrity_confirmation_report=None,
            post_refit_confirmation_report=None,
            run_ids=run_ids,
        )

    confirmation_prepared_runs: list[dict[str, object]] = []
    for train_seed, heldout_seed in confirmation_seed_panel:
        prepared_run = _context_residual_prepare_run(
            resolved_config=resolved_config,
            store=store,
            generator=generator,
            model=model,
            assay_runner=assay_runner,
            train_seed=int(train_seed),
            heldout_seed=int(heldout_seed),
            seed_panel="confirmation",
        )
        confirmation_prepared_runs.append(prepared_run)
        run_ids.append(prepared_run["run_id"])
    confirmation_pre_entries = [
        {
            "run_id": prepared_run["run_id"],
            "run_dir": prepared_run["run_dir"],
            "seed_panel": prepared_run["seed_panel"],
            "train_seed": prepared_run["train_seed"],
            "heldout_seed": prepared_run["heldout_seed"],
            "auxiliary_probe_fit_seed": prepared_run["auxiliary_probe_fit_seed"],
            "pre_refit": {
                key: value
                for key, value in prepared_run["pre_refit"].items()
                if key
                not in (
                    "heldout_hidden_states",
                    "predictive_hidden_states",
                    "auxiliary_hidden_states",
                    "learned_orientation_logits",
                    "probe_scoring_mask",
                )
            },
            "artifacts_complete": True,
        }
        for prepared_run in confirmation_prepared_runs
    ]
    pre_confirmation_report = _context_residual_build_pre_report(
        seed_panel="confirmation",
        run_entries=confirmation_pre_entries,
    )
    confirmation_run_entries: list[dict[str, object]] | None = None
    integrity_confirmation_report: dict[str, object] | None = None
    post_confirmation_report: dict[str, object] | None = None
    if bool(pre_confirmation_report["passes"]):
        confirmation_run_entries = [_context_residual_complete_run(prepared_run) for prepared_run in confirmation_prepared_runs]
        integrity_confirmation_report = _context_residual_build_integrity_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
        )
        post_confirmation_report = _context_residual_build_post_report(
            seed_panel="confirmation",
            run_entries=confirmation_run_entries,
            overall_entries=primary_run_entries + confirmation_run_entries,
        )
        structure_report = _context_residual_build_structure_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_run_entries,
        )
        advantage_gap_report = _context_residual_build_advantage_gap_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_run_entries,
        )
    else:
        advantage_gap_report = _context_residual_build_advantage_gap_report(
            primary_run_entries=primary_run_entries,
            confirmation_run_entries=confirmation_pre_entries,
        )

    verdict = _context_residual_build_verdict(
        package_manifest=package_manifest,
        nonregression_report=nonregression_report,
        pre_refit_primary_report=pre_primary_report,
        refit_integrity_primary_report=integrity_primary_report,
        post_refit_primary_report=post_primary_report,
        structure_report=structure_report,
        pre_refit_confirmation_report=pre_confirmation_report,
        refit_integrity_confirmation_report=integrity_confirmation_report,
        post_refit_confirmation_report=post_confirmation_report,
        confirmation_executed=True,
    )

    _write_json(output_root / CONTEXT_RESIDUAL_PRE_PRIMARY_REPORT_V1_ARTIFACT, pre_primary_report)
    _write_json(output_root / CONTEXT_RESIDUAL_INTEGRITY_PRIMARY_REPORT_V1_ARTIFACT, integrity_primary_report)
    _write_json(output_root / CONTEXT_RESIDUAL_POST_PRIMARY_REPORT_V1_ARTIFACT, post_primary_report)
    _write_json(output_root / CONTEXT_RESIDUAL_STRUCTURE_REPORT_V1_ARTIFACT, structure_report)
    _write_json(output_root / CONTEXT_RESIDUAL_ADVANTAGE_GAP_REPORT_V1_ARTIFACT, advantage_gap_report)
    _write_json(output_root / CONTEXT_RESIDUAL_VERDICT_V1_ARTIFACT, verdict)
    _write_json(output_root / CONTEXT_RESIDUAL_PRE_CONFIRMATION_REPORT_V1_ARTIFACT, pre_confirmation_report)
    if integrity_confirmation_report is not None:
        _write_json(output_root / CONTEXT_RESIDUAL_INTEGRITY_CONFIRMATION_REPORT_V1_ARTIFACT, integrity_confirmation_report)
    if post_confirmation_report is not None:
        _write_json(output_root / CONTEXT_RESIDUAL_POST_CONFIRMATION_REPORT_V1_ARTIFACT, post_confirmation_report)

    return ContextResidualRunResult(
        output_root=output_root,
        package_manifest=package_manifest,
        nonregression_report=nonregression_report,
        pre_refit_primary_report=pre_primary_report,
        refit_integrity_primary_report=integrity_primary_report,
        post_refit_primary_report=post_primary_report,
        structure_report=structure_report,
        advantage_gap_report=advantage_gap_report,
        verdict=verdict,
        pre_refit_confirmation_report=pre_confirmation_report,
        refit_integrity_confirmation_report=integrity_confirmation_report,
        post_refit_confirmation_report=post_confirmation_report,
        run_ids=run_ids,
    )
